function clearLoadingHideTimer() {
  if (state.loadingHideTimer != null) {
    window.clearTimeout(state.loadingHideTimer);
    state.loadingHideTimer = null;
  }
}

function waitForNextPaint() {
  return new Promise((resolve) => {
    window.requestAnimationFrame(() => {
      window.setTimeout(resolve, 0);
    });
  });
}

function eventHasLibraryRelations(eventItem) {
  if (!eventItem) return false;
  if (eventItem.parentEventId) return true;
  return timelineEvents.some((candidate) => candidate.parentEventId === eventItem.id);
}

function showConfirmModal({
  title = t("delete_confirm_title"),
  message = t("delete_confirm_message"),
  confirmLabel = t("delete"),
  cancelLabel = t("cancel"),
  optionLabel = "",
} = {}) {
  return new Promise((resolve) => {
    if (!ui.confirmDeleteModal) {
      resolve(optionLabel ? { confirmed: true, optionChecked: false } : true);
      return;
    }
    const previousTitle = ui.confirmDeleteTitle?.textContent ?? "";
    const previousMessage = ui.confirmDeleteMessage?.textContent ?? "";
    const previousCancelLabel = ui.confirmDeleteCancelButton?.textContent ?? "";
    const previousConfirmLabel = ui.confirmDeleteConfirmButton?.textContent ?? "";
    const previousOptionLabel = ui.confirmDeleteOptionLabel?.textContent ?? "";
    const previousOptionHidden = ui.confirmDeleteOptionField?.hidden ?? true;
    const previousOptionChecked = ui.confirmDeleteOptionInput?.checked ?? false;
    if (ui.confirmDeleteTitle) ui.confirmDeleteTitle.textContent = title;
    if (ui.confirmDeleteMessage) ui.confirmDeleteMessage.textContent = message;
    if (ui.confirmDeleteCancelButton) ui.confirmDeleteCancelButton.textContent = cancelLabel;
    if (ui.confirmDeleteConfirmButton) ui.confirmDeleteConfirmButton.textContent = confirmLabel;
    if (ui.confirmDeleteOptionField) ui.confirmDeleteOptionField.hidden = !optionLabel;
    if (ui.confirmDeleteOptionInput) ui.confirmDeleteOptionInput.checked = false;
    if (ui.confirmDeleteOptionLabel) ui.confirmDeleteOptionLabel.textContent = optionLabel;
    const cleanup = (result) => {
      const optionChecked = ui.confirmDeleteOptionInput?.checked === true;
      ui.confirmDeleteModal.hidden = true;
      ui.confirmDeleteCancelButton?.removeEventListener("click", onCancel);
      ui.confirmDeleteConfirmButton?.removeEventListener("click", onConfirm);
      ui.confirmDeleteBackdrop?.removeEventListener("click", onCancel);
      if (ui.confirmDeleteTitle) ui.confirmDeleteTitle.textContent = previousTitle;
      if (ui.confirmDeleteMessage) ui.confirmDeleteMessage.textContent = previousMessage;
      if (ui.confirmDeleteCancelButton) ui.confirmDeleteCancelButton.textContent = previousCancelLabel;
      if (ui.confirmDeleteConfirmButton) ui.confirmDeleteConfirmButton.textContent = previousConfirmLabel;
      if (ui.confirmDeleteOptionField) ui.confirmDeleteOptionField.hidden = previousOptionHidden;
      if (ui.confirmDeleteOptionInput) ui.confirmDeleteOptionInput.checked = previousOptionChecked;
      if (ui.confirmDeleteOptionLabel) ui.confirmDeleteOptionLabel.textContent = previousOptionLabel;
      resolve(optionLabel ? { confirmed: result, optionChecked } : result);
    };
    const onCancel = () => cleanup(false);
    const onConfirm = () => cleanup(true);
    ui.confirmDeleteModal.hidden = false;
    ui.confirmDeleteCancelButton?.addEventListener("click", onCancel, { once: true });
    ui.confirmDeleteConfirmButton?.addEventListener("click", onConfirm, { once: true });
    ui.confirmDeleteBackdrop?.addEventListener("click", onCancel, { once: true });
  });
}

function showTextPromptModal({
  title = t("chart_comment_label_prompt"),
  message = t("chart_comment_label_message"),
  defaultValue = "",
  extraInput = null,
  confirmLabel = t("chart_csv_paste_save"),
  cancelLabel = t("cancel"),
} = {}) {
  return new Promise((resolve) => {
    if (!ui.textPromptModal || !ui.textPromptInput) {
      resolve(extraInput
        ? {
          value: String(defaultValue || ""),
          extraValue: String(extraInput?.defaultValue ?? ""),
        }
        : String(defaultValue || ""));
      return;
    }
    const previousTitle = ui.textPromptTitle?.textContent ?? "";
    const previousMessage = ui.textPromptMessage?.textContent ?? "";
    const previousValue = ui.textPromptInput.value ?? "";
    const previousExtraHidden = ui.textPromptExtraField?.hidden ?? true;
    const previousExtraLabel = ui.textPromptExtraLabel?.textContent ?? "";
    const previousExtraHintHidden = ui.textPromptExtraHint?.hidden ?? true;
    const previousExtraHint = ui.textPromptExtraHint?.textContent ?? "";
    const previousExtraValue = ui.textPromptExtraInput?.value ?? "";
    const previousExtraType = ui.textPromptExtraInput?.type ?? "text";
    const previousExtraPlaceholder = ui.textPromptExtraInput?.placeholder ?? "";
    const previousCancelLabel = ui.textPromptCancelButton?.textContent ?? "";
    const previousConfirmLabel = ui.textPromptConfirmButton?.textContent ?? "";
    if (ui.textPromptTitle) ui.textPromptTitle.textContent = title;
    if (ui.textPromptMessage) ui.textPromptMessage.textContent = message;
    ui.textPromptInput.value = String(defaultValue ?? "");
    if (ui.textPromptExtraField && ui.textPromptExtraLabel && ui.textPromptExtraInput) {
      const hasExtraInput = !!extraInput;
      ui.textPromptExtraField.hidden = !hasExtraInput;
      ui.textPromptExtraLabel.textContent = extraInput?.label || "Platzierung";
      if (ui.textPromptExtraHint) {
        const nextHint = extraInput?.hint || "";
        ui.textPromptExtraHint.hidden = !(hasExtraInput && nextHint);
        ui.textPromptExtraHint.textContent = nextHint;
      }
      ui.textPromptExtraInput.value = String(extraInput?.defaultValue ?? "");
      ui.textPromptExtraInput.type = extraInput?.type || "text";
      ui.textPromptExtraInput.placeholder = extraInput?.placeholder || "YYYY-MM-DD";
    }
    if (ui.textPromptCancelButton) ui.textPromptCancelButton.textContent = cancelLabel;
    if (ui.textPromptConfirmButton) ui.textPromptConfirmButton.textContent = confirmLabel;
    const cleanup = (result) => {
      ui.textPromptModal.hidden = true;
      ui.textPromptCancelButton?.removeEventListener("click", onCancel);
      ui.textPromptConfirmButton?.removeEventListener("click", onConfirm);
      ui.textPromptBackdrop?.removeEventListener("click", onCancel);
      ui.textPromptInput?.removeEventListener("keydown", onKeyDown);
      ui.textPromptExtraInput?.removeEventListener("keydown", onKeyDown);
      if (ui.textPromptTitle) ui.textPromptTitle.textContent = previousTitle;
      if (ui.textPromptMessage) ui.textPromptMessage.textContent = previousMessage;
      if (ui.textPromptInput) ui.textPromptInput.value = previousValue;
      if (ui.textPromptExtraField) ui.textPromptExtraField.hidden = previousExtraHidden;
      if (ui.textPromptExtraLabel) ui.textPromptExtraLabel.textContent = previousExtraLabel;
      if (ui.textPromptExtraHint) {
        ui.textPromptExtraHint.hidden = previousExtraHintHidden;
        ui.textPromptExtraHint.textContent = previousExtraHint;
      }
      if (ui.textPromptExtraInput) {
        ui.textPromptExtraInput.value = previousExtraValue;
        ui.textPromptExtraInput.type = previousExtraType;
        ui.textPromptExtraInput.placeholder = previousExtraPlaceholder;
      }
      if (ui.textPromptCancelButton) ui.textPromptCancelButton.textContent = previousCancelLabel;
      if (ui.textPromptConfirmButton) ui.textPromptConfirmButton.textContent = previousConfirmLabel;
      resolve(result);
    };
    const onCancel = () => cleanup(null);
    const onConfirm = () => {
      const rawPrimaryValue = String(ui.textPromptInput?.value ?? "");
      const resolvedPrimaryValue = rawPrimaryValue.trim()
        ? rawPrimaryValue
        : String(defaultValue ?? "");
      if (extraInput) {
        const rawExtraValue = String(ui.textPromptExtraInput?.value ?? "");
        const resolvedExtraValue = rawExtraValue.trim()
          ? rawExtraValue
          : String(extraInput?.defaultValue ?? "");
        cleanup({
          value: resolvedPrimaryValue,
          extraValue: resolvedExtraValue,
        });
        return;
      }
      cleanup(resolvedPrimaryValue);
    };
    const onKeyDown = (event) => {
      if (event.key === "Escape") {
        event.preventDefault();
        onCancel();
      } else if (event.key === "Enter") {
        event.preventDefault();
        onConfirm();
      }
    };
    ui.textPromptModal.hidden = false;
    ui.textPromptCancelButton?.addEventListener("click", onCancel, { once: true });
    ui.textPromptConfirmButton?.addEventListener("click", onConfirm, { once: true });
    ui.textPromptBackdrop?.addEventListener("click", onCancel, { once: true });
    ui.textPromptInput?.addEventListener("keydown", onKeyDown);
    ui.textPromptExtraInput?.addEventListener("keydown", onKeyDown);
    window.requestAnimationFrame(() => {
      ui.textPromptInput?.focus();
      ui.textPromptInput?.select();
    });
  });
}

function showPresentationRenderModal({
  defaultStartValue = "",
  defaultEndValue = "",
  defaultMinStepId = scaleSteps[0]?.id || "1d",
  defaultMaxStepId = scaleSteps[scaleSteps.length - 1]?.id || "1Ga",
} = {}) {
  return new Promise((resolve) => {
    if (
      !ui.presentationRenderModal
      || !ui.presentationRenderStartInput
      || !ui.presentationRenderEndInput
      || !ui.presentationRenderZoomMinSelect
      || !ui.presentationRenderZoomMaxSelect
    ) {
      resolve(null);
      return;
    }

    const previousStart = ui.presentationRenderStartInput.value;
    const previousEnd = ui.presentationRenderEndInput.value;
    const previousMinOptions = ui.presentationRenderZoomMinSelect.innerHTML;
    const previousMaxOptions = ui.presentationRenderZoomMaxSelect.innerHTML;
    const previousSaveText = ui.presentationRenderSaveReadout?.textContent ?? "";
    const previousSaveSelected = ui.presentationRenderSaveReadout?.dataset.selected ?? "";
    const previousCancelLabel = ui.presentationRenderCancelButton?.textContent ?? "";
    const previousConfirmLabel = ui.presentationRenderConfirmButton?.textContent ?? "";
    const previousChooseLabel = ui.presentationRenderChooseLocationButton?.textContent ?? "";
    let selectedSaveTarget = null;

    ui.presentationRenderStartInput.value = String(defaultStartValue ?? "");
    ui.presentationRenderEndInput.value = String(defaultEndValue ?? "");

    ui.presentationRenderZoomMinSelect.replaceChildren();
    ui.presentationRenderZoomMaxSelect.replaceChildren();
    scaleSteps.forEach((step) => {
      ui.presentationRenderZoomMinSelect.appendChild(createSelectOption(step.id, stepToLabel(step), step.id === defaultMinStepId));
      ui.presentationRenderZoomMaxSelect.appendChild(createSelectOption(step.id, stepToLabel(step), step.id === defaultMaxStepId));
    });
    if (ui.presentationRenderCancelButton) ui.presentationRenderCancelButton.textContent = t("cancel");
    if (ui.presentationRenderConfirmButton) ui.presentationRenderConfirmButton.textContent = t("render");
    if (ui.presentationRenderChooseLocationButton) ui.presentationRenderChooseLocationButton.textContent = t("presentation_render_save_choose");
    if (ui.presentationRenderSaveReadout) {
      ui.presentationRenderSaveReadout.textContent = t("presentation_render_save_missing");
      ui.presentationRenderSaveReadout.dataset.selected = "";
      ui.presentationRenderSaveReadout.classList.add("is-empty");
    }

    const cleanup = () => {
      ui.presentationRenderModal.hidden = true;
      ui.presentationRenderCancelButton?.removeEventListener("click", onCancel);
      ui.presentationRenderConfirmButton?.removeEventListener("click", onConfirm);
      ui.presentationRenderChooseLocationButton?.removeEventListener("click", onChooseLocation);
      ui.presentationRenderBackdrop?.removeEventListener("click", onCancel);
      ui.presentationRenderStartInput?.removeEventListener("keydown", onKeyDown);
      ui.presentationRenderEndInput?.removeEventListener("keydown", onKeyDown);
      ui.presentationRenderZoomMinSelect?.removeEventListener("keydown", onKeyDown);
      ui.presentationRenderZoomMaxSelect?.removeEventListener("keydown", onKeyDown);
      ui.presentationRenderStartInput.value = previousStart;
      ui.presentationRenderEndInput.value = previousEnd;
      ui.presentationRenderZoomMinSelect.innerHTML = previousMinOptions;
      ui.presentationRenderZoomMaxSelect.innerHTML = previousMaxOptions;
      if (ui.presentationRenderSaveReadout) {
        ui.presentationRenderSaveReadout.textContent = previousSaveText;
        ui.presentationRenderSaveReadout.dataset.selected = previousSaveSelected;
        ui.presentationRenderSaveReadout.classList.toggle("is-empty", !previousSaveSelected);
      }
      if (ui.presentationRenderCancelButton) ui.presentationRenderCancelButton.textContent = previousCancelLabel;
      if (ui.presentationRenderConfirmButton) ui.presentationRenderConfirmButton.textContent = previousConfirmLabel;
      if (ui.presentationRenderChooseLocationButton) ui.presentationRenderChooseLocationButton.textContent = previousChooseLabel;
    };

    const onCancel = () => {
      cleanup();
      resolve(null);
    };

    const onChooseLocation = async () => {
      try {
        const target = await choosePresentationSaveTarget();
        if (!target) return;
        selectedSaveTarget = target;
        if (ui.presentationRenderSaveReadout) {
          ui.presentationRenderSaveReadout.textContent = target.label || t("presentation_render_filename");
          ui.presentationRenderSaveReadout.dataset.selected = "true";
          ui.presentationRenderSaveReadout.classList.remove("is-empty");
        }
      } catch {
        // Picker cancelled.
      }
    };

    const onConfirm = () => {
      const startParsed = parseEditorTemporalValue(ui.presentationRenderStartInput.value);
      const endParsed = parseEditorTemporalValue(ui.presentationRenderEndInput.value);
      if (!startParsed || !endParsed || !selectedSaveTarget) {
        return;
      }
      const minStepId = String(ui.presentationRenderZoomMinSelect.value || defaultMinStepId);
      const maxStepId = String(ui.presentationRenderZoomMaxSelect.value || defaultMaxStepId);
      cleanup();
      resolve({
        rangeStart: Math.min(startParsed.value, endParsed.value),
        rangeEnd: Math.max(startParsed.value, endParsed.value),
        minZoomStepId: minStepId,
        maxZoomStepId: maxStepId,
        saveTarget: selectedSaveTarget,
      });
    };

    const onKeyDown = (event) => {
      if (event.key === "Escape") {
        event.preventDefault();
        onCancel();
      } else if (event.key === "Enter") {
        event.preventDefault();
        onConfirm();
      }
    };

    ui.presentationRenderModal.hidden = false;
    ui.presentationRenderCancelButton?.addEventListener("click", onCancel, { once: true });
    ui.presentationRenderConfirmButton?.addEventListener("click", onConfirm, { once: true });
    ui.presentationRenderChooseLocationButton?.addEventListener("click", onChooseLocation);
    ui.presentationRenderBackdrop?.addEventListener("click", onCancel, { once: true });
    ui.presentationRenderStartInput?.addEventListener("keydown", onKeyDown);
    ui.presentationRenderEndInput?.addEventListener("keydown", onKeyDown);
    ui.presentationRenderZoomMinSelect?.addEventListener("keydown", onKeyDown);
    ui.presentationRenderZoomMaxSelect?.addEventListener("keydown", onKeyDown);
    window.setTimeout(() => {
      ui.presentationRenderStartInput?.focus();
      ui.presentationRenderStartInput?.select();
    }, 0);
  });
}

