function getNextChartColor(existingCharts = chartItems, preferredIndex = null) {
  const normalizedPalette = CHART_COLOR_SEQUENCE.map((color) => color.toLowerCase());
  const usedColors = new Set(
    (Array.isArray(existingCharts) ? existingCharts : [])
      .map((chartItem) => String(chartItem?.color || "").trim().toLowerCase())
      .filter(Boolean),
  );
  if (Number.isInteger(preferredIndex) && preferredIndex >= 0) {
    return normalizedPalette[preferredIndex % normalizedPalette.length];
  }
  const unusedColor = normalizedPalette.find((color) => !usedColors.has(color));
  if (unusedColor) return unusedColor;
  const nextIndex = usedColors.size % normalizedPalette.length;
  return normalizedPalette[nextIndex];
}

function assignChartDisplayColor(chartItem, options = {}) {
  if (!chartItem) return;
  const {
    existingCharts = chartItems,
    preferredIndex = null,
    force = false,
    syncPrimaryTableColor = false,
  } = options;
  const nextColor = getNextChartColor(existingCharts, preferredIndex);
  const currentColor = String(chartItem.color || "").trim();
  if (force || !currentColor) {
    chartItem.color = nextColor;
  }
  const primaryTable = getChartPrimaryTable(chartItem);
  if (primaryTable && (
    force
    || !String(primaryTable.color || "").trim()
    || (syncPrimaryTableColor && getChartTables(chartItem).length <= 1)
  )) {
    primaryTable.color = chartItem.color;
  }
}

function cloneTrashPayload(payload) {
  if (typeof structuredClone === "function") {
    return structuredClone(payload);
  }
  return JSON.parse(JSON.stringify(payload));
}

function getTrashCounts() {
  return {
    events: trashStore.events.length,
    charts: trashStore.charts.length,
    bookmarks: trashStore.bookmarks.length,
    timelineComments: trashStore.timelineComments.length,
  };
}

function getTrashTotalCount() {
  const counts = getTrashCounts();
  return counts.events + counts.charts + counts.bookmarks + counts.timelineComments;
}

function hasTrashEntries() {
  return getTrashTotalCount() > 0;
}

function removeEventReferencesToDeletedIds(deletedEventIds) {
  timelineEvents.forEach((eventItem) => {
    if (deletedEventIds.has(eventItem.parentEventId)) {
      eventItem.parentEventId = null;
    }
  });
  chartItems.forEach((chartItem) => {
    if (deletedEventIds.has(chartItem.parentEventId)) {
      chartItem.parentEventId = null;
    }
  });
  sourceItems.forEach((sourceItem) => {
    if (deletedEventIds.has(sourceItem.coupledEventId)) {
      sourceItem.coupledEventId = null;
    }
  });
}

function trashEventTree(eventId) {
  const deletedIds = new Set([eventId, ...getEventDescendantIds(eventId)]);
  const removedEvents = timelineEvents
    .filter((eventItem) => deletedIds.has(eventItem.id))
    .map((eventItem) => cloneTrashPayload({
      ...eventItem,
      groupId: null,
      parentEventId: null,
      expanded: false,
      enabled: eventItem.enabled !== false,
    }));
  if (!removedEvents.length) return;
  removeEventReferencesToDeletedIds(deletedIds);
  for (let index = timelineEvents.length - 1; index >= 0; index -= 1) {
    if (deletedIds.has(timelineEvents[index].id)) {
      if (state.openEditorId === timelineEvents[index].id) state.openEditorId = null;
      if (state.selectedEventId === timelineEvents[index].id) state.selectedEventId = null;
      timelineEvents.splice(index, 1);
    }
  }
  trashStore.events.push(...removedEvents);
}

function trashChart(chartId) {
  const chartIndex = chartItems.findIndex((chartItem) => chartItem.id === chartId);
  if (chartIndex === -1) return;
  const chartItem = chartItems[chartIndex];
  trashStore.charts.push(cloneTrashPayload({
    ...chartItem,
    groupId: null,
    parentEventId: null,
    visible: chartItem.visible !== false,
  }));
  deleteChartDraftRowsForChart(chartItem.id);
  if (state.openChartEditorId === chartItem.id) state.openChartEditorId = null;
  if (state.activeChartId === chartItem.id) state.activeChartId = null;
  if (state.openChartCommentEditorId) {
    const resolvedComment = findChartCommentById(state.openChartCommentEditorId);
    if (resolvedComment?.chartItem?.id === chartItem.id) {
      state.openChartCommentEditorId = null;
    }
  }
  chartItems.splice(chartIndex, 1);
}

function trashBookmark(bookmarkId) {
  const bookmarkIndex = state.tickBookmarks.findIndex((bookmark) => bookmark.id === bookmarkId);
  if (bookmarkIndex === -1) return;
  const bookmark = state.tickBookmarks[bookmarkIndex];
  trashStore.bookmarks.push(cloneTrashPayload({
    ...bookmark,
    groupId: null,
    ownerGroupId: null,
  }));
  if (state.openBookmarkEditorId === bookmark.id) {
    state.openBookmarkEditorId = null;
  }
  state.tickBookmarks.splice(bookmarkIndex, 1);
}

function trashTimelineComment(commentId) {
  const commentIndex = timelineComments.findIndex((comment) => comment.id === commentId);
  if (commentIndex === -1) return;
  const comment = timelineComments[commentIndex];
  trashStore.timelineComments.push(cloneTrashPayload({
    ...comment,
    groupId: null,
    enabled: comment.enabled !== false,
  }));
  if (state.openTimelineCommentEditorId === comment.id) {
    state.openTimelineCommentEditorId = null;
  }
  timelineComments.splice(commentIndex, 1);
}

function trashGroupTree(groupId) {
  const descendantIds = new Set(getDescendantGroupIds(groupId));
  const deletedEventIds = new Set(
    timelineEvents
      .filter((eventItem) => descendantIds.has(eventItem.groupId))
      .map((eventItem) => eventItem.id),
  );
  const removedEvents = timelineEvents
    .filter((eventItem) => descendantIds.has(eventItem.groupId))
    .map((eventItem) => cloneTrashPayload({
      ...eventItem,
      groupId: null,
      parentEventId: null,
      expanded: false,
      enabled: eventItem.enabled !== false,
    }));
  const removedCharts = chartItems
    .filter((chartItem) => descendantIds.has(chartItem.groupId))
    .map((chartItem) => cloneTrashPayload({
      ...chartItem,
      groupId: null,
      parentEventId: null,
      visible: chartItem.visible !== false,
    }));
  const removedSources = sourceItems
    .filter((sourceItem) => descendantIds.has(sourceItem.groupId))
    .map((sourceItem) => cloneTrashPayload({
      ...sourceItem,
      groupId: null,
      enabled: sourceItem.enabled !== false,
    }));
  const removedBookmarks = state.tickBookmarks
    .filter((bookmark) => descendantIds.has(bookmark.groupId))
    .map((bookmark) => cloneTrashPayload({
      ...bookmark,
      groupId: null,
      ownerGroupId: null,
    }));
  const removedTimelineComments = timelineComments
    .filter((comment) => descendantIds.has(comment.groupId))
    .map((comment) => cloneTrashPayload({
      ...comment,
      groupId: null,
      enabled: comment.enabled !== false,
    }));

  removeEventReferencesToDeletedIds(deletedEventIds);

  if (state.openGroupEditorId && descendantIds.has(state.openGroupEditorId)) {
    state.openGroupEditorId = null;
  }
  if (state.activeContextGroupId && descendantIds.has(state.activeContextGroupId)) {
    state.activeContextGroupId = null;
  }

  for (let index = chartItems.length - 1; index >= 0; index -= 1) {
    if (descendantIds.has(chartItems[index].groupId)) {
      deleteChartDraftRowsForChart(chartItems[index].id);
      if (state.openChartEditorId === chartItems[index].id) state.openChartEditorId = null;
      if (state.activeChartId === chartItems[index].id) state.activeChartId = null;
      chartItems.splice(index, 1);
    }
  }
  for (let index = sourceItems.length - 1; index >= 0; index -= 1) {
    if (descendantIds.has(sourceItems[index].groupId)) {
      removeSourceFromCollections(sourceItems[index].id);
      sourceItems.splice(index, 1);
    }
  }
  for (let index = sourceCollections.length - 1; index >= 0; index -= 1) {
    if (descendantIds.has(sourceCollections[index].groupId)) {
      deleteSourceCollectionById(sourceCollections[index].id);
    }
  }
  if (state.openChartCommentEditorId && !findChartCommentById(state.openChartCommentEditorId)) {
    state.openChartCommentEditorId = null;
  }
  for (let index = timelineEvents.length - 1; index >= 0; index -= 1) {
    if (descendantIds.has(timelineEvents[index].groupId)) {
      if (state.openEditorId === timelineEvents[index].id) state.openEditorId = null;
      if (state.selectedEventId === timelineEvents[index].id) state.selectedEventId = null;
      timelineEvents.splice(index, 1);
    }
  }
  for (let index = state.tickBookmarks.length - 1; index >= 0; index -= 1) {
    if (descendantIds.has(state.tickBookmarks[index].groupId)) {
      if (state.openBookmarkEditorId === state.tickBookmarks[index].id) {
        state.openBookmarkEditorId = null;
      }
      state.tickBookmarks.splice(index, 1);
    }
  }
  for (let index = timelineComments.length - 1; index >= 0; index -= 1) {
    if (descendantIds.has(timelineComments[index].groupId)) {
      if (state.openTimelineCommentEditorId === timelineComments[index].id) {
        state.openTimelineCommentEditorId = null;
      }
      timelineComments.splice(index, 1);
    }
  }
  for (let index = eventGroups.length - 1; index >= 0; index -= 1) {
    if (descendantIds.has(eventGroups[index].id)) {
      eventGroups.splice(index, 1);
    }
  }

  trashStore.events.push(...removedEvents);
  trashStore.charts.push(...removedCharts);
  trashStore.sources.push(...removedSources);
  trashStore.bookmarks.push(...removedBookmarks);
  trashStore.timelineComments.push(...removedTimelineComments);
}

function restoreEventFromTrash(eventId) {
  const index = trashStore.events.findIndex((eventItem) => eventItem.id === eventId);
  if (index === -1) return;
  const restored = cloneTrashPayload(trashStore.events[index]);
  restored.groupId = null;
  restored.parentEventId = null;
  restored.expanded = false;
  restored.enabled = restored.enabled !== false;
  timelineEvents.push(restored);
  trashStore.events.splice(index, 1);
}

function restoreChartFromTrash(chartId) {
  const index = trashStore.charts.findIndex((chartItem) => chartItem.id === chartId);
  if (index === -1) return;
  const restored = cloneTrashPayload(trashStore.charts[index]);
  restored.groupId = null;
  restored.parentEventId = null;
  restored.visible = restored.visible !== false;
  chartItems.push(restored);
  normalizeChartItem(restored);
  trashStore.charts.splice(index, 1);
}

function restoreBookmarkFromTrash(bookmarkId) {
  const index = trashStore.bookmarks.findIndex((bookmark) => bookmark.id === bookmarkId);
  if (index === -1) return;
  const restored = cloneTrashPayload(trashStore.bookmarks[index]);
  restored.groupId = null;
  restored.ownerGroupId = null;
  state.tickBookmarks.push(restored);
  state.tickBookmarks = sanitizeTickBookmarksCollection(state.tickBookmarks);
  trashStore.bookmarks.splice(index, 1);
}

function restoreTimelineCommentFromTrash(commentId) {
  const index = trashStore.timelineComments.findIndex((comment) => comment.id === commentId);
  if (index === -1) return;
  const restored = cloneTrashPayload(trashStore.timelineComments[index]);
  restored.groupId = null;
  restored.enabled = restored.enabled !== false;
  timelineComments.push(restored);
  trashStore.timelineComments.splice(index, 1);
}

