function createEmptySourceItem() {
  return {
    id: createUniqueId("source"),
    kind: "source",
    sourceType: "film",
    source: "wikidata",
    sourceId: "",
    externalId: "",
    title: "",
    description: "",
    url: "",
    imageUrl: "",
    yearLabel: "",
    groupId: null,
    coupledEventId: null,
    enabled: true,
  };
}

function normalizeSourceItem(sourceItem) {
  if (!sourceItem || typeof sourceItem !== "object") return null;
  const normalized = {
    ...createEmptySourceItem(),
    ...sourceItem,
  };
  normalized.id = String(normalized.id || createUniqueId("source"));
  normalized.sourceType = inferSourceTypeFromItem(sourceItem, normalized.sourceType);
  normalized.source = String(normalized.source || "wikidata").trim() || "wikidata";
  normalized.sourceId = String(normalized.sourceId || "").trim();
  normalized.wikidataId = normalizeWikidataEntityId(normalized.wikidataId || (normalized.source === "wikidata" ? normalized.sourceId : ""));
  normalized.archiveSourceTypes = normalizeSourceArchiveTypes(normalized);
  normalized.externalId = String(normalized.externalId || "").trim();
  normalized.title = String(normalized.title || "").trim() || normalized.sourceId || t("source_film");
  normalized.description = String(normalized.description || "").trim();
  normalized.url = String(normalized.url || "").trim();
  normalized.imageUrl = String(normalized.imageUrl || "").trim();
  normalized.yearLabel = String(normalized.yearLabel || "").trim();
  normalized.countryLabel = String(normalized.countryLabel || "").trim();
  normalized.countryIds = Array.isArray(normalized.countryIds)
    ? normalized.countryIds.map((value) => normalizeWikidataEntityId(value)).filter(Boolean)
    : [];
  normalized.wikidataImageWidth = Number.isFinite(Number(normalized.wikidataImageWidth)) ? Number(normalized.wikidataImageWidth) : null;
  normalized.wikidataImageHeight = Number.isFinite(Number(normalized.wikidataImageHeight)) ? Number(normalized.wikidataImageHeight) : null;
  normalized.wikidataThumbCropCenterX = Number.isFinite(Number(normalized.wikidataThumbCropCenterX)) ? Number(normalized.wikidataThumbCropCenterX) : 0.5;
  normalized.wikidataThumbCropCenterY = Number.isFinite(Number(normalized.wikidataThumbCropCenterY)) ? Number(normalized.wikidataThumbCropCenterY) : 0.5;
  normalized.wikidataThumbCropZoom = Number.isFinite(Number(normalized.wikidataThumbCropZoom)) ? Number(normalized.wikidataThumbCropZoom) : 1;
  normalized.groupId = normalized.groupId && getGroupById(normalized.groupId) ? normalized.groupId : null;
  normalized.enabled = normalized.enabled !== false;
  return ensureSourceEventFields(normalized);
}

function cloneDefaultValue(value) {
  if (Array.isArray(value)) return [...value];
  if (value && typeof value === "object") return structuredClone(value);
  return value;
}

function getSourceImdbId(sourceItem) {
  return String(sourceItem?.imdbId || sourceItem?.externalId || "").trim();
}

function getSourceImdbUrl(sourceItem) {
  const explicitUrl = String(sourceItem?.url || "").trim();
  if (explicitUrl) return explicitUrl;
  const imdbId = getSourceImdbId(sourceItem);
  return imdbId ? `https://www.imdb.com/title/${encodeURIComponent(imdbId)}/` : "";
}

function getSourceTmdbMediaType(sourceItem) {
  const explicitType = String(sourceItem?.tmdbMediaType || sourceItem?.mediaType || "").trim().toLowerCase();
  if (explicitType === "tv" || explicitType === "movie") return explicitType;
  const sourceId = String(sourceItem?.sourceId || "").trim();
  if (sourceId.startsWith("tv:")) return "tv";
  return "movie";
}

function getSourceTmdbId(sourceItem) {
  const explicitId = String(sourceItem?.tmdbId || "").trim();
  if (explicitId) return explicitId;
  const sourceId = String(sourceItem?.sourceId || "").trim();
  const match = sourceId.match(/^(movie|tv):(.+)$/);
  return match ? match[2] : (sourceItem?.source === "tmdb" ? sourceId : "");
}

function getSourceTmdbUrl(sourceItem) {
  const explicitUrl = String(sourceItem?.url || "").trim();
  if (explicitUrl && explicitUrl.includes("themoviedb.org")) return explicitUrl;
  const tmdbId = getSourceTmdbId(sourceItem);
  if (!tmdbId) return "";
  const mediaPath = getSourceTmdbMediaType(sourceItem) === "tv" ? "tv" : "movie";
  return `${TMDB_WEB_URL}/${mediaPath}/${encodeURIComponent(tmdbId)}`;
}

function getSourceCoverUrl(sourceItem) {
  return String(
    sourceItem?.manualImageUrl
    || sourceItem?.wikidataImageThumbUrl
    || sourceItem?.wikidataImagePreviewUrl
    || sourceItem?.wikidataImageUrl
    || sourceItem?.imageUrl
    || "",
  ).trim();
}

function getSourceBrowserMetaText(sourceItem) {
  return [sourceItem?.countryLabel, sourceItem?.yearLabel].filter(Boolean).join(" ");
}

function ensureSourceEventFields(sourceItem) {
  if (!sourceItem || typeof sourceItem !== "object") return sourceItem;
  const hadStartYear = Number.isFinite(Number(sourceItem.startYear));
  const hadImageDisplaySetting = sourceItem.imageDisplayEnabled !== undefined;
  const eventDefaults = createEmptyEvent();
  Object.entries(eventDefaults).forEach(([key, value]) => {
    if (sourceItem[key] === undefined) {
      sourceItem[key] = cloneDefaultValue(value);
    }
  });
  const imdbId = getSourceImdbId(sourceItem);
  const tmdbUrl = getSourceTmdbUrl(sourceItem);
  const coverUrl = getSourceCoverUrl(sourceItem);
  sourceItem.kind = "source";
  sourceItem.sourceType = normalizeSourceType(sourceItem.sourceType);
  sourceItem.objectKind = `source:${sourceItem.sourceType}`;
  sourceItem.source = String(sourceItem.source || "wikidata").trim() || "wikidata";
  sourceItem.sourceId = String(sourceItem.sourceId || "").trim();
  sourceItem.tmdbMediaType = sourceItem.source === "tmdb" ? getSourceTmdbMediaType(sourceItem) : String(sourceItem.tmdbMediaType || "").trim();
  sourceItem.tmdbId = sourceItem.source === "tmdb" ? getSourceTmdbId(sourceItem) : String(sourceItem.tmdbId || "").trim();
  sourceItem.externalId = String(sourceItem.externalId || "").trim();
  sourceItem.imdbId = imdbId;
  sourceItem.url = sourceItem.source === "tmdb" ? tmdbUrl : String(sourceItem.url || "").trim();
  sourceItem.eventSubtype = sourceItem.sourceType;
  sourceItem.coupledEventId = sourceItem.coupledEventId && getEventById(sourceItem.coupledEventId)
    ? sourceItem.coupledEventId
    : null;
  sourceItem.parentEventId = null;
  sourceItem.category = String(sourceItem.category || (sourceItem.sourceType === "film" ? t("source_film") : t("sources_folder"))).trim();
  sourceItem.wikidataTypeProfile = String(sourceItem.wikidataTypeProfile || (sourceItem.sourceType === "film" ? "film" : "")).trim();
  if (sourceItem.lane === undefined || sourceItem.lane === null || String(sourceItem.lane).trim() === "") {
    sourceItem.lane = "+0";
  }
  sourceItem.imageAspectMode = getSourceImageAspectMode(sourceItem.sourceType);
  sourceItem.imageDisplayEnabled = hadImageDisplaySetting ? sourceItem.imageDisplayEnabled === true : Boolean(coverUrl);
  sourceItem.imageSidePanelEnabled = sourceItem.imageSidePanelEnabled !== false;
  sourceItem.imageHideTimelineLabel = sourceItem.imageHideTimelineLabel === true;
  sourceItem.manualImageSource = String(sourceItem.manualImageSource || "").trim();
  sourceItem.manualImageUrl = String(sourceItem.manualImageUrl || "").trim();
  sourceItem.wikidataImagePreviewUrl = sourceItem.wikidataImagePreviewUrl || coverUrl || null;
  sourceItem.wikidataImageThumbUrl = sourceItem.wikidataImageThumbUrl || coverUrl || null;
  sourceItem.wikidataImageUrl = sourceItem.wikidataImageUrl || coverUrl || null;
  sourceItem.imageUrl = getSourceCoverUrl(sourceItem);
  sourceItem.wikidataImageLookupCompleted = sourceItem.wikidataImageLookupCompleted === true
    || Boolean(sourceItem.imageUrl || sourceItem.wikidataImageUrl || sourceItem.wikidataImagePreviewUrl);
  if (!hadStartYear) {
    const yearMatch = String(sourceItem.yearLabel || "").match(/-?\d+/);
    const parsedYear = yearMatch ? Number(yearMatch[0]) : null;
    if (Number.isFinite(parsedYear)) {
      sourceItem.startYear = parsedYear;
      sourceItem.endYear = parsedYear;
      sourceItem.startDateValue = parsedYear;
      sourceItem.endDateValue = parsedYear;
      sourceItem.startPrecision = 9;
      sourceItem.endPrecision = 9;
      sourceItem.isRange = false;
    }
  }
  normalizeEventDisplaySettings(sourceItem);
  sourceItem.imageAspectMode = getSourceImageAspectMode(sourceItem.sourceType);
  sourceItem.imageDisplayEnabled = sourceItem.imageDisplayEnabled === true && Boolean(getSourceCoverUrl(sourceItem));
  sourceItem.imageSidePanelEnabled = sourceItem.imageSidePanelEnabled !== false;
  sourceItem.imageUrl = getSourceCoverUrl(sourceItem);
  return sourceItem;
}

const CHART_COMMENT_LANES = [...POSITIVE_LANES.slice().reverse(), "+0", "-0", ...NEGATIVE_LANES];

function normalizeChartCommentLane(value, fallback = 1) {
  if (value === "+0" || value === "-0") return value;
  const numericValue = Number(value);
  if (POSITIVE_LANES.includes(numericValue) || NEGATIVE_LANES.includes(numericValue)) return numericValue;
  return fallback;
}

function getChartCommentLaneIndex(value) {
  const normalizedLane = normalizeChartCommentLane(value);
  const index = CHART_COMMENT_LANES.findIndex((lane) => lane === normalizedLane);
  return index === -1 ? CHART_COMMENT_LANES.findIndex((lane) => lane === 1) : index;
}

function getNearestChartCommentLaneFromY(pointerY, lineY = getTimelineLineY()) {
  let bestLane = 1;
  let bestDistance = Number.POSITIVE_INFINITY;
  CHART_COMMENT_LANES.forEach((lane) => {
    const laneY = getMarkerYForCommentLane(lane, lineY);
    const distance = Math.abs(pointerY - laneY);
    if (distance < bestDistance) {
      bestLane = lane;
      bestDistance = distance;
    }
  });
  return bestLane;
}

function getMarkerYForCommentLane(lane, lineY = getTimelineLineY()) {
  const normalizedLane = normalizeChartCommentLane(lane);
  const referenceY = isBottomTimelinePositionActive() ? getEventLaneReferenceY() : lineY;
  if (normalizedLane === "+0") return referenceY;
  if (normalizedLane === "-0") return referenceY + BAR_LANE_GAP;
  if (typeof normalizedLane === "number" && normalizedLane > 0) {
    return referenceY - BAR_LANE_GAP * normalizedLane;
  }
  if (typeof normalizedLane === "number" && normalizedLane < 0) {
    return referenceY + BAR_LANE_GAP * (Math.abs(normalizedLane) + 1);
  }
  return referenceY - BAR_LANE_GAP;
}

function getCommentAlignForLocalX(localX, anchorX) {
  return Number.isFinite(localX) && localX < anchorX ? "left" : "right";
}

function createEmptyChartComment(comment = {}, fallback = {}) {
  return {
    id: comment.id || createUniqueId("chart-comment"),
    title: String(comment.title || fallback.title || "").trim(),
    description: String(comment.description || fallback.description || "").trim(),
    tableId: String(comment.tableId || fallback.tableId || "").trim(),
    pointX: Number(comment.pointX ?? fallback.pointX),
    pointPrecision: Number.isFinite(comment.pointPrecision) ? Number(comment.pointPrecision) : (Number.isFinite(fallback.pointPrecision) ? Number(fallback.pointPrecision) : null),
    lane: normalizeChartCommentLane(comment.lane ?? fallback.lane ?? 1),
    align: (comment.align || fallback.align) === "left" ? "left" : "right",
    color: String(comment.color || fallback.color || "").trim(),
    lineStyle: normalizeLineStyle(comment.lineStyle, fallback.lineStyle ?? "dotted"),
    framed: comment.framed === true || fallback.framed === true,
    visibleStepMin: Number.isFinite(comment.visibleStepMin) ? Number(comment.visibleStepMin) : (Number.isFinite(fallback.visibleStepMin) ? Number(fallback.visibleStepMin) : undefined),
    visibleStepMax: Number.isFinite(comment.visibleStepMax) ? Number(comment.visibleStepMax) : (Number.isFinite(fallback.visibleStepMax) ? Number(fallback.visibleStepMax) : undefined),
    enabled: comment.enabled !== false,
  };
}

function normalizeChartComment(comment = {}, fallback = {}) {
  const normalized = createEmptyChartComment(comment, fallback);
  if (!normalized.tableId || !Number.isFinite(normalized.pointX)) return null;
  if (!normalized.title) {
    normalized.title = t("chart_comment_default_title");
  }
  return normalized;
}

function getTimelineCommentPrecisionForStep(step = getStep()) {
  if (!step) return 9;
  if (step.unit === "day" || step.unit === "week") return 11;
  if (step.unit === "month") return 10;
  return 9;
}

function createEmptyTimelineComment(comment = {}, fallback = {}) {
  return {
    id: comment.id || createUniqueId("timeline-comment"),
    title: String(comment.title || fallback.title || "").trim(),
    description: String(comment.description || fallback.description || "").trim(),
    timeValue: Number(comment.timeValue ?? fallback.timeValue),
    timePrecision: Number.isFinite(comment.timePrecision) ? Number(comment.timePrecision) : (Number.isFinite(fallback.timePrecision) ? Number(fallback.timePrecision) : 9),
    lane: normalizeChartCommentLane(comment.lane ?? fallback.lane ?? 1),
    align: (comment.align || fallback.align) === "left" ? "left" : "right",
    color: String(comment.color || fallback.color || "").trim(),
    lineStyle: normalizeLineStyle(comment.lineStyle, fallback.lineStyle ?? "dotted"),
    framed: comment.framed === true || fallback.framed === true,
    visibleStepMin: Number.isFinite(comment.visibleStepMin) ? Number(comment.visibleStepMin) : (Number.isFinite(fallback.visibleStepMin) ? Number(fallback.visibleStepMin) : undefined),
    visibleStepMax: Number.isFinite(comment.visibleStepMax) ? Number(comment.visibleStepMax) : (Number.isFinite(fallback.visibleStepMax) ? Number(fallback.visibleStepMax) : undefined),
    enabled: comment.enabled !== false,
    groupId: comment.groupId ?? fallback.groupId ?? null,
  };
}

function normalizeTimelineComment(comment = {}, fallback = {}) {
  const normalized = createEmptyTimelineComment(comment, fallback);
  if (!Number.isFinite(normalized.timeValue)) return null;
  if (!normalized.title) {
    normalized.title = t("chart_comment_default_title");
  }
  return normalized;
}

function createEmptyEventComment(comment = {}, fallback = {}) {
  return {
    id: comment.id || createUniqueId("event-comment"),
    title: String(comment.title || fallback.title || "").trim(),
    description: String(comment.description || fallback.description || "").trim(),
    anchorTimeValue: Number(comment.anchorTimeValue ?? fallback.anchorTimeValue),
    anchorTimePrecision: Number.isFinite(comment.anchorTimePrecision) ? Number(comment.anchorTimePrecision) : (Number.isFinite(fallback.anchorTimePrecision) ? Number(fallback.anchorTimePrecision) : 9),
    lane: normalizeChartCommentLane(comment.lane ?? fallback.lane ?? 1),
    align: (comment.align || fallback.align) === "left" ? "left" : "right",
    color: String(comment.color || fallback.color || "").trim(),
    lineStyle: normalizeLineStyle(comment.lineStyle, fallback.lineStyle ?? "dotted"),
    framed: comment.framed === true || fallback.framed === true,
    visibleStepMin: Number.isFinite(comment.visibleStepMin) ? Number(comment.visibleStepMin) : (Number.isFinite(fallback.visibleStepMin) ? Number(fallback.visibleStepMin) : undefined),
    visibleStepMax: Number.isFinite(comment.visibleStepMax) ? Number(comment.visibleStepMax) : (Number.isFinite(fallback.visibleStepMax) ? Number(fallback.visibleStepMax) : undefined),
    enabled: comment.enabled !== false,
  };
}

function normalizeEventComment(comment = {}, fallback = {}) {
  const normalized = createEmptyEventComment(comment, fallback);
  if (!Number.isFinite(normalized.anchorTimeValue)) return null;
  if (!normalized.title) {
    normalized.title = t("chart_comment_default_title");
  }
  return normalized;
}

function clampEventCommentAnchorToEvent(eventItem, value) {
  if (!eventItem || !Number.isFinite(value)) return value;
  const start = getTimelineValueForEventStart(eventItem);
  const end = getTimelineValueForEventEnd(eventItem);
  if (!Number.isFinite(start) || !Number.isFinite(end)) return value;
  return clamp(value, Math.min(start, end), Math.max(start, end));
}

function hasEventCommentAnchorConflict(eventItem, commentId, anchorTimeValue) {
  if (!eventItem || !Number.isFinite(anchorTimeValue)) return false;
  return getEventComments(eventItem).some((comment) => (
    comment.id !== commentId
    && Number.isFinite(comment.anchorTimeValue)
    && Math.abs(comment.anchorTimeValue - anchorTimeValue) < 1e-9
  ));
}

const CHART_AXIS_LANES_TOP_TO_BOTTOM = [
  ...POSITIVE_LANES.slice().reverse(),
  "+0",
  "-0",
  ...NEGATIVE_LANES,
];

function isValidChartAxisLane(value) {
  return value === "+0"
    || value === "-0"
    || POSITIVE_LANES.includes(Number(value))
    || NEGATIVE_LANES.includes(Number(value));
}

function normalizeChartAxisLaneValue(value, fallback = POSITIVE_LANES[0]) {
  if (value === "+0" || value === "-0") return value;
  const numericValue = Number(value);
  if (POSITIVE_LANES.includes(numericValue) || NEGATIVE_LANES.includes(numericValue)) return numericValue;
  return fallback;
}

function getChartAxisLaneIndex(value) {
  const normalized = normalizeChartAxisLaneValue(value);
  const index = CHART_AXIS_LANES_TOP_TO_BOTTOM.findIndex((lane) => lane === normalized);
  return index === -1 ? 0 : index;
}

function normalizeChartAxisSpan(startLane, endLane) {
  const normalizedStart = normalizeChartAxisLaneValue(startLane, POSITIVE_LANES[0]);
  const normalizedEnd = normalizeChartAxisLaneValue(endLane, POSITIVE_LANES[POSITIVE_LANES.length - 1]);
  const startIndex = getChartAxisLaneIndex(normalizedStart);
  const endIndex = getChartAxisLaneIndex(normalizedEnd);
  const topLane = startIndex <= endIndex ? normalizedStart : normalizedEnd;
  const bottomLane = startIndex <= endIndex ? normalizedEnd : normalizedStart;
  return {
    startLane: bottomLane,
    endLane: topLane,
  };
}

function createEmptyChartTable(table = {}, fallback = {}) {
  return {
    id: table.id || createUniqueId("chart-table"),
    title: String(table.title || fallback.title || "").trim(),
    sourceEntity: String(table.sourceEntity || fallback.sourceEntity || "").trim(),
    sourceMetric: String(table.sourceMetric || fallback.sourceMetric || "").trim(),
    sourceUnit: String(table.sourceUnit || fallback.sourceUnit || "").trim(),
    sourceUnitShort: String(table.sourceUnitShort || fallback.sourceUnitShort || "").trim(),
    color: String(table.color || fallback.color || "#c96f4a").trim() || "#c96f4a",
    lineStyle: normalizeLineStyle(table.lineStyle, fallback.lineStyle),
    fillMode: table.fillMode === "soft" ? "soft" : (fallback.fillMode === "soft" ? "soft" : "none"),
    visible: table.visible !== false,
    xPrecision: table.xPrecision || fallback.xPrecision || "year",
    points: [],
  };
}

function normalizeChartTable(chartItem, table, index = 0) {
  const normalized = createEmptyChartTable(table, {
    title: index === 0 ? chartItem.title : "",
    sourceEntity: chartItem.sourceEntity,
    sourceMetric: chartItem.sourceMetric,
    sourceUnit: chartItem.sourceUnit,
    sourceUnitShort: chartItem.sourceUnitShort,
    color: chartItem.color,
    lineStyle: chartItem.lineStyle,
    fillMode: chartItem.fillMode,
    xPrecision: chartItem.xPrecision,
  });
  normalized.points = Array.isArray(table?.points)
    ? table.points
      .map((point, pointIndex) => ({
        id: point?.id || `${normalized.id}-point-${pointIndex + 1}`,
        x: Number(point?.x),
        precision: Number.isFinite(point?.precision) ? Number(point.precision) : null,
        y: Number(point?.y),
        label: String(point?.label || "").trim(),
        description: String(point?.description || "").trim(),
        sourceTitle: String(point?.sourceTitle || point?.source || "").trim(),
        meta: {
          sourceUrl: String(point?.meta?.sourceUrl || point?.sourceUrl || "").trim(),
          uncertainty: normalizeChartPointUncertainty(point?.meta?.uncertainty || point?.uncertainty || ""),
        },
        visible: point?.visible !== false,
        chainBreakAfter: point?.chainBreakAfter === true,
      }))
      .filter((point) => Number.isFinite(point.x) && Number.isFinite(point.y))
      .sort((left, right) => left.x - right.x)
    : [];
  return normalized;
}

function getChartTables(chartItem) {
  return Array.isArray(chartItem?.tables) ? chartItem.tables : [];
}

function getAnnotatedChartPoints(points = []) {
  let chainOpen = false;
  return [...points]
    .sort((left, right) => left.x - right.x)
    .map((point) => {
      const isBoundary = point?.chainBreakAfter === true;
      const effectiveVisible = point?.visible !== false && !chainOpen && !isBoundary;
      const annotatedPoint = {
        ...point,
        _isChainBoundary: isBoundary,
        _effectiveVisible: effectiveVisible,
      };
      if (isBoundary) {
        chainOpen = !chainOpen;
      }
      return annotatedPoint;
    });
}

function getChartEffectivePointGroups(renderSpec) {
  const sortedPoints = getAnnotatedChartPoints(Array.isArray(renderSpec?.table?.points) ? renderSpec.table.points : []);
  const groups = [];
  let currentGroup = [];
  sortedPoints.forEach((point) => {
    if (point._effectiveVisible) {
      currentGroup.push(point);
    } else if (currentGroup.length) {
      groups.push(currentGroup);
      currentGroup = [];
    }
  });
  if (currentGroup.length) groups.push(currentGroup);
  return groups;
}

function getChartComments(chartItem) {
  return Array.isArray(chartItem?.comments) ? chartItem.comments : [];
}

function getEventComments(eventItem) {
  if (!eventItem) return [];
  eventItem.comments = (Array.isArray(eventItem.comments) ? eventItem.comments : [])
    .map((comment) => normalizeEventComment(comment))
    .filter(Boolean)
    .sort((left, right) => {
      if (left.anchorTimeValue !== right.anchorTimeValue) return left.anchorTimeValue - right.anchorTimeValue;
      return getChartCommentLaneIndex(left.lane) - getChartCommentLaneIndex(right.lane);
    });
  return eventItem.comments;
}

function ensureChartEditableTable(chartItem) {
  if (!chartItem) return;
  const hasTables = Array.isArray(chartItem.tables) && chartItem.tables.length > 0;
  if (!hasTables) {
    chartItem.tables = [createEmptyChartTable({}, {
      title: chartItem.title,
      sourceEntity: chartItem.sourceEntity,
      sourceMetric: chartItem.sourceMetric,
      sourceUnit: chartItem.sourceUnit,
      sourceUnitShort: chartItem.sourceUnitShort,
      color: chartItem.color,
      lineStyle: chartItem.lineStyle,
      fillMode: chartItem.fillMode,
      xPrecision: chartItem.xPrecision,
    })];
  }
  normalizeChartItem(chartItem);
}

function getChartPrimaryTable(chartItem) {
  return getChartTables(chartItem)[0] ?? null;
}

function getChartAllPoints(chartItem) {
  return getChartTables(chartItem)
    .flatMap((table) => Array.isArray(table?.points) ? table.points : [])
    .filter((point) => Number.isFinite(point?.x) && Number.isFinite(point?.y))
    .sort((left, right) => left.x - right.x);
}

function getChartPointCount(chartItem) {
  return getChartAllPoints(chartItem).length;
}

function getChartDateRangeLabel(chartItem) {
  const points = getChartAllPoints(chartItem);
  if (!points.length) return "-";
  const firstPoint = points[0];
  const lastPoint = points[points.length - 1];
  return `${formatTimelineValue(firstPoint.x, firstPoint.precision ?? 9)} ${t("until_connector")} ${formatTimelineValue(lastPoint.x, lastPoint.precision ?? 9)}`;
}

function getChartStepValue(pointX, step = getStep()) {
  return alignTimelineValueToStepStart(pointX, step);
}

function getChartTableOccupiedTickCount(table, step = getStep(), viewRange = getVisibleRange()) {
  const keys = new Set(
    (Array.isArray(table?.points) ? table.points : [])
      .filter((point) => Number.isFinite(point?.x) && point.x >= viewRange.start && point.x <= viewRange.end)
      .map((point) => getChartStepValue(point.x, step).toFixed(9)),
  );
  return keys.size;
}

function getChartTableResolution(table) {
  const sourceEntity = String(table?.sourceEntity || "").toLowerCase();
  if (sourceEntity === "daily") return "day";
  if (sourceEntity === "weekly") return "week";
  if (sourceEntity === "monthly") return "month";
  if (sourceEntity === "yearly") return "year";
  const xPrecision = String(table?.xPrecision || "").toLowerCase();
  if (xPrecision === "day") return "day";
  if (xPrecision === "month") return "month";
  const hasDayPrecision = (Array.isArray(table?.points) ? table.points : []).some((point) => Number(point?.precision) >= 11);
  if (hasDayPrecision) return "day";
  const hasMonthPrecision = (Array.isArray(table?.points) ? table.points : []).some((point) => Number(point?.precision) >= 10);
  if (hasMonthPrecision) return "month";
  return "year";
}

function getChartResolutionRank(resolution = "year") {
  switch (resolution) {
    case "day": return 0;
    case "week": return 1;
    case "month": return 2;
    default: return 3;
  }
}

function getChartResolutionPriorityForStep(step = getStep()) {
  if (!step) return ["month", "year", "week", "day"];
  if (step.id === "1d" || step.id === "1w") return ["day", "week", "month", "year"];
  if (step.id === "1m") return ["week", "month", "year", "day"];
  if (step.unit === "year" && step.amount >= 5) return ["year", "month", "week", "day"];
  return ["month", "year", "week", "day"];
}

function getChartTableRange(table) {
  const points = Array.isArray(table?.points) ? table.points : [];
  if (!points.length) return null;
  return {
    min: points[0].x,
    max: points[points.length - 1].x,
  };
}

function mergeChartRanges(ranges = []) {
  const normalized = ranges
    .filter((range) => Number.isFinite(range?.min) && Number.isFinite(range?.max))
    .map((range) => ({
      min: Math.min(range.min, range.max),
      max: Math.max(range.min, range.max),
    }))
    .sort((left, right) => left.min - right.min);
  if (!normalized.length) return [];
  const merged = [normalized[0]];
  for (let index = 1; index < normalized.length; index += 1) {
    const current = normalized[index];
    const last = merged[merged.length - 1];
    if (current.min <= last.max) {
      last.max = Math.max(last.max, current.max);
    } else {
      merged.push(current);
    }
  }
  return merged;
}

function subtractChartRanges(baseRange, excludedRanges = []) {
  if (!Number.isFinite(baseRange?.min) || !Number.isFinite(baseRange?.max)) return [];
  const mergedExcluded = mergeChartRanges(excludedRanges);
  const results = [];
  let cursor = baseRange.min;
  mergedExcluded.forEach((range) => {
    if (range.max <= cursor || range.min >= baseRange.max) return;
    if (range.min > cursor) {
      results.push({ min: cursor, max: Math.min(range.min, baseRange.max) });
    }
    cursor = Math.max(cursor, range.max);
  });
  if (cursor < baseRange.max) {
    results.push({ min: cursor, max: baseRange.max });
  }
  return results.filter((range) => range.max > range.min);
}

function getPointsInRanges(points = [], ranges = []) {
  if (!ranges.length) return [];
  return points.filter((point) => ranges.some((range) => point.x >= range.min && point.x <= range.max));
}

function intersectChartRanges(baseRanges = [], limiterRanges = []) {
  if (!baseRanges.length || !limiterRanges.length) return [];
  const intersections = [];
  baseRanges.forEach((baseRange) => {
    limiterRanges.forEach((limiterRange) => {
      const min = Math.max(baseRange.min, limiterRange.min);
      const max = Math.min(baseRange.max, limiterRange.max);
      if (Number.isFinite(min) && Number.isFinite(max) && max > min) {
        intersections.push({ min, max });
      }
    });
  });
  return mergeChartRanges(intersections);
}

function getChartPointsForRenderSpec(renderSpec, options = {}) {
  if (!renderSpec?.table) return [];
  const allPoints = getAnnotatedChartPoints(Array.isArray(renderSpec.table.points) ? renderSpec.table.points : [])
    .filter((point) => point._effectiveVisible);
  const ranges = Array.isArray(renderSpec.ranges) ? renderSpec.ranges : [];
  let points = getPointsInRanges(allPoints, ranges);
  const viewRange = options.viewRange || null;
  if (viewRange) {
    const inView = points.filter((point) => point.x >= viewRange.start && point.x <= viewRange.end);
    const before = [...points]
      .filter((point) => point.x < viewRange.start)
      .sort((left, right) => right.x - left.x)[0] ?? null;
    const after = points
      .filter((point) => point.x > viewRange.end)
      .sort((left, right) => left.x - right.x)[0] ?? null;
    points = [
      ...(before ? [before] : []),
      ...inView,
      ...(after ? [after] : []),
    ];
  }
  return points;
}

function getChartScalePointsForRenderSpec(renderSpec) {
  if (!renderSpec?.table) return [];
  const allPoints = Array.isArray(renderSpec.table.points) ? renderSpec.table.points : [];
  const ranges = Array.isArray(renderSpec.ranges) ? renderSpec.ranges : [];
  return getPointsInRanges(
    allPoints.filter((point) => Number.isFinite(point?.x) && Number.isFinite(point?.y)),
    ranges,
  );
}

function getChartRenderSpecOccupiedTickCount(renderSpec, step = getStep(), viewRange = getVisibleRange()) {
  const keys = new Set(
    getChartPointsForRenderSpec(renderSpec, { viewRange })
      .map((point) => getChartStepValue(point.x, step).toFixed(9)),
  );
  return keys.size;
}

function getRenderableChartTables(chartItem, options = {}) {
  const step = options.step || getStep();
  const groupedByResolution = new Map();
  getChartTables(chartItem)
    .filter((table) => table.visible !== false && Array.isArray(table.points) && table.points.length >= 2)
    .forEach((table) => {
      const resolution = getChartTableResolution(table);
      const current = groupedByResolution.get(resolution);
      if (!current || table.points.length > current.points.length) {
        groupedByResolution.set(resolution, table);
      }
    });

  const orderedTables = getChartResolutionPriorityForStep(step)
    .map((resolution) => groupedByResolution.get(resolution))
    .filter(Boolean);

  if (!orderedTables.length) return [];

  const renderSpecs = [];
  const coveredRanges = [];
  orderedTables.forEach((table, index) => {
    const tableRange = getChartTableRange(table);
    if (!tableRange) return;
    const allowedRanges = index === 0
      ? [tableRange]
      : subtractChartRanges(tableRange, coveredRanges);
    if (!allowedRanges.length) return;
    const renderSpec = {
      table,
      resolution: getChartTableResolution(table),
      ranges: allowedRanges,
    };
    renderSpecs.push(renderSpec);
    coveredRanges.push(tableRange);
  });

  return renderSpecs;
}

function normalizeChartItem(chartItem) {
  if (!chartItem) return;
  chartItem.id = chartItem.id || createUniqueId("chart");
  chartItem.type = "chart";
  chartItem.title = String(chartItem.title || "Chart").trim() || "Chart";
  chartItem.description = String(chartItem.description || "").trim();
  chartItem.sourceTitle = String(chartItem.sourceTitle || "").trim();
  chartItem.sourceUrl = String(chartItem.sourceUrl || "").trim();
  chartItem.sourceUnit = String(chartItem.sourceUnit || "").trim();
  chartItem.sourceUnitShort = String(chartItem.sourceUnitShort || "").trim();
  chartItem.groupId = chartItem.groupId || null;
  chartItem.parentEventId = chartItem.parentEventId || null;
  chartItem.color = String(chartItem.color || "#c96f4a").trim() || "#c96f4a";
  chartItem.lineStyle = normalizeLineStyle(chartItem.lineStyle);
  chartItem.fillMode = chartItem.fillMode === "soft" ? "soft" : "none";
  chartItem.visible = chartItem.visible !== false;
  chartItem.displayMode = chartItem.displayMode === "background" || chartItem.displayMode === "foreground"
    ? chartItem.displayMode
    : "mixed";
  chartItem.yAxisEnabled = chartItem.yAxisEnabled !== false;
  chartItem.yAxisSide = chartItem.yAxisSide === "right" ? "right" : "left";
  chartItem.yScaleMode = chartItem.yScaleMode === "log" ? "log" : "linear";
  chartItem.yAxisLabel = String(chartItem.yAxisLabel || "").trim();
  chartItem.showZeroExtension = chartItem.showZeroExtension === true;
  const normalizedAxisSpan = normalizeChartAxisSpan(chartItem.yAxisLaneStart, chartItem.yAxisLaneEnd);
  chartItem.yAxisLaneStart = normalizedAxisSpan.startLane;
  chartItem.yAxisLaneEnd = normalizedAxisSpan.endLane;
  chartItem.yOffsetPx = Number.isFinite(chartItem.yOffsetPx) ? chartItem.yOffsetPx : 0;
  chartItem.xPrecision = chartItem.xPrecision || "year";
  const legacyPoints = Array.isArray(chartItem.points) ? chartItem.points : [];
  const incomingTables = Array.isArray(chartItem.tables) && chartItem.tables.length
    ? chartItem.tables
    : [{
      id: chartItem.id ? `${chartItem.id}-table-default` : createUniqueId("chart-table"),
      title: chartItem.title,
      sourceEntity: chartItem.sourceEntity,
      sourceMetric: chartItem.sourceMetric,
      sourceUnit: chartItem.sourceUnit,
      sourceUnitShort: chartItem.sourceUnitShort,
      color: chartItem.color,
      lineStyle: chartItem.lineStyle,
      fillMode: chartItem.fillMode,
      xPrecision: chartItem.xPrecision,
      points: legacyPoints,
    }];
  chartItem.tables = incomingTables
    .map((table, index) => normalizeChartTable(chartItem, table, index))
    .filter((table) => Array.isArray(table.points));
  chartItem.tables.sort((left, right) => {
    const rankDelta = getChartResolutionRank(getChartTableResolution(left)) - getChartResolutionRank(getChartTableResolution(right));
    if (rankDelta !== 0) return rankDelta;
    return (right.points?.length || 0) - (left.points?.length || 0);
  });
  chartItem.comments = (Array.isArray(chartItem.comments) ? chartItem.comments : [])
    .map((comment) => normalizeChartComment(comment))
    .filter(Boolean)
    .sort((left, right) => {
      if (left.pointX !== right.pointX) return left.pointX - right.pointX;
      return getChartCommentLaneIndex(left.lane) - getChartCommentLaneIndex(right.lane);
    });
  const primaryTable = getChartPrimaryTable(chartItem);
  chartItem.points = primaryTable?.points ?? [];
  chartItem.xPrecision = primaryTable?.xPrecision || chartItem.xPrecision || "year";
  chartItem.sourceEntity = String(chartItem.sourceEntity || primaryTable?.sourceEntity || "").trim();
  chartItem.sourceMetric = String(chartItem.sourceMetric || primaryTable?.sourceMetric || "").trim();
  if (!chartItem.sourceUnit) {
    chartItem.sourceUnit = String(primaryTable?.sourceUnit || "").trim();
  }
  if (!chartItem.sourceUnitShort) {
    chartItem.sourceUnitShort = String(primaryTable?.sourceUnitShort || "").trim();
  }
  const allPoints = getChartAllPoints(chartItem);
  const hasSubYearPrecision = chartItem.xPrecision === "day"
    || chartItem.xPrecision === "month"
    || allPoints.some((point) => Number(point?.precision) >= 10);
  const inferredVisibleStepMin = hasSubYearPrecision ? scaleSteps[0].years : 1;
  if (!Number.isFinite(chartItem.visibleStepMin) || (hasSubYearPrecision && chartItem.visibleStepMin === 1)) {
    chartItem.visibleStepMin = inferredVisibleStepMin;
  }
  chartItem.visibleStepMax = Number.isFinite(chartItem.visibleStepMax) ? chartItem.visibleStepMax : 1000000000;
  if (chartItem.sourceKey === "alphavantage" && ["daily", "weekly", "monthly"].includes(chartItem.sourceEntity)) {
    const preferredVisibility = getAlphaVantageVariantVisibility(chartItem.sourceEntity);
    const usesLegacyVisibility = !Number.isFinite(chartItem.visibleStepMin)
      || chartItem.visibleStepMin === 1
      || chartItem.visibleStepMin === scaleSteps[0].years
      || !Number.isFinite(chartItem.visibleStepMax)
      || chartItem.visibleStepMax >= 1000000000;
    if (usesLegacyVisibility) {
      chartItem.visibleStepMin = preferredVisibility.visibleStepMin;
      chartItem.visibleStepMax = preferredVisibility.visibleStepMax;
    }
  }
  if (!chartItem.sourceUnit) {
    chartItem.sourceUnit = inferChartUnit(chartItem);
  }
}

function getChartTimelineRange(chartItem) {
  const points = getChartAllPoints(chartItem);
  const xValues = points
    .map((point) => Number(point?.x))
    .filter((value) => Number.isFinite(value));
  if (!xValues.length) return null;
  return {
    min: Math.min(...xValues),
    max: Math.max(...xValues),
  };
}

function getChartById(chartId) {
  return chartItems.find((chartItem) => chartItem.id === chartId) ?? null;
}

function findChartCommentById(commentId) {
  for (const chartItem of chartItems) {
    const comment = getChartComments(chartItem).find((entry) => entry.id === commentId);
    if (comment) {
      return { chartItem, comment };
    }
  }
  return null;
}

function getChartsForGroup(groupId) {
  return chartItems
    .filter((chartItem) => chartItem.groupId === groupId)
    .sort((left, right) => String(left.title || "").localeCompare(String(right.title || ""), getUiSortLocale()));
}

function getUngroupedCharts() {
  return chartItems
    .filter((chartItem) => !chartItem.groupId)
    .sort((left, right) => String(left.title || "").localeCompare(String(right.title || ""), getUiSortLocale()));
}

function findChartPointForComment(chartItem, comment, renderSpecs = null) {
  if (!chartItem || !comment?.tableId || !Number.isFinite(comment.pointX)) return null;
  const sourceTables = Array.isArray(renderSpecs)
    ? renderSpecs.map((renderSpec) => renderSpec?.table).filter(Boolean)
    : getChartTables(chartItem);
  const table = sourceTables.find((entry) => entry.id === comment.tableId);
  if (!table) return null;
  const isRangeAllowed = (pointX) => {
    if (!Array.isArray(renderSpecs)) return true;
    const matchingSpec = renderSpecs.find((renderSpec) => renderSpec?.table?.id === table.id);
    if (!matchingSpec) return false;
    return (Array.isArray(matchingSpec.ranges) ? matchingSpec.ranges : []).some((range) => pointX >= range.min && pointX <= range.max);
  };
  const point = (Array.isArray(table.points) ? table.points : []).find((entry) => (
    Number.isFinite(entry?.x)
    && Math.abs(entry.x - comment.pointX) < 1e-9
    && isRangeAllowed(entry.x)
  ));
  return point ? { table, point } : null;
}

function getAllChartsSorted() {
  return [...chartItems]
    .sort((left, right) => String(left.title || "").localeCompare(String(right.title || ""), getUiSortLocale()));
}

function getChildChartsForEvent(eventId) {
  return chartItems
    .filter((chartItem) => chartItem.parentEventId === eventId)
    .sort((left, right) => String(left.title || "").localeCompare(String(right.title || ""), getUiSortLocale()));
}

function getAssignableParentEventsForChart(chartItem) {
  if (!chartItem?.groupId) return [];
  const specialTreeKind = getSpecialTreeKindForGroup(chartItem.groupId);
  if (!specialTreeKind) return getEventsForGroup(chartItem.groupId);
  const projectRootId = getRootGroupId(chartItem.groupId);
  return timelineEvents
    .filter((eventItem) => getRootGroupId(eventItem.groupId) === projectRootId)
    .sort((left, right) => String(left.title || "").localeCompare(String(right.title || ""), getUiSortLocale()));
}

function sanitizeChartHierarchy() {
  chartItems.forEach((chartItem) => {
    if (!chartItem.groupId) {
      chartItem.parentEventId = null;
      return;
    }
    if (!getGroupById(chartItem.groupId)) {
      chartItem.groupId = null;
      chartItem.parentEventId = null;
      return;
    }
    if (!chartItem.parentEventId) return;
    const parentEvent = getEventById(chartItem.parentEventId);
    const sameGroup = parentEvent && parentEvent.groupId === chartItem.groupId;
    const sameProjectRoot = parentEvent && getRootGroupId(parentEvent.groupId) === getRootGroupId(chartItem.groupId);
    if (!parentEvent || (!sameGroup && !sameProjectRoot)) {
      chartItem.parentEventId = null;
    }
  });
}

function createChartValueDraftRow(point = {}) {
  return {
    id: point.id || createUniqueId("chart-row"),
    visible: point.visible !== false,
    chainBreakAfter: point.chainBreakAfter === true,
    x: point.x ?? "",
    precision: point.precision ?? null,
    y: point.y ?? "",
    sourceTitle: point.sourceTitle || "",
    label: point.label || "",
    description: point.description || "",
    meta: point.meta ?? null,
  };
}

function getChartTableDraftKey(chartItem, table = getChartPrimaryTable(chartItem)) {
  return `${chartItem.id}:${table?.id || "default"}`;
}

function deleteChartDraftRowsForChart(chartId) {
  [...chartValueDraftRows.keys()].forEach((key) => {
    if (key === chartId || key.startsWith(`${chartId}:`)) {
      chartValueDraftRows.delete(key);
    }
  });
}

function getChartValueDraftRows(chartItem, table = getChartPrimaryTable(chartItem)) {
  const draftKey = getChartTableDraftKey(chartItem, table);
  const existing = chartValueDraftRows.get(draftKey);
  if (Array.isArray(existing) && existing.length) {
    return existing;
  }
  const sourcePoints = Array.isArray(table?.points) ? table.points : [];
  const rows = sourcePoints.length
    ? sourcePoints.map((point) => createChartValueDraftRow(point))
    : [createChartValueDraftRow()];
  chartValueDraftRows.set(draftKey, rows);
  return rows;
}

function syncChartPointsFromDraftRows(chartItem, table = getChartPrimaryTable(chartItem)) {
  const rows = getChartValueDraftRows(chartItem, table);
  const nextPoints = [];
  rows.forEach((row) => {
    const xText = String(row.x ?? "").trim();
    const yText = String(row.y ?? "").trim();
    if (!xText && !yText) return;
    const temporal = parseEditorTemporalValue(xText);
      const nextX = temporal?.value ?? Number.NaN;
    const nextY = Number(yText);
    if (!Number.isFinite(nextX) || !Number.isFinite(nextY)) return;
    nextPoints.push({
      id: row.id || createUniqueId("chart-point"),
      x: nextX,
      precision: temporal?.precision ?? 9,
      y: nextY,
      label: row.label || "",
      description: row.description || "",
      meta: row.meta ?? null,
      sourceTitle: String(row.sourceTitle || "").trim(),
      visible: row.visible !== false,
      chainBreakAfter: row.chainBreakAfter === true,
    });
  });
  nextPoints.sort((left, right) => left.x - right.x);
  if (table) {
    table.points = nextPoints;
    table.xPrecision = nextPoints.some((point) => Number(point.precision) >= 11)
      ? "day"
      : nextPoints.some((point) => Number(point.precision) >= 10)
        ? "month"
        : "year";
  }
  chartItem.points = getChartPrimaryTable(chartItem)?.points ?? [];
}

function getVisibleCharts() {
  const step = getStep();
  const stepYears = getStepYears(step);
  const viewRange = getVisibleRange();
  return chartItems.filter((chartItem) => (
    chartItem.visible !== false
    && (chartItem.groupId == null || getGroupById(chartItem.groupId)?.enabled !== false)
    && (!Number.isFinite(chartItem.visibleStepMin) || stepYears >= chartItem.visibleStepMin)
    && (!Number.isFinite(chartItem.visibleStepMax) || stepYears <= chartItem.visibleStepMax)
    && getRenderableChartTables(chartItem, { step, viewRange }).length > 0
  ));
}

function getActiveChart() {
  const visibleCharts = getVisibleCharts();
  if (!visibleCharts.length) return null;
  const preferredId = state.openChartEditorId ?? state.activeChartId;
  return visibleCharts.find((chartItem) => chartItem.id === preferredId) ?? visibleCharts[0];
}

function getChartAxisGroupKey(chartItem) {
  const unit = inferChartUnit(chartItem).toLowerCase();
  if (unit) return `unit:${unit}`;
  const legacyLabel = String(chartItem?.yAxisLabel || "").trim().toLowerCase();
  return legacyLabel ? `label:${legacyLabel}` : null;
}

function getChartAxisGroupId(chartItem) {
  const labelKey = getChartAxisGroupKey(chartItem);
  return labelKey ? `axis:${labelKey}` : `chart:${chartItem.id}`;
}

function getChartAxisGroups(charts = getVisibleCharts()) {
  const groups = new Map();
  charts.forEach((chartItem) => {
    const groupId = getChartAxisGroupId(chartItem);
    const current = groups.get(groupId);
    if (current) {
      current.push(chartItem);
    } else {
      groups.set(groupId, [chartItem]);
    }
  });
  return groups;
}

function getChartsInAxisGroup(chartItem, charts = chartItems) {
  const targetGroupId = getChartAxisGroupId(chartItem);
  return charts.filter((candidate) => getChartAxisGroupId(candidate) === targetGroupId);
}

function getChartsForAxisDrag(chartItem, charts = getVisibleCharts()) {
  const selectedCharts = getSelectedAxisCharts(charts);
  if (
    state.showYAxis
    && selectedCharts.length > 1
    && selectedCharts.some((candidate) => candidate.id === chartItem.id)
  ) {
    return selectedCharts;
  }
  return chartItem ? [chartItem] : [];
}

function getChartsForSharedAxis(chartItem, charts = getVisibleCharts()) {
  const selectedCharts = getSelectedAxisCharts(charts);
  if (
    state.showYAxis
    && selectedCharts.length > 1
    && selectedCharts.some((candidate) => candidate.id === chartItem?.id)
  ) {
    return selectedCharts;
  }
  return chartItem ? [chartItem] : [];
}

function getChartAxisGroupRepresentative(chartItem, charts = getVisibleCharts()) {
  const group = getChartsForSharedAxis(chartItem, charts);
  if (!group.length) return chartItem;
  return group.find((candidate) => candidate.id === state.activeChartId)
    ?? group.find((candidate) => candidate.id === chartItem.id)
    ?? group[0];
}

function getChartAxisGroupOffset(chartItem, charts = getVisibleCharts()) {
  const representative = getChartAxisGroupRepresentative(chartItem, charts);
  return Number(representative?.yOffsetPx) || 0;
}

function getChartSpanForCharts(charts = []) {
  const primaryChart = Array.isArray(charts) ? charts.find(Boolean) : null;
  if (!primaryChart) {
    return normalizeChartAxisSpan(POSITIVE_LANES[0], POSITIVE_LANES[POSITIVE_LANES.length - 1]);
  }
  return normalizeChartAxisSpan(primaryChart.yAxisLaneStart, primaryChart.yAxisLaneEnd);
}

function setChartAxisGroupOffset(chartItem, offsetPx, charts = chartItems) {
  getChartsForSharedAxis(chartItem, charts).forEach((candidate) => {
    candidate.yOffsetPx = offsetPx;
  });
}

function getChartAxisGroupSpan(chartItem, charts = getVisibleCharts()) {
  const representative = getChartAxisGroupRepresentative(chartItem, charts);
  return normalizeChartAxisSpan(
    representative?.yAxisLaneStart,
    representative?.yAxisLaneEnd,
  );
}

function setChartAxisGroupSpan(chartItem, startLane, endLane, charts = chartItems) {
  const normalized = normalizeChartAxisSpan(startLane, endLane);
  getChartsForSharedAxis(chartItem, charts).forEach((candidate) => {
    candidate.yAxisLaneStart = normalized.startLane;
    candidate.yAxisLaneEnd = normalized.endLane;
  });
}

function setChartSpanForCharts(charts = [], startLane, endLane) {
  const normalized = normalizeChartAxisSpan(startLane, endLane);
  charts.forEach((candidate) => {
    if (!candidate) return;
    candidate.yAxisLaneStart = normalized.startLane;
    candidate.yAxisLaneEnd = normalized.endLane;
  });
}

function syncSelectedChartAxisIds(charts = getVisibleCharts()) {
  const visibleIds = new Set(charts.map((chartItem) => chartItem.id));
  state.selectedChartAxisIds = (Array.isArray(state.selectedChartAxisIds) ? state.selectedChartAxisIds : [])
    .filter((chartId) => visibleIds.has(chartId));
  if (!state.selectedChartAxisIds.length && state.showYAxis) {
    const fallbackChart = charts.find((chartItem) => chartItem.id === state.activeChartId && chartItem.yAxisEnabled !== false)
      ?? charts.find((chartItem) => chartItem.yAxisEnabled !== false)
      ?? null;
    if (fallbackChart) {
      state.selectedChartAxisIds = [fallbackChart.id];
    }
  }
  if (!state.selectedChartAxisIds.length && !charts.length) {
    state.showYAxis = false;
  }
}

function getSelectedAxisCharts(charts = getVisibleCharts()) {
  syncSelectedChartAxisIds(charts);
  const visibleMap = new Map(charts.map((chartItem) => [chartItem.id, chartItem]));
  const orderedIds = state.showYAxis ? state.selectedChartAxisIds : [];
  return orderedIds
    .map((chartId) => visibleMap.get(chartId))
    .filter((chartItem) => chartItem && chartItem.yAxisEnabled !== false);
}

function activateChartAxisSelection(chartItem) {
  state.activeChartId = chartItem?.id ?? null;
  if (chartItem && chartItem.yAxisEnabled !== false) {
    state.selectedChartAxisIds = [chartItem.id];
    state.showYAxis = true;
  } else {
    state.selectedChartAxisIds = [];
    state.showYAxis = false;
  }
}

function isChartMuteMode() {
  return state.chartDisplayMode === "events";
}

function isChartHiddenMode() {
  return state.chartDisplayMode === "hidden";
}

function getChartRenderColor(chartItem) {
  if (isChartMuteMode()) return "#8b949b";
  return chartItem.color || "#a4b0b8";
}

function getChartProbeSelectionKey(selection) {
  if (!selection) return "";
  return [
    selection.probeKind || "",
    selection.chartId || "",
    selection.tableId || "",
    selection.pointId || "",
    selection.pointX,
    selection.pointY,
    selection.labelText || "",
    selection.sourceTitle || "",
  ].join("|");
}

function isAdditionalCalendarProbeCandidate(candidate) {
  return candidate?.probeKind === "additional-calendar";
}

function hasAdditionalCalendarProbeCandidates(candidates = state.chartProbeCandidates) {
  return Array.isArray(candidates) && candidates.some((candidate) => isAdditionalCalendarProbeCandidate(candidate));
}

function isPointerOnAdditionalCalendarTrack(pointer, lineY) {
  if (!pointer || !Number.isFinite(pointer.y)) return false;
  return pointer.y >= lineY - 10 && pointer.y <= lineY + 32;
}

function resolveChartProbeSelection(pointer = state.chartProbePointer, candidates = state.chartProbeCandidates) {
  if (!state.chartProbeEnabled || !pointer || !Array.isArray(candidates) || !candidates.length) return null;
  const lineY = getTimelineLineY();
  const additionalCalendarCandidates = candidates.filter((candidate) => isAdditionalCalendarProbeCandidate(candidate));
  const chartCandidates = candidates.filter((candidate) => !isAdditionalCalendarProbeCandidate(candidate));
  const scopedCandidates = additionalCalendarCandidates.length
    ? (
      isPointerOnAdditionalCalendarTrack(pointer, lineY) || state.chartProbeAdditionalCalendarShiftLock
        ? additionalCalendarCandidates
        : (chartCandidates.length ? chartCandidates : [])
    )
    : candidates;
  if (!scopedCandidates.length) return null;
  let nearestXDistance = Infinity;
  scopedCandidates.forEach((candidate) => {
    nearestXDistance = Math.min(nearestXDistance, Math.abs(candidate.screenX - pointer.x));
  });
  if (!Number.isFinite(nearestXDistance)) return null;
  const sameXCandidates = scopedCandidates.filter((candidate) => (
    Math.abs(candidate.screenX - pointer.x) <= nearestXDistance + 0.01
  ));
  if (!sameXCandidates.length) return null;
  let bestCandidate = sameXCandidates[0];
  let bestYDistance = Math.abs(bestCandidate.screenY - pointer.y);
  sameXCandidates.slice(1).forEach((candidate) => {
    const nextYDistance = Math.abs(candidate.screenY - pointer.y);
    if (nextYDistance < bestYDistance - 0.01) {
      bestCandidate = candidate;
      bestYDistance = nextYDistance;
    }
  });
  return bestCandidate;
}

function setChartProbePointer(pointer, { redrawIfChanged = true } = {}) {
  state.chartProbePointer = pointer;
  const nextSelection = resolveChartProbeSelection(pointer);
  const previousKey = getChartProbeSelectionKey(state.chartProbeSelection);
  const nextKey = getChartProbeSelectionKey(nextSelection);
  state.chartProbeSelection = nextSelection;
  if (redrawIfChanged && previousKey !== nextKey) {
    drawTimeline();
  }
}

function getChartDraftRowChainMutedSet(rows = []) {
  const mutedIds = new Set();
  let chainOpen = false;
  rows.forEach((row) => {
    const isBoundary = row?.chainBreakAfter === true;
    if (chainOpen || isBoundary) {
      mutedIds.add(row.id);
    }
    if (isBoundary) {
      chainOpen = !chainOpen;
    }
  });
  return mutedIds;
}

function clearChartProbeSelection({ redraw = false } = {}) {
  const hadSelection = Boolean(state.chartProbeSelection || state.chartProbePointer);
  state.chartProbePointer = null;
  state.chartProbeSelection = null;
  state.chartProbeAdditionalCalendarShiftLock = false;
  if (redraw && hadSelection) {
    drawTimeline();
  }
}

function getChartProbeLabelMetrics(lineY) {
  const selection = state.chartProbeSelection;
  if (!selection) return null;
  const chartItem = chartItems.find((candidate) => candidate?.id === selection.chartId) || null;
  const unitShort = inferChartUnitShort(chartItem);
  const labelText = String(selection.labelText || "").trim()
    || `${formatChartAxisValue(selection.pointY)}${unitShort ? ` ${unitShort}` : ""}`;
  const valueWidth = Math.max(58, Math.ceil(measureCommentTextWidth(labelText, "600 12px Segoe UI")) + 22);
  const sourceText = String(selection.sourceTitle || "").trim();
  const sourceEnabled = state.chartProbeSourceEnabled && Boolean(sourceText);
  const sourceFont = "500 10.5px Segoe UI";
  const sourceTextMaxWidth = 188;
  const sourceLabelText = sourceEnabled ? truncateTextToWidth(sourceText, sourceTextMaxWidth, sourceFont) : "";
  const sourceWidth = sourceLabelText ? Math.ceil(measureCommentTextWidth(sourceLabelText, sourceFont)) + 8 : 0;
  const labelHeight = 24;
  const sourceHeight = sourceLabelText ? 18 : 0;
  const sourceOverlap = sourceLabelText ? 5 : 0;
  const minY = 20;
  const totalHeight = labelHeight + (sourceLabelText ? sourceHeight - sourceOverlap : 0);
  const stripHeight = ui.openWorkspaceStrip?.offsetHeight ?? 0;
  const baseBottomGap = labelHeight + 8;
  const defaultBottomGap = baseBottomGap + (sourceLabelText ? labelHeight : 0);
  const maxY = Math.max(minY, state.height - stripHeight - totalHeight - defaultBottomGap);
  const defaultY = maxY;
  const labelY = clamp(
    Number.isFinite(state.chartProbeLabelY) ? state.chartProbeLabelY : defaultY,
    minY,
    maxY,
  );
  return {
    labelText,
    valueWidth,
    sourceWidth,
    labelHeight,
    labelY,
    sourceLabelText,
    sourceHeight,
    sourceOverlap,
    totalHeight,
    minY,
    maxY,
  };
}

function getChartDisplayPreset(chartItem) {
  const displayMode = state.chartDisplayMode;
  const isActive = getActiveChart()?.id === chartItem.id;
  if (displayMode === "events") {
    return { opacity: isActive ? 0.52 : 0.32, strokeWidth: isActive ? 2.5 : 1.9 };
  }
  if (displayMode === "chart-focus") {
    return { opacity: isActive ? 0.96 : 0.42, strokeWidth: isActive ? 3.2 : 2.1 };
  }
  return { opacity: isActive ? 0.86 : 0.62, strokeWidth: isActive ? 2.9 : 2.2 };
}

function parseChartImportPayload(payload) {
  if (payload?.type === "chart") return [payload];
  if (payload?.type === "chart-export" && Array.isArray(payload.charts)) return payload.charts;
  if (Array.isArray(payload?.charts)) return payload.charts;
  if (Array.isArray(payload)) return payload;
  return [];
}

function getFilenameBase(filename) {
  return String(filename || "")
    .replace(/\.[^.]+$/, "")
    .trim();
}

function parseDelimitedLine(line, delimiter) {
  const cells = [];
  let current = "";
  let inQuotes = false;
  for (let index = 0; index < line.length; index += 1) {
    const char = line[index];
    const nextChar = line[index + 1];
    if (char === "\"") {
      if (inQuotes && nextChar === "\"") {
        current += "\"";
        index += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }
    if (char === delimiter && !inQuotes) {
      cells.push(current);
      current = "";
      continue;
    }
    current += char;
  }
  cells.push(current);
  return cells.map((cell) => cell.trim());
}

function splitDelimitedRecords(text) {
  const records = [];
  let current = "";
  let inQuotes = false;
  const normalized = String(text || "").replace(/\r\n/g, "\n").replace(/\r/g, "\n");
  for (let index = 0; index < normalized.length; index += 1) {
    const char = normalized[index];
    const nextChar = normalized[index + 1];
    if (char === "\"") {
      if (inQuotes && nextChar === "\"") {
        current += "\"\"";
        index += 1;
      } else {
        inQuotes = !inQuotes;
        current += char;
      }
      continue;
    }
    if (char === "\n" && !inQuotes) {
      records.push(current);
      current = "";
      continue;
    }
    current += char;
  }
  records.push(current);
  return records;
}

function detectDelimitedTextSeparator(lines) {
  const candidates = [",", ";", "\t"];
  const sampleLines = lines.filter((line) => String(line || "").trim()).slice(0, 5);
  let bestDelimiter = ",";
  let bestScore = -1;
  candidates.forEach((delimiter) => {
    const score = sampleLines.reduce((sum, line) => sum + (parseDelimitedLine(line, delimiter).length - 1), 0);
    if (score > bestScore) {
      bestScore = score;
      bestDelimiter = delimiter;
    }
  });
  return bestDelimiter;
}

function normalizeDelimitedHeaderName(name) {
  return String(name || "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, "")
    .replace(/[_-]/g, "");
}

function headerLooksLikeTimeAxis(name) {
  const normalized = normalizeDelimitedHeaderName(name);
  return [
    "x",
    "date",
    "year",
    "time",
    "datum",
    "jahr",
    "zeit",
    "timeline",
    "mavorheute",
    "gavorheute",
    "kavorheute",
    "bp",
    "yearsbeforepresent",
    "millionyearsago",
  ].some((token) => normalized === token || normalized.includes(token));
}

function headerLooksLikeValueAxis(name) {
  const normalized = normalizeDelimitedHeaderName(name);
  return [
    "y",
    "value",
    "wert",
    "measure",
    "metric",
    "prozent",
    "percent",
    "percentage",
    "volumenprozent",
    "ppm",
    "population",
    "co2",
    "oxygen",
    "sauerstoff",
  ].some((token) => normalized === token || normalized.includes(token));
}

function headerLooksLikeSourceField(name) {
  const normalized = normalizeDelimitedHeaderName(name);
  return [
    "source",
    "quelle",
    "reference",
    "ref",
    "citation",
    "sourcetitle",
    "quellenachweis",
  ].some((token) => normalized === token || normalized.includes(token));
}

function headerLooksLikeSourceUrlField(name) {
  const normalized = normalizeDelimitedHeaderName(name);
  return [
    "sourceurl",
    "url",
    "link",
    "weblink",
    "quellurl",
    "quellenlink",
  ].some((token) => normalized === token || normalized.includes(token));
}

function headerLooksLikeUncertaintyField(name) {
  const normalized = normalizeDelimitedHeaderName(name);
  return [
    "uncertainty",
    "unsicherheit",
    "quality",
    "certainty",
    "confidence",
  ].some((token) => normalized === token || normalized.includes(token));
}

function normalizeChartPointUncertainty(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (!normalized || normalized === "none" || normalized === "direct" || normalized === "exact") return "";
  if (normalized === "partialreconstruction" || normalized === "partial-reconstruction" || normalized === "teilrekonstruktion") return "partial-reconstruction";
  if (normalized === "fullreconstruction" || normalized === "full-reconstruction" || normalized === "vollrekonstruktion") return "full-reconstruction";
  if (normalized === "interpolated" || normalized === "interpolation") return "interpolated";
  if (normalized === "estimated" || normalized === "estimate" || normalized === "geschaetzt" || normalized === "geschätzt") return "estimated";
  if (normalized === "modeled" || normalized === "modelled" || normalized === "modelliert") return "modeled";
  return normalized;
}

function isChartPointUncertain(point) {
  return Boolean(normalizeChartPointUncertainty(point?.meta?.uncertainty));
}

function buildChartPayloadFromDelimitedText(text, fallbackTitle = "") {
  const normalizedText = String(text || "").replace(/^\uFEFF/, "");
  const records = splitDelimitedRecords(normalizedText);
  const lines = records.map((line) => String(line || "").trim());
  const nonEmptyLines = lines.filter(Boolean);
  if (nonEmptyLines.length < 2) {
    throw new Error("invalid-chart-payload");
  }

  const delimiter = detectDelimitedTextSeparator(nonEmptyLines);
  const metadata = {
    title: "",
    unit: "",
    unitShort: "",
    sourceTitle: "",
    description: "",
  };
  let headerLineIndex = 0;
  const isHeaderRecord = (line) => {
    const cells = parseDelimitedLine(line, delimiter);
    if (!cells.length) return false;
    let xIndex = cells.findIndex((cell) => headerLooksLikeTimeAxis(cell));
    let yIndex = cells.findIndex((cell) => headerLooksLikeValueAxis(cell));
    if (xIndex < 0 && cells.length >= 1) xIndex = 0;
    if (yIndex < 0 && cells.length >= 2) yIndex = xIndex === 0 ? 1 : 0;
    return xIndex >= 0 && yIndex >= 0;
  };

  while (headerLineIndex < lines.length) {
    if (!lines[headerLineIndex]) {
      headerLineIndex += 1;
      continue;
    }
    const cells = parseDelimitedLine(lines[headerLineIndex], delimiter);
    if (cells.length < 2) break;
    const key = normalizeDelimitedHeaderName(cells[0]);
    const value = cells.slice(1).map((cell) => String(cell || "")).join(delimiter).trim();
    if (key === "title" || key === "titel") {
      metadata.title = value;
      headerLineIndex += 1;
      continue;
    }
    if (key === "unit" || key === "einheit") {
      metadata.unit = value;
      headerLineIndex += 1;
      continue;
    }
    if (key === "unitshort" || key === "einheitkurz" || key === "einheit_kurz") {
      metadata.unitShort = value;
      headerLineIndex += 1;
      continue;
    }
    if (key === "sourcetitle" || key === "quelle" || key === "chartsource" || key === "source") {
      metadata.sourceTitle = value;
      headerLineIndex += 1;
      continue;
    }
    if (key === "description" || key === "beschreibung") {
      const descriptionParts = [value];
      headerLineIndex += 1;
      while (headerLineIndex < lines.length) {
        const nextLine = lines[headerLineIndex];
        if (!nextLine) {
          descriptionParts.push("");
          headerLineIndex += 1;
          continue;
        }
        const nextCells = parseDelimitedLine(nextLine, delimiter);
        const nextKey = normalizeDelimitedHeaderName(nextCells[0]);
        if (
          nextKey === "title" ||
          nextKey === "titel" ||
          nextKey === "unit" ||
          nextKey === "einheit" ||
          nextKey === "unitshort" ||
          nextKey === "einheitkurz" ||
          nextKey === "einheit_kurz" ||
          nextKey === "sourcetitle" ||
          nextKey === "quelle" ||
          nextKey === "chartsource" ||
          nextKey === "source" ||
          nextKey === "description" ||
          nextKey === "beschreibung" ||
          isHeaderRecord(nextLine)
        ) {
          break;
        }
        descriptionParts.push(nextLine);
        headerLineIndex += 1;
      }
      metadata.description = descriptionParts.join("\n").trim();
      continue;
    }
    break;
  }

  while (headerLineIndex < lines.length && !lines[headerLineIndex]) {
    headerLineIndex += 1;
  }

  if (headerLineIndex >= lines.length - 1) {
    throw new Error("invalid-chart-payload");
  }

  const headerCells = parseDelimitedLine(lines[headerLineIndex], delimiter);
  const headerMap = new Map(headerCells.map((cell, index) => [normalizeDelimitedHeaderName(cell), index]));

  const getHeaderIndex = (...aliases) => {
    for (const alias of aliases) {
      const index = headerMap.get(normalizeDelimitedHeaderName(alias));
      if (Number.isInteger(index)) return index;
    }
    return -1;
  };

  let xIndex = getHeaderIndex("x", "date", "year", "time", "datum", "jahr");
  let yIndex = getHeaderIndex("y", "value", "wert");
  let sourceIndex = getHeaderIndex("source", "quelle", "sourcetitle");
  let sourceUrlIndex = getHeaderIndex("sourceUrl", "url", "link", "weblink");
  let uncertaintyIndex = getHeaderIndex("uncertainty", "unsicherheit", "quality");

  if (xIndex < 0) {
    xIndex = headerCells.findIndex((cell) => headerLooksLikeTimeAxis(cell));
  }
  if (yIndex < 0) {
    yIndex = headerCells.findIndex((cell) => headerLooksLikeValueAxis(cell));
  }
  if (sourceIndex < 0) {
    sourceIndex = headerCells.findIndex((cell) => headerLooksLikeSourceField(cell));
  }
  if (sourceUrlIndex < 0) {
    sourceUrlIndex = headerCells.findIndex((cell) => headerLooksLikeSourceUrlField(cell));
  }
  if (uncertaintyIndex < 0) {
    uncertaintyIndex = headerCells.findIndex((cell) => headerLooksLikeUncertaintyField(cell));
  }

  if (xIndex < 0 && headerCells.length >= 1) xIndex = 0;
  if (yIndex < 0 && headerCells.length >= 2) {
    yIndex = xIndex === 0 ? 1 : 0;
  }
  if (sourceIndex < 0 && headerCells.length >= 3) {
    sourceIndex = headerCells.findIndex((_, index) => index !== xIndex && index !== yIndex);
  }

  if (xIndex < 0 || yIndex < 0) {
    throw new Error("chart-csv-missing-columns");
  }

  const points = [];
  for (let lineIndex = headerLineIndex + 1; lineIndex < lines.length; lineIndex += 1) {
    if (!lines[lineIndex]) continue;
    const cells = parseDelimitedLine(lines[lineIndex], delimiter);
    const xText = String(cells[xIndex] || "").trim();
    const yText = String(cells[yIndex] || "").trim().replace(",", ".");
    if (!xText && !yText) continue;
    const temporal = parseEditorTemporalValue(xText);
    const yValue = Number(yText);
    if (!temporal || !Number.isFinite(yValue)) continue;
    points.push({
      id: createUniqueId("chart-point"),
      x: temporal.value,
      precision: temporal.precision ?? 9,
      y: yValue,
      label: "",
      description: "",
      meta: {
        sourceUrl: sourceUrlIndex >= 0 ? String(cells[sourceUrlIndex] || "").trim() : "",
        uncertainty: uncertaintyIndex >= 0 ? normalizeChartPointUncertainty(cells[uncertaintyIndex]) : "",
      },
      sourceTitle: sourceIndex >= 0 ? String(cells[sourceIndex] || "").trim() : "",
      visible: true,
    });
  }

  if (!points.length) {
    throw new Error("invalid-chart-payload");
  }

  points.sort((left, right) => left.x - right.x);

  return {
    type: "chart",
    title: metadata.title || fallbackTitle || "Chart",
    sourceTitle: metadata.sourceTitle || (delimiter === "\t" ? "TSV" : "CSV"),
    sourceUrl: "",
    sourceUnit: metadata.unit || "",
    sourceUnitShort: metadata.unitShort || "",
    description: metadata.description || "",
    points,
  };
}

function normalizeOwidChartSearchResults(payload) {
  return (payload?.results ?? payload?.hits ?? [])
    .filter((entry) => {
      const url = String(entry?.url || "").trim();
      return Boolean(url) && (
        entry?.type === "chart"
        || entry?.contentType === "chart"
        || url.includes("/grapher/")
      );
    })
    .map((entry) => ({
      source: "owid",
      id: entry.slug || entry.url,
      slug: entry.slug || "",
      title: String(entry.title || "Chart").trim(),
      subtitle: String(entry.subtitle || "").trim(),
      description: String(entry.description || entry.excerpt || "").trim(),
      variantName: String(entry.variantName || "").trim(),
      availableEntities: Array.isArray(entry.availableEntities) ? entry.availableEntities.filter(Boolean) : [],
      availableTabs: Array.isArray(entry.availableTabs) ? entry.availableTabs.filter(Boolean) : [],
      url: String(entry.url || "").trim(),
      publishedAt: entry.publishedAt || "",
      updatedAt: entry.updatedAt || "",
    }));
}

function getChartSourceLabel(sourceKey) {
  if (sourceKey === "worldbank") return t("chart_source_worldbank");
  if (sourceKey === "alphavantage") return t("chart_source_alphavantage");
  if (sourceKey === "eurostat") return t("chart_source_eurostat");
  if (sourceKey === "oecd") return t("chart_source_oecd");
  return t("chart_source_owid");
}

function getAlphaVantageApiKey() {
  return String(state.alphaVantageApiKey || "").trim() || ALPHA_VANTAGE_DEFAULT_API_KEY;
}

function hasCustomAlphaVantageApiKey() {
  return Boolean(String(state.alphaVantageApiKey || "").trim());
}

function sourceRequiresApiKey(sourceKey) {
  return sourceKey === "alphavantage";
}

function sourceHasConfiguredApiKey(sourceKey) {
  if (sourceKey === "alphavantage") return hasCustomAlphaVantageApiKey() && state.alphaVantageApiVerified === true;
  return false;
}

function updateAlphaVantageApiUi() {
  const sourceKey = state.chartSearchSource || "owid";
  const requiresApi = sourceRequiresApiKey(sourceKey);
  const hasApiKey = sourceHasConfiguredApiKey(sourceKey);
  if (ui.alphaVantageApiPanel) {
    ui.alphaVantageApiPanel.hidden = sourceKey !== "alphavantage";
  }
  if (ui.alphaVantageApiKeyInput && ui.alphaVantageApiKeyInput.value !== String(state.alphaVantageApiKey || "")) {
    ui.alphaVantageApiKeyInput.value = String(state.alphaVantageApiKey || "");
  }
  if (ui.chartSourceApiStatus) {
    ui.chartSourceApiStatus.hidden = !requiresApi;
    ui.chartSourceApiStatus.textContent = t("chart_source_api_label");
    ui.chartSourceApiStatus.classList.toggle("is-ready", requiresApi && hasApiKey);
    ui.chartSourceApiStatus.classList.toggle("is-missing", requiresApi && !hasApiKey);
    ui.chartSourceApiStatus.title = requiresApi
      ? (hasApiKey ? t("chart_source_api_ready") : t("chart_source_api_missing"))
      : "";
    ui.chartSourceApiStatus.setAttribute("aria-label", ui.chartSourceApiStatus.title || t("chart_source_api_label"));
  }
}

function getAlphaVantageVariantLabel(variantValue = "") {
  if (variantValue === ALPHA_VANTAGE_ALL_VARIANTS_VALUE) {
    return t("chart_variant_all");
  }
  return ALPHA_VANTAGE_VARIANTS.find((variant) => variant.value === variantValue)?.label || "Daily";
}

function getAlphaVantageVariantValues() {
  return ALPHA_VANTAGE_VARIANTS.map((variant) => variant.value);
}

function getAlphaVantageTableVariantSet(chartItem) {
  const variants = new Set();
  getChartTables(chartItem).forEach((table) => {
    const sourceEntity = String(table?.sourceEntity || "").trim().toLowerCase();
    if (getAlphaVantageVariantValues().includes(sourceEntity)) {
      variants.add(sourceEntity);
    }
  });
  return variants;
}

function isAlphaVantageAllVariantsChartComplete(chartItem) {
  if (!chartItem || chartItem.sourceKey !== "alphavantage" || chartItem.sourceEntity !== ALPHA_VANTAGE_ALL_VARIANTS_VALUE) {
    return false;
  }
  const variants = getAlphaVantageTableVariantSet(chartItem);
  return getAlphaVantageVariantValues().every((value) => variants.has(value));
}

function getDefaultAlphaVantageVariant(result) {
  const availableVariants = Array.isArray(result?.availableEntities) ? result.availableEntities : [];
  return availableVariants.includes(ALPHA_VANTAGE_ALL_VARIANTS_VALUE)
    ? ALPHA_VANTAGE_ALL_VARIANTS_VALUE
    : (availableVariants.includes("daily") ? "daily" : (availableVariants[0] || "daily"));
}

function normalizeWorldBankChartSearchResults(query) {
  const tokens = String(query || "")
    .toLowerCase()
    .split(/\s+/)
    .map((token) => token.trim())
    .filter(Boolean);
  if (!tokens.length) return [];
  const scored = WORLD_BANK_CHART_CATALOG
    .map((entry) => {
      const haystack = [
        entry.id,
        entry.title,
        entry.description,
        entry.unit,
        entry.topic,
      ].join(" ").toLowerCase();
      let score = 0;
      tokens.forEach((token) => {
        if (entry.title.toLowerCase().startsWith(token)) score += 6;
        if (entry.title.toLowerCase().includes(token)) score += 4;
        if (entry.description.toLowerCase().includes(token)) score += 2;
        if (String(entry.unit || "").toLowerCase().includes(token)) score += 1;
        if (haystack.includes(token)) score += 1;
      });
      return { entry, score };
    })
    .filter(({ score }) => score > 0)
    .sort((left, right) => right.score - left.score || left.entry.title.localeCompare(right.entry.title, "en"));

  return scored.slice(0, 20).map(({ entry }) => ({
    source: "worldbank",
    id: entry.id,
    sourceItemId: entry.id,
    title: entry.title,
    subtitle: entry.description,
    description: entry.description,
    variantName: entry.topic,
    availableEntities: ["World"],
    entityCodeMap: { World: "WLD" },
    url: `https://api.worldbank.org/v2/country/WLD/indicator/${entry.id}?format=json&per_page=20000`,
    unit: entry.unit,
    topic: entry.topic,
    rangeLabel: t("chart_date_range_unknown"),
  }));
}

async function searchOwidCharts(query) {
  const params = new URLSearchParams({
    q: query,
    type: "charts",
    hitsPerPage: "12",
  });
  const response = await fetchWithTimeout(`${OWID_SEARCH_API_URL}?${params.toString()}`);
  if (!response.ok) throw new Error("owid-search-failed");
  return normalizeOwidChartSearchResults(await response.json());
}

function normalizeAlphaVantageSearchResults(payload) {
  const matches = Array.isArray(payload?.bestMatches) ? payload.bestMatches : [];
  return matches
    .map((entry) => {
      const symbol = String(entry?.["1. symbol"] || "").trim();
      const name = String(entry?.["2. name"] || "").trim();
      if (!symbol || !name) return null;
      const type = String(entry?.["3. type"] || "").trim();
      const region = String(entry?.["4. region"] || "").trim();
      const currency = String(entry?.["8. currency"] || "").trim();
      const score = Number(entry?.["9. matchScore"] || 0);
      const subtitleParts = [type, region, currency].filter(Boolean);
      return {
        source: "alphavantage",
        id: symbol,
        sourceItemId: symbol,
        symbol,
        title: name,
        subtitle: subtitleParts.join(" · "),
        description: subtitleParts.join(" · "),
        variantName: symbol,
        availableEntities: [ALPHA_VANTAGE_ALL_VARIANTS_VALUE, ...ALPHA_VANTAGE_VARIANTS.map((variant) => variant.value)],
        entityLabels: {
          [ALPHA_VANTAGE_ALL_VARIANTS_VALUE]: getAlphaVantageVariantLabel(ALPHA_VANTAGE_ALL_VARIANTS_VALUE),
          ...Object.fromEntries(ALPHA_VANTAGE_VARIANTS.map((variant) => [variant.value, variant.label])),
        },
        url: `${ALPHA_VANTAGE_API_URL}?function=SYMBOL_SEARCH&keywords=${encodeURIComponent(symbol)}`,
        unit: currency || "price",
        assetType: type,
        region,
        currency,
        matchScore: Number.isFinite(score) ? score : 0,
        rangeLabel: t("chart_date_range_unknown"),
        isFallbackCatalog: false,
      };
    })
    .filter(Boolean)
    .sort((left, right) => right.matchScore - left.matchScore || left.title.localeCompare(right.title, "en"))
    .slice(0, 20);
}

function searchAlphaVantageFallbackCatalog(query) {
  const tokens = String(query || "")
    .toLowerCase()
    .split(/\s+/)
    .map((token) => token.trim())
    .filter(Boolean);
  if (!tokens.length) return [];

  return ALPHA_VANTAGE_SYMBOL_FALLBACKS
    .map((entry) => {
      const haystack = [
        entry.symbol,
        entry.name,
        entry.type,
        entry.region,
        entry.currency,
        ...(Array.isArray(entry.aliases) ? entry.aliases : []),
      ].join(" ").toLowerCase();
      let score = 0;
      tokens.forEach((token) => {
        if (entry.symbol.toLowerCase() === token) score += 10;
        if (entry.symbol.toLowerCase().startsWith(token)) score += 7;
        if (entry.name.toLowerCase().startsWith(token)) score += 6;
        if (entry.name.toLowerCase().includes(token)) score += 4;
        if (haystack.includes(token)) score += 1;
      });
      return { entry, score };
    })
    .filter(({ score }) => score > 0)
    .sort((left, right) => right.score - left.score || left.entry.name.localeCompare(right.entry.name, "en"))
    .slice(0, 20)
    .map(({ entry }) => ({
      source: "alphavantage",
      id: entry.symbol,
      sourceItemId: entry.symbol,
      symbol: entry.symbol,
      title: entry.name,
      subtitle: [entry.type, entry.region, entry.currency].filter(Boolean).join(" · "),
      description: [entry.type, entry.region, entry.currency].filter(Boolean).join(" · "),
      variantName: entry.symbol,
      availableEntities: [ALPHA_VANTAGE_ALL_VARIANTS_VALUE, ...ALPHA_VANTAGE_VARIANTS.map((variant) => variant.value)],
      entityLabels: {
        [ALPHA_VANTAGE_ALL_VARIANTS_VALUE]: getAlphaVantageVariantLabel(ALPHA_VANTAGE_ALL_VARIANTS_VALUE),
        ...Object.fromEntries(ALPHA_VANTAGE_VARIANTS.map((variant) => [variant.value, variant.label])),
      },
      url: `${ALPHA_VANTAGE_API_URL}?function=SYMBOL_SEARCH&keywords=${encodeURIComponent(entry.symbol)}`,
      unit: entry.currency || "price",
      assetType: entry.type,
      region: entry.region,
      currency: entry.currency,
      matchScore: 0,
      rangeLabel: t("chart_date_range_unknown"),
      isFallbackCatalog: true,
    }));
}

function getAlphaVantageSearchKeywords(query = "") {
  const raw = String(query || "").trim();
  if (!raw) return [];
  const normalized = raw.replace(/\s+/g, " ").trim();
  const alnum = normalized.replace(/[^\p{L}\p{N}.&-]+/gu, " ").replace(/\s+/g, " ").trim();
  const tokens = alnum
    .split(/\s+/)
    .map((token) => token.trim())
    .filter((token) => token.length >= 2);
  const candidates = [
    normalized,
    normalized.toUpperCase(),
    alnum,
    tokens[0] || "",
    tokens.slice(0, 2).join(" ").trim(),
  ].filter(Boolean);
  return [...new Set(candidates)];
}

async function searchAlphaVantageCharts(query) {
  const keywords = getAlphaVantageSearchKeywords(query);
  const mergedResults = new Map();
  const fallbackResults = searchAlphaVantageFallbackCatalog(query);
  fallbackResults.forEach((result) => {
    const key = `${result.sourceItemId}|fallback|${result.title}`;
    mergedResults.set(key, result);
  });
  if (!hasCustomAlphaVantageApiKey()) {
    return { results: [...mergedResults.values()], usedFallback: true };
  }
  try {
    for (let index = 0; index < keywords.length; index += 1) {
      const keyword = keywords[index];
      const params = new URLSearchParams({
        function: "SYMBOL_SEARCH",
        keywords: keyword,
        apikey: getAlphaVantageApiKey(),
      });
      const response = await fetchWithTimeout(`${ALPHA_VANTAGE_API_URL}?${params.toString()}`);
      if (!response.ok) throw new Error("alphavantage-search-failed");
      const payload = await response.json();
      const remoteResults = normalizeAlphaVantageSearchResults(payload);
      remoteResults.forEach((result) => {
        const key = `${result.sourceItemId}|remote|${result.title}`;
        if (!mergedResults.has(key)) {
          mergedResults.set(key, result);
        }
      });
      if (mergedResults.size >= 12) break;
      if (index < keywords.length - 1) {
        await new Promise((resolve) => window.setTimeout(resolve, 350));
      }
    }
    const combinedResults = [...mergedResults.values()];
    if (combinedResults.length) {
      const onlyFallbackResults = combinedResults.every((result) => result.isFallbackCatalog === true);
      return { results: combinedResults, usedFallback: onlyFallbackResults };
    }
    return { results: fallbackResults, usedFallback: true };
  } catch {
    if (fallbackResults.length) return { results: fallbackResults, usedFallback: true };
    throw new Error("alphavantage-search-failed");
  }
}

async function validateAlphaVantageApiKey(apiKey = state.alphaVantageApiKey) {
  const normalizedKey = String(apiKey || "").trim();
  if (!normalizedKey) {
    state.alphaVantageApiVerified = false;
    updateAlphaVantageApiUi();
    populateChartSourceSelect(false);
    scheduleLocalAutosave();
    return false;
  }
  const params = new URLSearchParams({
    function: "SYMBOL_SEARCH",
    keywords: "IBM",
    apikey: normalizedKey,
  });
  try {
    const response = await fetchWithTimeout(`${ALPHA_VANTAGE_API_URL}?${params.toString()}`);
    if (!response.ok) throw new Error("alphavantage-validate-failed");
    const payload = await response.json();
    const isValid = Array.isArray(payload?.bestMatches) && payload.bestMatches.length > 0;
    state.alphaVantageApiVerified = isValid;
    updateAlphaVantageApiUi();
    populateChartSourceSelect(false);
    scheduleLocalAutosave();
    return isValid;
  } catch {
    state.alphaVantageApiVerified = false;
    updateAlphaVantageApiUi();
    populateChartSourceSelect(false);
    scheduleLocalAutosave();
    return false;
  }
}

function fetchJsonp(resource, callbackParam = "callback", timeoutMs = 12000) {
  return new Promise((resolve, reject) => {
    const callbackName = `timemapJsonp_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
    const url = new URL(resource);
    url.searchParams.set(callbackParam, callbackName);
    const script = document.createElement("script");
    let settled = false;
    const cleanup = () => {
      if (script.parentNode) script.parentNode.removeChild(script);
      delete window[callbackName];
    };
    const timeoutId = window.setTimeout(() => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(new Error("fetch-timeout"));
    }, timeoutMs);
    window[callbackName] = (payload) => {
      if (settled) return;
      settled = true;
      window.clearTimeout(timeoutId);
      cleanup();
      resolve(payload);
    };
    script.onerror = () => {
      if (settled) return;
      settled = true;
      window.clearTimeout(timeoutId);
      cleanup();
      reject(new Error("jsonp-failed"));
    };
    script.src = url.toString();
    document.head.appendChild(script);
  });
}

function getWorldBankFallbackEntities() {
  return {
    availableEntities: WORLD_BANK_ENTITY_FALLBACKS.map((entry) => entry.name),
    entityCodeMap: Object.fromEntries(WORLD_BANK_ENTITY_FALLBACKS.map((entry) => [entry.name, entry.code])),
  };
}

async function ensureWorldBankEntityOptions() {
  if (worldBankEntitiesCache) return worldBankEntitiesCache;
  try {
    let payload = null;
    try {
      const response = await fetchWithTimeout("https://api.worldbank.org/v2/country?format=json&per_page=400");
      if (response.ok) {
        payload = await response.json();
      }
    } catch {
      payload = null;
    }
    if (!payload) {
      payload = await fetchJsonp("https://api.worldbank.org/v2/country?format=jsonP&per_page=400", "prefix");
    }
    const rows = Array.isArray(payload?.[1]) ? payload[1] : [];
    const entities = rows
      .filter((row) => {
        const code = String(row?.id || "").trim();
        if (!code) return false;
        if (code === "WLD") return true;
        return String(row?.region?.value || "").trim() !== "Aggregates";
      })
      .map((row) => ({
        code: String(row?.id || "").trim(),
        name: String(row?.name || "").trim(),
      }))
      .filter((row) => row.code && row.name);
    entities.sort((left, right) => {
      if (left.code === "WLD") return -1;
      if (right.code === "WLD") return 1;
      return left.name.localeCompare(right.name, "en");
    });
    worldBankEntitiesCache = entities.length
      ? {
        availableEntities: entities.map((entry) => entry.name),
        entityCodeMap: Object.fromEntries(entities.map((entry) => [entry.name, entry.code])),
      }
      : getWorldBankFallbackEntities();
  } catch {
    worldBankEntitiesCache = getWorldBankFallbackEntities();
  }
  return worldBankEntitiesCache;
}

async function searchWorldBankCharts(query) {
  const entityOptions = await ensureWorldBankEntityOptions().catch(() => getWorldBankFallbackEntities());
  return normalizeWorldBankChartSearchResults(query).map((result) => ({
    ...result,
    availableEntities: entityOptions.availableEntities,
    entityCodeMap: entityOptions.entityCodeMap,
  }));
}

async function fetchWithTimeout(resource, options = {}, timeoutMs = 12000) {
  const controller = new AbortController();
  const timeoutId = window.setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(resource, { ...options, signal: controller.signal });
  } catch (error) {
    if (error?.name === "AbortError") {
      throw new Error("fetch-timeout");
    }
    throw error;
  } finally {
    window.clearTimeout(timeoutId);
  }
}

function parseCsvLine(line) {
  const values = [];
  let current = "";
  let quoted = false;
  for (let index = 0; index < line.length; index += 1) {
    const char = line[index];
    const next = line[index + 1];
    if (char === '"') {
      if (quoted && next === '"') {
        current += '"';
        index += 1;
      } else {
        quoted = !quoted;
      }
      continue;
    }
    if (char === "," && !quoted) {
      values.push(current);
      current = "";
      continue;
    }
    current += char;
  }
  values.push(current);
  return values;
}

function parseCsvRows(csvText) {
  const lines = String(csvText || "")
    .replace(/^\uFEFF/, "")
    .split(/\r?\n/)
    .filter((line) => line.trim().length > 0);
  if (!lines.length) return [];
  const headers = parseCsvLine(lines[0]).map((header) => header.trim());
  return lines.slice(1).map((line) => {
    const values = parseCsvLine(line);
    return headers.reduce((row, header, index) => {
      row[header] = values[index] ?? "";
      return row;
    }, {});
  });
}

function getDefaultOwidEntity(result) {
  if (!Array.isArray(result?.availableEntities) || !result.availableEntities.length) return "";
  return result.availableEntities.includes("World")
    ? "World"
    : result.availableEntities[0];
}

function getDefaultChartSearchEntity(result) {
  if (result?.source === "alphavantage") {
    return getDefaultAlphaVantageVariant(result);
  }
  if (result?.source === "worldbank") {
    return Array.isArray(result?.availableEntities) && result.availableEntities.includes("World")
      ? "World"
      : (result?.availableEntities?.[0] || "World");
  }
  return getDefaultOwidEntity(result);
}

function getOwidChartUrls(result) {
  const baseUrl = new URL(result.url, "https://ourworldindata.org");
  return {
    csvUrl: `${baseUrl.origin}${baseUrl.pathname}.csv${baseUrl.search}`,
    metadataUrl: `${baseUrl.origin}${baseUrl.pathname}.metadata.json${baseUrl.search}`,
  };
}

async function fetchOwidChartBundle(result) {
  const { csvUrl, metadataUrl } = getOwidChartUrls(result);
  const [csvResponse, metadataResponse] = await Promise.all([
    fetchWithTimeout(csvUrl),
    fetchWithTimeout(metadataUrl),
  ]);
  if (!csvResponse.ok || !metadataResponse.ok) throw new Error("owid-fetch-failed");
  const [csvText, metadata] = await Promise.all([
    csvResponse.text(),
    metadataResponse.json(),
  ]);
  return { csvText, metadata };
}

function getOwidColumnMetadata(metadata, columnName) {
  if (!metadata?.columns) return null;
  if (Array.isArray(metadata.columns)) {
    return metadata.columns.find((column) => (
      column?.slug === columnName
      || column?.shortName === columnName
      || column?.titleShort === columnName
      || column?.titlePublic === columnName
      || column?.titleLong === columnName
      || column?.name === columnName
    )) ?? null;
  }
  return metadata.columns[columnName] ?? null;
}

function extractOwidUnit(columnMeta = {}, result = {}) {
  const candidateValues = [
    columnMeta.unit,
    columnMeta.unitShort,
    columnMeta.shortUnit,
    columnMeta.display?.unit,
    columnMeta.display?.unitShort,
    columnMeta.presentation?.unit,
    result.unit,
    result.unitShort,
  ];
  const directUnit = candidateValues
    .map((value) => String(value || "").trim())
    .find(Boolean);
  if (directUnit) return directUnit;

  const fallbackTexts = [
    columnMeta.descriptionShort,
    columnMeta.description,
    columnMeta.titleLong,
    result.subtitle,
    result.description,
    result.variantName,
  ]
    .map((value) => String(value || "").trim())
    .filter(Boolean);

  for (const text of fallbackTexts) {
    const parenMatch = text.match(/\(([A-Za-z%][A-Za-z0-9/%\s.-]{0,30})\)/);
    if (parenMatch) return parenMatch[1].trim();

    const measuredInMatch = text.match(/measured\s+in\s+([^.;,]+)/i);
    if (measuredInMatch) return measuredInMatch[1].trim();

    const unitIsMatch = text.match(/unit\s+is\s+([^.;,]+)/i);
    if (unitIsMatch) return unitIsMatch[1].trim();
  }

  return "";
}

function resolveOwidValueColumn(rows, metadata) {
  const firstRow = rows[0];
  if (!firstRow) return null;
  const ignoredColumns = new Set(["Entity", "Code", "Year", "Day"]);
  const headers = Object.keys(firstRow).filter((header) => !ignoredColumns.has(header));
  const preferredHeader = headers.find((header) => rows.some((row) => Number.isFinite(Number(row[header]))));
  if (!preferredHeader) return null;
  return {
    name: preferredHeader,
    metadata: getOwidColumnMetadata(metadata, preferredHeader),
  };
}

function parseOwidPointX(rawValue, precision) {
  const value = String(rawValue ?? "").trim();
  if (!value) return NaN;
  if (precision === "day") {
    const match = value.match(/^(-?\d{1,6})-(\d{2})-(\d{2})$/);
    if (!match) return NaN;
    return buildTimelineValue(Number(match[1]), Number(match[2]), Number(match[3]));
  }
  const year = Number(value);
  return Number.isFinite(year) ? toAstronomicalYear(Math.round(year)) : NaN;
}

function getChartPointRangeLabel(points = []) {
  if (!Array.isArray(points) || points.length === 0) return t("chart_date_range_unknown");
  const sortedPoints = [...points]
    .filter((point) => Number.isFinite(point.x))
    .sort((left, right) => left.x - right.x);
  if (!sortedPoints.length) return t("chart_date_range_unknown");
  const start = sortedPoints[0];
  const end = sortedPoints[sortedPoints.length - 1];
  const precision = Number.isFinite(start.x) && Number.isInteger(start.x) && Number.isFinite(end.x) && Number.isInteger(end.x)
    ? 9
    : 11;
  const startLabel = formatTimelineValue(start.x, precision);
  const endLabel = formatTimelineValue(end.x, precision);
  return startLabel === endLabel ? startLabel : `${startLabel} ${t("until_connector")} ${endLabel}`;
}

function buildOwidChartItem(result, csvText, metadata, selectedEntity = "") {
  const rows = parseCsvRows(csvText);
  const timeColumn = rows[0]?.Day ? "Day" : (rows[0]?.Year ? "Year" : null);
  if (!timeColumn) throw new Error("owid-missing-time");
  const effectiveEntity = selectedEntity || getDefaultOwidEntity(result);
  const relevantRows = rows.filter((row) => {
    if (!row.Entity || !effectiveEntity) return true;
    return String(row.Entity).trim() === effectiveEntity;
  });
  const sourceRows = relevantRows.length ? relevantRows : rows;
  const valueColumn = resolveOwidValueColumn(sourceRows, metadata);
  if (!valueColumn) throw new Error("owid-missing-value");
  const xPrecision = timeColumn === "Day" ? "day" : "year";
  const points = sourceRows
    .map((row, index) => ({
      id: `${result.slug || "owid"}-point-${index + 1}`,
      x: parseOwidPointX(row[timeColumn], xPrecision),
      y: Number(row[valueColumn.name]),
      label: "",
      description: effectiveEntity || String(row.Entity || "").trim(),
      sourceTitle: t("chart_source_owid"),
      visible: true,
    }))
    .filter((point) => Number.isFinite(point.x) && Number.isFinite(point.y))
    .sort((left, right) => left.x - right.x);
  if (points.length < 2) throw new Error("owid-not-enough-points");

  const columnMeta = valueColumn.metadata ?? {};
  const unit = extractOwidUnit(columnMeta, result);
const titleSuffix = effectiveEntity ? ` — ${effectiveEntity}` : "";
  const descriptionParts = [
    result.subtitle,
    result.variantName,
    unit,
  ].filter(Boolean);
  const axisLabelParts = [
    result.title,
    effectiveEntity && effectiveEntity !== "World" ? effectiveEntity : "",
    unit ? `(${unit})` : "",
  ].filter(Boolean);

  return {
    ...createEmptyChart(),
    sourceKey: "owid",
    sourceItemId: result.slug,
    sourceEntity: effectiveEntity,
    sourceMetric: valueColumn.name,
    sourceUnit: unit,
yAxisLabel: axisLabelParts.join(" — ") || valueColumn.name || "",
    title: `${result.title}${titleSuffix}`,
description: descriptionParts.join(" · "),
    sourceTitle: t("chart_source_owid"),
    sourceUrl: result.url,
    xPrecision,
    points,
  };
}

function getWorldBankEntityCode(result, entityName = "") {
  const key = String(entityName || getDefaultChartSearchEntity(result) || "World");
  return result?.entityCodeMap?.[key] || "WLD";
}

async function fetchWorldBankSeries(result, selectedEntity = "") {
  const entityName = selectedEntity || getDefaultChartSearchEntity(result);
  const entityCode = getWorldBankEntityCode(result, entityName);
  const jsonUrl = new URL(`https://api.worldbank.org/v2/country/${entityCode}/indicator/${result.sourceItemId || result.id}`);
  jsonUrl.search = new URLSearchParams({
    format: "json",
    per_page: "20000",
  }).toString();
  try {
    const response = await fetchWithTimeout(jsonUrl.toString());
    if (response.ok) {
      return { payload: await response.json(), entityName, entityCode, url: jsonUrl.toString() };
    }
  } catch {
    // Fallback to JSONP below.
  }
  const jsonpUrl = new URL(`https://api.worldbank.org/v2/country/${entityCode}/indicator/${result.sourceItemId || result.id}`);
  jsonpUrl.search = new URLSearchParams({
    format: "jsonP",
    per_page: "20000",
  }).toString();
  const payload = await fetchJsonp(jsonpUrl.toString(), "prefix");
  return { payload, entityName, entityCode, url: jsonUrl.toString() };
}

function buildWorldBankChartItemFromPayload(result, payload, selectedEntity = "", entityCode = "WLD", sourceUrl = "") {
  const rows = Array.isArray(payload?.[1]) ? payload[1] : [];
  const effectiveEntity = selectedEntity || getDefaultChartSearchEntity(result);
  const points = rows
    .map((row, index) => {
      const year = Number(String(row?.date || "").slice(0, 4));
      const value = Number(row?.value);
      return {
        id: `${result.sourceItemId || result.id}-point-${index + 1}`,
        x: Number.isFinite(year) ? toAstronomicalYear(year) : NaN,
        y: value,
        label: "",
        description: effectiveEntity,
        sourceTitle: t("chart_source_worldbank"),
        visible: true,
      };
    })
    .filter((point) => Number.isFinite(point.x) && Number.isFinite(point.y))
    .sort((left, right) => left.x - right.x);
  if (points.length < 2) throw new Error("worldbank-not-enough-points");

  const unit = String(result.unit || "").trim();
const titleSuffix = effectiveEntity ? ` — ${effectiveEntity}` : "";
  const axisLabelParts = [
    result.title,
    effectiveEntity && effectiveEntity !== "World" ? effectiveEntity : "",
    unit ? `(${unit})` : "",
  ].filter(Boolean);
  const descriptionParts = [
    result.description,
    result.topic,
    unit,
  ].filter(Boolean);

  return {
    ...createEmptyChart(),
    sourceKey: "worldbank",
    sourceItemId: result.sourceItemId || result.id,
    sourceEntity: effectiveEntity,
    sourceEntityCode: entityCode,
    sourceMetric: result.sourceItemId || result.id,
    sourceUnit: unit,
yAxisLabel: axisLabelParts.join(" — ") || result.title || "",
    title: `${result.title}${titleSuffix}`,
description: descriptionParts.join(" · "),
    sourceTitle: t("chart_source_worldbank"),
    sourceUrl: sourceUrl || result.url || "",
    xPrecision: "year",
    points,
  };
}

async function buildWorldBankChartItemFromSearchResult(result, selectedEntity = "") {
  const { payload, entityName, entityCode, url } = await fetchWorldBankSeries(result, selectedEntity);
  return buildWorldBankChartItemFromPayload(result, payload, entityName, entityCode, url);
}

function getAlphaVantageVariantConfig(variantValue = "") {
  return ALPHA_VANTAGE_VARIANTS.find((variant) => variant.value === variantValue) || ALPHA_VANTAGE_VARIANTS[0];
}

function getAlphaVantageVariantVisibility(variantValue = "") {
  const oneDay = scaleSteps.find((step) => step.id === "1d")?.years ?? (1 / DAYS_PER_YEAR);
  const oneWeek = scaleSteps.find((step) => step.id === "1w")?.years ?? (7 / DAYS_PER_YEAR);
  const oneMonth = scaleSteps.find((step) => step.id === "1m")?.years ?? (1 / 12);
  if (variantValue === "daily") {
    return { visibleStepMin: oneDay, visibleStepMax: oneWeek };
  }
  if (variantValue === "weekly") {
    return { visibleStepMin: oneWeek, visibleStepMax: oneMonth };
  }
  return { visibleStepMin: oneMonth, visibleStepMax: 1000000000 };
}

function isAlphaVantageRateLimitPayload(payload) {
  const infoText = String(payload?.Information || payload?.Note || "").toLowerCase();
  return infoText.includes("rate limit")
    || infoText.includes("please visit")
    || infoText.includes("call frequency")
    || infoText.includes("higher api call frequency");
}

function getAlphaVantageLocalSeriesFallback(symbol = "", variantValue = "") {
  const normalizedSymbol = String(symbol || "").trim().toUpperCase();
  const normalizedVariant = String(variantValue || "").trim().toLowerCase();
  const series = ALPHA_VANTAGE_LOCAL_SERIES_FALLBACKS[normalizedSymbol]?.[normalizedVariant];
  if (!series || typeof series !== "object") return null;
  const variant = getAlphaVantageVariantConfig(normalizedVariant);
  return {
    payload: {
      "Meta Data": {
        "2. Symbol": normalizedSymbol,
        "3. Last Refreshed": Object.keys(series).sort().slice(-1)[0] || "",
        "6. Time Zone": "US/Eastern",
      },
      [variant.seriesKey]: series,
    },
    url: `local-fallback:${normalizedSymbol}:${normalizedVariant}`,
  };
}

function escapeCsvCell(value) {
  const text = String(value ?? "");
  if (/[",\n\r]/.test(text)) {
    return `"${text.replace(/"/g, "\"\"")}"`;
  }
  return text;
}

function buildCsvTextFromChartTable(chartItem, table) {
  const lines = [];
  const title = String(chartItem?.title || table?.title || "Chart").trim();
  const unit = String(chartItem?.sourceUnit || table?.sourceUnit || "").trim();
  const unitShort = String(chartItem?.sourceUnitShort || table?.sourceUnitShort || "").trim();
  const sourceTitle = String(chartItem?.sourceTitle || "").trim();
  const description = String(chartItem?.description || "").trim();
  if (title) lines.push(`title,${escapeCsvCell(title)}`);
  if (unit) lines.push(`unit,${escapeCsvCell(unit)}`);
  if (unitShort) lines.push(`unitShort,${escapeCsvCell(unitShort)}`);
  if (sourceTitle) lines.push(`sourceTitle,${escapeCsvCell(sourceTitle)}`);
  if (description) lines.push(`description,${escapeCsvCell(description)}`);
  const points = Array.isArray(table?.points) ? table.points : [];
  const includeSourceUrl = points.some((point) => String(point?.meta?.sourceUrl || "").trim());
  const includeUncertainty = points.some((point) => normalizeChartPointUncertainty(point?.meta?.uncertainty));
  const headerColumns = ["x", "y", "source"];
  if (includeSourceUrl) headerColumns.push("sourceUrl");
  if (includeUncertainty) headerColumns.push("uncertainty");
  lines.push(headerColumns.join(","));
  points.forEach((point) => {
    const xValue = formatTemporalEditorValue(Number(point.x), point.precision ?? 9, false);
    const yValue = Number.isFinite(point.y) ? String(point.y) : "";
    const sourceValue = String(point.sourceTitle || "").trim();
    const row = [
      escapeCsvCell(xValue),
      escapeCsvCell(yValue),
      escapeCsvCell(sourceValue),
    ];
    if (includeSourceUrl) row.push(escapeCsvCell(String(point?.meta?.sourceUrl || "").trim()));
    if (includeUncertainty) row.push(escapeCsvCell(normalizeChartPointUncertainty(point?.meta?.uncertainty)));
    lines.push(row.join(","));
  });
  return lines.join("\n");
}

function buildDefaultChartCsvTemplate(title = "Neuer Chart") {
  return [
    `title,${escapeCsvCell(String(title || "Neuer Chart").trim() || "Neuer Chart")}`,
    "unit,Einheit",
    "unitShort,U",
    "sourceTitle,Quelle oder Ersteller",
    "description,Kurze Beschreibung des Charts",
    "x,y,source",
    "1900,0,Quelle A",
    "1910,0,Quelle B",
  ].join("\n");
}

function getChartCsvEditorValue(chartItem, table) {
  const draft = String(chartItem?.csvPasteDraft || "");
  if (draft) return draft;
  const hasPoints = Array.isArray(table?.points) && table.points.length > 0;
  if (chartItem?.setupMode === "csv-empty" && !hasPoints) return "";
  if (chartItem?.setupMode === "csv-template" && !hasPoints) {
    return buildDefaultChartCsvTemplate(chartItem?.title || "Neuer Chart");
  }
  return buildCsvTextFromChartTable(chartItem, table);
}

function sanitizeFilenamePart(value, fallback = "chart") {
  const cleaned = String(value || "")
    .replace(/[<>:"/\\|?*\u0000-\u001F]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  return cleaned || fallback;
}

function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function renderHighlightedCsvHtml(csvText) {
  const text = String(csvText ?? "");
  const lines = text.replace(/\r\n/g, "\n").split("\n");
  let headerSeen = false;
  const joinColoredCells = (cells, tokenClasses) => cells
    .map((cell, index) => {
      const tokenClass = tokenClasses[Math.min(index, tokenClasses.length - 1)] || "csv-token-source";
      const prefix = index ? '<span class="csv-token-comma">,</span>' : "";
      return `${prefix}<span class="${tokenClass}">${escapeHtml(cell)}</span>`;
    })
    .join("");
  const htmlLines = lines.map((line) => {
    if (!line.length) return '<span class="csv-code-line"><br></span>';
    const cells = parseDelimitedLine(line, ",");
    const normalizedCells = cells.map((cell) => normalizeDelimitedHeaderName(cell));
    const isHeader = normalizedCells.length >= 2
      && normalizedCells[0] === "x"
      && normalizedCells[1] === "y";
    if (!headerSeen && normalizedCells[0] && !isHeader && cells.length >= 2) {
      return `<span class="csv-code-line">${joinColoredCells(cells, ["csv-token-meta-key", "csv-token-source"])}</span>`;
    }
    if (isHeader) {
      headerSeen = true;
      return `<span class="csv-code-line">${joinColoredCells(cells, ["csv-token-header", "csv-token-header", "csv-token-header"])}</span>`;
    }
    if (!headerSeen) {
      return `<span class="csv-code-line"><span class="csv-token-error">${escapeHtml(line)}</span></span>`;
    }
    if (cells.length < 2) {
      return `<span class="csv-code-line"><span class="csv-token-error">${escapeHtml(line)}</span></span>`;
    }
    return `<span class="csv-code-line">${joinColoredCells(cells, ["csv-token-x", "csv-token-y", "csv-token-source"])}</span>`;
  });
  return htmlLines.join("");
}

function buildDefaultSourceCollectionCsvTemplate(title = "") {
  const collectionTitle = String(title || "").trim() || t("source_collection_default_title");
  return [
    `collectionTitle,${escapeCsvCell(collectionTitle)}`,
    "title,creator,yearFrom,yearTo,publishedYear,sourceType,note",
    "Quellenbeispiel,Urheber,100,200,1959,film,Kurze Notiz",
    "Bildbeispiel,Maler,1888,,1888,image,Kurze Notiz",
    "Textbeispiel,Autor,-44,-27,-27,text,Kurze Notiz",
  ].join("\n");
}

function getSourceCollectionCsvEditorValue(collection) {
  const draft = String(collection?.csvPasteDraft || "");
  return draft || buildDefaultSourceCollectionCsvTemplate(collection?.title || "");
}

function renderHighlightedSourceCollectionCsvHtml(csvText) {
  const text = String(csvText ?? "");
  const lines = text.replace(/\r\n/g, "\n").split("\n");
  let headerSeen = false;
  const joinColoredCells = (cells, tokenClasses) => cells
    .map((cell, index) => {
      const tokenClass = tokenClasses[Math.min(index, tokenClasses.length - 1)] || "csv-token-source";
      const prefix = index ? '<span class="csv-token-comma">,</span>' : "";
      return `${prefix}<span class="${tokenClass}">${escapeHtml(cell)}</span>`;
    })
    .join("");
  return lines.map((line) => {
    if (!line.length) return '<span class="csv-code-line"><br></span>';
    const cells = parseDelimitedLine(line, ",");
    const normalizedCells = cells.map((cell) => normalizeDelimitedHeaderName(cell));
    if (!headerSeen && normalizedCells[0] === "collectiontitle" && cells.length >= 2) {
      return `<span class="csv-code-line">${joinColoredCells(cells, ["csv-token-meta-key", "csv-token-source"])}</span>`;
    }
    const isHeader = normalizedCells.includes("title")
      && normalizedCells.includes("sourcetype")
      && (normalizedCells.includes("yearfrom") || normalizedCells.includes("year"));
    if (isHeader) {
      headerSeen = true;
      return `<span class="csv-code-line">${joinColoredCells(cells, [
        "csv-token-header",
        "csv-token-header",
        "csv-token-header",
        "csv-token-header",
        "csv-token-header",
        "csv-token-header",
        "csv-token-header",
      ])}</span>`;
    }
    if (!headerSeen) {
      return `<span class="csv-code-line"><span class="csv-token-error">${escapeHtml(line)}</span></span>`;
    }
    if (cells.length < 3) {
      return `<span class="csv-code-line"><span class="csv-token-error">${escapeHtml(line)}</span></span>`;
    }
    return `<span class="csv-code-line">${joinColoredCells(cells, [
      "csv-token-source",
      "csv-token-meta-key",
      "csv-token-x",
      "csv-token-y",
      "csv-token-y",
      "csv-token-header",
      "csv-token-source",
    ])}</span>`;
  }).join("");
}

function renderHighlightedPlainTextHtml(textValue) {
  const text = String(textValue ?? "");
  const lines = text.replace(/\r\n/g, "\n").split("\n");
  return lines.map((line) => {
    if (!line.length) return '<span class="csv-code-line"><br></span>';
    return `<span class="csv-code-line"><span class="prompt-code-text">${escapeHtml(line)}</span></span>`;
  }).join("");
}

function createPromptCodeEditor(options = {}) {
  const {
    value = "",
    placeholder = "",
    onInput = null,
    readOnly = false,
  } = options;

  const wrapper = document.createElement("div");
  wrapper.className = "prompt-code-editor";

  if (readOnly) {
    const pre = document.createElement("pre");
    pre.className = "prompt-code-display";
    pre.textContent = String(value ?? "");
    wrapper.appendChild(pre);
    return { wrapper, textarea: null };
  }

  const textarea = document.createElement("textarea");
  textarea.className = "prompt-code-input";
  textarea.rows = 5;
  textarea.placeholder = placeholder;
  textarea.value = String(value ?? "");
  textarea.spellcheck = false;
  textarea.wrap = "soft";
  textarea.addEventListener("input", () => {
    if (typeof onInput === "function") onInput(textarea.value);
  });
  wrapper.appendChild(textarea);
  return { wrapper, textarea };
}

function createCsvCodeEditor(options = {}) {
  const {
    value = "",
    placeholder = "",
    onInput = null,
    onCommit = null,
    readOnly = false,
    displayOnly = false,
    softWrap = false,
    renderHighlightHtml = renderHighlightedCsvHtml,
  } = options;
  const wrapper = document.createElement("div");
  wrapper.className = "csv-code-editor";
  if (softWrap) wrapper.classList.add("is-soft-wrap");
  if (displayOnly) wrapper.classList.add("is-display-only");

  const highlight = document.createElement("pre");
  highlight.className = "csv-code-highlight";
  highlight.setAttribute("aria-hidden", "true");
  if (softWrap) highlight.classList.add("is-soft-wrap");

  const syncHighlight = (scrollSource = null) => {
    const currentText = scrollSource?.value ?? value ?? placeholder ?? "";
    highlight.innerHTML = renderHighlightHtml(currentText);
    if (scrollSource) {
      highlight.scrollTop = scrollSource.scrollTop;
      highlight.scrollLeft = scrollSource.scrollLeft;
    }
  };

  if (displayOnly) {
    wrapper.appendChild(highlight);
    syncHighlight();
    return { wrapper, textarea: null, refresh: () => syncHighlight() };
  }

  const textarea = document.createElement("textarea");
  textarea.className = "chart-csv-paste-area chart-csv-sync-area csv-code-input";
  textarea.spellcheck = false;
  textarea.wrap = softWrap ? "soft" : "off";
  textarea.placeholder = placeholder;
  textarea.value = value;
  textarea.readOnly = readOnly;
  if (readOnly) textarea.setAttribute("aria-readonly", "true");
  if (softWrap) textarea.classList.add("is-soft-wrap");

  textarea.addEventListener("input", () => {
    syncHighlight(textarea);
    if (typeof onInput === "function") onInput(textarea.value);
  });
  textarea.addEventListener("change", () => {
    if (typeof onCommit === "function") onCommit(textarea.value, textarea, syncHighlight);
  });
  textarea.addEventListener("scroll", () => {
    highlight.scrollTop = textarea.scrollTop;
    highlight.scrollLeft = textarea.scrollLeft;
  });

  wrapper.append(highlight, textarea);
  syncHighlight(textarea);
  return { wrapper, textarea, refresh: syncHighlight };
}

function buildChartGenerationPrompt(requestText) {
  const normalizedRequest = String(requestText || "").trim();
  const options = state.chartGenerateOptions || {};
  const extraRules = [];
  if (options.strictOnly) {
    extraRules.push("- Verwende ausschließlich direkt belegte Werte. Wenn für bestimmte Zeitpunkte keine konkrete Datengrundlage vorliegt, lasse diese Datenpunkte aus, auch wenn der Zeitraum dadurch lückenhaft wird.");
  }
  if (options.allowPartialRecon) {
    extraRules.push("- Teilrekonstruktionen sind erlaubt, wenn sie klar gekennzeichnet werden und sich eng an belastbaren Teilquellen orientieren.");
  }
  if (options.allowFullRecon) {
    extraRules.push("- Vollrekonstruktionen oder vollständig modellierte Abschnitte sind erlaubt, müssen aber eindeutig als rekonstruiert oder modelliert markiert werden.");
  }
  if (options.sourceLinks) {
    extraRules.push("- Ergänze zusätzlich zur knappen Quellenangabe pro Datenpunkt eine Weblink-Spalte sourceUrl mit einem direkten Link zur Quelle oder Datenseite.");
  }
  if (options.explicitUncertainty) {
    extraRules.push("- Ergänze eine zusätzliche Spalte uncertainty. Zulässige Werte sind none, partial-reconstruction, full-reconstruction, interpolated, estimated oder modeled.");
  }
  const extraRulesBlock = extraRules.length
    ? `\nZusätzliche Vorgaben für diesen Auftrag:\n${extraRules.join("\n")}\n`
    : "";
  return `Ich möchte eine TimeMap-kompatible CSV für folgenden Chart erstellen lassen:

${normalizedRequest}

Gehe dabei wie folgt vor:

Erstelle eine vollständige, validierte CSV für einen TimeMap-kompatiblen Chart. Gib keine Datei aus, keinen Download-Link und keine Vorschau, sondern ausschließlich den vollständigen CSV-Inhalt in einem Markdown-Codeblock mit der Sprachkennung csv. Ergänze danach eine kurze Zusammenfassung.

Die CSV muss exakt nach diesem Schema aufgebaut sein:

title,<Titel des Charts>
unit,<Einheit der y-Werte>
unitShort,<Kurzform der Einheit für Achse und Messbox>
sourceTitle,<Ersteller des Charts im Format KI-Modell, YYYY-MM-DD>
description,<kurze Beschreibung des Charts oder der Datenlage>
x,y,source
<Zeitwert>,<numerischer Wert>,<knappe Quellenangabe>

Die Zeile description ist optional, soll aber verwendet werden, wenn sie für das Verständnis hilfreich ist. Wenn description verwendet wird, muss sie vor der Header-Zeile x,y,source stehen. Die eigentliche Tabelle muss exakt mit x,y,source beginnen.

Regeln für die Metadaten:
- title benennt den Chart knapp und fachlich passend.
- unit enthält die ausgeschriebene oder längere fachliche Einheit.
- unitShort enthält die kurze Darstellungsform der Einheit, die sich für Y-Achse und Messbox eignet, zum Beispiel %, ppm, °C, Mio. t, USD, Mrd. USD, km² oder Personen/km².
- Wenn keine etablierte Kurzform existiert, bilde eine möglichst knappe, verständliche Kurzform.
- sourceTitle benennt nicht die Datengrundlage, sondern den Ersteller dieses Charts im Format „<Name des verwendeten KI-Modells>, <Datum der Erstellung im Format YYYY-MM-DD>“.
- Die eigentliche Datengrundlage, Datensätze und Quellen gehören in source, description und den Begleittext, nicht in sourceTitle.

Regeln für die x-Spalte:
- x enthält immer einen timelinefähigen Zeitwert.
- Erlaubt sind reine Jahre wie 1789, 2026 oder -44.
- Erlaubt sind Jahres-Monats-Angaben wie 1789-07.
- Erlaubt sind vollständige Datumsangaben wie 1789-07-14.
- Zeiten vor Jahr 1 müssen negativ notiert werden, zum Beispiel -44 oder -44-03-15.
- Geologische, prähistorische und historische Angaben wie 2,5 Ga vor heute, 150 Ma vor heute, 10 ka vor heute oder 4000 v. Chr. dürfen niemals direkt in x stehen, sondern müssen in numerische Jahreswerte umgerechnet werden, zum Beispiel -2500000000, -150000000, -10000 oder -4000.
- Schreibe niemals Ga, Ma, ka, BCE, v. Chr., AD, CE oder „Jahre vor heute“ in x.
- Sortiere alle Werte chronologisch aufsteigend vom ältesten negativen Wert bis zum jüngsten positiven Wert.
- Wenn ein Ereignis oder Zeitraum nur ungefähr datiert ist, nutze einen sinnvollen numerischen Näherungswert und mache die Unsicherheit in source oder im Begleittext transparent.
- Wenn ein Zeitraum statt eines Einzelpunkts gemeint ist, wähle einen sinnvollen repräsentativen Punkt wie Beginn, Mitte oder Ende und erkläre dies kurz.

Regeln für die y-Spalte:
- y enthält ausschließlich numerische Werte.
- Schreibe keine Prozentzeichen, Einheiten, Kommentare oder Text in y.
- Die Einheit steht ausschließlich in unit.
- Wenn Quellen verschiedene Einheiten verwenden, rechne in eine einheitliche y-Einheit um.
- Wenn keine Einheit vorgegeben ist, wähle die fachlich sinnvollste Einheit.
- Bei ordinalen, indexierten oder qualitativen Daten nutze eine nachvollziehbare numerische Skala und erkläre sie kurz.

Regeln für source:
- Jede Datenzeile enthält eine knappe Quellenangabe.
- Beispiele: „Autor et al. 2022“, „Offizielle Statistik 2024“, „Datenrepository“, „Historische Quelle“, „Eigene Berechnung nach Quelle A“.
- Markiere rekonstruierte, modellierte, geschätzte, interpolierte oder geglättete Werte klar, zum Beispiel „Autor et al. 2022; interpoliert“ oder „Eigene Schätzung nach Quelle A“.
- Verwende keine langen URLs in source.
- Nenne im Begleittext die wichtigsten Quellen mit Titeln oder Links, sofern verfügbar.

Datenqualität:
- Recherchiere bei faktenabhängigen wissenschaftlichen, historischen, wirtschaftlichen, technischen, politischen oder gesellschaftlichen Themen mehrere belastbare Quellen.
- Bevorzuge Primärquellen, offizielle Statistiken, Datensätze, wissenschaftliche Publikationen, Repositorien, Fachinstitutionen und seriöse Übersichtsarbeiten.
- Bei aktuellen oder veränderlichen Themen prüfe aktuelle Quellen.
- Wenn keine exakten Messwerte verfügbar sind, erstelle klar gekennzeichnete rekonstruierte, geschätzte oder interpolierte Chart-Stützpunkte.
- Tue niemals so, als seien modellierte Werte direkte Messwerte.
- Tue bei historischen Daten niemals so, als seien ungefähre Datierungen exakt.

Quellenkritik und Transparenz:
- Prüfe, ob Quellen normativ, politisch, werblich, aktivistisch, journalistisch, institutionell oder wissenschaftlich geprägt sind, und berücksichtige dies kritisch bei Auswahl und Formulierung.
- Wenn Quellen sich in Methode, Definition, Messzeitraum, Stichprobe oder politischem Kontext unterscheiden, mache diese Unterschiede im description-Feld oder im Begleittext ausdrücklich sichtbar.
- Verwende keine scheinbar neutralen Formulierungen, wenn die Datengrundlage umstritten, lückenhaft oder interessengeleitet ist.
- Wenn mehrere plausible Datensätze existieren, bevorzuge den methodisch transparentesten und im Fachkontext belastbarsten Datensatz und nenne konkurrierende Ansätze im Begleittext kurz.
- Wenn Werte aus Sekundärquellen übernommen werden, prüfe nach Möglichkeit deren Primärquelle und bevorzuge diese.
- Wenn nur schwache, indirekte oder abgeleitete Quellen verfügbar sind, benenne das ausdrücklich.
- Wenn ein Wert nur über Umrechnung, Rekonstruktion, Glättung oder Aggregation entsteht, erläutere den Charakter dieser Ableitung klar und knapp.
- Nutze description nicht nur beschreibend, sondern auch für kurze quellenkritische Einordnung, wenn das für das Verständnis des Charts wichtig ist.

Datendichte:
- Wähle ausreichend Datenpunkte für eine gut lesbare interaktive Darstellung.
- Zwei Werte sind nur zulässig, wenn ausdrücklich genau zwei Datenpunkte verlangt werden oder das Thema sachlich nur zwei Punkte hergibt.
- Bei sehr langen Zeiträumen dürfen frühe Abschnitte gröber gestützt sein, während jüngere oder besonders relevante Abschnitte dichter abgedeckt werden.
- Vermeide fachlich unplausible Sprünge.
- Runde sinnvoll und vermeide künstliche Präzision.
${extraRulesBlock}

CSV-Format:
- Nutze Komma als Trennzeichen.
- Setze Felder mit Kommata korrekt in doppelte Anführungszeichen.
- Metadaten, Header und Datenzeilen stehen alle im selben CSV-Dokument.
- Die Metadatenzeilen sollen in der Reihenfolge title, unit, unitShort, sourceTitle und dann optional description ausgegeben werden.
- Gib den vollständigen CSV-Inhalt in einem Markdown-Codeblock mit Sprachkennung csv aus.

Validiere vor der Ausgabe:
- Es gibt mindestens die Metadatenzeilen title, unit, unitShort und sourceTitle.
- description steht, falls vorhanden, vor der Header-Zeile.
- Danach folgt exakt x,y,source.
- Alle x-Werte sind timelinefähig.
- Alle y-Werte sind numerisch.
- Zeiten vor Jahr 1 sind negativ notiert.
- Geologische, prähistorische oder historische Vor-Jahr-1-Zeiten sind nicht versehentlich positiv.
- Die Datei ist chronologisch aufsteigend sortiert.
- y enthält keine Einheitssymbole wie %, kg, °C, ppm oder USD.
- x enthält keine Einheiten oder Textzusätze wie Ga, Ma, ka, BCE, v. Chr., AD oder CE.
- Titel, Einheit, unitShort und sourceTitle sind passend.
- sourceTitle enthält tatsächlich Ersteller und Datum statt Datengrundlage.
- Die Datendichte ist ausreichend.
- Zusätzliche optionale Spalten wie sourceUrl oder uncertainty sind, falls verwendet, konsistent befüllt.

Nach dem CSV-Codeblock nenne kurz:
- empfohlenen Dateinamen mit Endung .csv
- Zeitraum
- Einheit
- Kurzform der Einheit
- Anzahl der Datenpunkte
- wichtigste Quellen
- kurzen Hinweis zu Unsicherheiten, falls Daten rekonstruiert, geschätzt oder interpoliert sind
- kurzen quellenkritischen Hinweis, falls Datengrundlage methodisch, politisch oder historisch problematisch ist`;
}

function buildSourceCollectionGenerationPrompt(requestText) {
  const normalizedRequest = String(requestText || "").trim();
  const options = state.sourceGenerateOptions || {};
  const extraRules = [];
  if (options.wikidataOnly) {
    extraRules.push("- Verwende nur konkrete Quellen, die voraussichtlich in Wikidata beschrieben sind. Gib dennoch keine Wikidata-IDs aus; TimeMap löst IDs später selbst auf.");
  } else {
    extraRules.push("- Gib keine Wikidata-IDs oder TMDb-IDs aus. TimeMap löst IDs später selbst über die App auf.");
  }
  extraRules.push("- Verwende nur einzeln nachweisbare Quellen, keine Sammelbegriffe.");
  if (options.primaryOnly) {
    extraRules.push("- Bevorzuge ausschließlich Primärquellen oder Originalwerke. Sekundärliteratur und spätere Überblickswerke sollen ausgeschlossen werden.");
  }
  if (options.datableOnly) {
    extraRules.push("- Nimm nur Quellen auf, für die ein plausibles Jahr oder ein plausibler Zeitraum bestimmbar ist.");
  }
  extraRules.push(options.mixedTypes
    ? "- Unterschiedliche Quellarten dürfen gemischt werden, wenn sie fachlich sinnvoll sind."
    : "- Halte die Quellarten möglichst homogen.");
  if (options.markUncertainty) {
    extraRules.push("- Markiere unsichere Zuordnungen, Datierungen oder Quellarten in der Spalte note knapp und transparent.");
  }
  const focus = String(state.sourceGenerateFocus || "").trim();
  if (focus) {
    extraRules.push(`- Berücksichtige bevorzugt Quellen aus folgendem regionalen, sprachlichen oder kulturellen Kontext: ${focus}.`);
  }
  return `Ich möchte eine TimeMap-kompatible CSV für eine Sammlung von Quellen erstellen lassen:

${normalizedRequest}

Erstelle eine validierte CSV mit konkreten Einzelquellen. Gib keine Datei aus, keinen Download-Link und keine Vorschau, sondern ausschließlich den vollständigen CSV-Inhalt in einem Markdown-Codeblock mit der Sprachkennung csv. Ergänze danach eine kurze Zusammenfassung.

Die CSV muss exakt nach diesem Schema aufgebaut sein:

collectionTitle,<Titel der Sammlung>
title,creator,yearFrom,yearTo,publishedYear,sourceType,note
<Titel>,<Urheber>,<Beginn der erzählten oder abgedeckten Zeit>,<Ende der erzählten oder abgedeckten Zeit>,<Jahr herausgegeben>,<film|image|text>,<knappe Notiz>

Regeln:
- collectionTitle benennt die Sammlung knapp und fachlich passend. Wenn in der Anfrage bereits ein eindeutiger Sammlungstitel genannt wird, übernimm ihn. Wenn kein Titel genannt wird, bilde automatisch einen präzisen Titel aus Thema, Zeitraum oder Quellenauswahl.
- title enthält den konkreten Titel oder eine präzise Bezeichnung der Einzelquelle.
- creator enthält den Urheber im weiten Sinn: Autor, Regisseur, Herausgeber, Maler, Fotograf, Institution oder verantwortliche Person.
- yearFrom ist der timelinefähige Beginn der erzählten, behandelten oder abgedeckten Zeit der Quelle.
- yearTo ist das timelinefähige Ende der erzählten, behandelten oder abgedeckten Zeit der Quelle. Wenn die Quelle nur als Zeitpunkt dargestellt werden soll oder kein sinnvoller Endwert bekannt ist, bleibt yearTo leer.
- publishedYear ist das Erscheinungs-, Veröffentlichungs- oder Herstellungsjahr, sofern abweichend oder fachlich relevant.
- sourceType ist einer der Werte film, image oder text.
- note enthält Unsicherheit, Auswahlbegründung oder knappe Hinweise. Wenn keine Notiz nötig ist, lasse die Zelle leer.
- Gib keine Spalten für Wikidata-ID, TMDb-ID, IMDb-ID oder sonstige externe IDs aus.
- Erfinde keine IDs und notiere keine ID-Vermutungen in note. Die App übernimmt die technische Zuordnung.
- Verwende keine Sammelzeilen. Jede Zeile beschreibt genau eine Einzelquelle.
- Sortiere die Quellen chronologisch nach yearFrom.
- Die Spaltenpositionen müssen exakt eingehalten werden: title in Spalte 1, creator in Spalte 2, yearFrom in Spalte 3, yearTo in Spalte 4, publishedYear in Spalte 5, sourceType in Spalte 6, note in Spalte 7.
- Wenn yearFrom und yearTo beide vorhanden sind, wird die Quelle als Strecke dargestellt. Wenn nur yearFrom vorhanden ist, wird sie als Punkt dargestellt.

Zusätzliche Vorgaben für diesen Auftrag:
${extraRules.join("\n")}`;
}

function renderChartsGenerateArea() {
  if (!ui.chartsModeGenerateArea) return;
  ui.chartsModeGenerateArea.replaceChildren();

  const panel = document.createElement("div");
  panel.className = "chart-create-mode chart-generate-mode";

  const helper = document.createElement("p");
  helper.id = "chartsGenerateStatus";
  helper.className = "event-description";
  helper.textContent = state.chartGeneratePrompt ? t("chart_generate_default") : t("chart_generate_helper");
  panel.appendChild(helper);

  if (!state.chartGeneratePrompt) {
    const optionsField = document.createElement("fieldset");
    optionsField.className = "chart-generate-options";
    const optionsLegend = document.createElement("legend");
    optionsLegend.textContent = t("chart_generate_options_label");
    optionsField.appendChild(optionsLegend);

    const optionDefinitions = [
      ["strictOnly", "chart_generate_option_strict_only"],
      ["allowPartialRecon", "chart_generate_option_partial_recon"],
      ["allowFullRecon", "chart_generate_option_full_recon"],
      ["sourceLinks", "chart_generate_option_source_links"],
      ["explicitUncertainty", "chart_generate_option_uncertainty"],
    ];
    optionDefinitions.forEach(([key, labelKey]) => {
      const label = document.createElement("label");
      label.className = "chart-generate-option";
      const checkbox = document.createElement("input");
      checkbox.type = "checkbox";
      checkbox.checked = Boolean(state.chartGenerateOptions?.[key]);
      checkbox.addEventListener("change", () => {
        state.chartGenerateOptions[key] = checkbox.checked;
        if (key === "strictOnly" && checkbox.checked) {
          state.chartGenerateOptions.allowPartialRecon = false;
          state.chartGenerateOptions.allowFullRecon = false;
          renderChartsGenerateArea();
          return;
        }
        if ((key === "allowPartialRecon" || key === "allowFullRecon") && checkbox.checked) {
          state.chartGenerateOptions.strictOnly = false;
          renderChartsGenerateArea();
        }
      });
      const text = document.createElement("span");
      text.textContent = t(labelKey);
      label.append(checkbox, text);
      optionsField.appendChild(label);
    });
    panel.appendChild(optionsField);
  }

  const field = document.createElement("label");
  field.className = "field chart-create-mode-code-field";
  const heading = document.createElement("span");
  heading.textContent = state.chartGeneratePrompt
    ? t("chart_generate_prompt_label")
    : t("chart_generate_input_label");
  field.appendChild(heading);

  const editorApi = createPromptCodeEditor({
    value: state.chartGeneratePrompt || state.chartGenerateRequest || "",
    placeholder: state.chartGeneratePrompt ? "" : t("chart_generate_input_placeholder"),
    onInput: state.chartGeneratePrompt ? null : (value) => {
      state.chartGenerateRequest = value;
    },
    readOnly: Boolean(state.chartGeneratePrompt),
  });
  field.appendChild(editorApi.wrapper);
  panel.appendChild(field);

  const actions = document.createElement("div");
  actions.className = "chart-create-mode-actions chart-generate-actions";

  if (state.chartGeneratePrompt) {
    const backButton = document.createElement("button");
    backButton.type = "button";
    backButton.className = "secondary-button";
    backButton.textContent = t("chart_generate_back");
    backButton.addEventListener("click", () => {
      state.chartGeneratePrompt = "";
      state.chartGeneratePromptCopied = false;
      renderChartsGenerateArea();
    });

    const copyButton = document.createElement("button");
    copyButton.type = "button";
    copyButton.className = "secondary-button";
    copyButton.textContent = t("chart_generate_copy");
    copyButton.addEventListener("click", async () => {
      try {
        await navigator.clipboard.writeText(state.chartGeneratePrompt || "");
        state.chartGeneratePromptCopied = true;
        helper.textContent = t("chart_generate_copy_done");
        csvButton.disabled = false;
      } catch {
        helper.textContent = t("chart_generate_copy");
      }
    });

    const csvButton = document.createElement("button");
    csvButton.type = "button";
    csvButton.className = "secondary-button button-chart-generate-next";
    csvButton.textContent = t("chart_generate_open_csv");
    csvButton.disabled = !state.chartGeneratePromptCopied;
    csvButton.addEventListener("click", () => {
      if (!state.chartGeneratePromptCopied) return;
      createNewChartToCsvCodeTab();
      state.activeDataMode = "charts";
      state.chartsModeAction = null;
      updateDataModeUi();
    });

    actions.append(backButton, copyButton, csvButton);
  } else {
    const generateButton = document.createElement("button");
    generateButton.type = "button";
    generateButton.className = "secondary-button";
    generateButton.textContent = t("chart_generate_submit");
    generateButton.addEventListener("click", () => {
      const requestText = String(state.chartGenerateRequest || "").trim();
      if (!requestText) {
        helper.textContent = t("chart_generate_empty");
        editorApi.textarea.focus();
        return;
      }
      state.chartGeneratePrompt = buildChartGenerationPrompt(requestText);
      state.chartGeneratePromptCopied = false;
      renderChartsGenerateArea();
    });
    actions.appendChild(generateButton);
  }

  panel.appendChild(actions);
  ui.chartsModeGenerateArea.appendChild(panel);

  if (!state.chartGeneratePrompt) {
    window.requestAnimationFrame(() => editorApi.textarea.focus());
  }
}

