      wikidataThumbCropCenterX: eventItem.imageDisplayEnabled === true ? (eventItem.wikidataThumbCropCenterX ?? 0.5) : 0.5,
      wikidataThumbCropCenterY: eventItem.imageDisplayEnabled === true ? (eventItem.wikidataThumbCropCenterY ?? 0.5) : 0.5,
