function mergeImportedBookmarks(bookmarks, importedRootGroupId = null, groupIdMap = new Map()) {
  const validBookmarks = sanitizeTickBookmarksCollection(bookmarks);
  if (!validBookmarks.length) return;
  const existingKeys = new Set(
    state.tickBookmarks.map((bookmark) => `${bookmark.stepIndex}|${bookmark.tickValue}`),
  );
  validBookmarks.forEach((bookmark) => {
    if (state.tickBookmarks.length >= MAX_TICK_BOOKMARKS) return;
    if (!Number.isFinite(bookmark?.tickValue) || !Number.isFinite(bookmark?.centerYear)) return;
    const stepIndex = clamp(Number(bookmark.stepIndex) || 0, 0, scaleSteps.length - 1);
    const key = `${stepIndex}|${bookmark.tickValue}`;
    if (existingKeys.has(key)) {
      const existingBookmark = state.tickBookmarks.find((entry) => (
        entry.stepIndex === stepIndex
        && Math.abs(entry.tickValue - bookmark.tickValue) < (getStepYears() / 100)
      ));
      if (existingBookmark && bookmark.title) {
        existingBookmark.title = String(bookmark.title).trim() || existingBookmark.title;
      }
      if (existingBookmark && bookmark.groupId && !existingBookmark.groupId) {
        existingBookmark.groupId = groupIdMap.get(bookmark.groupId) ?? null;
      }
      if (existingBookmark && importedRootGroupId && !existingBookmark.ownerGroupId) {
        existingBookmark.ownerGroupId = importedRootGroupId;
      }
      if (existingBookmark) {
        existingBookmark.enabled = bookmark.enabled !== false;
      }
      return;
    }
    state.tickBookmarks.push({
      id: createUniqueId("bookmark-import"),
      tickValue: bookmark.tickValue,
      centerYear: bookmark.centerYear,
      stepIndex,
      title: String(bookmark.title || "").trim() || getTickBookmarkLabel({ ...bookmark, stepIndex }),
      ownerGroupId: importedRootGroupId ?? bookmark.ownerGroupId ?? null,
      groupId: bookmark.groupId ? (groupIdMap.get(bookmark.groupId) ?? null) : null,
      enabled: bookmark.enabled !== false,
    });
    existingKeys.add(key);
  });
}

async function downloadFolderExport(groupId) {
  const groupItem = getGroupById(groupId);
  if (!groupItem) return;
  const specialTreeKind = getSpecialTreeKindForGroup(groupId);
  const exportRange = getFolderExportTimelineRange(groupId);
  const matchingBookmarks = specialTreeKind === "bookmarks"
    ? getBookmarksForGroupTree(groupId)
    : getBookmarksForTimelineRange(exportRange);
  let includeBookmarks = specialTreeKind === "bookmarks";
  if (specialTreeKind !== "bookmarks" && matchingBookmarks.length > 0) {
    includeBookmarks = await showConfirmModal({
      title: t("export_bookmarks_title"),
      message: t("export_bookmarks_message"),
      confirmLabel: t("export_with_bookmarks"),
      cancelLabel: t("export_without_bookmarks"),
    });
  }
  const payload = buildFolderExportPayload(groupId, { includeBookmarks });
  if (!payload) return;

  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: "application/json" });
  const blobUrl = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = blobUrl;
  link.download = getGroupExportFilename(groupItem);
  document.body.appendChild(link);
  link.click();
  link.remove();
  window.setTimeout(() => URL.revokeObjectURL(blobUrl), 0);
  ui.eventBrowserInfo.textContent = tf("folder_exported", { title: groupItem.title });
}

async function downloadChartExport(chartId) {
  const chartItem = getChartById(chartId);
  if (!chartItem) return;
  const exportTable = getChartPrimaryTable(chartItem);
  if (!exportTable) return;
  const csvText = buildCsvTextFromChartTable(chartItem, exportTable);
  const blob = new Blob([csvText], { type: "text/csv;charset=utf-8" });
  const blobUrl = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = blobUrl;
  link.download = `${sanitizeFilenamePart(chartItem.title || "chart")}.csv`;
  document.body.appendChild(link);
  link.click();
  link.remove();
  window.setTimeout(() => URL.revokeObjectURL(blobUrl), 0);
  ui.eventBrowserInfo.textContent = tf("chart_exported", { title: chartItem.title });
}

async function handleRenderLibrary() {
  if (getRenderableBrowserContentCount() === 0) return;
  const currentStep = getStep();
  const currentRange = getVisibleRange();
  const precision = getTemporalPrecisionForStep(currentStep);
  const renderSettings = await showPresentationRenderModal({
    defaultStartValue: formatTimelineValue(currentRange.start, precision),
    defaultEndValue: formatTimelineValue(currentRange.end, precision),
    defaultMinStepId: scaleSteps[0]?.id || "1d",
    defaultMaxStepId: currentStep?.id || scaleSteps[scaleSteps.length - 1]?.id || "1Ga",
  });
  if (!renderSettings) return;
  const snapshot = createPresentationSnapshotForExport(
    renderSettings.rangeStart,
    renderSettings.rangeEnd,
    renderSettings.minZoomStepId,
    renderSettings.maxZoomStepId,
  );
  const html = await buildPresentationDocumentHtml({
    snapshot,
    rangeStart: renderSettings.rangeStart,
    rangeEnd: renderSettings.rangeEnd,
    minZoomStepId: renderSettings.minZoomStepId,
    maxZoomStepId: renderSettings.maxZoomStepId,
  });
  await downloadAndOpenPresentationHtml(html, renderSettings.saveTarget);
}

async function handleRenderProject(rootGroupId) {
  const rootGroup = getGroupById(rootGroupId);
  if (!isProjectRootGroup(rootGroup)) return;
  const projectRange = getFolderExportTimelineRange(rootGroupId);
  const defaultStartValue = Number.isFinite(rootGroup.timelineStartYear)
    ? rootGroup.timelineStartYear
    : (projectRange?.min ?? getVisibleRange().start);
  const defaultEndValue = Number.isFinite(rootGroup.timelineEndYear)
    ? rootGroup.timelineEndYear
    : (projectRange?.max ?? getVisibleRange().end);
  const defaultMinStepId = getPresentationStepIdForYears(Number(rootGroup.visibleStepMin));
  const defaultMaxStepId = getPresentationStepIdForYears(Number(rootGroup.visibleStepMax));
  const renderSettings = await showPresentationRenderModal({
    defaultStartValue: formatTimelineValue(defaultStartValue, 9),
    defaultEndValue: formatTimelineValue(defaultEndValue, 9),
    defaultMinStepId: defaultMinStepId || scaleSteps[0]?.id || "1d",
    defaultMaxStepId: defaultMaxStepId || getStep()?.id || scaleSteps[scaleSteps.length - 1]?.id || "1Ga",
  });
  if (!renderSettings) return;
  const snapshot = createPresentationSnapshotForExport(
    renderSettings.rangeStart,
    renderSettings.rangeEnd,
    renderSettings.minZoomStepId,
    renderSettings.maxZoomStepId,
    rootGroupId,
  );
  const html = await buildPresentationDocumentHtml({
    snapshot,
    rangeStart: renderSettings.rangeStart,
    rangeEnd: renderSettings.rangeEnd,
    minZoomStepId: renderSettings.minZoomStepId,
    maxZoomStepId: renderSettings.maxZoomStepId,
  });
  await downloadAndOpenPresentationHtml(html, renderSettings.saveTarget);
}

async function importFolderPayload(payload, onProgress = null) {
  if (!payload || payload.type !== "timemap-folder-export" || !Array.isArray(payload.groups) || !Array.isArray(payload.events)) {
    throw new Error("ungültiges-format");
  }

  const groupIdMap = new Map();
  const eventIdMap = new Map();
  const chartIdMap = new Map();
  const folderTitle = payload.title ?? payload.groups.find((group) => group.parentGroupId == null)?.title ?? "TimeMap";

  if (typeof onProgress === "function") {
    onProgress({
      text: tf("loading_import_folder", { title: folderTitle }),
      progress: 56,
    });
  }

  const orderedGroups = [...payload.groups].sort((left, right) => {
    if (left.parentGroupId == null && right.parentGroupId != null) return -1;
    if (left.parentGroupId != null && right.parentGroupId == null) return 1;
  return String(left.title ?? "").localeCompare(String(right.title ?? ""), "de");
  });

  orderedGroups.forEach((sourceGroup) => {
    const groupItem = {
      ...createEmptyGroup(),
      ...sourceGroup,
      id: createUniqueId("group-import"),
      parentGroupId: sourceGroup.parentGroupId ? (groupIdMap.get(sourceGroup.parentGroupId) ?? null) : null,
      expanded: false,
      enabled: sourceGroup.enabled !== false,
      forceSettings: sourceGroup.forceSettings === true,
      timelinePosition: normalizeTimelinePosition(sourceGroup.timelinePosition),
      additionalCalendar: normalizeAdditionalTimelineCalendar(sourceGroup.additionalCalendar),
      iconName: normalizeGroupIconName(sourceGroup.iconName),
      iconColor: normalizeGroupIconColor(sourceGroup.iconColor),
      categories: normalizeProjectCategories(sourceGroup.categories),
    };
    migrateLocalizedDescriptionState(groupItem);
    groupIdMap.set(sourceGroup.id, groupItem.id);
    eventGroups.push(groupItem);
  });

  payload.events.forEach((sourceEvent) => {
    const eventItem = {
      ...createEmptyEvent(),
      ...sourceEvent,
      id: createUniqueId("import"),
      groupId: sourceEvent.groupId ? (groupIdMap.get(sourceEvent.groupId) ?? null) : null,
      parentEventId: null,
      enabled: sourceEvent.enabled !== false,
      isRange: Boolean(sourceEvent.isRange),
      displayMode: sourceEvent.displayMode === "bar" || sourceEvent.displayMode === "area"
        ? sourceEvent.displayMode
        : "line",
      areaManualPositionLocked: sourceEvent.areaManualPositionLocked === true,
      imageDisplayEnabled: sourceEvent.imageDisplayEnabled === true,
      imageSidePanelEnabled: sourceEvent.imageSidePanelEnabled !== false,
      imageHideTimelineLabel: sourceEvent.imageHideTimelineLabel === true,
      manualImageSourceType: normalizeMediaSourceType(sourceEvent.manualImageSourceType, sourceEvent.manualImageUrl ? "url" : "none"),
      manualImageUrl: sourceEvent.manualImageUrl ?? "",
      manualImageSource: sourceEvent.manualImageSource ?? "",
      manualImageAssetPath: normalizeLocalAssetPath(sourceEvent.manualImageAssetPath),
      wikidataImageFile: sourceEvent.wikidataImageFile ?? null,
      wikidataImageUrl: sourceEvent.wikidataImageUrl ?? null,
      wikidataImageThumbUrl: sourceEvent.wikidataImageThumbUrl ?? null,
      wikidataImagePreviewUrl: sourceEvent.wikidataImagePreviewUrl ?? null,
      wikidataImageWidth: sourceEvent.wikidataImageWidth ?? null,
      wikidataImageHeight: sourceEvent.wikidataImageHeight ?? null,
      wikidataThumbCropCenterX: sourceEvent.wikidataThumbCropCenterX ?? 0.5,
      wikidataThumbCropCenterY: sourceEvent.wikidataThumbCropCenterY ?? 0.5,
      wikidataThumbCropZoom: sourceEvent.wikidataThumbCropZoom ?? 1,
      imageAspectMode: String(sourceEvent.imageAspectMode || "").trim() === "cover" ? "cover" : "",
      imdbId: String(sourceEvent.imdbId || "").trim(),
      workInformation: sourceEvent.workInformation ?? "",
      workInformationSource: sourceEvent.workInformationSource === "wikidata" || sourceEvent.workInformationSource === "manual"
        ? sourceEvent.workInformationSource
        : "",
      additionalInformationExpanded: sourceEvent.additionalInformationExpanded === true
        ? true
        : sourceEvent.additionalInformationExpanded === false
          ? false
          : null,
      projectCategoryId: String(sourceEvent.projectCategoryId || "").trim(),
      workInformationLookupCompleted: Boolean(
        (sourceEvent.workInformationSource === "wikidata" || sourceEvent.workInformationSource === "manual")
        && sourceEvent.workInformation
      ),
      wikidataImageLookupCompleted: Boolean(
        sourceEvent.wikidataImageFile
        && (sourceEvent.wikidataImageUrl || sourceEvent.wikidataImagePreviewUrl || sourceEvent.wikidataImageThumbUrl)
      ),
    };
    migrateLocalizedDescriptionState(eventItem);
    eventIdMap.set(sourceEvent.id, eventItem.id);
    timelineEvents.push(eventItem);
  });

  payload.events.forEach((sourceEvent) => {
    const importedEvent = getEventById(eventIdMap.get(sourceEvent.id));
    if (!importedEvent) return;
    importedEvent.parentEventId = sourceEvent.parentEventId ? (eventIdMap.get(sourceEvent.parentEventId) ?? null) : null;
    normalizeEventDisplaySettings(importedEvent);
  });

  prunePresetProjectCategoriesAcrossState();

  (payload.charts ?? []).forEach((sourceChart) => {
    const chartItem = {
      ...createEmptyChart(),
      ...sourceChart,
      id: createUniqueId("chart-import"),
      groupId: sourceChart.groupId ? (groupIdMap.get(sourceChart.groupId) ?? null) : null,
      parentEventId: null,
      visible: sourceChart.visible !== false,
      yAxisEnabled: sourceChart.yAxisEnabled !== false,
      points: Array.isArray(sourceChart.points)
        ? sourceChart.points.map((point) => ({
          x: point.x,
          precision: point.precision ?? null,
          y: point.y,
          label: point.label ?? "",
          description: point.description ?? "",
          meta: point.meta ?? null,
          sourceTitle: point.sourceTitle ?? "",
          visible: point.visible !== false,
          chainBreakAfter: point.chainBreakAfter === true,
        }))
        : [],
    };
    normalizeChartItem(chartItem);
    const targetGroup = getDefaultGroupForNewItem("charts");
    if (pushToState && targetGroup && !chartItem.groupId) {
      chartItem.groupId = targetGroup.id;
      expandGroupAncestors(targetGroup.id);
    }
    assignChartDisplayColor(chartItem, {
      existingCharts: chartItems,
      syncPrimaryTableColor: true,
    });
    chartIdMap.set(sourceChart.id, chartItem.id);
    chartItems.push(chartItem);
  });

  (payload.charts ?? []).forEach((sourceChart) => {
    const importedChart = getChartById(chartIdMap.get(sourceChart.id));
    if (!importedChart) return;
    importedChart.parentEventId = sourceChart.parentEventId ? (eventIdMap.get(sourceChart.parentEventId) ?? null) : null;
    normalizeChartItem(importedChart);
  });

  (payload.sources ?? []).forEach((sourceItem) => {
    const normalizedSource = normalizeSourceItem({
      ...sourceItem,
      id: createUniqueId("source-import"),
      groupId: sourceItem.groupId ? (groupIdMap.get(sourceItem.groupId) ?? null) : null,
      coupledEventId: sourceItem.coupledEventId ? (eventIdMap.get(sourceItem.coupledEventId) ?? null) : null,
      enabled: sourceItem.enabled !== false,
    });
    if (normalizedSource) sourceItems.push(normalizedSource);
  });

  if (payload.chartViewState && typeof payload.chartViewState === "object") {
    const importedSelectedChartAxisIds = (Array.isArray(payload.chartViewState.selectedChartAxisIds)
      ? payload.chartViewState.selectedChartAxisIds
      : [])
      .map((chartId) => chartIdMap.get(chartId))
      .filter(Boolean);
    const importedActiveChartId = payload.chartViewState.activeChartId
      ? (chartIdMap.get(payload.chartViewState.activeChartId) ?? null)
      : null;
    state.selectedChartAxisIds = importedSelectedChartAxisIds;
    state.activeChartId = importedActiveChartId ?? importedSelectedChartAxisIds[0] ?? state.activeChartId ?? null;
    state.showYAxis = payload.chartViewState.showYAxis === true && importedSelectedChartAxisIds.length > 0;
    state.chartAxisGroupToggleEnabled = payload.chartViewState.chartAxisGroupToggleEnabled === true;
  }

  sanitizeEventHierarchy();
  const importedRootGroupId = payload.rootGroupId ? groupIdMap.get(payload.rootGroupId) : null;
  mergeImportedBookmarks(payload.bookmarks, importedRootGroupId ?? null, groupIdMap);
  pruneEmptyProjectSpecialFolders();
  const importedRootGroup = importedRootGroupId ? getGroupById(importedRootGroupId) : null;
  if (typeof onProgress === "function" && importedRootGroup) {
    onProgress({
      title: importedRootGroup.title,
      text: tf("loading_import_folder", { title: importedRootGroup.title }),
      progress: 64,
      groupId: importedRootGroup.id,
    });
    await waitForNextPaint();
  }
  if (importedRootGroup) {
    state.openEditorId = null;
    state.openGroupEditorId = null;
  }
  if (typeof onProgress === "function") {
    onProgress({
      text: t("loading_localize_content"),
      progress: 76,
    });
    await waitForNextPaint();
  }
  await refreshLocalizedWikidataContent();
  if (importedRootGroup) {
    ui.eventBrowserInfo.textContent = tf("folder_imported", { title: importedRootGroup.title });
  } else {
    ui.eventBrowserInfo.textContent = t("folder_imported_generic");
  }
  renderEpochMenu();
  renderEventList();
  drawTimeline();
  if (typeof onProgress === "function") {
    onProgress({
      text: t("loading_update_view"),
      progress: 94,
    });
    await waitForNextPaint();
  }
}

function hideTooltip() {
  if (state.clickTimer) {
    clearTimeout(state.clickTimer);
    state.clickTimer = null;
  }
  state.lastClickEventId = null;
  state.lastClickTime = 0;
  state.tooltipEventId = null;
  state.tooltipExpandedEventId = null;
  state.tooltipViewerMaximized = false;
  if (ui.eventTooltip) {
    ui.eventTooltip.classList.remove("is-expanded");
    ui.eventTooltip.classList.remove("is-maximized");
    ui.eventTooltip.hidden = true;
    ui.eventTooltip.replaceChildren();
  }
  document.body.classList.remove("event-tooltip-viewer-open");
}

function handleTooltipWheel(event) {
  if (!ui.eventTooltip || ui.eventTooltip.hidden) return;
  event.preventDefault();
  event.stopPropagation();
  const container = ui.eventTooltip;
  const maxScrollTop = Math.max(0, container.scrollHeight - container.clientHeight);
  if (maxScrollTop <= 0) return;
  container.scrollTop = clamp(container.scrollTop + event.deltaY, 0, maxScrollTop);
}

function updateExpandedTooltipImageLayout() {
  if (!ui.eventTooltip) return;
  const imageWrap = ui.eventTooltip.querySelector(".event-tooltip-image");
  const image = imageWrap?.querySelector("img");
  if (!imageWrap || !image) return;
  if (!ui.eventTooltip.classList.contains("is-expanded")) {
    imageWrap.style.removeProperty("height");
    return;
  }
  if (ui.eventTooltip.classList.contains("is-maximized")) {
    imageWrap.style.removeProperty("height");
    return;
  }
  const naturalWidth = Number(image.naturalWidth) || 0;
  const naturalHeight = Number(image.naturalHeight) || 0;
  const wrapWidth = imageWrap.clientWidth || 0;
  if (naturalWidth <= 0 || naturalHeight <= 0 || wrapWidth <= 0) return;
  const computedMaxHeight = Number.parseFloat(getComputedStyle(imageWrap).maxHeight);
  const maxPreviewHeight = Number.isFinite(computedMaxHeight) && computedMaxHeight > 0
    ? computedMaxHeight
    : Math.max(180, window.innerHeight * 0.66);
  const nextHeight = Math.min(wrapWidth * (naturalHeight / naturalWidth), maxPreviewHeight);
  imageWrap.style.height = `${nextHeight}px`;
}

function positionTooltip(anchorX, markerY) {
  if (!ui.eventTooltip) return;
  const isExpanded = state.tooltipExpandedEventId != null && state.tooltipExpandedEventId === state.tooltipEventId;
  const isMaximized = isExpanded && state.tooltipViewerMaximized === true;
  ui.eventTooltip.classList.toggle("is-expanded", isExpanded);
  ui.eventTooltip.classList.toggle("is-maximized", isMaximized);
  document.body.classList.toggle("event-tooltip-viewer-open", isMaximized);
  if (isExpanded) {
    ui.eventTooltip.style.left = "auto";
    ui.eventTooltip.style.right = "0px";
    ui.eventTooltip.style.top = "0px";
    if (isMaximized) {
      ui.eventTooltip.style.bottom = "0px";
      ui.eventTooltip.style.height = "";
      ui.eventTooltip.style.setProperty("--viewer-available-height", "100vh");
    } else {
      ui.eventTooltip.style.bottom = "";
      ui.eventTooltip.style.height = "";
      ui.eventTooltip.style.removeProperty("--viewer-available-height");
    }
    requestAnimationFrame(updateExpandedTooltipImageLayout);
    return;
  }
  ui.eventTooltip.style.right = "auto";
  ui.eventTooltip.style.bottom = "";
  ui.eventTooltip.style.height = "";
  ui.eventTooltip.style.removeProperty("--viewer-available-height");
  updateExpandedTooltipImageLayout();
  const stageRect = svg.getBoundingClientRect();
  const tooltipWidth = 320;
  const stripHeight = ui.openWorkspaceStrip?.offsetHeight ?? 0;
  const tooltipHeight = ui.eventTooltip.offsetHeight || 0;
  const anchorViewportX = stageRect.left + anchorX;
  const markerViewportY = stageRect.top + markerY;
  const left = Math.max(12, Math.min(anchorViewportX - tooltipWidth / 2, window.innerWidth - tooltipWidth - 12));
  const maxTop = Math.max(12, window.innerHeight - stripHeight - tooltipHeight - 10);
  const preferredTop = markerViewportY - tooltipHeight - 18;
  const top = Math.max(12, Math.min(maxTop, preferredTop));
  ui.eventTooltip.style.left = `${left}px`;
  ui.eventTooltip.style.top = `${top}px`;
}

function getViewerButtonIconMarkup(kind) {
  if (kind === "zoom-in") {
    return `
      <svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">
        <circle cx="10.5" cy="10.5" r="5.75" />
        <line x1="10.5" y1="7.75" x2="10.5" y2="13.25" />
        <line x1="7.75" y1="10.5" x2="13.25" y2="10.5" />
        <line x1="15.25" y1="15.25" x2="20" y2="20" />
      </svg>
    `;
  }
  if (kind === "zoom-out") {
    return `
      <svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">
        <circle cx="10.5" cy="10.5" r="5.75" />
        <line x1="7.75" y1="10.5" x2="13.25" y2="10.5" />
        <line x1="15.25" y1="15.25" x2="20" y2="20" />
      </svg>
    `;
  }
  if (kind === "maximize") {
    return `
      <svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">
        <path d="M8 4H5a1 1 0 0 0-1 1v3M16 4h3a1 1 0 0 1 1 1v3M20 16v3a1 1 0 0 1-1 1h-3M8 20H5a1 1 0 0 1-1-1v-3" />
        <path d="M9 9 4 4M15 9l5-5M15 15l5 5M9 15l-5 5" />
      </svg>
    `;
  }
  if (kind === "minimize") {
    return `
      <svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">
        <path d="M4 8V5a1 1 0 0 1 1-1h3M20 8V5a1 1 0 0 0-1-1h-3M4 16v3a1 1 0 0 0 1 1h3M20 16v3a1 1 0 0 1-1 1h-3" />
        <path d="M10 10 5 5M14 10l5-5M14 14l5 5M10 14l-5 5" />
      </svg>
    `;
  }
  return `
    <svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">
      <path d="M6 6 18 18M18 6 6 18" />
    </svg>
  `;
}

function showTooltip(eventItem, anchorX, markerY) {
  if (!ui.eventTooltip) return;
  const previousTooltipEventId = state.tooltipEventId;
  if (previousTooltipEventId !== eventItem.id) {
    state.tooltipViewerMaximized = false;
  }
  state.tooltipEventId = eventItem.id;
  state.tooltipExpandedEventId = eventItem.id;
  ui.eventTooltip.replaceChildren();
  const contentWrap = document.createElement("div");
  contentWrap.className = "event-tooltip-info";
  const viewerHead = document.createElement("div");
  viewerHead.className = "event-tooltip-viewer-head";
  const viewerActions = document.createElement("div");
  viewerActions.className = "event-tooltip-viewer-actions";
  const imageUrl = getEventPanelImageUrl(eventItem, "preview");
  if (imageUrl) {
    const viewerIsMaximized = state.tooltipViewerMaximized === true;
    viewerActions.replaceChildren();
    if (!viewerIsMaximized) {
      const maximizeButton = document.createElement("button");
      maximizeButton.type = "button";
      maximizeButton.className = "event-tooltip-viewer-button";
      maximizeButton.innerHTML = getViewerButtonIconMarkup("maximize");
      maximizeButton.title = "Maximieren";
      maximizeButton.setAttribute("aria-label", "Maximieren");
      maximizeButton.addEventListener("click", (event) => {
        event.preventDefault();
        event.stopPropagation();
        state.tooltipViewerMaximized = true;
        showTooltip(eventItem, anchorX, markerY);
      });
      viewerActions.appendChild(maximizeButton);
    }

    const imageWrap = document.createElement("div");
    imageWrap.className = "event-tooltip-image";
    imageWrap.classList.add(viewerIsMaximized ? "is-zoom-out" : "is-zoom-in");
    const image = document.createElement("img");
    const applyTooltipImageAspectRatio = () => {
      const naturalWidth = Number(eventItem.wikidataImageWidth) || Number(image.naturalWidth) || 0;
      const naturalHeight = Number(eventItem.wikidataImageHeight) || Number(image.naturalHeight) || 0;
      if (naturalWidth > 0 && naturalHeight > 0) {
        imageWrap.style.setProperty("--image-aspect-ratio", `${naturalWidth} / ${naturalHeight}`);
        updateExpandedTooltipImageLayout();
      }
    };
    image.addEventListener("load", applyTooltipImageAspectRatio);
    image.alt = eventItem.title || "Event image";
    image.src = imageUrl;
    if (image.complete) {
      applyTooltipImageAspectRatio();
    }
    if (!viewerIsMaximized) {
      const imageAffordance = document.createElement("span");
      imageAffordance.className = "event-tooltip-image-affordance";
      imageAffordance.setAttribute("aria-hidden", "true");
      imageAffordance.innerHTML = getViewerButtonIconMarkup("zoom-in");
      imageWrap.appendChild(imageAffordance);
    }
    imageWrap.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      state.tooltipExpandedEventId = eventItem.id;
      state.tooltipViewerMaximized = !state.tooltipViewerMaximized;
      showTooltip(eventItem, anchorX, markerY);
    });
    imageWrap.appendChild(image);
    ui.eventTooltip.appendChild(viewerHead);
    ui.eventTooltip.appendChild(imageWrap);
  }
  const closeButton = document.createElement("button");
  closeButton.type = "button";
  closeButton.className = "event-tooltip-viewer-button";
  closeButton.innerHTML = getViewerButtonIconMarkup("close");
  closeButton.title = t("close");
  closeButton.setAttribute("aria-label", t("close"));
  closeButton.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    hideTooltip();
  });
  viewerActions.appendChild(closeButton);
  viewerHead.appendChild(viewerActions);
  if (!ui.eventTooltip.contains(viewerHead)) {
    ui.eventTooltip.appendChild(viewerHead);
  }
  const title = createHtmlTitleContent(eventItem);
  const meta = document.createElement("span");
  meta.className = "event-tooltip-meta";
  meta.textContent = getEventDateLabel(eventItem);
  const secondaryCalendarLabel = getActiveAdditionalTimelineCalendar() === "chinese-sexagenary"
    ? getChineseSexagenaryYearLabelForEvent(eventItem)
    : "";
  const secondaryCalendarMeta = document.createElement("span");
  secondaryCalendarMeta.className = "event-tooltip-meta event-tooltip-secondary-calendar";
  secondaryCalendarMeta.textContent = secondaryCalendarLabel
    ? `${t("chinese_sexagenary_year")}: ${secondaryCalendarLabel}`
    : "";
  const sourceNote = createDescriptionSourceNote(eventItem);
  sourceNote.classList.add("event-tooltip-source-note-bottom");
  const imageSourceText = getEventImageSourceText(eventItem);
  if (imageSourceText) {
    const baseSourceText = sourceNote.textContent || "";
    sourceNote.textContent = baseSourceText
      ? `${baseSourceText}, ${t("image_source_prefix")}: ${imageSourceText}`
      : `${t("image_source_prefix")}: ${imageSourceText}`;
  }
  const description = renderMarkdownBlock(eventItem.description || t("no_description"));
  description.classList.add("event-description");
  const isLiteraryWork = eventItem.wikidataTypeProfile === "literary-work";
  const literaryExcerpt = isLiteraryWork ? String(eventItem.workInformation || "").trim() : "";
  const workInfoLines = isLiteraryWork ? [] : parseWorkInformationLines(eventItem.workInformation);
  const hasWorkInfo = isLiteraryWork ? Boolean(literaryExcerpt) : workInfoLines.length > 0;
  const suppressMeta = !isLiteraryWork && hasWorkInfo;
  const suppressDescription = !isLiteraryWork && hasWorkInfo && eventItem.workInformationSource === "wikidata";
  const shouldLoadWorkInformation = Boolean(eventItem.sourceId && !hasWorkInfo && eventItem.wikidataTypeProfile === "painting");

  contentWrap.append(title);
  if (!suppressMeta) {
    contentWrap.appendChild(meta);
    if (secondaryCalendarLabel) {
      contentWrap.appendChild(secondaryCalendarMeta);
    }
  }
  if (isLiteraryWork && literaryExcerpt) {
    const excerptBlock = renderMarkdownBlock(literaryExcerpt);
    excerptBlock.classList.add("event-description", "event-literary-excerpt");
    contentWrap.appendChild(excerptBlock);
  } else if (hasWorkInfo) {
    const workInfoBlock = document.createElement("div");
    workInfoBlock.className = "event-painting-info";
    workInfoLines.forEach((line) => {
      const infoRow = document.createElement("div");
      infoRow.className = "event-painting-info-row";
      const infoValue = document.createElement("span");
      infoValue.textContent = line;
      infoRow.appendChild(infoValue);
      workInfoBlock.appendChild(infoRow);
    });
    contentWrap.appendChild(workInfoBlock);
  } else if (shouldLoadWorkInformation) {
    const loadingNote = document.createElement("span");
    loadingNote.className = "event-painting-info-loading";
    loadingNote.textContent = "Werkinformationen werden geladen…";
    contentWrap.appendChild(loadingNote);
  }
  if (!suppressDescription) {
    contentWrap.appendChild(description);
  }
  contentWrap.appendChild(sourceNote);
  ui.eventTooltip.appendChild(contentWrap);
  ui.eventTooltip.hidden = false;
  positionTooltip(anchorX, markerY);
  if (shouldLoadWorkInformation) {
    ensurePaintingInfo(eventItem, { force: true }).then(() => {
      if (state.tooltipEventId === eventItem.id && !ui.eventTooltip.hidden) {
        const nextWorkInfoLines = parseWorkInformationLines(eventItem.workInformation);
        const loadingNote = contentWrap.querySelector(".event-painting-info-loading");
        if (loadingNote) loadingNote.remove();
        const existingWorkInfoBlock = contentWrap.querySelector(".event-painting-info");
        if (existingWorkInfoBlock) existingWorkInfoBlock.remove();
        const existingMeta = Array.from(contentWrap.children).find((child) => child === meta);
        if (nextWorkInfoLines.length > 0) {
          if (existingMeta) {
            existingMeta.remove();
          }
          const workInfoBlock = document.createElement("div");
          workInfoBlock.className = "event-painting-info";
          nextWorkInfoLines.forEach((line) => {
            const infoRow = document.createElement("div");
            infoRow.className = "event-painting-info-row";
            const infoValue = document.createElement("span");
            infoValue.textContent = line;
            infoRow.appendChild(infoValue);
            workInfoBlock.appendChild(infoRow);
          });
          contentWrap.insertBefore(workInfoBlock, suppressDescription ? sourceNote : description);
          if (eventItem.workInformationSource === "wikidata" && description.parentNode === contentWrap) {
            description.remove();
          }
        } else if (!contentWrap.contains(meta)) {
          contentWrap.insertBefore(meta, description.parentNode === contentWrap ? description : sourceNote);
        }
        sourceNote.textContent = getDescriptionSourceLabel(getResolvedDescriptionEntry(eventItem));
      }
    }).catch(() => {
      if (state.tooltipEventId === eventItem.id && !ui.eventTooltip.hidden) {
        const loadingNote = contentWrap.querySelector(".event-painting-info-loading");
        if (loadingNote) {
          loadingNote.textContent = "Wikidata-Abruf fehlgeschlagen";
        }
      }
    });
  }
}

function showInfoTooltip(titleText, metaText, descriptionText, anchorX, markerY) {
  if (!ui.eventTooltip) return;
  state.tooltipEventId = null;
  ui.eventTooltip.replaceChildren();
  const title = createPlainTitleContent(titleText, "strong");
  const meta = document.createElement("span");
  meta.textContent = metaText;
  const description = renderMarkdownBlock(descriptionText || t("no_description"));
  description.classList.add("event-description");
  ui.eventTooltip.append(title, meta, description);
  ui.eventTooltip.hidden = false;
  positionTooltip(anchorX, markerY);
}

function handleDocumentPointerDownForInfoTooltip(event) {
  if (!ui.eventTooltip || ui.eventTooltip.hidden) return;
  if (ui.eventTooltip.classList.contains("is-expanded")) return;
  const target = event.target;
  if (target instanceof Node && ui.eventTooltip.contains(target)) return;
  hideTooltip();
}

function estimateWrappedLineCount(text, maxCharsPerLine = 26) {
  const normalized = String(text || "").trim();
  if (!normalized) return 1;
  const segments = normalized.split(/\s+/);
  let lines = 1;
  let currentLength = 0;
  segments.forEach((segment) => {
    const nextLength = currentLength === 0 ? segment.length : currentLength + 1 + segment.length;
    if (nextLength > maxCharsPerLine) {
      lines += 1;
      currentLength = segment.length;
    } else {
      currentLength = nextLength;
    }
  });
  return lines;
}

function estimateWrappedMaxLineLength(text, maxCharsPerLine = 26) {
  const normalized = String(text || "").trim();
  if (!normalized) return 0;
  const segments = normalized.split(/\s+/);
  let longest = 0;
  let currentLength = 0;
  segments.forEach((segment) => {
    const nextLength = currentLength === 0 ? segment.length : currentLength + 1 + segment.length;
    if (nextLength > maxCharsPerLine) {
      longest = Math.max(longest, currentLength, Math.min(segment.length, maxCharsPerLine));
      currentLength = Math.min(segment.length, maxCharsPerLine);
    } else {
      currentLength = nextLength;
      longest = Math.max(longest, currentLength);
    }
  });
  return Math.max(longest, currentLength);
}

let commentMeasureCanvas = null;
const EVENT_CONTEXT_DELETE_HOLD_MS = 700;
let chartPointDeleteHoldState = null;
let groupBrowserMenuDeleteHoldState = null;
let sourceCollectionMenuDeleteHoldState = null;

function getCommentMeasureContext() {
  if (!commentMeasureCanvas && typeof document !== "undefined") {
    commentMeasureCanvas = document.createElement("canvas");
  }
  return commentMeasureCanvas ? commentMeasureCanvas.getContext("2d") : null;
}

function measureCommentTextWidth(text, font) {
  const context = getCommentMeasureContext();
  if (!context) {
    return String(text || "").length * 7;
  }
  context.font = font;
  return context.measureText(String(text || "")).width;
}

function truncateTextToWidth(text, maxWidth, font) {
  const normalized = String(text || "").trim();
  if (!normalized) return "";
  if (measureCommentTextWidth(normalized, font) <= maxWidth) return normalized;
  const ellipsis = "…";
  let low = 0;
  let high = normalized.length;
  let best = ellipsis;
  while (low <= high) {
    const mid = Math.floor((low + high) / 2);
    const candidate = `${normalized.slice(0, mid).trimEnd()}${ellipsis}`;
    if (measureCommentTextWidth(candidate, font) <= maxWidth) {
      best = candidate;
      low = mid + 1;
    } else {
      high = mid - 1;
    }
  }
  return best;
}

function wrapCommentTextByWidth(text, maxWidth, font) {
  const normalized = String(text || "").trim();
  if (!normalized) {
    return { lines: [], maxLineWidth: 0 };
  }
  const words = normalized.split(/\s+/);
  const lines = [];
  let currentLine = "";
  let currentWidth = 0;
  let maxLineWidth = 0;

  words.forEach((word) => {
    const nextLine = currentLine ? `${currentLine} ${word}` : word;
    const nextWidth = measureCommentTextWidth(nextLine, font);
    if (currentLine && nextWidth > maxWidth) {
      lines.push(currentLine);
      maxLineWidth = Math.max(maxLineWidth, currentWidth);
      currentLine = word;
      currentWidth = measureCommentTextWidth(word, font);
    } else {
      currentLine = nextLine;
      currentWidth = nextWidth;
    }
  });

  if (currentLine) {
    lines.push(currentLine);
    maxLineWidth = Math.max(maxLineWidth, currentWidth);
  }

  return { lines, maxLineWidth };
}

function measureCommentCardLayout(text, description = "", framed = true) {
  const labelText = String(text || "").trim();
  const detailText = String(description || "").trim();
  const titleFont = `${scaleTimelineTextSize(12.5)}px "Segoe UI", Arial, sans-serif`;
  const detailFont = `${scaleTimelineTextSize(11.5)}px "Segoe UI", Arial, sans-serif`;
  const maxInnerWidth = framed ? 196 : 210;
  const titleWrap = wrapCommentTextByWidth(labelText, maxInnerWidth, titleFont);
  const detailWrap = detailText ? wrapCommentTextByWidth(detailText, maxInnerWidth, detailFont) : { lines: [], maxLineWidth: 0 };
  const widestLine = Math.max(titleWrap.maxLineWidth, detailWrap.maxLineWidth, framed ? 48 : 32);
  const horizontalPadding = framed ? 22 : 8;
  const minWidth = framed ? 92 : 60;
  const maxWidth = framed ? 220 : 218;
  const width = clamp(Math.ceil(widestLine) + horizontalPadding, minWidth, maxWidth);
  return {
    width,
    titleLineCount: Math.max(1, titleWrap.lines.length),
    detailLineCount: detailWrap.lines.length,
  };
}

function createChartCommentLabelCard({
  x,
  y,
  text,
  description = "",
  color,
  muted = false,
  framed = true,
  align = "right",
  clampToViewport = true,
}) {
  const labelText = String(text || "").trim();
  const detailText = String(description || "").trim();
  const layout = measureCommentCardLayout(labelText, detailText, framed);
  const width = layout.width;
  const titleLineCount = layout.titleLineCount;
  const detailLineCount = layout.detailLineCount;
  const titleLineHeight = Math.ceil(scaleTimelineTextSize(17));
  const detailLineHeight = Math.ceil(scaleTimelineTextSize(15));
  const paddingTop = framed ? 7 : 2;
  const paddingBottom = framed ? 8 : 1;
  const gapY = detailText ? 3 : 0;
  const height = Math.max(
    framed ? 30 : 18,
    titleLineCount * titleLineHeight + detailLineCount * detailLineHeight + paddingTop + paddingBottom + gapY + (framed ? 3 : 0),
  );
  const bulletGap = 10;
  const unclampedX = align === "left" ? x - width - bulletGap : x + bulletGap;
  const xPosition = clampToViewport
    ? clamp(unclampedX, 8, Math.max(8, state.width - width - 8))
    : unclampedX;
  const titleAnchorOffset = paddingTop + 11;
  const topY = y - titleAnchorOffset;
  const foreignObject = createSvgElement("foreignObject", {
    x: xPosition,
    y: topY,
    width: framed ? width + 2 : width,
    height: framed ? height + 2 : height,
    "pointer-events": "none",
  });
  const wrapper = document.createElementNS("http://www.w3.org/1999/xhtml", "div");
  wrapper.className = "chart-comment-label-card";
  if (muted) wrapper.classList.add("is-muted");
  if (!framed) wrapper.classList.add("is-plain");
  wrapper.classList.add(align === "left" ? "is-left" : "is-right");
  wrapper.style.setProperty("--comment-accent", color || "#c96f4a");
  wrapper.style.width = `${width}px`;
  wrapper.style.maxWidth = `${width}px`;
  const titleNode = document.createElementNS("http://www.w3.org/1999/xhtml", "div");
  titleNode.className = "chart-comment-label-title";
  const titleTextNode = document.createElementNS("http://www.w3.org/1999/xhtml", "span");
  titleTextNode.className = "chart-comment-label-text";
  titleTextNode.textContent = labelText;
  titleNode.appendChild(titleTextNode);
  wrapper.appendChild(titleNode);
  if (detailText) {
    const detailNode = document.createElementNS("http://www.w3.org/1999/xhtml", "div");
    detailNode.className = "chart-comment-label-description";
    const detailTextNode = document.createElementNS("http://www.w3.org/1999/xhtml", "span");
    detailTextNode.className = "chart-comment-label-text";
    detailTextNode.textContent = detailText;
    detailNode.appendChild(detailTextNode);
    wrapper.appendChild(detailNode);
  }
  foreignObject.appendChild(wrapper);
  return {
    element: foreignObject,
    bounds: { x: xPosition, y: topY, width, height },
  };
}

function formatChartPointX(value, xPrecision = "year", pointPrecision = null) {
  const precision = Number.isFinite(pointPrecision)
    ? pointPrecision
    : (xPrecision === "day" ? 11 : 9);
  return formatTimelineValue(value, precision);
}

function getChartLegendLabel(chartItem) {
  const unitSuffix = chartItem.sourceUnit ? ` (${chartItem.sourceUnit})` : "";
  return `${chartItem.title || chartItem.yAxisLabel || chartItem.sourceMetric || t("chart_axis_label_none")}${unitSuffix}`;
}

function inferChartUnitShort(chartItem) {
  const directUnitShort = String(chartItem?.sourceUnitShort || "").trim();
  if (directUnitShort) return directUnitShort;
  const primaryTable = getChartPrimaryTable(chartItem);
  const tableUnitShort = String(primaryTable?.sourceUnitShort || "").trim();
  if (tableUnitShort) return tableUnitShort;
  return "";
}

function inferChartUnit(chartItem) {
  const directUnit = String(chartItem?.sourceUnit || "").trim();
  if (directUnit) return directUnit;

  const directUnitShort = inferChartUnitShort(chartItem);
  if (directUnitShort) return directUnitShort;

  const axisLabel = String(chartItem?.yAxisLabel || "").trim();
  const axisMatch = axisLabel.match(/\(([^)]+)\)\s*$/);
  if (axisMatch) return axisMatch[1].trim();

  const description = String(chartItem?.description || "").trim();
  const measuredInMatch = description.match(/measured\s+in\s+([^.;,]+)/i);
  if (measuredInMatch) return measuredInMatch[1].trim();

  const parenMatch = description.match(/\(([A-Za-z%][A-Za-z0-9/%\s.-]{0,30})\)/);
  if (parenMatch) return parenMatch[1].trim();

  return "";
}

function formatChartAxisValue(value, options = {}) {
  const { compact = false } = options;
  const numericValue = Number(value);
  const absValue = Math.abs(numericValue);
  const locale = state.language === "de" ? "de-DE" : "en-US";
  if (compact) {
    const units = [
      { limit: 1e12, suffix: "T" },
      { limit: 1e9, suffix: "G" },
      { limit: 1e6, suffix: "M" },
      { limit: 1e3, suffix: "K" },
    ];
    const unit = units.find((entry) => absValue >= entry.limit);
    if (unit) {
      const formatter = new Intl.NumberFormat(locale, {
        minimumFractionDigits: 0,
        maximumFractionDigits: 2,
      });
      return `${formatter.format(numericValue / unit.limit)} ${unit.suffix}`;
    }
  }
  const formatter = new Intl.NumberFormat(locale, {
    maximumFractionDigits: absValue < 10 ? 2 : 0,
  });
  return formatter.format(numericValue);
}

function formatNumericLabel(value) {
  const numericValue = Number(value);
  if (!Number.isFinite(numericValue)) return "";
  const locale = state.language === "en" ? "en-US" : "de-DE";
  const formatter = new Intl.NumberFormat(locale, {
    maximumFractionDigits: 2,
  });
  return formatter.format(numericValue);
}

function getChartAxisUnitText(chartItem) {
  return String(chartItem?.sourceUnit || "").trim()
    || inferChartUnitShort(chartItem)
    || inferChartUnit(chartItem)
    || t("chart_unit_unknown");
}

function renderChartAxisHud(chartItem, chartsMuted, selectedCharts = []) {
  if (!ui.chartAxisHud) return;
  ui.chartAxisHud.replaceChildren();
  if (!chartItem || isChartHiddenMode()) {
    ui.chartAxisHud.hidden = true;
    return;
  }
  if (!chartItem.sourceUnit && !chartItem.sourceUnitShort) {
    chartItem.sourceUnit = inferChartUnit(chartItem);
  }
  const axisUnitText = getChartAxisUnitText(chartItem);
  const isSharedAxis = selectedCharts.length > 1;
  const title = document.createElement("strong");
  title.style.color = chartsMuted ? "#8b949b" : getChartRenderColor(chartItem);
  title.textContent = isSharedAxis
    ? axisUnitText
    : (chartItem.title || chartItem.sourceMetric || "Chart");
  const unit = document.createElement("span");
  unit.textContent = isSharedAxis ? "" : axisUnitText;
  if (isSharedAxis) {
    unit.hidden = true;
  }
  ui.chartAxisHud.append(title, unit);
  ui.chartAxisHud.hidden = false;
}

function renderTimelineStepHud(step) {
  if (!ui.timelineStepHud) return;
  const stepNode = document.createElement("div");
  stepNode.className = "timeline-step-hud-step";
  stepNode.textContent = stepToLabel(step);
  const nodes = [stepNode];
  const calendarLabel = getAdditionalTimelineCalendarHudLabel();
  if (calendarLabel) {
    const calendarNode = document.createElement("div");
    calendarNode.className = "timeline-step-hud-calendar";
    calendarNode.textContent = calendarLabel;
    nodes.push(calendarNode);
  }
  ui.timelineStepHud.replaceChildren(...nodes);
}

function getTickBookmarkLabel(bookmark) {
  const step = scaleSteps[bookmark.stepIndex] || getStep();
return `${getTickLabel(bookmark.tickValue, step, true)} · ${stepToLabel(step)}`;
}

function getTickBookmarkTitle(bookmark) {
  const storedTitle = String(bookmark?.title || "").trim();
  return storedTitle || getTickBookmarkLabel(bookmark);
}

function getTimelineStepComparisonTolerance(step = getStep()) {
  if (step?.unit === "day") return 60 * 60 * 1000;
  if (step?.unit === "week") return 6 * 60 * 60 * 1000;
  if (step?.unit === "month") return 12 * 60 * 60 * 1000;
  return Math.max(Math.abs(getStepYears(step)) / 1000, 1e-9);
}

function isSameTimelineStepValue(leftValue, rightValue, step = getStep()) {
  const leftPosition = getComparableTimelinePosition(leftValue, step);
  const rightPosition = getComparableTimelinePosition(rightValue, step);
  return Math.abs(leftPosition - rightPosition) <= getTimelineStepComparisonTolerance(step);
}

function isBookmarkRenderable(bookmark) {
  if (!bookmark || !Number.isFinite(bookmark.tickValue) || !Number.isFinite(bookmark.centerYear)) return false;
  const stepIndex = clamp(Number(bookmark.stepIndex), 0, scaleSteps.length - 1);
  const step = scaleSteps[stepIndex];
  if (!step) return false;
  const alignedValue = alignTimelineValueToStepStart(bookmark.tickValue, step);
  return isSameTimelineStepValue(alignedValue, bookmark.tickValue, step);
}

function sanitizeTickBookmarksCollection(bookmarks) {
  if (!Array.isArray(bookmarks)) return [];
  const seenKeys = new Set();
  const sanitized = [];
  bookmarks.forEach((bookmark) => {
    if (!isBookmarkRenderable(bookmark)) return;
    const stepIndex = clamp(Number(bookmark.stepIndex), 0, scaleSteps.length - 1);
    const normalizedBookmark = {
      id: String(bookmark.id || createUniqueId("bookmark")),
      tickValue: Number(bookmark.tickValue),
      centerYear: Number(bookmark.centerYear),
      stepIndex,
      title: String(bookmark.title || "").trim() || getTickBookmarkLabel({ ...bookmark, stepIndex }),
      ownerGroupId: bookmark.ownerGroupId ?? null,
      groupId: bookmark.groupId && getGroupById(bookmark.groupId) ? bookmark.groupId : null,
      enabled: bookmark.enabled !== false,
    };
    const key = `${normalizedBookmark.stepIndex}|${normalizedBookmark.tickValue}`;
    if (seenKeys.has(key)) return;
    seenKeys.add(key);
    sanitized.push(normalizedBookmark);
  });
  return sanitized.slice(0, MAX_TICK_BOOKMARKS);
}

function isCurrentBookmark(bookmark) {
  const step = scaleSteps[bookmark.stepIndex] || getStep();
  return bookmark.stepIndex === state.stepIndex && isSameTimelineStepValue(bookmark.centerYear, state.centerYear, step);
}

function toggleTickBookmark(tickValue) {
  const step = getStep();
  const existingIndex = state.tickBookmarks.findIndex((bookmark) => (
    bookmark.stepIndex === state.stepIndex
    && isSameTimelineStepValue(bookmark.tickValue, tickValue, step)
  ));
  if (existingIndex >= 0) {
    const [removedBookmark] = state.tickBookmarks.splice(existingIndex, 1);
    if (removedBookmark?.id && state.openBookmarkEditorId === removedBookmark.id) {
      state.openBookmarkEditorId = null;
    }
    renderEventList();
    return;
  }
  if (state.tickBookmarks.length >= MAX_TICK_BOOKMARKS) {
    return;
  }
  const newBookmark = {
    id: createUniqueId("bookmark"),
    tickValue,
    centerYear: state.centerYear,
    stepIndex: state.stepIndex,
    title: "",
    ownerGroupId: null,
    groupId: null,
    enabled: true,
  };
  const targetGroup = getDefaultGroupForNewItem("bookmarks");
  if (targetGroup) {
    newBookmark.groupId = targetGroup.id;
    expandGroupAncestors(targetGroup.id);
  }
  newBookmark.title = getTickBookmarkLabel(newBookmark);
  state.tickBookmarks.push(newBookmark);
  state.bookmarkFolderExpanded = !targetGroup;
  renderEventList();
}

function jumpToTickBookmark(bookmark) {
  if (!bookmark) return;
  hideTooltip();
  state.subYearTickAnchorValue = null;
  state.centerYear = bookmark.centerYear;
  state.stepIndex = clamp(bookmark.stepIndex, 0, scaleSteps.length - 1);
  drawTimeline();
}

function getOpenEditorBookmark() {
  return state.openBookmarkEditorId
    ? state.tickBookmarks.find((bookmark) => bookmark.id === state.openBookmarkEditorId) ?? null
    : null;
}

function getGregorianEasterDateUtc(year) {
  if (!Number.isInteger(year) || year < 1583) return null;
  const a = year % 19;
  const b = Math.floor(year / 100);
  const c = year % 100;
  const d = Math.floor(b / 4);
  const e = b % 4;
  const f = Math.floor((b + 8) / 25);
  const g = Math.floor((b - f + 1) / 3);
  const h = (19 * a + b - d - g + 15) % 30;
  const i = Math.floor(c / 4);
  const k = c % 4;
  const l = (32 + 2 * e + 2 * i - h - k) % 7;
  const m = Math.floor((a + 11 * h + 22 * l) / 451);
  const month = Math.floor((h + l - 7 * m + 114) / 31);
  const day = ((h + l - 7 * m + 114) % 31) + 1;
  return createUtcDateSafe(year, month - 1, day);
}

function isEasterBookmark(bookmark) {
  if (!bookmark) return false;
  const step = scaleSteps[bookmark.stepIndex] || null;
  if (!step || step.id !== "1d") return false;
  const date = timelineValueToDate(bookmark.tickValue);
  if (!date) return false;
  const year = date.getUTCFullYear();
  if (year < 1583) return false;
  const easterDate = getGregorianEasterDateUtc(year);
  if (!easterDate) return false;
  return date.getUTCFullYear() === easterDate.getUTCFullYear()
    && date.getUTCMonth() === easterDate.getUTCMonth()
    && date.getUTCDate() === easterDate.getUTCDate();
}

function renderTimelineBookmarkHud() {
  if (!ui.timelineBookmarkHud) return;
  const renderableBookmarks = Array.isArray(state.tickBookmarks)
    ? state.tickBookmarks.filter((bookmark) => {
      if (bookmark.enabled === false) return false;
      if (bookmark.groupId) {
        const groupItem = getGroupById(bookmark.groupId);
        if (!groupItem || groupItem.enabled === false) return false;
      }
      return true;
    })
    : [];
  const hideForEasterPi = renderableBookmarks.some((bookmark) => isCurrentBookmark(bookmark) && isEasterBookmark(bookmark));
  if (hideForEasterPi) {
    ui.timelineBookmarkHud.replaceChildren();
    ui.timelineBookmarkHud.hidden = true;
    return;
  }
  ui.timelineBookmarkHud.replaceChildren();
  if (!renderableBookmarks.length) {
    ui.timelineBookmarkHud.hidden = true;
    return;
  }
  [...renderableBookmarks].forEach((bookmark) => {
    const row = document.createElement("button");
    row.type = "button";
    row.className = "timeline-bookmark-row";
    if (isCurrentBookmark(bookmark)) row.classList.add("is-active");
    row.textContent = getTickBookmarkTitle(bookmark);
    row.addEventListener("click", () => jumpToTickBookmark(bookmark));
    row.addEventListener("dblclick", (event) => {
      event.preventDefault();
      event.stopPropagation();
      openBookmarkInLibrary(bookmark, { forceOpen: true, jump: false });
    });
    ui.timelineBookmarkHud.appendChild(row);
  });
  ui.timelineBookmarkHud.hidden = false;
}

function renderTimelineEasterHud() {
  if (!ui.timelineEasterHud) return;
  const activeBookmark = state.tickBookmarks.find((bookmark) => (
    bookmark.enabled !== false
    && (!bookmark.groupId || getGroupById(bookmark.groupId)?.enabled !== false)
    && isCurrentBookmark(bookmark)
    && isEasterBookmark(bookmark)
  )) ?? null;
  if (!activeBookmark) {
    ui.timelineEasterHud.hidden = true;
    ui.timelineEasterHud.textContent = "";
    ui.timelineEasterHud.removeAttribute("title");
    return;
  }
  ui.timelineEasterHud.textContent = "π";
  ui.timelineEasterHud.title = `Ostern · ${getTickLabel(activeBookmark.tickValue, scaleSteps[activeBookmark.stepIndex] || getStep(), true)}`;
  ui.timelineEasterHud.hidden = false;
}

