function hideChartPointContextMenu() {
  resetChartPointDeleteHold();
  state.chartPointContextMenuState = null;
  if (ui.chartPointContextMenu) {
    ui.chartPointContextMenu.hidden = true;
  }
}

function resetChartPointDeleteHold() {
  if (!chartPointDeleteHoldState) {
    if (ui.chartPointEventDeleteButton) {
      ui.chartPointEventDeleteButton.classList.remove("is-hold-active", "is-hold-ready");
      ui.chartPointEventDeleteButton.style.removeProperty("--hold-progress");
    }
    if (ui.chartPointCommentRemoveButton) {
      ui.chartPointCommentRemoveButton.classList.remove("is-hold-active", "is-hold-ready");
      ui.chartPointCommentRemoveButton.style.removeProperty("--hold-progress");
    }
    return;
  }
  const { button, frame } = chartPointDeleteHoldState;
  if (frame) cancelAnimationFrame(frame);
  if (button) {
    button.classList.remove("is-hold-active", "is-hold-ready");
    button.style.removeProperty("--hold-progress");
    if (Number.isFinite(chartPointDeleteHoldState.pointerId) && button.hasPointerCapture?.(chartPointDeleteHoldState.pointerId)) {
      try {
        button.releasePointerCapture(chartPointDeleteHoldState.pointerId);
      } catch {
        // Ignore pointer capture release failures.
      }
    }
  }
  chartPointDeleteHoldState = null;
}

function tickChartPointDeleteHold() {
  if (!chartPointDeleteHoldState) return;
  const elapsed = performance.now() - chartPointDeleteHoldState.startedAt;
  const progress = Math.max(0, Math.min(1, elapsed / EVENT_CONTEXT_DELETE_HOLD_MS));
  chartPointDeleteHoldState.button.style.setProperty("--hold-progress", `${progress * 100}%`);
  if (progress >= 1) {
    chartPointDeleteHoldState.armed = true;
    chartPointDeleteHoldState.button.classList.add("is-hold-ready");
    chartPointDeleteHoldState.frame = null;
    return;
  }
  chartPointDeleteHoldState.frame = requestAnimationFrame(tickChartPointDeleteHold);
}

function beginChartPointDeleteHold(event) {
  const button = event.currentTarget;
  if (!(button instanceof HTMLButtonElement) || button.hidden) return;
  event.preventDefault();
  event.stopPropagation();
  resetChartPointDeleteHold();
  const action = button === ui.chartPointCommentRemoveButton
    ? removeChartCommentFromContextMenu
    : deleteEventFromContextMenu;
  chartPointDeleteHoldState = {
    button,
    action,
    pointerId: Number.isFinite(event.pointerId) ? event.pointerId : null,
    startedAt: performance.now(),
    armed: false,
    frame: null,
  };
  button.classList.add("is-hold-active");
  button.style.setProperty("--hold-progress", "0%");
  chartPointDeleteHoldState.frame = requestAnimationFrame(tickChartPointDeleteHold);
}

function finishChartPointDeleteHold(event) {
  if (!chartPointDeleteHoldState) return;
  event.preventDefault();
  event.stopPropagation();
  const { button, action } = chartPointDeleteHoldState;
  const releaseTarget = document.elementFromPoint(event.clientX, event.clientY);
  const releasedOnButton = Boolean(
    releaseTarget
    && button
    && (releaseTarget === button || button.contains(releaseTarget))
  );
  const shouldDelete = chartPointDeleteHoldState.armed === true && releasedOnButton;
  resetChartPointDeleteHold();
  if (shouldDelete && typeof action === "function") action();
}

function cancelChartPointDeleteHold(event) {
  if (!chartPointDeleteHoldState) return;
  event.preventDefault();
  event.stopPropagation();
  resetChartPointDeleteHold();
}

