function showChartPointContextMenu(event, payload) {
  if (!ui.chartPointContextMenu) return;
  event.preventDefault();
  event.stopPropagation();
  resetChartPointDeleteHold();
  const isComment = payload?.kind === "comment" || payload?.kind === "timeline-comment" || payload?.kind === "event-comment";
  const isEventPoint = payload?.kind === "event-point";
  const isEventRange = payload?.kind === "event-range";
  const canHideOrDeleteEvent = isEventPoint || isEventRange;
  const showCommentAdd = !isComment && !isEventRange;
  const sourceItem = payload?.sourceId ? getSourceById(payload.sourceId) : null;
  const showCouple = Boolean(sourceItem && payload?.couplingCandidateEventId && sourceItem.coupledEventId !== payload.couplingCandidateEventId);
  const showUncouple = Boolean(sourceItem?.coupledEventId);
  const menuWidth = 180;
  const visibleActionCount = (isComment ? 1 : 0)
    + (showCommentAdd ? 1 : 0)
    + (showCouple ? 1 : 0)
    + (showUncouple ? 1 : 0)
    + (canHideOrDeleteEvent ? 2 : 0);
  const menuHeight = 12 + (visibleActionCount * 38);
  const x = Math.max(12, Math.min(event.clientX, window.innerWidth - menuWidth - 12));
  const y = Math.max(12, Math.min(event.clientY, window.innerHeight - menuHeight - 12));
  state.chartPointContextMenuState = {
    ...payload,
    x,
    y,
  };
  if (ui.chartPointCommentAddButton) ui.chartPointCommentAddButton.hidden = !showCommentAdd;
  if (ui.sourceCoupleButton) {
    ui.sourceCoupleButton.textContent = state.language === "en" ? "Couple" : "Koppeln";
    ui.sourceCoupleButton.hidden = !showCouple;
  }
  if (ui.sourceUncoupleButton) {
    ui.sourceUncoupleButton.textContent = state.language === "en" ? "Uncouple" : "Entkoppeln";
    ui.sourceUncoupleButton.hidden = !showUncouple;
  }
  if (ui.chartPointEventHideButton) ui.chartPointEventHideButton.hidden = !canHideOrDeleteEvent;
  if (ui.chartPointEventDeleteButton) ui.chartPointEventDeleteButton.hidden = !canHideOrDeleteEvent;
  if (ui.chartPointCommentRemoveButton) ui.chartPointCommentRemoveButton.hidden = !isComment;
  ui.chartPointContextMenu.style.left = `${x}px`;
  ui.chartPointContextMenu.style.top = `${y}px`;
  ui.chartPointContextMenu.hidden = false;
}

function coupleSourceFromContextMenu() {
  const payload = state.chartPointContextMenuState;
  hideChartPointContextMenu();
  const sourceItem = payload?.sourceId ? getSourceById(payload.sourceId) : null;
  const targetEvent = payload?.couplingCandidateEventId ? getEventById(payload.couplingCandidateEventId) : null;
  if (!sourceItem || !targetEvent || !isRangeEvent(targetEvent)) return;
  sourceItem.coupledEventId = targetEvent.id;
  sourceItem.parentEventId = null;
  renderEventList();
  renderDetailsSidePanel();
  drawTimeline();
  scheduleLocalAutosave();
}

function uncoupleSourceFromContextMenu() {
  const payload = state.chartPointContextMenuState;
  hideChartPointContextMenu();
  const sourceItem = payload?.sourceId ? getSourceById(payload.sourceId) : null;
  if (!sourceItem) return;
  sourceItem.coupledEventId = null;
  renderEventList();
  renderDetailsSidePanel();
  drawTimeline();
  scheduleLocalAutosave();
}

function beginChartCommentPlacementFromContextMenu() {
  const payload = state.chartPointContextMenuState;
  hideChartPointContextMenu();
  if (!payload) return;
  if (payload.kind === "timeline-point") {
    state.pendingChartCommentPlacement = {
      kind: "timeline",
      timeValue: payload.timeValue,
      timePrecision: payload.timePrecision ?? 9,
      pointerY: getTimelineLineY(),
    };
  } else if (payload.kind === "event-point") {
    state.pendingChartCommentPlacement = {
      kind: "event",
      eventId: payload.eventId,
      anchorTimeValue: payload.anchorTimeValue,
      anchorTimePrecision: payload.anchorTimePrecision ?? 9,
      pointerY: getTimelineLineY(),
    };
  } else {
    state.pendingChartCommentPlacement = {
      kind: "chart",
      chartId: payload.chartId,
      tableId: payload.tableId,
      pointX: payload.pointX,
      pointY: payload.pointY,
      pointPrecision: payload.pointPrecision ?? null,
      pointerY: getTimelineLineY(),
    };
  }
  drawTimeline();
}

function handleDocumentPointerDownForChartPointContextMenu(event) {
  if (!ui.chartPointContextMenu || ui.chartPointContextMenu.hidden) return;
  if (ui.chartPointContextMenu.contains(event.target)) return;
  hideChartPointContextMenu();
}

function handleDocumentPointerDownForSubgroupBrowserMenu(event) {
  if (!state.openSubgroupBrowserMenuId && !state.openSideSubgroupBrowserMenuId && !state.openSourceCollectionBrowserMenuId) return;
  const target = event.target;
  if (target instanceof Element && target.closest(".group-row-menu-shell")) return;
  state.openSubgroupBrowserMenuId = null;
  state.openSideSubgroupBrowserMenuId = null;
  state.openSourceCollectionBrowserMenuId = null;
  renderEventList();
  renderDetailsSidePanel();
}

function removeChartCommentFromContextMenu() {
  const payload = state.chartPointContextMenuState;
  hideChartPointContextMenu();
  if (!payload) return;
  if (payload.kind === "timeline-comment") {
    trashTimelineComment(payload.commentId);
    renderEventList();
    drawTimeline();
    scheduleLocalAutosave();
    return;
  }
  if (payload.kind === "event-comment") {
    const resolvedComment = findEventCommentById(payload.commentId);
    if (!resolvedComment) return;
    const comments = getEventComments(resolvedComment.eventItem);
    const commentIndex = comments.findIndex((comment) => comment.id === payload.commentId);
    if (commentIndex === -1) return;
    comments.splice(commentIndex, 1);
    if (state.openEventCommentEditorId === payload.commentId) {
      state.openEventCommentEditorId = null;
      renderDetailsSidePanel();
    }
    renderEventList();
    drawTimeline();
    scheduleLocalAutosave();
    return;
  }
  if (payload.kind !== "comment") return;
  const chartItem = getChartById(payload.chartId);
  if (!chartItem) return;
  const comments = getChartComments(chartItem);
  const commentIndex = comments.findIndex((comment) => comment.id === payload.commentId);
  if (commentIndex === -1) return;
  comments.splice(commentIndex, 1);
  normalizeChartItem(chartItem);
  if (state.openChartCommentEditorId === payload.commentId) {
    state.openChartCommentEditorId = null;
    renderDetailsSidePanel();
  }
  renderEventList();
  drawTimeline();
  scheduleLocalAutosave();
}

function hideEventFromContextMenu() {
  const payload = state.chartPointContextMenuState;
  hideChartPointContextMenu();
  if (!payload || (payload.kind !== "event-point" && payload.kind !== "event-range")) return;
  const eventItem = getEventById(payload.eventId);
  if (!eventItem) return;
  eventItem.enabled = false;
  if (state.selectedEventId === eventItem.id) {
    state.selectedEventId = null;
    updateSelectionPanel();
  }
  if (state.openEditorId === eventItem.id) {
    state.openEditorId = null;
  }
  renderEventList();
  drawTimeline();
  scheduleLocalAutosave();
}

function deleteEventFromContextMenu() {
  const payload = state.chartPointContextMenuState;
  hideChartPointContextMenu();
  if (!payload || (payload.kind !== "event-point" && payload.kind !== "event-range")) return;
  trashEventTree(payload.eventId);
  renderEventList();
  drawTimeline();
  scheduleLocalAutosave();
}

function cancelPendingChartCommentPlacement({ redrawTimeline = true } = {}) {
  state.pendingChartCommentPlacement = null;
  if (redrawTimeline) drawTimeline();
}

async function tryPlacePendingChartComment(clientY, clientX = null) {
  const pending = state.pendingChartCommentPlacement;
  if (!pending) return false;
  if (pending.kind === "timeline") {
    const localPoint = getSvgLocalPointFromClient(clientX ?? 0, clientY);
    const localY = localPoint.y;
    const localX = clientX == null ? null : localPoint.x;
    const lane = getNearestChartCommentLaneFromY(localY);
    const defaultTimeText = formatTemporalEditorValue(
      pending.timeValue,
      pending.timePrecision ?? 9,
      false,
    );
    const promptResult = await showTextPromptModal({
      title: t("chart_comment_label_prompt"),
      message: t("chart_comment_label_message"),
      defaultValue: t("chart_comment_default_title"),
      extraInput: {
        label: "Platzierung",
        defaultValue: defaultTimeText,
        type: "text",
        placeholder: "YYYY-MM-DD",
      },
      confirmLabel: t("chart_csv_paste_save"),
      cancelLabel: t("cancel"),
    });
    if (promptResult == null) {
      cancelPendingChartCommentPlacement();
      return true;
    }
    const commentTitle = typeof promptResult === "string"
      ? promptResult
      : String(promptResult.value ?? "");
    let timeValue = pending.timeValue;
    let timePrecision = pending.timePrecision;
    if (promptResult && typeof promptResult === "object") {
      const parsedExtraTime = parseEditorTemporalValue(String(promptResult.extraValue ?? ""));
      if (parsedExtraTime) {
        timeValue = parsedExtraTime.value;
        timePrecision = parsedExtraTime.precision;
      }
    }
    const anchorX = getEventX(timeValue);
    const nextComment = normalizeTimelineComment({
      title: String(commentTitle).trim() || t("chart_comment_default_title"),
      timeValue,
      timePrecision,
      lane,
      align: getCommentAlignForLocalX(localX, anchorX),
      framed: false,
    });
    if (!nextComment) {
      cancelPendingChartCommentPlacement();
      return true;
    }
    const targetGroup = getDefaultGroupForNewItem("timeline");
    if (targetGroup) {
      nextComment.groupId = targetGroup.id;
      expandGroupAncestors(targetGroup.id);
    }
    timelineComments.push(nextComment);
    state.pendingChartCommentPlacement = null;
    state.timelineCommentFolderExpanded = !targetGroup;
    renderEventList();
    drawTimeline();
    scheduleLocalAutosave();
    return true;
  }
  if (pending.kind === "event") {
    const eventItem = getEditableTimelineItemById(pending.eventId);
    if (!eventItem) {
      cancelPendingChartCommentPlacement();
      return true;
    }
    const localPoint = getSvgLocalPointFromClient(clientX ?? 0, clientY);
    const localY = localPoint.y;
    const localX = clientX == null ? null : localPoint.x;
    const lane = getNearestChartCommentLaneFromY(localY);
    const eventStartValue = getTimelineValueForEventStart(eventItem);
    const eventEndValue = getTimelineValueForEventEnd(eventItem);
    const eventStartText = Number.isFinite(eventStartValue)
      ? formatTemporalEditorValue(
        eventStartValue,
        eventItem.startPrecision ?? 9,
        false,
      )
      : "?";
    const eventEndText = Number.isFinite(eventEndValue)
      ? formatTemporalEditorValue(
        eventEndValue,
        eventItem.endPrecision ?? eventItem.startPrecision ?? 9,
        Boolean(eventItem.endIsToday),
      )
      : eventStartText;
    const defaultTimeText = formatTemporalEditorValue(
      pending.anchorTimeValue,
      pending.anchorTimePrecision ?? 9,
      false,
    );
    const promptResult = await showTextPromptModal({
      title: t("chart_comment_label_prompt"),
      message: t("chart_comment_label_message"),
      defaultValue: t("chart_comment_default_title"),
      extraInput: {
        label: `Platzierung (${eventStartText} bis ${eventEndText})`,
        defaultValue: defaultTimeText,
        type: "text",
        placeholder: "YYYY-MM-DD",
      },
      confirmLabel: t("chart_csv_paste_save"),
      cancelLabel: t("cancel"),
    });
    if (promptResult == null) {
      cancelPendingChartCommentPlacement();
      return true;
    }
    const commentTitle = typeof promptResult === "string"
      ? promptResult
      : String(promptResult.value ?? "");
    let anchorTimeValue = pending.anchorTimeValue;
    let anchorTimePrecision = pending.anchorTimePrecision;
    if (promptResult && typeof promptResult === "object") {
      const parsedExtraTime = parseEditorTemporalValue(String(promptResult.extraValue ?? ""));
      if (parsedExtraTime) {
        anchorTimeValue = clampEventCommentAnchorToEvent(eventItem, parsedExtraTime.value);
        anchorTimePrecision = parsedExtraTime.precision;
      }
    }
    const anchorX = getEventX(anchorTimeValue);
    const nextComment = normalizeEventComment({
      title: String(commentTitle).trim() || t("chart_comment_default_title"),
      anchorTimeValue,
      anchorTimePrecision,
      lane,
      align: getCommentAlignForLocalX(localX, anchorX),
      framed: false,
    });
    if (!nextComment) {
      cancelPendingChartCommentPlacement();
      return true;
    }
    if (hasEventCommentAnchorConflict(eventItem, nextComment.id, nextComment.anchorTimeValue)) {
      cancelPendingChartCommentPlacement();
      return true;
    }
    getEventComments(eventItem).push(nextComment);
    eventItem.expanded = true;
    state.pendingChartCommentPlacement = null;
    renderEventList();
    drawTimeline();
    scheduleLocalAutosave();
    return true;
  }
  const chartItem = getChartById(pending.chartId);
  if (!chartItem) {
    cancelPendingChartCommentPlacement();
    return true;
  }
  const localPoint = getSvgLocalPointFromClient(clientX ?? 0, clientY);
  const localY = localPoint.y;
  const localX = clientX == null ? null : localPoint.x;
  const lane = getNearestChartCommentLaneFromY(localY);
  const anchorX = getEventX(pending.pointX);
  const promptResult = await showTextPromptModal({
    title: t("chart_comment_label_prompt"),
    message: t("chart_comment_label_message"),
    defaultValue: t("chart_comment_default_title"),
    confirmLabel: t("chart_csv_paste_save"),
    cancelLabel: t("cancel"),
  });
  if (promptResult == null) {
    cancelPendingChartCommentPlacement();
    return true;
  }
  const nextComment = normalizeChartComment({
    title: String(promptResult).trim() || t("chart_comment_default_title"),
    tableId: pending.tableId,
    pointX: pending.pointX,
    pointPrecision: pending.pointPrecision,
    lane,
    align: getCommentAlignForLocalX(localX, anchorX),
    framed: false,
  });
  if (!nextComment) {
    cancelPendingChartCommentPlacement();
    return true;
  }
  getChartComments(chartItem).push(nextComment);
  normalizeChartItem(chartItem);
  state.pendingChartCommentPlacement = null;
  if (!state.expandedChartIds.includes(chartItem.id)) {
    state.expandedChartIds = [...state.expandedChartIds, chartItem.id];
  }
  renderEventList();
  updateChartStripControls();
  drawTimeline();
  scheduleLocalAutosave();
  return true;
}

function bindEventSelection(target, eventItem) {
  bindEventDrag(target, eventItem);
  target.addEventListener("click", () => {
    if (Date.now() < state.suppressClickUntil) {
      return;
    }

    if (state.clickTimer) {
      clearTimeout(state.clickTimer);
    }
    state.lastClickEventId = eventItem.id;
    state.lastClickTime = Date.now();
    state.clickTimer = window.setTimeout(() => {
      state.clickTimer = null;
      const shouldToggleTooltipClosed = state.tooltipEventId === eventItem.id && ui.eventTooltip && !ui.eventTooltip.hidden;
      if (shouldToggleTooltipClosed) {
        hideTooltip();
        state.selectedEventId = eventItem.id;
        updateSelectionPanel();
        drawTimeline();
        return;
      }
      state.tooltipEventId = eventItem.id;
      state.selectedEventId = eventItem.id;
      updateSelectionPanel();
      drawTimeline();
    }, 240);
  });
  target.addEventListener("dblclick", (event) => {
    event.preventDefault();
    if (Date.now() < state.suppressClickUntil) {
      return;
    }
    if (eventItem.kind === "source") {
      openSourceInLibrary(eventItem);
    } else {
      openEventInLibrary(eventItem);
    }
  });
  target.addEventListener("keydown", (event) => {
    if (event.key === "Enter" || event.key === " ") {
      event.preventDefault();
      if (eventItem.kind === "source") {
        openSourceInLibrary(eventItem);
      } else {
        openEventInLibrary(eventItem);
      }
    }
  });
}

function bindEventContextMenu(target, getPayload) {
  if (!target || typeof getPayload !== "function") return;
  target.addEventListener("contextmenu", (event) => {
    const payload = getPayload(event);
    if (!payload) return;
    showChartPointContextMenu(event, payload);
  });
}

function drawChartsOnTimeline({ paddingX, lineY }) {
  if (isChartHiddenMode()) {
    state.chartDragBounds = {};
    state.chartProbeCandidates = [];
    state.chartProbeSelection = null;
    state.chartProbeOcclusionRects = [];
    state.chartCollisionSegments = [];
    renderChartAxisHud(null, false);
    renderChartLegendHud([], [], false);
    return;
  }
  const visibleCharts = getVisibleCharts();
  const visibleRange = getVisibleRange();
  const additionalCalendarProbeCandidates = getAdditionalCalendarProbeCandidates({
    paddingX,
    lineY,
    visibleRangeMin: Math.min(visibleRange.start, visibleRange.end),
    visibleRangeMax: Math.max(visibleRange.start, visibleRange.end),
  });
  state.chartDragBounds = {};
  if (!visibleCharts.length) {
    state.chartProbeCandidates = additionalCalendarProbeCandidates;
    state.chartProbeSelection = resolveChartProbeSelection(state.chartProbePointer, additionalCalendarProbeCandidates);
    state.chartProbeOcclusionRects = [];
    state.chartCollisionSegments = [];
    renderChartAxisHud(null, false);
    renderChartLegendHud([], [], false);
    return;
  }
  const chartsMuted = isChartMuteMode();
  const deferredChartCommentLabels = [];
  const measurementCandidates = [];
  const probeOcclusionRects = [];
  const chartCollisionSegments = [];

  const step = getStep();
  const viewRange = getVisibleRange();
  const renderSpecsMap = new Map();
  const getRenderSpecs = (chartItem) => {
    if (renderSpecsMap.has(chartItem.id)) return renderSpecsMap.get(chartItem.id);
    const renderSpecs = getRenderableChartTables(chartItem, { step, viewRange });
    renderSpecsMap.set(chartItem.id, renderSpecs);
    return renderSpecs;
  };
  const visiblePointsMap = new Map();
  const getVisibleChartPoints = (chartItem) => {
    if (visiblePointsMap.has(chartItem.id)) return visiblePointsMap.get(chartItem.id);
    const visiblePoints = getRenderSpecs(chartItem)
      .flatMap((renderSpec) => getChartPointsForRenderSpec(renderSpec, { viewRange }));
    visiblePointsMap.set(chartItem.id, visiblePoints);
    return visiblePoints;
  };
  const renderedChartLineSegmentsMap = new Map();
  const getRenderedChartLineSegments = (renderSpec) => {
    const rangeKey = (Array.isArray(renderSpec?.ranges) ? renderSpec.ranges : [])
      .map((range) => `${range.min}:${range.max}`)
      .join("|");
    const cacheKey = `${renderSpec?.table?.id || "unknown"}::${rangeKey}::${viewRange.start}:${viewRange.end}`;
    if (renderedChartLineSegmentsMap.has(cacheKey)) return renderedChartLineSegmentsMap.get(cacheKey);
    const pointGroups = getChartEffectivePointGroups(renderSpec)
      .map((group) => group.filter((point) => Number.isFinite(point?.x) && Number.isFinite(point?.y)))
      .filter((group) => group.length >= 2);
    const effectiveRanges = intersectChartRanges(
      Array.isArray(renderSpec?.ranges) ? renderSpec.ranges : [],
      [{ min: viewRange.start, max: viewRange.end }],
    );
    const lineSegments = [];
    effectiveRanges.forEach((effectiveRange) => {
      pointGroups.forEach((sortedPoints) => {
        const linePoints = [];
        const pushLinePoint = (x, y, isActual = false, sourcePoint = null) => {
          if (!Number.isFinite(x) || !Number.isFinite(y)) return;
          const lastPoint = linePoints[linePoints.length - 1];
          if (lastPoint && Math.abs(lastPoint.x - x) < 1e-9 && Math.abs(lastPoint.y - y) < 1e-9) {
            if (isActual) {
              lastPoint.isActual = true;
              lastPoint.sourcePoint = sourcePoint ?? lastPoint.sourcePoint;
            }
            return;
          }
          linePoints.push({ x, y, isActual, sourcePoint });
        };

        for (let index = 0; index < sortedPoints.length - 1; index += 1) {
          const leftPoint = sortedPoints[index];
          const rightPoint = sortedPoints[index + 1];
          if (!Number.isFinite(leftPoint.x) || !Number.isFinite(rightPoint.x)) continue;
          const segmentMinX = Math.min(leftPoint.x, rightPoint.x);
          const segmentMaxX = Math.max(leftPoint.x, rightPoint.x);
          if (segmentMaxX < effectiveRange.min || segmentMinX > effectiveRange.max) continue;

          const interpolateY = (x) => {
            if (Math.abs(rightPoint.x - leftPoint.x) < 1e-9) return leftPoint.y;
            const ratio = (x - leftPoint.x) / (rightPoint.x - leftPoint.x);
            return leftPoint.y + ((rightPoint.y - leftPoint.y) * ratio);
          };

          const clippedStartX = Math.max(effectiveRange.min, segmentMinX);
          const clippedEndX = Math.min(effectiveRange.max, segmentMaxX);

          if (leftPoint.x >= effectiveRange.min && leftPoint.x <= effectiveRange.max) {
            pushLinePoint(leftPoint.x, leftPoint.y, true, leftPoint);
          } else if (clippedStartX > segmentMinX && clippedStartX < segmentMaxX) {
            pushLinePoint(clippedStartX, interpolateY(clippedStartX));
          }

          if (rightPoint.x >= effectiveRange.min && rightPoint.x <= effectiveRange.max) {
            pushLinePoint(rightPoint.x, rightPoint.y, true, rightPoint);
          } else if (clippedEndX > segmentMinX && clippedEndX < segmentMaxX) {
            pushLinePoint(clippedEndX, interpolateY(clippedEndX));
          }
        }
        if (linePoints.length >= 2) {
          lineSegments.push(linePoints);
        }
      });
    });

    renderedChartLineSegmentsMap.set(cacheKey, lineSegments);
    return lineSegments;
  };
  const activeChart = getActiveChart();
  const selectedAxisCharts = getSelectedAxisCharts(visibleCharts);
  const axisScaleMap = new Map();
  const buildChartScale = (allYValues, visibleYValues, bounds) => {
    const fullMin = allYValues.length ? Math.min(...allYValues) : 0;
    const fullMax = allYValues.length ? Math.max(...allYValues) : 1;
    const visibleMinRaw = visibleYValues.length ? Math.min(...visibleYValues) : fullMin;
    const visibleMaxRaw = visibleYValues.length ? Math.max(...visibleYValues) : fullMax;
    const fullRangeMin = fullMin === fullMax ? fullMin - 1 : fullMin;
    const fullRangeMax = fullMin === fullMax ? fullMax + 1 : fullMax;
    return {
      yMin: fullRangeMin,
      yMax: fullRangeMax,
      fullYMin: fullRangeMin,
      fullYMax: fullRangeMax,
      visibleValueMin: visibleMinRaw,
      visibleValueMax: visibleMaxRaw,
      bounds,
      mapY(value) {
        return bounds.chartBottom - ((value - fullRangeMin) / (fullRangeMax - fullRangeMin)) * bounds.chartHeight;
      },
      mapAxisY(value) {
        return bounds.chartBottom - ((value - fullRangeMin) / (fullRangeMax - fullRangeMin)) * bounds.chartHeight;
      },
    };
  };
  visibleCharts.forEach((chartItem) => {
    const bounds = getChartPlotBounds(lineY, chartItem, visibleCharts);
    if (bounds.chartBottom <= bounds.chartTop + 24) return;
    const visibleYValues = getVisibleChartPoints(chartItem).map((point) => point.y);
    const allYValues = getRenderSpecs(chartItem)
      .flatMap((renderSpec) => getChartScalePointsForRenderSpec(renderSpec).map((point) => point.y));
    axisScaleMap.set(chartItem.id, buildChartScale(allYValues, visibleYValues, bounds));
  });
  const selectedAxisGroupId = selectedAxisCharts.length ? getChartAxisGroupId(selectedAxisCharts[0]) : null;
  if (selectedAxisCharts.length > 1 && selectedAxisGroupId) {
    const visibleYValues = selectedAxisCharts.flatMap((chartItem) => getVisibleChartPoints(chartItem).map((point) => point.y));
    const allYValues = selectedAxisCharts.flatMap((chartItem) => (
      getRenderSpecs(chartItem).flatMap((renderSpec) => getChartScalePointsForRenderSpec(renderSpec).map((point) => point.y))
    ));
    const bounds = getChartPlotBounds(lineY, selectedAxisCharts[0], visibleCharts);
    if (bounds.chartBottom > bounds.chartTop + 24) {
      const sharedScale = buildChartScale(allYValues, visibleYValues, bounds);
      selectedAxisCharts.forEach((chartItem) => {
        axisScaleMap.set(chartItem.id, sharedScale);
      });
    }
  }
  const getChartScale = (chartItem) => axisScaleMap.get(chartItem.id);
  const getChartY = (chartItem, value) => getChartScale(chartItem)?.mapY(value) ?? lineY;
  const activeScaleChart = selectedAxisCharts[0] ?? activeChart;
  const activeScale = activeScaleChart ? getChartScale(activeScaleChart) : null;

  if (state.showYAxis && activeScaleChart?.yAxisEnabled !== false && activeScale) {
    const axisX = 10;
    const axisColor = chartsMuted ? '#8b949b' : (activeScaleChart?.color || '#a4b0b8');
    const extensionColor = chartsMuted ? 'rgba(139, 148, 155, 0.42)' : 'rgba(238, 243, 246, 0.34)';
    const axisCharts = selectedAxisCharts.length ? selectedAxisCharts : [activeScaleChart].filter(Boolean);
    const axisVisiblePoints = axisCharts.flatMap((chartItem) => getVisibleChartPoints(chartItem));
    const nearestVisibleX = axisVisiblePoints.length
      ? Math.min(...axisVisiblePoints.map((point) => getEventX(point.x)))
      : state.width;
    const availableLabelWidth = Math.max(28, nearestVisibleX - (axisX + 18));
    svg.appendChild(createSvgElement('line', {
      x1: axisX,
      y1: activeScale.bounds.chartTop,
      x2: axisX,
      y2: activeScale.bounds.chartBottom,
      stroke: 'rgba(238, 243, 246, 0.58)',
      'stroke-width': 1.4,
    }));
    [activeScale.fullYMax, activeScale.fullYMin].forEach((value) => {
      const y = activeScale.mapAxisY(value);
      svg.appendChild(createSvgElement('line', {
        x1: axisX - 5,
        y1: y,
        x2: axisX,
        y2: y,
        stroke: 'rgba(238, 243, 246, 0.58)',
        'stroke-width': 1.2,
      }));
    });
    const visibleAxisEntries = [
      { value: activeScale.visibleValueMax, y: activeScale.mapAxisY(activeScale.visibleValueMax) },
      { value: activeScale.visibleValueMin, y: activeScale.mapAxisY(activeScale.visibleValueMin) },
    ];
    const mergedAxisEntries = visibleAxisEntries.length === 2 && Math.abs(visibleAxisEntries[0].y - visibleAxisEntries[1].y) < 24
      ? [{
        value: (visibleAxisEntries[0].value + visibleAxisEntries[1].value) / 2,
        y: (visibleAxisEntries[0].y + visibleAxisEntries[1].y) / 2,
      }]
      : visibleAxisEntries.filter((entry, index, entries) => index === 0 || Math.abs(entry.value - entries[index - 1].value) >= 1e-9);
    mergedAxisEntries.forEach(({ value, y }) => {
      const fullText = formatChartAxisValue(value);
      const estimatedWidth = fullText.length * 6.6;
      const compact = estimatedWidth > availableLabelWidth;
      svg.appendChild(createSvgElement('line', {
        x1: axisX - 7,
        y1: y,
        x2: axisX,
        y2: y,
        stroke: 'rgba(238, 243, 246, 0.9)',
        'stroke-width': 1.4,
      }));
      const label = createSvgElement('text', {
        x: axisX + 8,
        y: y + 4,
        fill: axisColor,
        opacity: 0.96,
        'font-size': scaleTimelineTextSize(11),
        'font-family': 'Segoe UI, Arial, sans-serif',
        'text-anchor': 'start',
      });
      label.textContent = formatChartAxisValue(value, { compact });
      svg.appendChild(label);
    });
    if (activeScaleChart.showZeroExtension === true) {
      const allPositive = activeScale.fullYMin > 0 && activeScale.fullYMax > 0;
      const allNegative = activeScale.fullYMin < 0 && activeScale.fullYMax < 0;
      const spansZero = activeScale.fullYMin < 0 && activeScale.fullYMax > 0;
      if (allPositive || allNegative) {
        const extensionLength = 26;
        const extensionStartY = allPositive ? activeScale.bounds.chartBottom : activeScale.bounds.chartTop;
        const extensionEndY = allPositive
          ? Math.min(state.height - 14, extensionStartY + extensionLength)
          : Math.max(14, extensionStartY - extensionLength);
        svg.appendChild(createSvgElement('line', {
          x1: axisX,
          y1: extensionStartY,
          x2: axisX,
          y2: extensionEndY,
          stroke: extensionColor,
          'stroke-width': 1.2,
        }));
        svg.appendChild(createSvgElement('line', {
          x1: axisX - 5,
          y1: extensionEndY,
          x2: axisX,
          y2: extensionEndY,
          stroke: extensionColor,
          'stroke-width': 1.1,
        }));
        const zeroLabel = createSvgElement('text', {
          x: axisX + 8,
          y: extensionEndY + 4,
          fill: chartsMuted ? '#8b949b' : 'rgba(238, 243, 246, 0.62)',
          'font-size': scaleTimelineTextSize(11),
          'font-family': 'Segoe UI, Arial, sans-serif',
          'text-anchor': 'start',
        });
        zeroLabel.textContent = "0";
        svg.appendChild(zeroLabel);
      } else if (spansZero) {
        const zeroY = activeScale.mapAxisY(0);
        svg.appendChild(createSvgElement('line', {
          x1: axisX - 7,
          y1: zeroY,
          x2: axisX,
          y2: zeroY,
          stroke: extensionColor,
          'stroke-width': 1.2,
        }));
        const zeroLabel = createSvgElement('text', {
          x: axisX + 8,
          y: zeroY + 4,
          fill: chartsMuted ? '#8b949b' : 'rgba(238, 243, 246, 0.62)',
          'font-size': scaleTimelineTextSize(11),
          'font-family': 'Segoe UI, Arial, sans-serif',
          'text-anchor': 'start',
        });
        zeroLabel.textContent = "0";
        svg.appendChild(zeroLabel);
      }
    }
  }

  renderChartAxisHud(activeScaleChart, chartsMuted, selectedAxisCharts);
  renderChartLegendHud(visibleCharts, selectedAxisCharts, chartsMuted);

  visibleCharts.forEach((chartItem) => {
    const preset = getChartDisplayPreset(chartItem);
    const chartScale = getChartScale(chartItem);
    if (!chartScale) return;
    const renderSpecs = getRenderSpecs(chartItem);
    renderSpecs.forEach((renderSpec) => {
      const { table } = renderSpec;
      const renderColor = chartsMuted ? '#8b949b' : (table.color || getChartRenderColor(chartItem));
      const pointPrecision = table.xPrecision || chartItem.xPrecision;
      const pointUnit = String(table.sourceUnit || chartItem.sourceUnit || '').trim();
      const pointTitle = table.title ? `${chartItem.title} · ${table.title}` : chartItem.title;
      const visiblePoints = getChartPointsForRenderSpec(renderSpec, { viewRange }).filter((point) => {
        if (point.x < viewRange.start || point.x > viewRange.end) return false;
        const x = getEventX(point.x);
        return x >= paddingX - 24 && x <= state.width - paddingX + 24;
      });
      const lineSegments = getRenderedChartLineSegments(renderSpec)
        .map((segment) => segment.filter((point) => {
          const x = getEventX(point.x);
          return x >= paddingX - 24 && x <= state.width - paddingX + 24;
        }))
        .filter((segment) => segment.length >= 2);
      if (!lineSegments.length) return;
      lineSegments.forEach((linePoints) => {
        const pointCoordinates = linePoints.map((point) => `${getEventX(point.x)},${getChartY(chartItem, point.y)}`);
        for (let index = 0; index < linePoints.length - 1; index += 1) {
          const leftPoint = linePoints[index];
          const rightPoint = linePoints[index + 1];
          chartCollisionSegments.push({
            x1: getEventX(leftPoint.x),
            y1: getChartY(chartItem, leftPoint.y),
            x2: getEventX(rightPoint.x),
            y2: getChartY(chartItem, rightPoint.y),
          });
        }

        if (table.fillMode === 'soft') {
          const fillPolygon = createSvgElement('polygon', {
            fill: renderColor,
            opacity: Math.min(0.16, preset.opacity * 0.2),
            points: [
              ...pointCoordinates,
              `${getEventX(linePoints[linePoints.length - 1].x)},${chartScale.bounds.chartBottom}`,
              `${getEventX(linePoints[0].x)},${chartScale.bounds.chartBottom}`,
            ].join(' '),
          });
          bindChartOpenOnDblClick(fillPolygon, chartItem);
          svg.appendChild(fillPolygon);
        }

        const polyline = createSvgElement('polyline', {
          fill: 'none',
          stroke: renderColor,
          opacity: preset.opacity,
          'stroke-width': preset.strokeWidth,
          'stroke-linejoin': 'round',
          'stroke-linecap': 'round',
          points: pointCoordinates.join(' '),
        });
        const polylineDasharray = getLineStyleDasharray(table.lineStyle);
        if (polylineDasharray) {
          polyline.setAttribute('stroke-dasharray', polylineDasharray);
        }
        bindChartDrag(polyline, chartItem, lineY);
        bindChartOpenOnDblClick(polyline, chartItem);
        svg.appendChild(polyline);

        const dragHit = createSvgElement('polyline', {
          fill: 'none',
          stroke: 'transparent',
          'stroke-width': 18,
          'stroke-linejoin': 'round',
          'stroke-linecap': 'round',
          points: pointCoordinates.join(' '),
        });
        bindChartDrag(dragHit, chartItem, lineY);
        bindChartOpenOnDblClick(dragHit, chartItem);
        svg.appendChild(dragHit);
      });

      visiblePoints.forEach((point) => {
        const pointX = getEventX(point.x);
        const pointY = getChartY(chartItem, point.y);
        measurementCandidates.push({
          chartId: chartItem.id,
          tableId: table.id,
          pointId: point.id || `${table.id}:${point.x}:${point.y}`,
          pointX: point.x,
          pointY: point.y,
          screenX: pointX,
          screenY: pointY,
          color: renderColor,
          sourceTitle: String(point?.sourceTitle || table?.sourceTitle || chartItem?.sourceTitle || "").trim(),
        });
        if (state.chartPointsHidden) return;
        const pointHoverHit = createSvgElement('circle', {
          cx: pointX,
          cy: pointY,
          r: 10,
          fill: '#ffffff',
          opacity: 0.001,
          'pointer-events': 'all',
        });
        pointHoverHit.addEventListener('contextmenu', (event) => {
          showChartPointContextMenu(event, {
            kind: "point",
            chartId: chartItem.id,
            tableId: table.id,
            pointX: point.x,
            pointY: point.y,
            pointPrecision: point.precision ?? pointPrecision ?? null,
          });
        });
        bindChartDrag(pointHoverHit, chartItem, lineY);
        bindChartOpenOnDblClick(pointHoverHit, chartItem);
        svg.appendChild(pointHoverHit);
        const pointIsUncertain = isChartPointUncertain(point);
        const pointMarker = createSvgElement('circle', {
          cx: pointX,
          cy: pointY,
          r: chartItem.id === activeChart?.id ? 3.4 : 2.6,
          fill: pointIsUncertain ? state.backgroundColor : renderColor,
          stroke: renderColor,
          'stroke-width': pointIsUncertain ? 1.8 : 0.6,
          opacity: Math.min(1, preset.opacity + 0.08),
          'pointer-events': 'all',
        });
        pointMarker.addEventListener('contextmenu', (event) => {
          showChartPointContextMenu(event, {
            kind: "point",
            chartId: chartItem.id,
            tableId: table.id,
            pointX: point.x,
            pointY: point.y,
            pointPrecision: point.precision ?? pointPrecision ?? null,
          });
        });
        bindChartDrag(pointMarker, chartItem, lineY);
        bindChartOpenOnDblClick(pointMarker, chartItem);
        svg.appendChild(pointMarker);
      });
    });
    getChartComments(chartItem)
      .filter((comment) => comment.enabled !== false && isItemVisibleAtCurrentZoom(comment))
      .forEach((comment) => {
        const resolvedPoint = findChartPointForComment(chartItem, comment, renderSpecs);
        if (!resolvedPoint) return;
        const commentColor = chartsMuted
          ? '#8b949b'
          : (comment.color || resolvedPoint.table.color || getChartRenderColor(chartItem));
        const commentLineStyle = comment.lineStyle || resolvedPoint.table.lineStyle || chartItem.lineStyle;
        const anchorX = getEventX(resolvedPoint.point.x);
        if (anchorX < paddingX - 24 || anchorX > state.width - paddingX + 24) return;
        const anchorY = getChartY(chartItem, resolvedPoint.point.y);
        const markerY = getMarkerYForCommentLane(comment.lane == null ? 1 : comment.lane, lineY);
        const connector = createSvgElement('line', {
          x1: anchorX,
          y1: anchorY,
          x2: anchorX,
          y2: markerY,
          stroke: commentColor,
          opacity: 0.8,
          'stroke-width': 1.6,
        });
        const connectorDasharray = getLineStyleDasharray(commentLineStyle);
        if (connectorDasharray) {
          connector.setAttribute('stroke-dasharray', connectorDasharray);
        }
        svg.appendChild(connector);

        const commentMarker = createSvgElement('circle', {
          cx: anchorX,
          cy: markerY,
          r: 4.5,
          fill: commentColor,
          opacity: 0.96,
        });
        commentMarker.addEventListener('contextmenu', (event) => {
          showChartPointContextMenu(event, {
            kind: "comment",
            chartId: chartItem.id,
            commentId: comment.id,
          });
        });
        const showCommentTooltip = () => {
          const xLabel = formatChartPointX(resolvedPoint.point.x, resolvedPoint.table.xPrecision || chartItem.xPrecision, resolvedPoint.point.precision);
          showInfoTooltip(
            comment.title || t('chart_comment_default_title'),
            `${t('chart_comment_anchor')}: ${xLabel}`,
            comment.description || chartItem.title || t('chart_comment_source_none'),
            anchorX,
            markerY,
          );
        };
        commentMarker.addEventListener('click', (event) => {
          event.stopPropagation();
          if (Date.now() < state.suppressClickUntil) return;
          if (state.clickTimer) {
            clearTimeout(state.clickTimer);
          }
          state.lastClickEventId = comment.id;
          state.lastClickTime = Date.now();
          state.clickTimer = window.setTimeout(() => {
            state.clickTimer = null;
            showCommentTooltip();
          }, 240);
        });
        commentMarker.addEventListener('dblclick', (event) => {
          event.preventDefault();
          event.stopPropagation();
          if (Date.now() < state.suppressClickUntil) return;
          if (state.clickTimer) {
            clearTimeout(state.clickTimer);
            state.clickTimer = null;
          }
          openChartCommentInLibrary(chartItem, comment);
        });
        bindChartCommentDrag(commentMarker, comment);
        svg.appendChild(commentMarker);

        const commentLabel = createChartCommentLabelCard({
          x: anchorX,
          y: markerY,
          text: getMarkdownPlainText(comment.title || t('chart_comment_default_title')),
          description: comment.description || "",
          color: commentColor,
          muted: chartsMuted,
          framed: comment.framed !== false,
          align: comment.align || "right",
        });
        if (commentLabel?.bounds) {
          probeOcclusionRects.push(commentLabel.bounds);
        }
        deferredChartCommentLabels.push(commentLabel.element);
      });
  });

  state.chartProbeCandidates = [...measurementCandidates, ...additionalCalendarProbeCandidates];
  state.chartProbeOcclusionRects = probeOcclusionRects;
  state.chartProbeSelection = resolveChartProbeSelection(state.chartProbePointer, state.chartProbeCandidates);
  state.chartCollisionSegments = chartCollisionSegments;
  const probeLine = createChartProbeLineElement(lineY);
  if (probeLine) {
    svg.appendChild(probeLine);
  }

  deferredChartCommentLabels.forEach((label) => {
    svg.appendChild(label);
  });

  if (state.pendingChartCommentPlacement) {
    const pending = state.pendingChartCommentPlacement;
    if (pending.kind !== "timeline") {
      const chartItem = getChartById(pending.chartId);
      if (chartItem) {
      const renderSpecs = getRenderSpecs(chartItem);
      const previewComment = {
        tableId: pending.tableId,
        pointX: pending.pointX,
      };
        const resolvedPoint = findChartPointForComment(chartItem, previewComment, renderSpecs);
        if (resolvedPoint) {
        const previewColor = resolvedPoint.table.color || getChartRenderColor(chartItem);
        const anchorX = getEventX(resolvedPoint.point.x);
        const anchorY = getChartY(chartItem, resolvedPoint.point.y);
        const previewLane = getNearestChartCommentLaneFromY(pending.pointerY ?? lineY, lineY);
        const markerY = getMarkerYForCommentLane(previewLane, lineY);
        const previewLine = createSvgElement('line', {
          x1: anchorX,
          y1: anchorY,
          x2: anchorX,
          y2: markerY,
          stroke: previewColor,
          opacity: 0.95,
          'stroke-width': 1.8,
          'stroke-dasharray': getLineStyleDasharray("dashed"),
        });
        const previewMarker = createSvgElement('circle', {
          cx: anchorX,
          cy: markerY,
          r: 4.5,
          fill: previewColor,
          opacity: 0.95,
        });
        svg.appendChild(previewLine);
        svg.appendChild(previewMarker);
      }
    }
    }
  }

}

function drawPendingTimelineCommentPlacementPreview(lineY) {
  const pending = state.pendingChartCommentPlacement;
  if (!pending || pending.kind !== "timeline") return;
  const previewColor = "#c96f4a";
  const anchorX = getEventX(pending.timeValue);
  const previewLane = getNearestChartCommentLaneFromY(pending.pointerY ?? lineY, lineY);
  const markerY = getMarkerYForCommentLane(previewLane, lineY);
  const previewLine = createSvgElement("line", {
    x1: anchorX,
    y1: lineY,
    x2: anchorX,
    y2: markerY,
    stroke: previewColor,
    opacity: 0.95,
    "stroke-width": 1.8,
    "stroke-dasharray": getLineStyleDasharray("dashed"),
  });
  const previewMarker = createSvgElement("circle", {
    cx: anchorX,
    cy: markerY,
    r: 4.5,
    fill: previewColor,
    opacity: 0.95,
  });
  svg.appendChild(previewLine);
  svg.appendChild(previewMarker);
}

function drawPendingEventCommentPlacementPreview(eventGeometries, lineY) {
  const pending = state.pendingChartCommentPlacement;
  if (!pending || pending.kind !== "event") return;
  const eventItem = getEditableTimelineItemById(pending.eventId);
  const geometry = eventItem ? eventGeometries.get(eventItem.id) : null;
  if (!eventItem || !geometry) return;
  const previewColor = eventItem.color || (isBarDisplay(eventItem) ? BAR_DEFAULT_COLOR : "#9ed3df");
  const anchorX = getEventX(pending.anchorTimeValue);
  const previewLane = getNearestChartCommentLaneFromY(pending.pointerY ?? lineY, lineY);
  const markerY = getMarkerYForCommentLane(previewLane, lineY);
  const previewLine = createSvgElement("line", {
    x1: anchorX,
    y1: geometry.markerY,
    x2: anchorX,
    y2: markerY,
    stroke: previewColor,
    opacity: 0.95,
    "stroke-width": 1.8,
    "stroke-dasharray": getLineStyleDasharray("dashed"),
  });
  const previewMarker = createSvgElement("circle", {
    cx: anchorX,
    cy: markerY,
    r: 4.5,
    fill: previewColor,
    opacity: 0.95,
  });
  svg.appendChild(previewLine);
  svg.appendChild(previewMarker);
}

function drawEventCommentsOnTimeline(visibleEvents, eventGeometries, lineY) {
  const deferredLabels = [];
  visibleEvents.forEach((eventItem) => {
    const geometry = eventGeometries.get(eventItem.id);
    if (!geometry) return;
    getEventComments(eventItem)
      .filter((comment) => comment.enabled !== false && isItemVisibleAtCurrentZoom(comment))
      .forEach((comment) => {
        const commentColor = comment.color || getEffectiveColor(eventItem) || (isBarDisplay(eventItem) ? BAR_DEFAULT_COLOR : "#9ed3df");
        const anchorX = getEventX(comment.anchorTimeValue);
        if (anchorX < TIMELINE_PADDING_X - 24 || anchorX > state.width - TIMELINE_PADDING_X + 24) return;
        const markerY = getMarkerYForCommentLane(comment.lane, lineY);
        const connector = createSvgElement("line", {
          x1: anchorX,
          y1: geometry.markerY,
          x2: anchorX,
          y2: markerY,
          stroke: commentColor,
          "stroke-width": 1.8,
          opacity: 0.95,
          "stroke-linecap": "round",
        });
        const connectorDasharray = getLineStyleDasharray(comment.lineStyle);
        if (connectorDasharray) {
          connector.setAttribute("stroke-dasharray", connectorDasharray);
        }
        svg.appendChild(connector);
        const marker = createSvgElement("circle", {
          cx: anchorX,
          cy: markerY,
          r: 4.5,
          fill: commentColor,
          opacity: 0.96,
        });
        marker.addEventListener("contextmenu", (event) => {
          showChartPointContextMenu(event, {
            kind: "event-comment",
            commentId: comment.id,
          });
        });
        const showCommentTooltip = () => {
          showInfoTooltip(
            comment.title || t("chart_comment_default_title"),
            `${t("timeline_comment_time")}: ${formatTimelineValue(comment.anchorTimeValue, comment.anchorTimePrecision ?? 9)}`,
            comment.description || eventItem.title || t("no_description"),
            anchorX,
            markerY,
          );
        };
        marker.addEventListener("click", (event) => {
          event.stopPropagation();
          if (Date.now() < state.suppressClickUntil) return;
          if (event.detail >= 2) {
            if (state.clickTimer) {
              clearTimeout(state.clickTimer);
              state.clickTimer = null;
            }
            openEventCommentInLibrary(eventItem, comment, { forceOpen: true });
            return;
          }
          if (state.clickTimer) clearTimeout(state.clickTimer);
          state.lastClickEventId = comment.id;
          state.lastClickTime = Date.now();
          state.clickTimer = window.setTimeout(() => {
            state.clickTimer = null;
            showCommentTooltip();
          }, 240);
        });
        marker.addEventListener("dblclick", (event) => {
          event.preventDefault();
          event.stopPropagation();
          if (state.clickTimer) {
            clearTimeout(state.clickTimer);
            state.clickTimer = null;
          }
          openEventCommentInLibrary(eventItem, comment, { forceOpen: true });
        });
        bindEventCommentDrag(marker, comment);
        svg.appendChild(marker);
        const label = createChartCommentLabelCard({
          x: anchorX,
          y: markerY,
          text: getMarkdownPlainText(comment.title || t("chart_comment_default_title")),
          description: comment.description || "",
          color: commentColor,
          muted: false,
          framed: comment.framed === true,
          align: comment.align || "right",
          clampToViewport: false,
        });
        label.element.setAttribute("pointer-events", "all");
        label.element.addEventListener("contextmenu", (event) => {
          showChartPointContextMenu(event, {
            kind: "event-comment",
            commentId: comment.id,
          });
        });
        label.element.addEventListener("click", (event) => {
          event.stopPropagation();
          if (Date.now() < state.suppressClickUntil) return;
          if (event.detail >= 2) {
            if (state.clickTimer) {
              clearTimeout(state.clickTimer);
              state.clickTimer = null;
            }
            openEventCommentInLibrary(eventItem, comment, { forceOpen: true });
            return;
          }
          if (state.clickTimer) clearTimeout(state.clickTimer);
          state.lastClickEventId = comment.id;
          state.lastClickTime = Date.now();
          state.clickTimer = window.setTimeout(() => {
            state.clickTimer = null;
            showCommentTooltip();
          }, 240);
        });
        label.element.addEventListener("dblclick", (event) => {
          event.preventDefault();
          event.stopPropagation();
          if (state.clickTimer) {
            clearTimeout(state.clickTimer);
            state.clickTimer = null;
          }
          openEventCommentInLibrary(eventItem, comment, { forceOpen: true });
        });
        bindEventCommentDrag(label.element, comment);
        deferredLabels.push(label.element);
      });
  });
  deferredLabels.forEach((element) => svg.appendChild(element));
}

