function createTrashRestoreButton(handler) {
  const restoreButton = document.createElement("button");
  restoreButton.type = "button";
  restoreButton.className = "group-row-export trash-row-restore";
  restoreButton.textContent = t("restore_label");
  restoreButton.addEventListener("click", (event) => {
    event.stopPropagation();
    handler();
    pruneEmptyProjectSpecialFolders();
    renderEventList();
    renderSearchResults();
    renderChartResults();
    updateSelectionPanel();
    drawTimeline();
  });
  return restoreButton;
}

