function renderEventList() {
  const editorPanelScrollTop = ui.editorPanel?.scrollTop ?? null;
  const searchPanelScrollTop = ui.searchPanel?.scrollTop ?? null;
  migrateLegacyFlagMarkerChildren();
  sanitizeEventHierarchy();
  state.tickBookmarks = sanitizeTickBookmarksCollection(state.tickBookmarks);
  moveLooseBrowserItemsIntoProject();
  normalizeSourceSubtypeGroups();
  pruneEmptyProjectSpecialFolders();
  if (state.openBookmarkEditorId && !state.tickBookmarks.some((bookmark) => bookmark.id === state.openBookmarkEditorId)) {
    state.openBookmarkEditorId = null;
  }
  if (state.openTimelineCommentEditorId && !timelineComments.some((comment) => comment.id === state.openTimelineCommentEditorId)) {
    state.openTimelineCommentEditorId = null;
  }
  if (state.openEventCommentEditorId && !findEventCommentById(state.openEventCommentEditorId)) {
    state.openEventCommentEditorId = null;
  }
  if (state.openChartEditorId && !chartItems.some((chartItem) => chartItem.id === state.openChartEditorId)) {
    state.openChartEditorId = null;
  }
  if (state.openChartCommentEditorId && !findChartCommentById(state.openChartCommentEditorId)) {
    state.openChartCommentEditorId = null;
  }
  if (!chartItems.length) {
    state.chartFolderExpanded = false;
  }
  if (!getUngroupedSourcesSorted().length) {
    state.sourceFolderExpanded = false;
  }
  const browserGroups = getBrowserGroups();
  const ungroupedEvents = getUngroupedEvents();
  if (!getUngroupedBookmarks().length) {
    state.bookmarkFolderExpanded = false;
  }
  if (!getUngroupedTimelineComments().length) {
    state.timelineCommentFolderExpanded = false;
  }
  if (!hasTrashEntries()) {
    state.trashFolderExpanded = false;
  }
  if (!ungroupedEvents.length) {
    state.eventsFolderExpanded = false;
  }
  if (!browserGroups.length) {
    state.eventProjectsFolderExpanded = false;
  }
  ui.eventList.replaceChildren();
  chartItems.forEach(normalizeChartItem);
  ui.eventBrowserInfo.textContent = `${tf("browser_info", { events: timelineEvents.length, folders: browserGroups.length })}${chartItems.length ? `, ${chartItems.length} ${t("chart_browser_label")}` : ""}${sourceItems.length ? `, ${sourceItems.length} ${t("sources_folder")}` : ""}${sourceCollections.length ? `, ${sourceCollections.length} ${t("source_collections_folder")}` : ""}${state.tickBookmarks.length ? `, ${state.tickBookmarks.length} ${t("bookmarks_folder")}` : ""}${timelineComments.length ? `, ${timelineComments.length} ${t("timeline_folder")}` : ""}`;

  if (timelineEvents.length === 0 && browserGroups.length === 0 && chartItems.length === 0 && sourceItems.length === 0 && sourceCollections.length === 0 && state.tickBookmarks.length === 0 && timelineComments.length === 0 && !state.folderImportLoading) {
    ui.editorEmptyState.hidden = false;
    const emptyState = document.createElement("p");
    emptyState.className = "event-description";
    emptyState.textContent = t("browser_empty");
    ui.eventList.appendChild(emptyState);
  } else {
    ui.editorEmptyState.hidden = true;
  }
  browserGroups.forEach((groupItem) => {
    const loadingState = state.folderImportLoading?.groupId === groupItem.id ? state.folderImportLoading : null;
    ui.eventList.appendChild(createGroupBrowserItem(groupItem, { loadingState }));
  });
  ui.eventList.appendChild(createTrashFolderBrowserItem());
  updateRenderLibraryButtonState();
  renderDetailsSidePanel();
  requestAnimationFrame(() => {
    if (ui.editorPanel && editorPanelScrollTop != null) {
      ui.editorPanel.scrollTop = editorPanelScrollTop;
    }
    if (ui.searchPanel && searchPanelScrollTop != null) {
      ui.searchPanel.scrollTop = searchPanelScrollTop;
    }
  });
  scheduleLocalAutosave();
}

function pan(direction) {
  const step = getStep();
  if (step.unit === "year") {
    state.subYearTickAnchorValue = null;
    state.centerYear = state.centerYear + direction * getStepYears(step);
  } else {
    state.centerYear = shiftTimelineValueByStep(state.centerYear, step, direction);
    state.subYearTickAnchorValue = state.subYearTickAnchorValue != null
      ? shiftTimelineValueByStep(state.subYearTickAnchorValue, step, direction)
      : alignTimelineValueToStepStart(state.centerYear, step);
  }
  drawTimeline();
}

function zoom(direction) {
  const currentStep = getStep();
  const nextIndex = clamp(state.stepIndex + direction, 0, scaleSteps.length - 1);
  if (nextIndex === state.stepIndex) return;
  const nextStep = scaleSteps[nextIndex];
  const isSubYearTransition = currentStep.unit !== "year" || nextStep.unit !== "year";
  const anchoredValue = getClosestVisibleTickValue(state.centerYear);
  const ratio = 0.5;
  state.subYearTickAnchorValue = isSubYearTransition
    ? alignTimelineValueToStepStart(anchoredValue, nextStep)
    : null;
  state.stepIndex = nextIndex;
  const newHalfRange = Math.floor(state.tickCount / 2) * getStepYears();
  state.centerYear = anchoredValue - ((ratio * 2) - 1) * newHalfRange;
  drawTimeline();
}

function zoomAtClientX(direction, clientX) {
  const currentStep = getStep();
  const nextIndex = clamp(state.stepIndex + direction, 0, scaleSteps.length - 1);
  if (nextIndex === state.stepIndex) return;

  const nextStep = scaleSteps[nextIndex];
  const anchoredValue = getTimelineValueAtRatio(getTimelineRatioForClientX(clientX));
  const ratio = getTimelineRatioForClientX(clientX);

  state.subYearTickAnchorValue = currentStep.unit !== "year" || nextStep.unit !== "year"
    ? alignTimelineValueToStepStart(anchoredValue, nextStep)
    : null;
  state.stepIndex = nextIndex;
  const newHalfRange = Math.floor(state.tickCount / 2) * getStepYears();
  state.centerYear = anchoredValue - ((ratio * 2) - 1) * newHalfRange;
  drawTimeline();
}

function resetView() {
  state.subYearTickAnchorValue = null;
  state.centerYear = getNowTimelineValue();
  state.stepIndex = scaleSteps.findIndex((step) => step.id === "1a");
  clearSelectedEvent();
}

function handleWheel(event) {
  event.preventDefault();
  const direction = event.deltaY > 0 ? 1 : -1;
  if (event.shiftKey) {
    zoomAtClientX(direction, event.clientX);
    return;
  }
  pan(direction);
}

function handleScrollAnchor() {
  syncActiveWorkspaceSectionFromScroll();
}

function createSearchResultItem(result) {
  const wrapper = document.createElement("label");
  wrapper.className = "search-result";
  const matchingEvents = getEventsWithSameSourceIdInScope(result.id, UNGROUPED_EVENT_SCOPE_KEY);
  const hasEnabledMatch = matchingEvents.some((eventItem) => eventItem.enabled !== false);
  if (hasEnabledMatch) wrapper.classList.add("is-imported");

  const checkbox = document.createElement("input");
  checkbox.type = "checkbox";
  checkbox.checked = hasEnabledMatch;
  checkbox.disabled = state.pendingAdds.has(result.id);
  checkbox.addEventListener("change", async () => {
    if (!checkbox.checked) {
      const needsConfirmation = matchingEvents.some((eventItem) => eventHasLibraryRelations(eventItem));
      if (needsConfirmation) {
        const confirmed = await confirmDeleteFromLibrary();
        if (!confirmed) {
          checkbox.checked = true;
          return;
        }
      }
      const matchingIds = new Set(matchingEvents.map((eventItem) => eventItem.id));
      if (matchingIds.has(state.selectedEventId)) {
        state.selectedEventId = null;
      }
      if (matchingIds.has(state.openEditorId)) {
        state.openEditorId = null;
      }
      for (let index = timelineEvents.length - 1; index >= 0; index -= 1) {
        if (
          timelineEvents[index].sourceId === result.id
          && getEventDuplicateScopeKey(timelineEvents[index]) === UNGROUPED_EVENT_SCOPE_KEY
        ) {
          timelineEvents.splice(index, 1);
        }
      }
      updateSelectionPanel();
      ui.searchStatus.textContent = tf("result_added", { title: result.label });
      renderEventList();
      renderSearchResults();
      drawTimeline();
      return;
    }
    if (matchingEvents.length > 0) {
      matchingEvents.forEach((eventItem) => {
        eventItem.enabled = true;
      });
      ui.searchStatus.textContent = tf("result_added", { title: result.label });
      renderEventList();
      renderSearchResults();
      drawTimeline();
      return;
    }
    state.pendingAdds.add(result.id);
    checkbox.disabled = true;
    setSearchLoadingState({
      visible: true,
      text: tf("loading_result", { title: result.label }),
      progress: 18,
    });
    let eventItem = null;
    try {
      eventItem = await addSearchResult(result, ({ text, progress }) => {
        setSearchLoadingState({ visible: true, text, progress });
      });
    } finally {
      state.pendingAdds.delete(result.id);
    }
    if (eventItem) {
        setSearchLoadingState({
          visible: true,
          text: t("loading_update_view"),
          progress: 92,
        });
        ui.searchStatus.textContent = tf("result_added", { title: eventItem.title });
        state.openGroupEditorId = null;
        state.openEditorId = eventItem.id;
        selectEvent(eventItem.id, true);
        renderEventList();
        scrollToDetails("auto");
        focusEditorNameField("event", { reveal: true, behavior: "auto" });
        setSearchLoadingState({
          visible: true,
          text: tf("result_added", { title: eventItem.title }),
          progress: 100,
        });
        hideSearchLoading(180);
    } else {
      checkbox.checked = false;
      checkbox.disabled = false;
      ui.searchStatus.textContent = tf("result_no_years", { title: result.label });
      hideSearchLoading(180);
    }
    renderSearchResults();
  });

  const content = document.createElement("div");
  content.className = "search-result-content";
  const head = document.createElement("div");
  head.className = "search-result-head";
  const title = document.createElement("strong");
  title.textContent = result.label;
  const recordId = document.createElement("small");
  recordId.className = "search-result-id";
  recordId.textContent = result.externalId ? `${result.externalId} · ${result.id}` : result.id;
  const description = document.createElement("span");
  description.className = "search-result-description";
  description.textContent = result.description || t("no_description");
  const meta = document.createElement("small");
  meta.className = "search-result-meta";
  meta.textContent = checkbox.checked ? t("search_added") : t("search_add_hint");
  head.append(title, recordId);
  content.append(head, description, meta);

  wrapper.append(checkbox, content);
  return wrapper;
}

async function importLibraryPayloadFromFile(file) {
  if (!file) return;
  try {
    const fileContent = await file.text();
    const lowerName = String(file.name || "").toLowerCase();

    if (lowerName.endsWith(".csv") || lowerName.endsWith(".tsv")) {
      const importedCharts = importDelimitedChartText(fileContent, file.name);
      const importedChart = importedCharts[0];
      if (importedChart) {
        activateChartAxisSelection(importedChart);
        state.chartFolderExpanded = true;
        state.openChartEditorId = null;
        if (ui.chartStatus) ui.chartStatus.textContent = tf("chart_status_imported", { title: importedChart.title });
      }
      updateChartStripControls();
      renderEventList();
      renderChartResults();
      drawTimeline();
      scrollToDetails("auto");
      return;
    }

    let payload = null;
    try {
      payload = JSON.parse(fileContent);
    } catch {
      payload = null;
    }
    const looksLikeFolderExport = payload?.type === "timemap-folder-export";
    const looksLikeChartImport = Boolean(payload && parseChartImportPayload(payload).length);

    if (looksLikeChartImport && !looksLikeFolderExport) {
      const importedCharts = importChartPayload(payload);
      const importedChart = importedCharts[0];
      if (importedChart) {
        activateChartAxisSelection(importedChart);
        state.chartFolderExpanded = true;
        state.openChartEditorId = null;
        if (ui.chartStatus) ui.chartStatus.textContent = tf("chart_status_imported", { title: importedChart.title });
      }
      updateChartStripControls();
      renderEventList();
      renderChartResults();
      drawTimeline();
      scrollToDetails("auto");
      return;
    }

    hideSearchLoading();
    setFolderImportLoading({
      visible: true,
      title: file.name,
      text: tf("loading_read_file", { title: file.name }),
      progress: 12,
    });
    await waitForNextPaint();
    setFolderImportLoading({
      visible: true,
      title: file.name,
      text: t("loading_parse_file"),
      progress: 34,
    });
    await waitForNextPaint();
    if (!looksLikeFolderExport) {
      throw new Error("invalid-import-payload");
    }
    setFolderImportLoading({
      visible: true,
      title: payload.title ?? file.name,
      text: tf("loading_import_folder", { title: payload.title ?? file.name }),
      progress: 52,
      groupId: null,
    });
    await waitForNextPaint();
    await importFolderPayload(payload, ({ title, text, progress, groupId }) => {
      setFolderImportLoading({
        visible: true,
        title: title ?? payload.title ?? file.name,
        text,
        progress,
        groupId: groupId ?? null,
      });
    });
    setFolderImportLoading({
      visible: true,
      title: payload.title ?? file.name,
      text: t("loading_update_view"),
      progress: 100,
      groupId: state.folderImportLoading?.groupId ?? null,
    });
    await waitForNextPaint();
    window.setTimeout(() => {
      setFolderImportLoading({ visible: false });
    }, 180);
  } catch (error) {
    if (error?.message === "chart-csv-missing-columns" || error?.message === "invalid-chart-payload") {
      if (ui.chartStatus) {
        ui.chartStatus.textContent = error?.message === "chart-csv-missing-columns"
          ? t("chart_csv_missing_columns")
          : t("chart_import_failed");
      }
    } else {
      ui.eventBrowserInfo.textContent = t("import_failed");
      window.setTimeout(() => {
        setFolderImportLoading({ visible: false });
      }, 180);
    }
  }
}

async function handleImportFolderFile(event) {
  const [file] = Array.from(event.target.files ?? []);
  if (!file) return;
  try {
    await importLibraryPayloadFromFile(file);
  } finally {
    event.target.value = "";
  }
}

function renderChartResults() {
  if (!ui.chartSearchResults) return;
  ui.chartSearchResults.replaceChildren();
  const visibleCount = Math.max(CHART_SEARCH_RESULTS_PAGE_SIZE, state.chartSearchResultsVisibleCount || CHART_SEARCH_RESULTS_PAGE_SIZE);
  if (state.chartSearchResults.length) {
    state.chartSearchResults.slice(0, visibleCount).forEach((result) => {
      const card = document.createElement("div");
      card.className = "chart-result-card";
      if (result.isFallbackCatalog) card.classList.add("is-fallback");

      const hasImportedVariant = isChartSearchSelectionImported(result, getDefaultChartSearchEntity(result));
      if (hasImportedVariant) card.classList.add("is-imported");
      const checkbox = document.createElement("input");
      checkbox.type = "checkbox";
      checkbox.checked = hasImportedVariant;
      checkbox.className = "chart-result-checkbox";

      const head = document.createElement("div");
      head.className = "chart-result-head";
      const title = document.createElement("strong");
      title.textContent = result.title;

      const source = document.createElement("small");
      source.className = "chart-result-source";
      source.textContent = result.isFallbackCatalog
        ? `${getChartSourceLabel(result.source)} · Fallback`
        : getChartSourceLabel(result.source);

      const range = document.createElement("small");
      range.className = "chart-result-meta";
      range.textContent = result.rangeLabel || t("chart_date_range_unknown");

      const variant = document.createElement("small");
      variant.className = "chart-result-meta";
      variant.textContent = result.variantName || result.subtitle || "";

      const subtitle = document.createElement("small");
      subtitle.className = "chart-result-meta chart-result-description";
      subtitle.textContent = result.subtitle || "";

      const entitySelect = document.createElement("select");
      const entityOptions = result.availableEntities.length ? result.availableEntities : [""];
      entityOptions.forEach((entityName, index) => {
        const option = document.createElement("option");
        option.value = entityName;
        option.textContent = result.entityLabels?.[entityName] || entityName || t("chart_entity_auto");
        option.selected = (entityName || "") === getDefaultChartSearchEntity(result) || (!entityName && index === 0);
        entitySelect.appendChild(option);
      });

      const importButton = document.createElement("button");
      importButton.type = "button";
      importButton.className = "secondary-button";
      const syncImportButtonLabel = () => {
        const importedCharts = getImportedChartsForSearchSelection(result, entitySelect.value);
        const isImported = isChartSearchSelectionImported(result, entitySelect.value);
        checkbox.checked = isImported;
        card.classList.toggle("is-imported", isImported);
        importButton.textContent = isImported ? t("chart_open_library") : t("chart_import_remote");
        importButton.dataset.openChartId = importedCharts[0]?.id || "";
      };
      syncImportButtonLabel();
      entitySelect.addEventListener("change", syncImportButtonLabel);
      checkbox.addEventListener("change", () => {
        const existingCharts = getImportedChartsForSearchSelection(result, entitySelect.value);
        if (!checkbox.checked) {
          if (existingCharts.length) {
            const existingIds = new Set(existingCharts.map((chartItem) => chartItem.id));
            for (let index = chartItems.length - 1; index >= 0; index -= 1) {
              if (existingIds.has(chartItems[index].id)) {
                chartItems.splice(index, 1);
              }
            }
            if (existingCharts.some((chartItem) => state.openChartEditorId === chartItem.id)) state.openChartEditorId = null;
            if (existingCharts.some((chartItem) => state.activeChartId === chartItem.id)) state.activeChartId = chartItems[0]?.id ?? null;
            state.selectedChartAxisIds = (state.selectedChartAxisIds || []).filter((chartId) => !existingIds.has(chartId));
            if (!state.selectedChartAxisIds.length || !chartItems.length) state.showYAxis = false;
            updateChartStripControls();
            renderEventList();
            renderChartResults();
            drawTimeline();
          }
          return;
        }
        handleChartSearchImport(result, entitySelect.value);
      });
      importButton.addEventListener("click", () => {
        const existingCharts = getImportedChartsForSearchSelection(result, entitySelect.value);
        if (isChartSearchSelectionImported(result, entitySelect.value) && existingCharts[0]) {
          openChartInLibrary(existingCharts[0]);
          return;
        }
        handleChartSearchImport(result, entitySelect.value);
      });

      const actions = document.createElement("div");
      actions.className = "chart-result-actions";
      const entityField = createField(result.source === "alphavantage" ? t("chart_variant") : t("chart_entities"), entitySelect);
      entityField.classList.add("chart-result-entity-field");
      head.append(title, source);
      actions.append(checkbox, entityField, importButton);

      card.append(head, range);
      if (variant.textContent) card.appendChild(variant);
      if (subtitle.textContent && subtitle.textContent !== variant.textContent && subtitle.textContent !== title.textContent) {
        card.appendChild(subtitle);
      }
      card.appendChild(actions);
      ui.chartSearchResults.appendChild(card);
    });
    if (state.chartSearchResults.length > visibleCount) {
      const moreButton = document.createElement("button");
      moreButton.type = "button";
      moreButton.className = "secondary-button search-more-button";
      moreButton.textContent = t("show_more_results");
      moreButton.addEventListener("click", () => {
        state.chartSearchResultsVisibleCount = visibleCount + CHART_SEARCH_RESULTS_PAGE_SIZE;
        renderChartResults();
      });
      ui.chartSearchResults.appendChild(moreButton);
    }
    return;
  }

  if (state.chartSearchQuery) {
    const hint = document.createElement("p");
    hint.className = "event-description";
    hint.textContent = t("chart_search_no_results");
    ui.chartSearchResults.appendChild(hint);
    return;
  }

  if (!chartItems.length) {
    const hint = document.createElement("p");
    hint.className = "event-description";
    hint.textContent = t("chart_import_hint");
    ui.chartSearchResults.appendChild(hint);
    return;
  }

  const hint = document.createElement("p");
  hint.className = "event-description";
  hint.textContent = t("chart_import_hint");
  ui.chartSearchResults.appendChild(hint);
}

function buildImportedChartItemsFromPayload(payload, options = {}) {
  const { existingCharts = chartItems, pushToState = false } = options;
  const chartPayloads = parseChartImportPayload(payload);
  if (!chartPayloads.length) {
    throw new Error("invalid-chart-payload");
  }
  const importedCharts = [];
  chartPayloads.forEach((chartPayload) => {
    const chartItem = {
      ...createEmptyChart(),
      ...structuredClone(chartPayload),
    };
    normalizeChartItem(chartItem);
    assignChartDisplayColor(chartItem, {
      existingCharts: [...existingCharts, ...importedCharts],
      syncPrimaryTableColor: true,
    });
    if (pushToState) {
      const targetGroup = getDefaultGroupForNewItem("charts");
      if (targetGroup && !chartItem.groupId) {
        chartItem.groupId = targetGroup.id;
        expandGroupAncestors(targetGroup.id);
      }
      chartItems.push(chartItem);
    }
    importedCharts.push(chartItem);
  });
  return importedCharts;
}

function importChartPayload(payload) {
  return buildImportedChartItemsFromPayload(payload, { existingCharts: chartItems, pushToState: true });
}

function parseChartTextToImportedCharts(text, filename = "", options = {}) {
  const { existingCharts = chartItems } = options;
  const lowerName = String(filename || "").toLowerCase();
  if (lowerName.endsWith(".csv") || lowerName.endsWith(".tsv")) {
    const chartPayload = buildChartPayloadFromDelimitedText(text, getFilenameBase(filename) || "Chart");
    return buildImportedChartItemsFromPayload(chartPayload, { existingCharts, pushToState: false });
  }
  try {
    return buildImportedChartItemsFromPayload(JSON.parse(text), { existingCharts, pushToState: false });
  } catch {
    const chartPayload = buildChartPayloadFromDelimitedText(text, getFilenameBase(filename) || "Chart");
    return buildImportedChartItemsFromPayload(chartPayload, { existingCharts, pushToState: false });
  }
}

function importDelimitedChartText(text, filename = "") {
  const chartPayload = buildChartPayloadFromDelimitedText(text, getFilenameBase(filename) || "Chart");
  return importChartPayload(chartPayload);
}

function applyImportedChartToExistingChart(targetChart, importedPayload) {
  if (!targetChart || !importedPayload) return null;
  const preserved = {
    id: targetChart.id,
    type: "chart",
    groupId: targetChart.groupId ?? null,
    parentEventId: targetChart.parentEventId ?? null,
    visible: targetChart.visible !== false,
    displayMode: targetChart.displayMode || "mixed",
    yAxisEnabled: targetChart.yAxisEnabled !== false,
    yAxisSide: targetChart.yAxisSide || "left",
    yScaleMode: targetChart.yScaleMode || "linear",
    yAxisLabel: targetChart.yAxisLabel || "",
    showZeroExtension: targetChart.showZeroExtension === true,
    yAxisLaneStart: targetChart.yAxisLaneStart,
    yAxisLaneEnd: targetChart.yAxisLaneEnd,
    yOffsetPx: Number.isFinite(targetChart.yOffsetPx) ? targetChart.yOffsetPx : 0,
    visibleStepMin: targetChart.visibleStepMin,
    visibleStepMax: targetChart.visibleStepMax,
    color: targetChart.color,
    comments: structuredClone(getChartComments(targetChart)),
    setupMode: null,
    csvPasteDraft: "",
    setupError: "",
  };
  Object.assign(targetChart, structuredClone(importedPayload), preserved);
  normalizeChartItem(targetChart);
  assignChartDisplayColor(targetChart, {
    existingCharts: chartItems.filter((candidate) => candidate.id !== targetChart.id),
    syncPrimaryTableColor: true,
  });
  deleteChartDraftRowsForChart(targetChart.id);
  state.chartCodeDraftEditorId = null;
  state.openChartEditorId = targetChart.id;
  state.chartValueDraftEditorId = targetChart.id;
  state.chartFolderExpanded = true;
  activateChartAxisSelection(targetChart);
  ensureImportedChartIsVisible(targetChart);
  if (state.chartDisplayMode === "hidden") {
    state.chartDisplayMode = "mixed";
  }
  return targetChart;
}

function ensureImportedChartIsVisible(chartItem) {
  if (!chartItem) return;
  const chartRange = getChartTimelineRange(chartItem);
  if (!chartRange) return;
  const viewRange = getVisibleRange();
  const overlapsView = chartRange.max >= viewRange.start && chartRange.min <= viewRange.end;
  if (overlapsView) return;
  state.subYearTickAnchorValue = null;
  state.centerYear = (chartRange.min + chartRange.max) / 2;
}

async function handleImportChartFile(event) {
  const [file] = Array.from(event.target.files ?? []);
  if (!file) return;

  try {
    const fileText = await file.text();
    const lowerName = String(file.name || "").toLowerCase();
    let importedCharts = [];
    if (lowerName.endsWith(".csv") || lowerName.endsWith(".tsv")) {
      importedCharts = importDelimitedChartText(fileText, file.name);
    } else {
      try {
        const payload = JSON.parse(fileText);
        importedCharts = importChartPayload(payload);
      } catch {
        importedCharts = importDelimitedChartText(fileText, file.name);
      }
    }
    const importedChart = importedCharts[0];
    if (importedChart) {
      ensureImportedChartIsVisible(importedChart);
      if (state.chartDisplayMode === "hidden") {
        state.chartDisplayMode = "mixed";
      }
      activateChartAxisSelection(importedChart);
      state.chartFolderExpanded = !importedChart.groupId;
      state.openChartEditorId = null;
      ui.chartStatus.textContent = tf("chart_status_imported", { title: importedChart.title });
    }
    updateChartStripControls();
    renderEventList();
    renderChartResults();
    drawTimeline();
    scrollToDetails("auto");
  } catch (error) {
    if (ui.chartStatus) {
      ui.chartStatus.textContent = error?.message === "chart-csv-missing-columns"
        ? t("chart_csv_missing_columns")
        : t("chart_import_failed");
    }
  } finally {
    event.target.value = "";
  }
}

function handleChartSearchInputChange() {
  if (!ui.chartSearchInput) return;
  state.chartSearchQuery = ui.chartSearchInput.value.trim();
  if (state.chartSearchQuery) return;
  state.chartSearchResults = [];
  state.chartSearchResultsVisibleCount = CHART_SEARCH_RESULTS_PAGE_SIZE;
  if (ui.chartStatus) ui.chartStatus.textContent = chartItems.length ? t("chart_status_default") : t("chart_search_default");
  renderChartResults();
}

async function handleChartSearchSubmit(event) {
  event.preventDefault();
  const query = ui.chartSearchInput?.value.trim() ?? "";
  state.chartSearchQuery = query;
  if (!query) {
    state.chartSearchResults = [];
    state.chartSearchResultsVisibleCount = CHART_SEARCH_RESULTS_PAGE_SIZE;
    if (ui.chartStatus) ui.chartStatus.textContent = chartItems.length ? t("chart_status_default") : t("chart_search_default");
    renderChartResults();
    return;
  }

  if (state.chartSearchSource !== "owid" && state.chartSearchSource !== "worldbank" && state.chartSearchSource !== "alphavantage") {
    if (ui.chartStatus) {
      const sourceLabel = state.chartSearchSource === "worldbank"
        ? t("chart_source_worldbank")
        : state.chartSearchSource === "alphavantage"
          ? t("chart_source_alphavantage")
        : state.chartSearchSource === "eurostat"
          ? t("chart_source_eurostat")
          : t("chart_source_oecd");
      ui.chartStatus.textContent = tf("chart_source_coming_soon", { source: sourceLabel });
    }
    state.chartSearchResults = [];
    state.chartSearchResultsVisibleCount = CHART_SEARCH_RESULTS_PAGE_SIZE;
    renderChartResults();
    return;
  }

  if (ui.chartStatus) {
    ui.chartStatus.textContent = tf("chart_search_loading", {
      query,
      source: getChartSourceLabel(state.chartSearchSource),
    });
  }
  try {
    let usedAlphaVantageFallback = false;
    if (state.chartSearchSource === "worldbank") {
      state.chartSearchResults = await searchWorldBankCharts(query);
    } else if (state.chartSearchSource === "alphavantage") {
      const searchOutcome = await searchAlphaVantageCharts(query);
      state.chartSearchResults = Array.isArray(searchOutcome?.results) ? searchOutcome.results : [];
      usedAlphaVantageFallback = searchOutcome?.usedFallback === true;
      if (hasCustomAlphaVantageApiKey()) {
        if (!usedAlphaVantageFallback) {
          state.alphaVantageApiVerified = true;
        }
        updateAlphaVantageApiUi();
        populateChartSourceSelect(false);
      }
    } else {
      state.chartSearchResults = await searchOwidCharts(query);
    }
    state.chartSearchResultsVisibleCount = CHART_SEARCH_RESULTS_PAGE_SIZE;
    if (ui.chartStatus) {
      ui.chartStatus.textContent = state.chartSearchResults.length
        ? (
          state.chartSearchSource === "alphavantage" && usedAlphaVantageFallback
            ? tf("chart_search_results_found_fallback", { count: state.chartSearchResults.length })
            : tf("chart_search_results_found", { count: state.chartSearchResults.length })
        )
        : t("chart_search_no_results");
    }
    renderChartResults();
    if (state.chartSearchSource === "owid") {
      state.chartSearchResults.forEach((result) => {
        hydrateChartSearchRange(result).then(() => {
          renderChartResults();
        });
      });
    }
  } catch {
    if (state.chartSearchSource === "alphavantage" && hasCustomAlphaVantageApiKey()) {
      state.alphaVantageApiVerified = false;
      updateAlphaVantageApiUi();
      populateChartSourceSelect(false);
    }
    state.chartSearchResults = [];
    state.chartSearchResultsVisibleCount = CHART_SEARCH_RESULTS_PAGE_SIZE;
    if (ui.chartStatus) ui.chartStatus.textContent = t("chart_search_failed");
  }
  renderChartResults();
}

function handleSearchInputChange() {
  if (!ui.searchInput || ui.searchInput.value.trim()) return;
  hideSearchLoading();
  state.searchResults = [];
  state.searchResultsVisibleCount = SEARCH_RESULTS_PAGE_SIZE;
  state.searchResultFilterValue = "";
  state.searchResultFilterOptions = [];
  ui.searchStatus.textContent = t("search_default");
  renderSearchFilterUi();
  renderSearchResults();
}

function handleSourcesSearchInputChange() {
  if (!ui.sourcesSearchInput || ui.sourcesSearchInput.value.trim()) return;
  state.sourcesSearchResults = [];
  if (ui.sourcesStatus) ui.sourcesStatus.textContent = t("sources_search_default");
  if (ui.sourcesResults) ui.sourcesResults.replaceChildren();
}

function getSourcesSearchSourceLabel(source = state.sourcesSearchSource) {
  if (source === "film") return t("source_film");
  if (source === "wikisource") return t("source_wikisource");
  if (source === "crossref") return t("source_crossref");
  return t("source_dataverse");
}

function createFilmSourceResultItem(result) {
  const wrapper = document.createElement("article");
  wrapper.className = "search-result source-result film-source-result";
  const imageUrl = String(result.imageUrl || "").trim();
  const imageWrap = document.createElement("div");
  imageWrap.className = "film-source-cover";
  if (imageUrl) {
    const image = document.createElement("img");
    image.src = imageUrl;
    image.alt = result.label || "Film";
    image.loading = "lazy";
    imageWrap.appendChild(image);
  } else {
    imageWrap.setAttribute("aria-hidden", "true");
  }
  wrapper.appendChild(imageWrap);

  const content = document.createElement("div");
  content.className = "search-result-content";
  const head = document.createElement("div");
  head.className = "search-result-head";
  const title = document.createElement("strong");
  title.textContent = result.label;
  const recordId = document.createElement("small");
  recordId.className = "search-result-id";
  recordId.textContent = [result.yearLabel, result.tmdbMediaType === "tv" ? "Serie" : "Film", `TMDb ${result.tmdbId}`].filter(Boolean).join(" · ");
  head.append(title, recordId);

  const description = document.createElement("span");
  description.className = "search-result-description";
  description.textContent = result.description || t("no_description");
  const meta = document.createElement("small");
  meta.className = "search-result-meta";
  if (result.tmdbUrl) {
    const tmdbLink = document.createElement("a");
    tmdbLink.href = result.tmdbUrl;
    tmdbLink.target = "_blank";
    tmdbLink.rel = "noopener noreferrer";
    tmdbLink.textContent = `TMDb ${result.tmdbId}`;
    meta.appendChild(tmdbLink);
  } else {
    meta.textContent = t("source_film");
  }
  const actionRow = document.createElement("div");
  actionRow.className = "library-actions";
  const addButton = document.createElement("button");
  addButton.type = "button";
  addButton.className = "secondary-button";
  addButton.textContent = t("source_add");
  addButton.disabled = sourceItems.some((sourceItem) => sourceItem.sourceType === "film" && sourceItem.source === "tmdb" && sourceItem.sourceId === result.sourceId);
  addButton.addEventListener("click", async () => {
    const targetGroup = getDefaultGroupForNewSource("film");
    const sourceItem = normalizeSourceItem({
      id: createUniqueId("source-film"),
      sourceType: "film",
      source: "tmdb",
      sourceId: result.sourceId,
      tmdbId: result.tmdbId,
      tmdbMediaType: result.tmdbMediaType,
      externalId: "",
      title: result.label,
      description: result.description,
      url: result.tmdbUrl,
      imageUrl: result.imageUrl,
      yearLabel: result.yearLabel,
      countryLabel: result.countryLabel,
      countryIds: result.countryIds,
      startYear: result.startYear,
      endYear: result.endYear,
      startDateValue: result.startDateValue,
      endDateValue: result.endDateValue,
      startPrecision: result.startPrecision,
      endPrecision: result.endPrecision,
      isRange: result.isRange,
      imageAspectMode: "cover",
      imageDisplayEnabled: Boolean(result.imageUrl),
      imageSidePanelEnabled: true,
      manualImageUrl: "",
      manualImageSource: "",
      wikidataImageUrl: result.imageUrl,
      wikidataImagePreviewUrl: result.imageUrl,
      wikidataImageThumbUrl: result.imageUrl,
      wikidataImageWidth: result.imageWidth,
      wikidataImageHeight: result.imageHeight,
      wikidataImageLookupCompleted: true,
      imdbId: "",
      groupId: targetGroup?.id ?? null,
      enabled: true,
    });
    if (!sourceItem) return;
    sourceItems.push(sourceItem);
    const sourceRoot = targetGroup ? getGroupById(getRootGroupId(targetGroup.id)) : null;
    if (sourceRoot) sourceRoot.expanded = true;
    if (targetGroup) expandGroupAncestors(targetGroup.id);
    state.sourceFolderExpanded = !targetGroup;
    ui.sourcesStatus.textContent = tf("source_added", { title: sourceItem.title });
    addButton.disabled = true;
    openSourceInLibrary(sourceItem);
    drawTimeline();
    scheduleLocalAutosave();
    if (!result.imageUrl) {
      await hydrateTmdbCoversForSources([sourceItem]);
      renderEventList();
      renderDetailsSidePanel();
      drawTimeline();
      scheduleLocalAutosave();
    }
  });
  actionRow.appendChild(addButton);
  content.append(head, description, meta, actionRow);
  wrapper.appendChild(content);
  return wrapper;
}

function renderSourcesResults() {
  if (!ui.sourcesResults) return;
  ui.sourcesResults.replaceChildren();
  if (!state.sourcesSearchResults.length) {
    const hint = document.createElement("p");
    hint.className = "event-description";
    hint.textContent = t("search_empty");
    ui.sourcesResults.appendChild(hint);
    return;
  }
  state.sourcesSearchResults.forEach((result) => {
    ui.sourcesResults.appendChild(createFilmSourceResultItem(result));
  });
}

async function handleSourcesSearchSubmit(event) {
  event.preventDefault();
  if (!ui.sourcesStatus) return;
  const query = ui.sourcesSearchInput?.value.trim() || "";
  if (!query) {
    ui.sourcesStatus.textContent = t("search_enter_query");
    return;
  }
  const sourceLabel = getSourcesSearchSourceLabel();
  if (state.sourcesSearchSource === "film") {
    if (!getTmdbApiToken()) {
      ui.sourcesStatus.textContent = t("tmdb_api_token_missing");
      return;
    }
    ui.sourcesStatus.textContent = tf("search_loading", { query });
    try {
      state.sourcesSearchResults = await searchFilmSources(query);
      ui.sourcesStatus.textContent = state.sourcesSearchResults.length
        ? tf("search_results_found", { count: state.sourcesSearchResults.length })
        : t("search_no_results");
    } catch {
      state.sourcesSearchResults = [];
      ui.sourcesStatus.textContent = t("search_failed");
    }
    renderSourcesResults();
    return;
  }
  ui.sourcesStatus.textContent = tf("sources_search_coming_soon", { source: sourceLabel });
  state.sourcesSearchResults = [];
  if (ui.sourcesResults) ui.sourcesResults.replaceChildren();
}

function suppressWorkspaceStripInteraction(event) {
  event.stopPropagation();
}

function renderSearchResults() {
  ui.searchResults.replaceChildren();
  const activeResults = getFilteredSearchResults();
  if (activeResults.length === 0) {
    const hint = document.createElement("p");
    hint.className = "event-description";
    hint.textContent = state.searchResults.length > 0 && state.searchResultFilterValue
      ? t("search_filter_empty")
      : t("search_empty");
    ui.searchResults.appendChild(hint);
    return;
  }
  const visibleCount = Math.max(SEARCH_RESULTS_PAGE_SIZE, state.searchResultsVisibleCount || SEARCH_RESULTS_PAGE_SIZE);
  activeResults.slice(0, visibleCount).forEach((result) => {
    ui.searchResults.appendChild(createSearchResultItem(result));
  });
  if (activeResults.length > visibleCount) {
    const moreButton = document.createElement("button");
    moreButton.type = "button";
    moreButton.className = "secondary-button search-more-button";
    moreButton.textContent = t("show_more_results");
    moreButton.addEventListener("click", () => {
      state.searchResultsVisibleCount = visibleCount + SEARCH_RESULTS_PAGE_SIZE;
      renderSearchResults();
    });
    ui.searchResults.appendChild(moreButton);
  }
}

function normalizeSearchResults(payload) {
  return (payload.search ?? []).map((entry) => ({
    id: entry.id,
    label: entry.label || entry.display?.label?.value || entry.id,
    description: entry.description || entry.display?.description?.value || "",
    instanceOfIds: [],
    instanceOfLabels: [],
    instanceOfText: "",
  }));
}

function uniqueSearchResultsById(results) {
  const seen = new Set();
  return (Array.isArray(results) ? results : []).filter((result) => {
    const id = normalizeWikidataEntityId(result?.id);
    if (!id || seen.has(id)) return false;
    seen.add(id);
    result.id = id;
    return true;
  });
}

function isWikidataFilmSearchResult(result) {
  const instanceIds = Array.isArray(result?.instanceOfIds) ? result.instanceOfIds : [];
  if (instanceIds.some((id) => WIKIDATA_FILM_SOURCE_INSTANCE_IDS.includes(normalizeWikidataEntityId(id)))) return true;
  const instanceText = String(result?.instanceOfText || "").toLocaleLowerCase();
  return /\bfilm\b|\bmovie\b|fernsehfilm|spielfilm|kurzfilm|\btelevision series\b|\btv series\b|fernsehserie|\bweb series\b|webserie|\bminiseries\b|miniserie/.test(instanceText);
}

function isExcludedWikidataEventSearchResult(result) {
  const instanceIds = Array.isArray(result?.instanceOfIds) ? result.instanceOfIds : [];
  if (instanceIds.some((id) => WIKIDATA_EVENT_SEARCH_EXCLUDED_INSTANCE_IDS.includes(normalizeWikidataEntityId(id)))) {
    return true;
  }
  const instanceLabels = Array.isArray(result?.instanceOfLabels) ? result.instanceOfLabels : [];
  const normalizedLabels = instanceLabels.map((label) => String(label || "").trim().toLocaleLowerCase()).filter(Boolean);
  return WIKIDATA_EVENT_SEARCH_EXCLUDED_INSTANCE_LABELS.some((label) => {
    const normalizedLabel = String(label || "").trim().toLocaleLowerCase();
    return normalizedLabel && normalizedLabels.includes(normalizedLabel);
  });
}

function getTmdbApiToken() {
  return String(state.tmdbApiToken || ui.tmdbApiTokenInput?.value || "").trim();
}

async function fetchTmdbJson(path, params = {}) {
  const token = getTmdbApiToken();
  if (!token) throw new Error("tmdb-token-missing");
  const url = new URL(`${TMDB_API_URL}${path}`);
  Object.entries(params).forEach(([key, value]) => {
    if (value !== undefined && value !== null && value !== "") url.searchParams.set(key, String(value));
  });
  const response = await fetchWithTimeout(url, {
    headers: {
      Accept: "application/json",
      Authorization: `Bearer ${token}`,
    },
  }, 12000);
  if (!response.ok) throw new Error(`tmdb-request-failed-${response.status}`);
  return response.json();
}

function buildTmdbImageUrl(path, size = "w342") {
  const normalizedPath = String(path || "").trim();
  return normalizedPath ? `${TMDB_IMAGE_BASE_URL}/${size}${normalizedPath}` : "";
}

async function fetchTmdbMediaSourceById(mediaType, tmdbId) {
  const normalizedMediaType = mediaType === "tv" ? "tv" : "movie";
  const normalizedTmdbId = String(tmdbId || "").trim();
  if (!normalizedTmdbId) return null;
  const payload = await fetchTmdbJson(`/${normalizedMediaType}/${encodeURIComponent(normalizedTmdbId)}`, {
    language: state.language === "en" ? "en-US" : "de-DE",
  });
  return normalizeTmdbSearchResult({
    ...payload,
    media_type: normalizedMediaType,
  });
}

async function hydrateTmdbCoverForSource(sourceItem, options = {}) {
  const { force = false } = options;
  if (!sourceItem || normalizeSourceType(sourceItem.sourceType) !== "film") return false;
  const tmdbId = getSourceTmdbId(sourceItem);
  if (!tmdbId) return false;
  if (!getTmdbApiToken()) return false;
  if (String(sourceItem.manualImageUrl || "").trim()) return false;
  if (!force && getSourceCoverUrl(sourceItem)) return false;
  const mediaInfo = await fetchTmdbMediaSourceById(getSourceTmdbMediaType(sourceItem), tmdbId);
  const imageUrl = String(mediaInfo?.imageUrl || "").trim();
  if (!imageUrl) return false;
  sourceItem.imageUrl = imageUrl;
  sourceItem.wikidataImageUrl = imageUrl;
  sourceItem.wikidataImagePreviewUrl = imageUrl;
  sourceItem.wikidataImageThumbUrl = imageUrl;
  sourceItem.wikidataImageWidth = mediaInfo.imageWidth ?? null;
  sourceItem.wikidataImageHeight = mediaInfo.imageHeight ?? null;
  sourceItem.imageDisplayEnabled = true;
  sourceItem.imageSidePanelEnabled = true;
  sourceItem.imageAspectMode = "cover";
  sourceItem.wikidataImageLookupCompleted = true;
  ensureSourceEventFields(sourceItem);
  return true;
}

async function hydrateTmdbCoversForSources(sourceList, options = {}) {
  const { force = false } = options;
  const candidates = (Array.isArray(sourceList) ? sourceList : [])
    .filter((sourceItem) => (
      sourceItem
      && normalizeSourceType(sourceItem.sourceType) === "film"
      && getSourceTmdbId(sourceItem)
      && !String(sourceItem.manualImageUrl || "").trim()
      && (force || !getSourceCoverUrl(sourceItem))
    ));
  if (!candidates.length || !getTmdbApiToken()) return 0;
  let hydratedCount = 0;
  for (const sourceItem of candidates) {
    try {
      if (await hydrateTmdbCoverForSource(sourceItem, { force })) hydratedCount += 1;
    } catch {
      // Keep source creation usable even if a poster cannot be loaded.
    }
  }
  return hydratedCount;
}

function normalizeSourceResolutionText(value) {
  return String(value || "")
    .trim()
    .toLocaleLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/&/g, " and ")
    .replace(/['"’‘`´]/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\b(der|die|das|the|a|an|le|la|les|l|el|il|lo|gli|i)\b/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getSourceResolutionYear(sourceItem) {
  const publishedMatch = String(sourceItem?.publishedYearLabel || "").match(/-?\d{1,4}/);
  if (publishedMatch) return Number(publishedMatch[0]);
  const yearMatch = String(sourceItem?.yearLabel || "").match(/-?\d{1,4}/);
  if (yearMatch) return Number(yearMatch[0]);
  const startYear = Number(sourceItem?.startYear);
  return Number.isFinite(startYear) ? toHistoricalYear(startYear) : null;
}

function getBestTmdbResolutionResult(sourceItem, results) {
  const sourceTitle = normalizeSourceResolutionText(sourceItem?.title);
  if (!sourceTitle) return null;
  const expectedYear = getSourceResolutionYear(sourceItem);
  const candidates = (Array.isArray(results) ? results : [])
    .map((result) => {
      const resultTitle = normalizeSourceResolutionText(result?.label);
      if (!resultTitle) return null;
      const exactTitle = resultTitle === sourceTitle;
      const nearTitle = exactTitle || resultTitle.includes(sourceTitle) || sourceTitle.includes(resultTitle);
      if (!nearTitle) return null;
      const resultYear = getSourceResolutionYear(result);
      const yearDistance = Number.isFinite(expectedYear) && Number.isFinite(resultYear)
        ? Math.abs(resultYear - expectedYear)
        : null;
      const score = (exactTitle ? 8 : 4)
        + (yearDistance === 0 ? 6 : yearDistance !== null && yearDistance <= 1 ? 3 : 0)
        + (result.imageUrl ? 1 : 0);
      return { result, score, exactTitle, yearDistance };
    })
    .filter(Boolean)
    .sort((left, right) => right.score - left.score);
  const best = candidates[0];
  if (!best) return null;
  const second = candidates[1];
  if (!best.exactTitle && best.score < 6) return null;
  if (best.yearDistance !== null && best.yearDistance > 2) return null;
  if (second && second.score === best.score) return null;
  return best.result;
}

function applyTmdbIdentityToSource(sourceItem, result) {
  if (!sourceItem || !result?.sourceId) return false;
  const changed = sourceItem.source !== "tmdb"
    || sourceItem.sourceId !== result.sourceId
    || sourceItem.tmdbId !== result.tmdbId
    || sourceItem.tmdbMediaType !== result.tmdbMediaType;
  sourceItem.source = "tmdb";
  sourceItem.sourceId = result.sourceId;
  sourceItem.tmdbId = result.tmdbId;
  sourceItem.tmdbMediaType = result.tmdbMediaType;
  sourceItem.externalId = "";
  sourceItem.url = result.tmdbUrl || getSourceTmdbUrl(sourceItem);
  if (!sourceItem.description && result.description) sourceItem.description = result.description;
  if (!sourceItem.yearLabel && result.yearLabel) sourceItem.yearLabel = result.yearLabel;
  if (!sourceItem.countryLabel && result.countryLabel) sourceItem.countryLabel = result.countryLabel;
  if ((!Array.isArray(sourceItem.countryIds) || !sourceItem.countryIds.length) && Array.isArray(result.countryIds)) {
    sourceItem.countryIds = result.countryIds;
  }
  ["startYear", "endYear", "startDateValue", "endDateValue", "startPrecision", "endPrecision", "isRange"].forEach((key) => {
    if (sourceItem[key] === undefined || sourceItem[key] === null || sourceItem[key] === "") {
      sourceItem[key] = result[key];
    }
  });
  if (result.imageUrl && !getSourceCoverUrl(sourceItem)) {
    sourceItem.imageUrl = result.imageUrl;
    sourceItem.wikidataImageUrl = result.imageUrl;
    sourceItem.wikidataImagePreviewUrl = result.imageUrl;
    sourceItem.wikidataImageThumbUrl = result.imageUrl;
    sourceItem.wikidataImageWidth = result.imageWidth ?? null;
    sourceItem.wikidataImageHeight = result.imageHeight ?? null;
    sourceItem.imageDisplayEnabled = true;
    sourceItem.imageSidePanelEnabled = true;
    sourceItem.wikidataImageLookupCompleted = true;
  }
  ensureSourceEventFields(sourceItem);
  return changed || Boolean(result.imageUrl);
}

async function resolveTmdbIdentityForSource(sourceItem) {
  if (!sourceItem || normalizeSourceType(sourceItem.sourceType) !== "film") return false;
  if (getSourceTmdbId(sourceItem) || !getTmdbApiToken()) return false;
  const results = await searchFilmSources(sourceItem.title);
  const match = getBestTmdbResolutionResult(sourceItem, results);
  if (!match) return false;
  return applyTmdbIdentityToSource(sourceItem, match);
}

async function resolveWikidataIdentityForSource(sourceItem) {
  if (!sourceItem || normalizeWikidataEntityId(sourceItem.wikidataId)) return false;
  const sourceTitle = normalizeSourceResolutionText(sourceItem.title);
  if (!sourceTitle) return false;
  const results = await searchWikidata(sourceItem.title);
  const exactMatches = uniqueSearchResultsById(results)
    .filter((result) => normalizeSourceResolutionText(result.label) === sourceTitle);
  if (exactMatches.length !== 1) return false;
  const wikidataId = normalizeWikidataEntityId(exactMatches[0].id);
  if (!wikidataId) return false;
  sourceItem.wikidataId = wikidataId;
  if (sourceItem.source === "manual" && !sourceItem.sourceId) {
    sourceItem.sourceId = wikidataId;
  }
  try {
    const entity = await fetchWikidataEntity(wikidataId);
    if (entity && applyWikidataTmdbClaimsToSource(sourceItem, entity)) {
      await hydrateTmdbCoversForSources([sourceItem], { force: true });
    }
  } catch {
    // Wikidata assignment remains valid even if linked TMDb claims cannot be fetched.
  }
  ensureSourceEventFields(sourceItem);
  return true;
}

async function resolveSourceIdentities(sourceList) {
  const candidates = Array.isArray(sourceList) ? sourceList.filter(Boolean) : [];
  let changedCount = 0;
  for (const sourceItem of candidates) {
    try {
      const tmdbChanged = await resolveTmdbIdentityForSource(sourceItem);
      const wikidataChanged = await resolveWikidataIdentityForSource(sourceItem);
      if (tmdbChanged || wikidataChanged) changedCount += 1;
    } catch {
      // Keep generated source imports usable even when a lookup fails.
    }
  }
  changedCount += await hydrateTmdbCoversForSources(candidates);
  return changedCount;
}

function getTmdbYearInfo(result) {
  const dateText = String(result?.release_date || result?.first_air_date || "").trim();
  const yearMatch = dateText.match(/^(\d{4})/);
  if (!yearMatch) return {};
  const historicalYear = Number(yearMatch[1]);
  const startYear = toAstronomicalYear(historicalYear);
  const parsedTemporal = parseEditorTemporalValue(dateText);
  return {
    yearLabel: String(historicalYear),
    startYear,
    endYear: startYear,
    startDateValue: parsedTemporal?.value ?? startYear,
    endDateValue: parsedTemporal?.value ?? startYear,
    startPrecision: parsedTemporal?.precision ?? 9,
    endPrecision: parsedTemporal?.precision ?? 9,
    isRange: false,
  };
}

function normalizeTmdbSearchResult(result) {
  const mediaType = result?.media_type === "tv" ? "tv" : result?.media_type === "movie" ? "movie" : "";
  if (!mediaType || !result?.id) return null;
  const title = String(mediaType === "tv" ? (result.name || result.original_name) : (result.title || result.original_title)).trim();
  if (!title) return null;
  const tmdbId = String(result.id);
  const yearInfo = getTmdbYearInfo(result);
  const posterUrl = buildTmdbImageUrl(result.poster_path, "w342");
  return {
    id: `tmdb-${mediaType}-${tmdbId}`,
    sourceId: `${mediaType}:${tmdbId}`,
    tmdbId,
    tmdbMediaType: mediaType,
    label: title,
    description: String(result.overview || "").trim(),
    imageUrl: posterUrl,
    imageWidth: null,
    imageHeight: null,
    countryLabel: Array.isArray(result.origin_country) ? result.origin_country.join(", ") : "",
    countryIds: [],
    tmdbUrl: `${TMDB_WEB_URL}/${mediaType}/${encodeURIComponent(tmdbId)}`,
    ...yearInfo,
  };
}

async function searchFilmSources(query) {
  const trimmedQuery = String(query || "").trim();
  if (!trimmedQuery) return [];
  const payload = await fetchTmdbJson("/search/multi", {
    query: trimmedQuery,
    include_adult: "false",
    language: state.language === "en" ? "en-US" : "de-DE",
    page: 1,
  });
  const seen = new Set();
  return (Array.isArray(payload?.results) ? payload.results : [])
    .map(normalizeTmdbSearchResult)
    .filter((result) => {
      if (!result || seen.has(result.sourceId)) return false;
      seen.add(result.sourceId);
      return true;
    })
    .slice(0, 30);
}

function getSearchFilterOptionsFromResults(results) {
  const optionsByKey = new Map();
  (Array.isArray(results) ? results : []).forEach((result) => {
    (Array.isArray(result?.instanceOfLabels) ? result.instanceOfLabels : []).forEach((label) => {
      const normalizedLabel = String(label || "").trim();
      const optionKey = normalizedLabel.toLocaleLowerCase();
      if (!normalizedLabel || optionsByKey.has(optionKey)) return;
      optionsByKey.set(optionKey, normalizedLabel);
    });
  });
  return [...optionsByKey.values()].sort((left, right) => left.localeCompare(right, state.language));
}

function syncSearchResultFilterOptions() {
  state.searchResultFilterOptions = getSearchFilterOptionsFromResults(state.searchResults);
  if (state.searchResultFilterValue && !state.searchResultFilterOptions.includes(state.searchResultFilterValue)) {
    state.searchResultFilterValue = "";
  }
}

function getFilteredSearchResults() {
  const activeFilter = String(state.searchResultFilterValue || "").trim();
  if (!activeFilter) return state.searchResults;
  return state.searchResults.filter((result) => (
    Array.isArray(result.instanceOfLabels)
    && result.instanceOfLabels.includes(activeFilter)
  ));
}

function updateSearchStatusForResults() {
  if (!ui.searchStatus) return;
  if (!state.searchResults.length) {
    ui.searchStatus.textContent = t("search_no_results");
    return;
  }
  const activeResults = getFilteredSearchResults();
  ui.searchStatus.textContent = state.searchResultFilterValue
    ? tf("search_results_filtered", { count: activeResults.length, total: state.searchResults.length })
    : tf("search_results_found", { count: state.searchResults.length });
}

function renderSearchFilterUi() {
  if (!ui.searchFilterField || !ui.searchFilterSelect) return;
  const hasResults = state.searchResults.length > 0;
  ui.searchFilterField.hidden = !hasResults;
  if (!hasResults) {
    ui.searchFilterSelect.replaceChildren();
    return;
  }
  const previousValue = state.searchResultFilterValue;
  ui.searchFilterSelect.replaceChildren();
  ui.searchFilterSelect.appendChild(createSelectOption("", t("search_filter_all"), previousValue === ""));
  state.searchResultFilterOptions.forEach((option) => {
    ui.searchFilterSelect.appendChild(createSelectOption(option, option, previousValue === option));
  });
  ui.searchFilterSelect.value = previousValue;
}

async function enrichSearchResultsWithInstanceOf(results) {
  const normalizedResults = Array.isArray(results) ? results : [];
  const resultIds = normalizedResults
    .map((result) => normalizeWikidataEntityId(result?.id))
    .filter(Boolean);
  if (!resultIds.length) return;
  let entitiesById = {};
  try {
    entitiesById = await fetchWikidataEntities(resultIds);
  } catch {
    entitiesById = {};
  }
  const linkedInstanceIds = [...new Set(
    resultIds.flatMap((resultId) => getClaimEntityIds(entitiesById[resultId], "P31"))
      .map((value) => normalizeWikidataEntityId(value))
      .filter(Boolean)
  )];
  let instanceEntitiesById = {};
  if (linkedInstanceIds.length) {
    try {
      instanceEntitiesById = await fetchWikidataEntities(linkedInstanceIds);
    } catch {
      instanceEntitiesById = {};
    }
  }
  normalizedResults.forEach((result) => {
    const normalizedId = normalizeWikidataEntityId(result?.id);
    const entity = normalizedId ? entitiesById[normalizedId] : null;
    const instanceIds = getClaimEntityIds(entity, "P31")
      .map((value) => normalizeWikidataEntityId(value))
      .filter((value, index, array) => value && array.indexOf(value) === index);
    const instanceLabels = instanceIds
      .map((id) => getEntityLabel(instanceEntitiesById[id], id))
      .filter(Boolean);
    result.instanceOfIds = instanceIds;
    result.instanceOfLabels = instanceLabels.length ? instanceLabels : instanceIds;
    result.instanceOfText = result.instanceOfLabels.join(", ");
  });
}

async function searchWikidata(query) {
  const url = new URL(WIKIDATA_API_URL);
  url.search = new URLSearchParams({
    action: "wbsearchentities",
    format: "json",
    origin: "*",
    language: getWikidataLanguageCode(),
    uselang: getWikidataLanguageCode(),
    type: "item",
    limit: "40",
    search: query,
  }).toString();

  const response = await fetch(url);
  if (!response.ok) throw new Error("wikidata-search-failed");
  return normalizeSearchResults(await response.json());
}

function extractTimeInfoFromTimeValue(timeValue) {
  if (!timeValue?.time) return null;
  const match = /^([+-]\d+)-(\d{2})-(\d{2})T/.exec(timeValue.time);
  if (!match) return null;
  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);
  const precision = Number(timeValue.precision ?? 9);
  let value = year;

  if (precision >= 11) {
    value = buildTimelineValue(year, month, day);
  } else if (precision >= 10) {
    value = buildTimelineValue(year, month, 1);
  }

  return { year, month, day, precision, value };
}

function getClaimTimeInfo(entity, propertyId) {
  const claims = entity.claims?.[propertyId];
  const timeValue = claims?.[0]?.mainsnak?.datavalue?.value;
  return extractTimeInfoFromTimeValue(timeValue);
}

function getPrimaryClaim(entity, propertyId) {
  const claims = Array.isArray(entity?.claims?.[propertyId]) ? entity.claims[propertyId] : [];
  return claims[0] ?? null;
}

function getClaimQualifierTimeInfo(claim, propertyId) {
  const qualifiers = Array.isArray(claim?.qualifiers?.[propertyId]) ? claim.qualifiers[propertyId] : [];
  const timeValue = qualifiers[0]?.datavalue?.value;
  return extractTimeInfoFromTimeValue(timeValue);
}

function getClaimYear(entity, propertyId) {
  return getClaimTimeInfo(entity, propertyId)?.year ?? null;
}

function getFlagImageUrl(entity) {
  const claims = entity.claims?.P41;
  const fileName = claims?.[0]?.mainsnak?.datavalue?.value;
  return buildCommonsFileUrl(fileName);
}

function getFlagImageCandidates(entity) {
  const claims = Array.isArray(entity?.claims?.P41) ? entity.claims.P41 : [];
  const seen = new Set();
  return claims
    .map((claim) => {
      const fileName = claim?.mainsnak?.datavalue?.value;
      if (typeof fileName !== "string" || !fileName.trim()) return null;
      const normalizedFileName = fileName.trim();
      if (seen.has(normalizedFileName)) return null;
      seen.add(normalizedFileName);
      return {
        key: normalizedFileName,
        fileName: normalizedFileName,
        url: buildCommonsFileUrl(normalizedFileName),
        label: formatFlagCandidateLabel(normalizedFileName),
        sourceType: "wikidata",
        sourceLabel: "Wikidata / Wikimedia Commons",
      };
    })
    .filter(Boolean);
}

function formatFlagCandidateLabel(fileName) {
  return String(fileName || "")
    .replace(/\.[a-z0-9]+$/i, "")
    .replace(/_/g, " ");
}

function deriveFlagCandidateLabelFromUrl(url) {
  const normalizedUrl = String(url || "").trim();
  if (!normalizedUrl) return t("flag");
  try {
    const parsed = new URL(normalizedUrl);
    const pathname = parsed.pathname.split("/").filter(Boolean).pop() || parsed.hostname || normalizedUrl;
    return decodeURIComponent(pathname).replace(/\.[a-z0-9]+$/i, "").replace(/[_-]+/g, " ");
  } catch {
    return normalizedUrl.replace(/\.[a-z0-9]+$/i, "").replace(/[_-]+/g, " ");
  }
}

function normalizeFlagImageCandidates(candidates) {
  if (!Array.isArray(candidates)) return [];
  const seen = new Set();
  return candidates
    .map((candidate) => {
      const fileName = String(candidate?.fileName || "").trim();
      const key = String(candidate?.key || fileName || "").trim();
      const sourceType = String(candidate?.sourceType || "").trim() === "manual" ? "manual" : "wikidata";
      const mediaSourceType = normalizeMediaSourceType(
        candidate?.mediaSourceType,
        sourceType === "wikidata" ? "wikidata" : "url",
      );
      const explicitUrl = String(candidate?.url || "").trim();
      const assetPath = normalizeLocalAssetPath(candidate?.assetPath);
      const resolvedUrl = explicitUrl || (fileName ? buildCommonsFileUrl(fileName) : "");
      if (!key || (!resolvedUrl && !assetPath) || seen.has(key)) return null;
      seen.add(key);
      const label = String(candidate?.label || "").trim()
        || (sourceType === "manual" ? deriveFlagCandidateLabelFromUrl(resolvedUrl) : formatFlagCandidateLabel(fileName || key));
      const sourceLabel = String(candidate?.sourceLabel || "").trim()
        || (sourceType === "manual" ? "" : "Wikidata / Wikimedia Commons");
      return {
        key,
        fileName,
        url: resolvedUrl,
        label,
        sourceType,
        mediaSourceType,
        assetPath,
        sourceLabel,
      };
    })
    .filter(Boolean);
}

function getFlagLibraryOwnerEvent(eventItem) {
  if (!eventItem) return null;
  if (!isFlagMarkerEvent(eventItem)) return eventItem;
  return eventItem.parentEventId ? getEventById(eventItem.parentEventId) : null;
}

function getSharedFlagImageCandidates(eventItem) {
  const ownerEvent = getFlagLibraryOwnerEvent(eventItem);
  if (!ownerEvent) return [];
  return normalizeFlagImageCandidates(ownerEvent.wikidataFlagCandidates);
}

function applyFlagCandidateSelectionToEvent(eventItem, candidateKey) {
  if (!eventItem) return;
  const normalizedCandidateKey = String(candidateKey || "").trim();
  const matchingCandidate = getSharedFlagImageCandidates(eventItem).find((candidate) => candidate.key === normalizedCandidateKey) ?? null;
  eventItem.flagImageFileName = matchingCandidate?.key ?? "";
  eventItem.flagImageUrl = matchingCandidate?.url ?? null;
  syncFlagMarkerAutoTitle(eventItem);
}

function syncFlagCandidateSelectionsForFamily(ownerEvent) {
  if (!ownerEvent) return;
  const normalizedCandidates = normalizeFlagImageCandidates(ownerEvent.wikidataFlagCandidates);
  ownerEvent.wikidataFlagCandidates = normalizedCandidates;
  ownerEvent.wikidataFlagCandidatesLookupCompleted = true;
  const validKeys = new Set(normalizedCandidates.map((candidate) => candidate.key));
  const fallbackCandidate = normalizedCandidates[0] ?? null;
  getFlagMarkerChildEvents(ownerEvent.id).forEach((childEvent) => {
    childEvent.wikidataFlagCandidates = normalizedCandidates;
    childEvent.wikidataFlagCandidatesLookupCompleted = true;
    const currentKey = String(childEvent.flagImageFileName || "").trim();
    const nextCandidate = currentKey && validKeys.has(currentKey)
      ? normalizedCandidates.find((candidate) => candidate.key === currentKey) ?? fallbackCandidate
      : fallbackCandidate;
    childEvent.flagImageFileName = nextCandidate?.key ?? "";
    childEvent.flagImageUrl = nextCandidate?.url ?? null;
    syncFlagMarkerAutoTitle(childEvent);
  });
}

function setSharedFlagImageCandidates(eventItem, candidates) {
  const ownerEvent = getFlagLibraryOwnerEvent(eventItem);
  if (!ownerEvent) return [];
  ownerEvent.wikidataFlagCandidates = normalizeFlagImageCandidates(candidates);
  ownerEvent.wikidataFlagCandidatesLookupCompleted = true;
  syncFlagCandidateSelectionsForFamily(ownerEvent);
  return ownerEvent.wikidataFlagCandidates;
}

function mergeSharedFlagImageCandidates(existingCandidates, wikidataCandidates) {
  const normalizedExisting = normalizeFlagImageCandidates(existingCandidates);
  const normalizedWikidata = normalizeFlagImageCandidates(wikidataCandidates).map((candidate) => ({
    ...candidate,
    sourceType: "wikidata",
    sourceLabel: "Wikidata / Wikimedia Commons",
  }));
  const manualCandidates = normalizedExisting.filter((candidate) => candidate.sourceType === "manual");
  return normalizeFlagImageCandidates([...normalizedWikidata, ...manualCandidates]);
}

function eventUsesLocalMediaAssets(eventItem) {
  if (!eventItem) return false;
  if (normalizeMediaSourceType(eventItem.manualImageSourceType) === "local-file" && normalizeLocalAssetPath(eventItem.manualImageAssetPath)) {
    return true;
  }
  const sharedFlagCandidates = getSharedFlagImageCandidates(eventItem);
  return sharedFlagCandidates.some((candidate) => normalizeMediaSourceType(candidate.mediaSourceType, "url") === "local-file" && normalizeLocalAssetPath(candidate.assetPath));
}

function projectHasLocalMediaAssets() {
  return timelineEvents.some((eventItem) => eventUsesLocalMediaAssets(eventItem));
}

function getEventSelectedFlagCandidate(eventItem) {
  const selectedKey = String(eventItem?.flagImageFileName || "").trim();
  if (!selectedKey) return null;
  return getSharedFlagImageCandidates(eventItem).find((candidate) => candidate.key === selectedKey) ?? null;
}

function getFlagMarkerDefaultTitle(eventItem) {
  const selectedCandidate = getEventSelectedFlagCandidate(eventItem) ?? getStoredFlagCandidate(eventItem);
  const candidateLabel = String(selectedCandidate?.label || "").trim();
  return candidateLabel || t("flag_event_title");
}

function syncFlagMarkerAutoTitle(eventItem) {
  if (!isFlagMarkerEvent(eventItem)) return;
  if (eventItem.flagTitleManual === true) return;
  eventItem.title = getFlagMarkerDefaultTitle(eventItem);
}

function normalizeFlagPresentationMode(value) {
  return String(value || "").trim() === "banner" ? "banner" : "mast";
}

function normalizeMediaSourceType(value, fallback = "none") {
  const normalized = String(value || "").trim();
  if (normalized === "url" || normalized === "local-file" || normalized === "wikidata") return normalized;
  return fallback;
}

function normalizeLocalAssetPath(value) {
  return typeof value === "string" && value.trim()
    ? value.trim().replace(/\\/g, "/")
    : "";
}

function sanitizeAssetFileName(fileName, fallbackBase = "asset") {
  const normalizedName = String(fileName || "").trim().replace(/[/\\]+/g, "-");
  const extensionMatch = normalizedName.match(/(\.[a-z0-9]{1,8})$/i);
  const extension = extensionMatch ? extensionMatch[1].toLowerCase() : "";
  const baseName = extension ? normalizedName.slice(0, -extension.length) : normalizedName;
  const safeBase = String(baseName || fallbackBase)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "") || fallbackBase;
  return `${safeBase}-${Date.now()}${extension}`;
}

function getStoredFlagCandidate(eventItem) {
  const fileName = String(eventItem?.flagImageFileName || "").trim();
  const url = String(eventItem?.flagImageUrl || "").trim();
  if (!url) return null;
  return {
    key: fileName || `legacy:${url}`,
    fileName,
    url,
    label: fileName ? formatFlagCandidateLabel(fileName) : deriveFlagCandidateLabelFromUrl(url),
    sourceType: fileName && !fileName.startsWith("manual:") ? "wikidata" : "manual",
    sourceLabel: fileName && !fileName.startsWith("manual:") ? "Wikidata / Wikimedia Commons" : "",
    isLegacy: true,
  };
}

function isFlagMarkerEvent(eventItem) {
  return String(eventItem?.eventSubtype || "").trim() === "flag-marker";
}

function getFlagMarkerChildEvents(parentEventId) {
  return timelineEvents.filter((eventItem) => isFlagMarkerEvent(eventItem) && eventItem.parentEventId === parentEventId);
}

function getFlagMarkerChildEvent(parentEventId) {
  return getFlagMarkerChildEvents(parentEventId)[0] ?? null;
}

function getFlagLookupEntityId(eventItem) {
  if (!eventItem) return null;
  if (isFlagMarkerEvent(eventItem)) {
    const explicitId = normalizeWikidataEntityId(eventItem.flagWikidataEntityId);
    if (explicitId) return explicitId;
    const parentItem = eventItem.parentEventId ? getEventById(eventItem.parentEventId) : null;
    return normalizeWikidataEntityId(parentItem?.sourceId);
  }
  return eventItem.source === "wikidata" ? normalizeWikidataEntityId(eventItem.sourceId) : null;
}

function syncFlagMarkerChildWithParent(parentEvent, childEvent) {
  if (!parentEvent || !childEvent) return;
  const parentStartValue = getTimelineValueForEventStart(parentEvent);
  const parentEndValue = getTimelineValueForEventEnd(parentEvent);
  const minParentValue = Math.min(parentStartValue, parentEndValue);
  const maxParentValue = Math.max(parentStartValue, parentEndValue);
  childEvent.groupId = parentEvent.groupId ?? null;
  childEvent.startYear = parentEvent.startYear;
  childEvent.endYear = parentEvent.endYear;
  childEvent.startDateValue = parentEvent.startDateValue;
  childEvent.endDateValue = parentEvent.endDateValue;
  childEvent.startPrecision = parentEvent.startPrecision;
  childEvent.endPrecision = parentEvent.endPrecision;
  childEvent.endIsToday = Boolean(parentEvent.endIsToday);
  childEvent.isRange = Boolean(parentEvent.isRange);
  childEvent.flagWikidataEntityId = normalizeWikidataEntityId(parentEvent.sourceId) || "";
  childEvent.wikidataFlagCandidates = getSharedFlagImageCandidates(parentEvent);
  childEvent.wikidataFlagCandidatesLookupCompleted = parentEvent.wikidataFlagCandidatesLookupCompleted === true;
  if (childEvent.flagPositionMode === "free") {
    const nextValue = Number(childEvent.flagAnchorDateValue);
    childEvent.flagAnchorDateValue = Number.isFinite(nextValue)
      ? clamp(nextValue, minParentValue, maxParentValue)
      : getEventAnchorYear(parentEvent);
  } else if (!Number.isFinite(Number(childEvent.flagAnchorDateValue))) {
    childEvent.flagAnchorDateValue = getEventAnchorYear(parentEvent);
  }
}

function createFlagMarkerEvent(parentEvent) {
  const nextEvent = createEmptyEvent();
  nextEvent.id = createUniqueId("flag");
  nextEvent.title = t("flag_event_title");
  nextEvent.eventSubtype = "flag-marker";
  nextEvent.groupId = parentEvent.groupId ?? null;
  nextEvent.parentEventId = parentEvent.id;
  nextEvent.flagDisplayEnabled = false;
  const sharedCandidates = getSharedFlagImageCandidates(parentEvent);
  nextEvent.flagImageUrl = null;
  nextEvent.flagImageFileName = "";
  nextEvent.flagPositionMode = "label";
  nextEvent.flagAnchorDateValue = getEventAnchorYear(parentEvent);
  nextEvent.flagAnchorPrecision = parentEvent.startPrecision ?? 9;
  nextEvent.wikidataFlagCandidates = sharedCandidates;
  nextEvent.wikidataFlagCandidatesLookupCompleted = parentEvent.wikidataFlagCandidatesLookupCompleted === true;
  nextEvent.flagWikidataEntityId = normalizeWikidataEntityId(parentEvent.sourceId) || "";
  nextEvent.flagTitleManual = false;
  nextEvent.title = t("flag_event_title");
  syncFlagMarkerChildWithParent(parentEvent, nextEvent);
  return nextEvent;
}

function createAdditionalFlagMarkerEvent(parentEvent) {
  return createFlagMarkerEvent(parentEvent);
}

function migrateLegacyFlagMarkerChildren() {
  const parentEvents = timelineEvents.filter((eventItem) => !isFlagMarkerEvent(eventItem));
  parentEvents.forEach((parentEvent) => {
    const hasLegacyFlagState = parentEvent.flagDisplayEnabled === true
      || Boolean(String(parentEvent.flagImageUrl || "").trim())
      || Boolean(String(parentEvent.flagImageFileName || "").trim())
      || normalizeFlagImageCandidates(parentEvent.wikidataFlagCandidates).length > 0;
    const existingChildren = getFlagMarkerChildEvents(parentEvent.id);
    if (existingChildren.length) {
      if (getSharedFlagImageCandidates(parentEvent).length === 0) {
        const inheritedCandidates = normalizeFlagImageCandidates(existingChildren.flatMap((childEvent) => childEvent.wikidataFlagCandidates || []));
        const storedCandidate = getStoredFlagCandidate(existingChildren[0]);
        parentEvent.wikidataFlagCandidates = inheritedCandidates.length
          ? inheritedCandidates
          : (storedCandidate ? [storedCandidate] : []);
      }
      existingChildren.forEach((childEvent) => {
        syncFlagMarkerChildWithParent(parentEvent, childEvent);
      });
      syncFlagCandidateSelectionsForFamily(parentEvent);
      return;
    }
    if (!hasLegacyFlagState) return;
    const flagChild = createFlagMarkerEvent(parentEvent);
    flagChild.flagDisplayEnabled = parentEvent.flagDisplayEnabled === true;
    flagChild.flagImageUrl = parentEvent.flagImageUrl ?? null;
    flagChild.flagImageFileName = String(parentEvent.flagImageFileName || "").trim();
    flagChild.flagTitleManual = false;
    syncFlagMarkerAutoTitle(flagChild);
    timelineEvents.push(flagChild);
    parentEvent.flagDisplayEnabled = false;
    parentEvent.flagImageUrl = null;
    parentEvent.flagImageFileName = "";
    parentEvent.flagTimelineOffsetX = 0;
    parentEvent.wikidataFlagCandidates = normalizeFlagImageCandidates(parentEvent.wikidataFlagCandidates);
    parentEvent.wikidataFlagCandidatesLookupCompleted = parentEvent.wikidataFlagCandidatesLookupCompleted === true
      || parentEvent.wikidataFlagCandidates.length > 0;
  });
}

function getClaimStringValues(entity, propertyId) {
  const claims = Array.isArray(entity?.claims?.[propertyId]) ? entity.claims[propertyId] : [];
  return claims
    .map((claim) => claim?.mainsnak?.datavalue?.value)
    .filter((value, index, array) => typeof value === "string" && value.trim() && array.indexOf(value) === index)
    .map((value) => value.trim());
}

function getFirstClaimFileName(entity, propertyId) {
  return getClaimStringValues(entity, propertyId)[0] || null;
}

function getPrimaryCoverImageFileName(entity) {
  return getFirstClaimFileName(entity, "P3383")
    || getFirstClaimFileName(entity, "P18");
}

function getPrimaryImageFileName(entity, options = {}) {
  const { preferCover = false } = options;
  return preferCover
    ? getPrimaryCoverImageFileName(entity)
    : getFirstClaimFileName(entity, "P18");
}

function getPrimaryImageUrl(entity) {
  return buildCommonsFileUrl(getPrimaryImageFileName(entity));
}

function applyWikidataTmdbClaimsToSource(sourceItem, entity) {
  if (!sourceItem || sourceItem.kind !== "source" || !entity) return false;
  const movieId = getClaimStringValues(entity, "P4947")[0] || "";
  const tvId = getClaimStringValues(entity, "P4983")[0] || "";
  const tmdbId = movieId || tvId;
  if (!tmdbId) return false;
  const tmdbMediaType = tvId ? "tv" : "movie";
  const sourceId = `${tmdbMediaType}:${tmdbId}`;
  const changed = sourceItem.source !== "tmdb"
    || sourceItem.sourceId !== sourceId
    || sourceItem.tmdbId !== tmdbId
    || sourceItem.tmdbMediaType !== tmdbMediaType;
  sourceItem.source = "tmdb";
  sourceItem.sourceId = sourceId;
  sourceItem.tmdbId = tmdbId;
  sourceItem.tmdbMediaType = tmdbMediaType;
  sourceItem.externalId = "";
  sourceItem.url = getSourceTmdbUrl(sourceItem);
  ensureSourceEventFields(sourceItem);
  return changed;
}

function getEntityLabel(entity, fallback = "") {
  if (!entity) return String(fallback || "");
  const preferredLanguage = getWikidataLanguageCode();
  const fallbackLanguage = preferredLanguage === "de" ? "en" : "de";
  return entity.labels?.[preferredLanguage]?.value
    || entity.labels?.[fallbackLanguage]?.value
    || String(fallback || "");
}

function getClaimEntityIds(entity, propertyId) {
  const claims = Array.isArray(entity?.claims?.[propertyId]) ? entity.claims[propertyId] : [];
  return claims
    .map((claim) => claim?.mainsnak?.datavalue?.value?.id)
    .filter((value, index, array) => typeof value === "string" && value && array.indexOf(value) === index);
}

