const WIKIDATA_FILM_SOURCE_INSTANCE_IDS = [
  ...WIKIDATA_TYPE_PROFILES.film.instanceOfIds,
  ...WIKIDATA_TYPE_PROFILES.series.instanceOfIds,
];
const WIKIDATA_EVENT_SEARCH_EXCLUDED_INSTANCE_IDS = [
  ...WIKIDATA_TYPE_PROFILES.film.instanceOfIds,
  ...WIKIDATA_TYPE_PROFILES.series.instanceOfIds,
];
const WIKIDATA_EVENT_SEARCH_EXCLUDED_INSTANCE_LABELS = [
  ...WIKIDATA_TYPE_PROFILES.film.instanceOfLabels,
  ...WIKIDATA_TYPE_PROFILES.series.instanceOfLabels,
];

function getTypeProfileFieldDefinitions(profileKey) {
  return WIKIDATA_TYPE_PROFILES[profileKey]?.fields ?? [];
}

function getWikidataTypeProfileKeyForInstanceIds(instanceIds, instanceText = "") {
  const normalizedIds = (Array.isArray(instanceIds) ? instanceIds : [])
    .map((value) => normalizeWikidataEntityId(value))
    .filter(Boolean);
  const matchedEntry = Object.entries(WIKIDATA_TYPE_PROFILES).find(([, profile]) =>
    profile.instanceOfIds.some((instanceId) => normalizedIds.includes(instanceId))
  );
  if (matchedEntry?.[0]) return matchedEntry[0];
  const normalizedInstanceText = String(instanceText || "").trim().toLowerCase();
  if (!normalizedInstanceText) return "";
  const labelMatchedEntry = Object.entries(WIKIDATA_TYPE_PROFILES).find(([, profile]) =>
    Array.isArray(profile.instanceOfLabels)
    && profile.instanceOfLabels.some((label) => normalizedInstanceText.includes(String(label || "").trim().toLowerCase()))
  );
  return labelMatchedEntry?.[0] ?? "";
}

function createTypedMetadata(profileKey = "") {
  const metadata = {};
  getTypeProfileFieldDefinitions(profileKey).forEach(({ key }) => {
    metadata[key] = { value: "", source: "" };
  });
  return metadata;
}

function updateEventWorkInformationFromTypedMetadata(eventItem) {
  if (!eventItem) return;
  const profileKey = eventItem.wikidataTypeProfile || "";
  if (!profileKey) return;
  eventItem.workInformation = composeTypedMetadataWorkInformation(profileKey, eventItem.typedMetadata);
  if (!eventItem.workInformation) {
    eventItem.workInformationSource = "";
    return;
  }
  eventItem.workInformationSource = Object.values(eventItem.typedMetadata || {}).some((entry) => entry?.source === "manual")
    ? "manual"
    : "wikidata";
}

function normalizeTypedMetadata(profileKey, metadata) {
  const normalized = createTypedMetadata(profileKey);
  const source = metadata && typeof metadata === "object" ? metadata : {};
  Object.keys(normalized).forEach((key) => {
    const entry = source[key];
    if (entry && typeof entry === "object") {
      normalized[key] = {
        value: typeof entry.value === "string" ? entry.value.trim() : "",
        source: entry.source === "wikidata" || entry.source === "manual" ? entry.source : "",
      };
      return;
    }
    if (typeof entry === "string") {
      normalized[key] = {
        value: entry.trim(),
        source: entry.trim() ? "manual" : "",
      };
    }
  });
  return normalized;
}

function getEffectiveTypedMetadataEntry(eventItem, key) {
  const entry = eventItem?.typedMetadata?.[key];
  if (!entry || typeof entry !== "object") {
    return { value: "", source: "" };
  }
  return {
    value: typeof entry.value === "string" ? entry.value.trim() : "",
    source: entry.source === "wikidata" || entry.source === "manual" ? entry.source : "",
  };
}

function setTypedMetadataManualValue(eventItem, key, value) {
  if (!eventItem) return;
  const profileKey = eventItem.wikidataTypeProfile || "";
  eventItem.typedMetadata = normalizeTypedMetadata(profileKey, eventItem.typedMetadata);
  const trimmedValue = String(value || "").trim();
  eventItem.typedMetadata[key] = {
    value: trimmedValue,
    source: trimmedValue ? "manual" : "",
  };
}

function composeTypedMetadataWorkInformation(profileKey, typedMetadata) {
  const metadata = normalizeTypedMetadata(profileKey, typedMetadata);
  return getTypeProfileFieldDefinitions(profileKey)
    .map(({ key, label }) => {
      const entry = metadata[key];
      return entry?.value ? `${label}: ${entry.value}` : "";
    })
    .filter(Boolean)
    .join("\n");
}

function getClaimQuantityValues(entity, propertyId) {
  const claims = Array.isArray(entity?.claims?.[propertyId]) ? entity.claims[propertyId] : [];
  return claims.map((claim) => {
    const quantityValue = claim?.mainsnak?.datavalue?.value;
    if (!quantityValue || typeof quantityValue.amount !== "string") return null;
    const numericAmount = Number(quantityValue.amount);
    if (!Number.isFinite(numericAmount)) return null;
    const unitUri = typeof quantityValue.unit === "string" ? quantityValue.unit : "";
    const unitId = unitUri.includes("/") ? unitUri.slice(unitUri.lastIndexOf("/") + 1) : (unitUri === "1" ? "" : unitUri);
    return {
      amount: numericAmount,
      unitId: unitId || "",
    };
  }).filter(Boolean);
}

function formatArtworkQuantityEntry(entry, linkedEntities = {}) {
  if (!entry || !Number.isFinite(entry.amount)) return "";
  const amountText = formatNumericLabel(entry.amount);
  const unitLabel = entry.unitId ? getEntityLabel(linkedEntities[entry.unitId], entry.unitId) : "";
  return unitLabel ? `${amountText} ${unitLabel}` : amountText;
}

function isPaintingEntity(entity) {
  if (!entity) return false;
  const instanceIds = getClaimEntityIds(entity, "P31");
  if (instanceIds.includes("Q3305213")) return true;
  const hasCreator = getClaimEntityIds(entity, "P170").length > 0;
  const hasInception = Boolean(getPrimaryClaim(entity, "P571"));
  const hasMaterial = getClaimEntityIds(entity, "P186").length > 0;
  const hasDimensions = getClaimQuantityValues(entity, "P2048").length > 0 || getClaimQuantityValues(entity, "P2049").length > 0;
  const hasCollectionOrLocation = getClaimEntityIds(entity, "P195").length > 0 || getClaimEntityIds(entity, "P276").length > 0;
  return hasCreator && (hasInception || hasMaterial || hasDimensions || hasCollectionOrLocation);
}

function buildPaintingWorkInformation(entity, linkedEntities = {}) {
  if (!entity || !isPaintingEntity(entity)) return "";
  const creatorIds = getClaimEntityIds(entity, "P170");
  const materialIds = getClaimEntityIds(entity, "P186");
  const collectionIds = getClaimEntityIds(entity, "P195");
  const locationIds = getClaimEntityIds(entity, "P276");
  const creators = creatorIds.map((id) => getEntityLabel(linkedEntities[id], id)).filter(Boolean);
  const materials = materialIds.map((id) => getEntityLabel(linkedEntities[id], id)).filter(Boolean);
  const collections = collectionIds.map((id) => getEntityLabel(linkedEntities[id], id)).filter(Boolean);
  const locations = locationIds.map((id) => getEntityLabel(linkedEntities[id], id)).filter(Boolean);
  const inceptionClaim = getPrimaryClaim(entity, "P571");
  const inception = inceptionClaim
    ? (extractTimeInfoFromTimeValue(inceptionClaim?.mainsnak?.datavalue?.value) ?? null)
    : getClaimTimeInfo(entity, "P571");
  const earliest = inceptionClaim
    ? getClaimQualifierTimeInfo(inceptionClaim, "P1319")
    : getClaimTimeInfo(entity, "P1319");
  const latest = inceptionClaim
    ? getClaimQualifierTimeInfo(inceptionClaim, "P1326")
    : getClaimTimeInfo(entity, "P1326");
  const dating = (() => {
    if (earliest && latest) {
      if (earliest.value === latest.value && earliest.precision === latest.precision) {
        return formatTemporalEditorValue(earliest.value, earliest.precision, false);
      }
      return `${formatTemporalEditorValue(earliest.value, earliest.precision, false)} bis ${formatTemporalEditorValue(latest.value, latest.precision, false)}`;
    }
    if (earliest) return formatTemporalEditorValue(earliest.value, earliest.precision, false);
    if (latest) return formatTemporalEditorValue(latest.value, latest.precision, false);
    if (inception) return formatTemporalEditorValue(inception.value, inception.precision, false);
    return "";
  })();
  const heightEntry = getClaimQuantityValues(entity, "P2048")[0] ?? null;
  const widthEntry = getClaimQuantityValues(entity, "P2049")[0] ?? null;
  const widthText = formatArtworkQuantityEntry(widthEntry, linkedEntities);
  const heightText = formatArtworkQuantityEntry(heightEntry, linkedEntities);
  const dimensions = [widthText, heightText].filter(Boolean).join(" × ");
  const locationText = [...collections, ...locations].filter((value, index, array) => value && array.indexOf(value) === index).join(", ");
  const lines = [
    creators.length ? `Künstler / Maler: ${creators.join(", ")}` : "",
    dating ? `Entstehungsjahr / Datierung: ${dating}` : "",
    materials.length ? `Technik / Material / Malgrund: ${materials.join(", ")}` : "",
    dimensions ? `Maße / Format: ${dimensions}` : "",
    locationText ? `Standort / Sammlung / Museum: ${locationText}` : "",
  ].filter(Boolean);
  return lines.join("\n");
}

function buildPaintingTypedMetadata(entity, linkedEntities = {}) {
  if (!entity || !isPaintingEntity(entity)) return createTypedMetadata("painting");
  const metadata = createTypedMetadata("painting");
  const creatorIds = getClaimEntityIds(entity, "P170");
  const materialIds = getClaimEntityIds(entity, "P186");
  const collectionIds = getClaimEntityIds(entity, "P195");
  const locationIds = getClaimEntityIds(entity, "P276");
  const creators = creatorIds.map((id) => getEntityLabel(linkedEntities[id], id)).filter(Boolean);
  const materials = materialIds.map((id) => getEntityLabel(linkedEntities[id], id)).filter(Boolean);
  const collections = collectionIds.map((id) => getEntityLabel(linkedEntities[id], id)).filter(Boolean);
  const locations = locationIds.map((id) => getEntityLabel(linkedEntities[id], id)).filter(Boolean);
  const inceptionClaim = getPrimaryClaim(entity, "P571");
  const inception = inceptionClaim
    ? (extractTimeInfoFromTimeValue(inceptionClaim?.mainsnak?.datavalue?.value) ?? null)
    : getClaimTimeInfo(entity, "P571");
  const earliest = inceptionClaim
    ? getClaimQualifierTimeInfo(inceptionClaim, "P1319")
    : getClaimTimeInfo(entity, "P1319");
  const latest = inceptionClaim
    ? getClaimQualifierTimeInfo(inceptionClaim, "P1326")
    : getClaimTimeInfo(entity, "P1326");
  const dating = (() => {
    if (earliest && latest) {
      if (earliest.value === latest.value && earliest.precision === latest.precision) {
        return formatTemporalEditorValue(earliest.value, earliest.precision, false);
      }
      return `${formatTemporalEditorValue(earliest.value, earliest.precision, false)} bis ${formatTemporalEditorValue(latest.value, latest.precision, false)}`;
    }
    if (earliest) return formatTemporalEditorValue(earliest.value, earliest.precision, false);
    if (latest) return formatTemporalEditorValue(latest.value, latest.precision, false);
    if (inception) return formatTemporalEditorValue(inception.value, inception.precision, false);
    return "";
  })();
  const heightEntry = getClaimQuantityValues(entity, "P2048")[0] ?? null;
  const widthEntry = getClaimQuantityValues(entity, "P2049")[0] ?? null;
  const widthText = formatArtworkQuantityEntry(widthEntry, linkedEntities);
  const heightText = formatArtworkQuantityEntry(heightEntry, linkedEntities);
  const dimensions = [widthText, heightText].filter(Boolean).join(" × ");
  const locationText = [...collections, ...locations]
    .filter((value, index, array) => value && array.indexOf(value) === index)
    .join(", ");

  metadata.creator = { value: creators.join(", "), source: creators.length ? "wikidata" : "" };
  metadata.dating = { value: dating, source: dating ? "wikidata" : "" };
  metadata.material = { value: materials.join(", "), source: materials.length ? "wikidata" : "" };
  metadata.dimensions = { value: dimensions, source: dimensions ? "wikidata" : "" };
  metadata.location = { value: locationText, source: locationText ? "wikidata" : "" };
  return metadata;
}

function createEmptyPaintingInfo() {
  return {
    artist: "",
    inception: "",
    techniqueMaterial: "",
    dimensions: "",
    location: "",
  };
}

function normalizePaintingInfo(info) {
  const base = createEmptyPaintingInfo();
  if (!info || typeof info !== "object") return base;
  Object.keys(base).forEach((key) => {
    base[key] = typeof info[key] === "string" ? info[key].trim() : "";
  });
  return base;
}

function getEffectivePaintingInfo(eventItem) {
  const wikidataInfo = normalizePaintingInfo(eventItem?.wikidataPaintingInfo);
  const manualInfo = normalizePaintingInfo(eventItem?.manualPaintingInfo);
  const result = createEmptyPaintingInfo();
  Object.keys(result).forEach((key) => {
    result[key] = wikidataInfo[key] || manualInfo[key] || "";
  });
  return result;
}

function getKnownEventCategories(currentCategory = "") {
  const known = new Set();
  if (currentCategory && String(currentCategory).trim()) {
    known.add(String(currentCategory).trim());
  }
  timelineEvents.forEach((eventItem) => {
    const category = String(eventItem?.category || "").trim();
    if (category) known.add(category);
  });
  return [...known].sort((a, b) => a.localeCompare(b, "de", { sensitivity: "base" }));
}

async function ensurePaintingInfo(eventItem, { force = false, entity: providedEntity = null } = {}) {
  if (!eventItem || !eventItem.sourceId) return null;
  if (!force && eventItem.workInformationSource === "wikidata" && eventItem.workInformation) {
    eventItem.workInformationLookupState = "ready";
    eventItem.workInformationLookupError = "";
    eventItem.workInformationLookupCompleted = true;
    return eventItem.workInformation;
  }
  eventItem.workInformationLookupState = "loading";
  eventItem.workInformationLookupError = "";
  try {
    const entity = providedEntity || await fetchWikidataEntity(eventItem.sourceId);
    if (!entity) {
      eventItem.workInformationLookupState = "error";
      eventItem.workInformationLookupError = "leere Antwort";
      eventItem.workInformationLookupCompleted = true;
      return null;
    }
    if (!isPaintingEntity(entity)) {
      eventItem.workInformation = "";
      eventItem.workInformationSource = "";
      eventItem.additionalInformationExpanded = null;
      eventItem.workInformationLookupState = "nonpainting";
      eventItem.workInformationLookupError = "";
      eventItem.workInformationLookupCompleted = true;
      return "";
    }
    const linkedIds = [
      ...getClaimEntityIds(entity, "P170"),
      ...getClaimEntityIds(entity, "P186"),
      ...getClaimEntityIds(entity, "P195"),
      ...getClaimEntityIds(entity, "P276"),
      ...getClaimQuantityValues(entity, "P2048").map((entry) => entry.unitId),
      ...getClaimQuantityValues(entity, "P2049").map((entry) => entry.unitId),
    ]
      .map((value) => normalizeWikidataEntityId(value))
      .filter((value, index, array) => /^Q\d+$/i.test(value || "") && array.indexOf(value) === index);
    let linkedEntities = {};
    try {
      linkedEntities = await fetchWikidataEntities(linkedIds);
    } catch {
      linkedEntities = {};
    }
  const workInformation = buildPaintingWorkInformation(entity, linkedEntities);
    eventItem.typedMetadata = normalizeTypedMetadata("painting", eventItem.typedMetadata);
    const wikidataMetadata = buildPaintingTypedMetadata(entity, linkedEntities);
    Object.keys(wikidataMetadata).forEach((key) => {
      const nextEntry = wikidataMetadata[key];
      if (nextEntry?.value) {
        eventItem.typedMetadata[key] = { value: nextEntry.value, source: "wikidata" };
      } else if (eventItem.typedMetadata[key]?.source === "wikidata") {
        eventItem.typedMetadata[key] = { value: "", source: "" };
      }
    });
    eventItem.wikidataTypeProfile = "painting";
    eventItem.workInformation = composeTypedMetadataWorkInformation("painting", eventItem.typedMetadata) || workInformation;
    eventItem.workInformationSource = eventItem.workInformation
      ? (Object.values(eventItem.typedMetadata).some((entry) => entry?.source === "manual") ? "manual" : "wikidata")
      : "";
    eventItem.workInformationLookupState = workInformation ? "ready" : "empty";
    eventItem.workInformationLookupError = "";
    eventItem.workInformationLookupCompleted = true;
    return workInformation;
  } catch (error) {
    eventItem.workInformationLookupState = "error";
    eventItem.workInformationLookupError = String(error?.message || error || "unbekannter Fehler");
    eventItem.workInformationLookupCompleted = true;
    return null;
  }
}

async function ensureTypedMetadataForEvent(eventItem, { force = false, entity: providedEntity = null } = {}) {
  if (!eventItem || !eventItem.sourceId) return null;
  eventItem.typedMetadataLookupStatus = "loading";
  eventItem.typedMetadataLookupError = "";
  const entity = providedEntity || await fetchWikidataEntity(eventItem.sourceId);
  if (!entity) {
    eventItem.typedMetadataLookupStatus = "no-entity";
    return null;
  }
  await ensureEventWikidataInstanceOfInfo(eventItem, { force, entity });
  const profileKey = eventItem.wikidataTypeProfile || "";
  if (!profileKey) {
    eventItem.typedMetadataLookupStatus = "no-profile";
    return null;
  }
  if (profileKey === "painting") {
    const linkedIds = [
      ...getClaimEntityIds(entity, "P170"),
      ...getClaimEntityIds(entity, "P186"),
      ...getClaimEntityIds(entity, "P195"),
      ...getClaimEntityIds(entity, "P276"),
      ...getClaimQuantityValues(entity, "P2048").map((entry) => entry.unitId),
      ...getClaimQuantityValues(entity, "P2049").map((entry) => entry.unitId),
    ]
      .map((value) => normalizeWikidataEntityId(value))
      .filter((value, index, array) => /^Q\d+$/i.test(value || "") && array.indexOf(value) === index);
    let linkedEntities = {};
    try {
      linkedEntities = await fetchWikidataEntities(linkedIds);
    } catch {
      linkedEntities = {};
    }
    const wikidataMetadata = buildPaintingTypedMetadata(entity, linkedEntities);
    eventItem.typedMetadata = normalizeTypedMetadata("painting", eventItem.typedMetadata);
    let hasAnyWikidataValue = false;
    Object.keys(wikidataMetadata).forEach((key) => {
      const nextEntry = wikidataMetadata[key];
      if (nextEntry?.value) {
        eventItem.typedMetadata[key] = { value: nextEntry.value, source: "wikidata" };
        hasAnyWikidataValue = true;
      }
    });
    updateEventWorkInformationFromTypedMetadata(eventItem);
    eventItem.typedMetadataLookupStatus = hasAnyWikidataValue ? "success" : "empty";
    return eventItem.typedMetadata;
  }
  eventItem.typedMetadataLookupStatus = "no-profile";
  return null;
}

function getWikidataYears(entity) {
  const birthTime = getClaimTimeInfo(entity, "P569");
  const deathTime = getClaimTimeInfo(entity, "P570");
  if (birthTime && deathTime) {
    return {
      startYear: Math.min(birthTime.year, deathTime.year),
      endYear: Math.max(birthTime.year, deathTime.year),
      startDateValue: Math.min(birthTime.value, deathTime.value),
      endDateValue: Math.max(birthTime.value, deathTime.value),
      startPrecision: birthTime.year <= deathTime.year ? birthTime.precision : deathTime.precision,
      endPrecision: birthTime.year <= deathTime.year ? deathTime.precision : birthTime.precision,
    };
  }

  const pointCandidates = ["P585", "P571", "P577", "P569", "P570", "P580"];
  const rangeStart = getClaimTimeInfo(entity, "P580") ?? getClaimTimeInfo(entity, "P571");
  const rangeEnd = getClaimTimeInfo(entity, "P582") ?? getClaimTimeInfo(entity, "P576") ?? getClaimTimeInfo(entity, "P570");
  if (rangeStart && rangeEnd) {
    const startsEarlier = rangeStart.value <= rangeEnd.value;
    return {
      startYear: Math.min(rangeStart.year, rangeEnd.year),
      endYear: Math.max(rangeStart.year, rangeEnd.year),
      startDateValue: Math.min(rangeStart.value, rangeEnd.value),
      endDateValue: Math.max(rangeStart.value, rangeEnd.value),
      startPrecision: startsEarlier ? rangeStart.precision : rangeEnd.precision,
      endPrecision: startsEarlier ? rangeEnd.precision : rangeStart.precision,
    };
  }

  for (const propertyId of pointCandidates) {
    const pointTime = getClaimTimeInfo(entity, propertyId);
    if (pointTime) {
      return {
        startYear: pointTime.year,
        endYear: pointTime.year,
        startDateValue: pointTime.value,
        endDateValue: pointTime.value,
        startPrecision: pointTime.precision,
        endPrecision: pointTime.precision,
      };
    }
  }
  return null;
}

async function fetchWikidataEntity(entityId) {
  const normalizedEntityId = normalizeWikidataEntityId(entityId);
  if (!normalizedEntityId) return null;
  if (wikidataEntityCache.has(normalizedEntityId)) {
    return wikidataEntityCache.get(normalizedEntityId);
  }
  try {
    const url = new URL(WIKIDATA_API_URL);
    url.search = new URLSearchParams({
      action: "wbgetentities",
      format: "json",
      origin: "*",
      ids: normalizedEntityId,
      languages: getWikidataLanguageFallbacks(),
      languagefallback: "1",
      props: "labels|descriptions|claims",
    }).toString();

    const response = await fetch(url);
    if (!response.ok) throw new Error("Wikidata-Details konnten nicht geladen werden");
    const payload = await response.json();
    const entity = payload.entities?.[normalizedEntityId] ?? null;
    if (entity) {
      wikidataEntityCache.set(normalizedEntityId, entity);
    }
    return entity;
  } catch {
    const fallbackUrl = `https://www.wikidata.org/wiki/Special:EntityData/${normalizedEntityId}.json`;
    const fallbackResponse = await fetch(fallbackUrl);
    if (!fallbackResponse.ok) throw new Error("Wikidata-Details konnten nicht geladen werden");
    const fallbackPayload = await fallbackResponse.json();
    const entity = fallbackPayload.entities?.[normalizedEntityId] ?? null;
    if (entity) {
      wikidataEntityCache.set(normalizedEntityId, entity);
    }
    return entity;
  }
}

async function fetchWikidataEntities(entityIds) {
  const ids = [...new Set(entityIds.map((entityId) => normalizeWikidataEntityId(entityId)).filter(Boolean))];
  if (ids.length === 0) return {};
  const chunkSize = 40;
  const entities = {};
  const missingIds = [];

  ids.forEach((id) => {
    if (wikidataEntityCache.has(id)) {
      entities[id] = wikidataEntityCache.get(id);
    } else {
      missingIds.push(id);
    }
  });

  if (missingIds.length === 0) {
    return entities;
  }

  for (let index = 0; index < missingIds.length; index += chunkSize) {
    const chunk = missingIds.slice(index, index + chunkSize);
    const url = new URL(WIKIDATA_API_URL);
    url.search = new URLSearchParams({
      action: "wbgetentities",
      format: "json",
      origin: "*",
      ids: chunk.join("|"),
      languages: getWikidataLanguageFallbacks(),
      languagefallback: "1",
      props: "labels|descriptions|claims",
    }).toString();

    const response = await fetch(url);
    if (!response.ok) throw new Error("Wikidata-Details konnten nicht geladen werden");
    const payload = await response.json();
    const fetchedEntities = payload.entities ?? {};
    Object.entries(fetchedEntities).forEach(([id, entity]) => {
      if (entity) {
        wikidataEntityCache.set(id, entity);
        entities[id] = entity;
      }
    });
  }

  return entities;
}

function buildEventFromWikidata(entityId, entity, searchFallback) {
  const years = getWikidataYears(entity);
  const flagCandidates = getFlagImageCandidates(entity);
  const preferredLanguage = getWikidataLanguageCode();
  const fallbackLanguage = preferredLanguage === "de" ? "en" : "de";
  const label = entity.labels?.[preferredLanguage]?.value || entity.labels?.[fallbackLanguage]?.value || searchFallback.label || entityId;
  const description = entity.descriptions?.[preferredLanguage]?.value || entity.descriptions?.[fallbackLanguage]?.value || searchFallback.description || "";
  return {
    id: `wikidata-${entityId}`,
    source: "wikidata",
    sourceId: entityId,
    startYear: years?.startYear ?? null,
    endYear: years?.endYear ?? null,
    startDateValue: years?.startDateValue ?? years?.startYear ?? null,
    endDateValue: years?.endDateValue ?? years?.endYear ?? null,
    startPrecision: years?.startPrecision ?? null,
    endPrecision: years?.endPrecision ?? null,
    endIsToday: false,
    isRange: years ? (years.startDateValue !== years.endDateValue || years.startYear !== years.endYear) : false,
    visibleStepMin: undefined,
    visibleStepMax: undefined,
    lane: undefined,
    displayMode: "line",
    color: undefined,
    flagImageUrl: flagCandidates[0]?.url ?? null,
    flagDisplayEnabled: false,
    flagImageFileName: flagCandidates[0]?.fileName ?? "",
    flagWikidataEntityId: normalizeWikidataEntityId(entityId) || "",
    flagTimelineOffsetX: 0,
    wikidataFlagCandidates: flagCandidates,
    wikidataFlagCandidatesLookupCompleted: true,
    imageDisplayEnabled: false,
    imageSidePanelEnabled: true,
    wikidataImageFile: null,
    wikidataImageUrl: null,
    wikidataImageThumbUrl: null,
    wikidataImagePreviewUrl: null,
    wikidataImageWidth: null,
    wikidataImageHeight: null,
    wikidataThumbCropCenterX: 0.5,
    wikidataThumbCropCenterY: 0.5,
    wikidataThumbCropZoom: 1,
    imageAspectMode: "",
    imdbId: getClaimStringValues(entity, "P345")[0] || "",
    workInformation: "",
    workInformationSource: "",
    wikidataImageLookupCompleted: false,
    wikidataInstanceOfText: "",
    wikidataTypeIds: [],
    wikidataTypeProfile: "",
    typedMetadata: {},
    typedMetadataLookupStatus: "",
    typedMetadataLookupError: "",
    title: label,
    customTitle: "",
    customTitleLanguage: "",
    description,
    eventSubtype: "",
    wikidataTitle: label,
    wikidataDescription: description,
    descriptionTranslations: {},
    wikidataDescriptionMap: {
      [getContentLanguageCode()]: description,
    },
    category: "",
    projectCategoryId: "",
    groupId: null,
    parentEventId: null,
    relationLineStyle: "none",
    relationDirection: "parent-to-child",
    enabled: true,
  };
}

function applyWikidataEntityToEvent(eventItem, entity, fallback = {}) {
  if (!eventItem || !entity) return;
  const years = getWikidataYears(entity);
  const flagCandidates = getFlagImageCandidates(entity);
  const previousSelectedFlagFileName = String(eventItem.flagImageFileName || "").trim();
  const preferredLanguage = getWikidataLanguageCode();
  const fallbackLanguage = preferredLanguage === "de" ? "en" : "de";
  const label = entity.labels?.[preferredLanguage]?.value || entity.labels?.[fallbackLanguage]?.value || fallback.label || eventItem.title || eventItem.sourceId;
  const description = entity.descriptions?.[preferredLanguage]?.value || entity.descriptions?.[fallbackLanguage]?.value || fallback.description || eventItem.description || "";
  const previousLocalizedTitle = String(eventItem.wikidataTitle || "");
  const previousLocalizedDescription = String(eventItem.wikidataDescription || "");

  if (!eventItem.title || eventItem.title === previousLocalizedTitle) {
    eventItem.title = label;
  }
  if (!eventItem.description || eventItem.description === previousLocalizedDescription) {
    eventItem.description = description;
  }
  eventItem.wikidataTitle = label;
  eventItem.wikidataDescription = description;
  eventItem.wikidataTypeIds = getClaimEntityIds(entity, "P31")
    .map((value) => normalizeWikidataEntityId(value))
    .filter((value, index, array) => value && array.indexOf(value) === index);
  eventItem.wikidataTypeProfile = getWikidataTypeProfileKeyForInstanceIds(eventItem.wikidataTypeIds, eventItem.wikidataInstanceOfText);
  eventItem.wikidataInstanceOfText = "";
  eventItem.typedMetadata = normalizeTypedMetadata(eventItem.wikidataTypeProfile, eventItem.typedMetadata);
  eventItem.imdbId = getClaimStringValues(entity, "P345")[0] || eventItem.imdbId || "";
  if (eventItem.kind === "source") {
    eventItem.imageAspectMode = getSourceImageAspectMode(eventItem.sourceType);
  } else if (eventItem.kind !== "source") {
    eventItem.imageAspectMode = "";
  }
  const mergedFlagCandidates = mergeSharedFlagImageCandidates(getSharedFlagImageCandidates(eventItem), flagCandidates);
  setSharedFlagImageCandidates(eventItem, mergedFlagCandidates);
  const selectedFlagCandidate = mergedFlagCandidates.find((candidate) => candidate.key === previousSelectedFlagFileName) ?? mergedFlagCandidates[0] ?? null;
  eventItem.flagImageFileName = selectedFlagCandidate?.key ?? "";
  eventItem.flagImageUrl = selectedFlagCandidate?.url ?? null;
  if (!eventItem.displayMode) {
    eventItem.displayMode = eventItem.category === "Epoche" ? "bar" : "line";
  }
  if (years) {
    eventItem.startYear = years.startYear;
    eventItem.endYear = years.endYear;
    eventItem.startDateValue = years.startDateValue ?? years.startYear;
    eventItem.endDateValue = years.endDateValue ?? years.endYear;
    eventItem.startPrecision = years.startPrecision ?? 9;
    eventItem.endPrecision = years.endPrecision ?? 9;
    eventItem.endIsToday = false;
    eventItem.isRange = years.startDateValue !== years.endDateValue || years.startYear !== years.endYear;
  } else {
    eventItem.startYear = null;
    eventItem.endYear = null;
    eventItem.startDateValue = null;
    eventItem.endDateValue = null;
    eventItem.startPrecision = null;
    eventItem.endPrecision = null;
    eventItem.endIsToday = false;
    eventItem.isRange = eventItem.category === "Aeon"
      || eventItem.category === "Aera"
      || eventItem.category === "Äon"
      || eventItem.category === "Ära"
      || eventItem.category === "Periode"
      || eventItem.category === "Epoche";
  }
  normalizeEventDisplaySettings(eventItem);
}

async function ensureEventWikidataImageInfo(eventItem, options = {}) {
  const { force = false } = options;
  if (!eventItem || !["wikidata", "imdb"].includes(eventItem.source) || !eventItem.sourceId) return null;
  if (!force && eventItem.wikidataImageLookupCompleted === true) {
    if (eventItem.wikidataImageFile && eventItem.wikidataImageUrl) {
      return {
        fileName: eventItem.wikidataImageFile,
        url: eventItem.wikidataImageUrl,
      };
    }
    return null;
  }

  const cacheKey = eventItem.sourceId;
  if (!force && pendingEventImageLookupBySourceId.has(cacheKey)) {
    return pendingEventImageLookupBySourceId.get(cacheKey);
  }

  const lookupPromise = (async () => {
    try {
      const entity = await fetchWikidataEntity(eventItem.sourceId);
      const fileName = getPrimaryImageFileName(entity, { preferCover: isCoverImageEvent(eventItem) });
      const imageInfo = fileName ? await fetchCommonsImageInfo(fileName) : null;
      const url = imageInfo?.url ?? buildCommonsFileUrl(fileName);
      eventItem.wikidataImageFile = fileName;
      eventItem.wikidataImageUrl = url;
      eventItem.wikidataImageThumbUrl = imageInfo?.thumbUrl ?? url;
      eventItem.wikidataImagePreviewUrl = imageInfo?.previewUrl ?? url;
      eventItem.wikidataImageWidth = imageInfo?.width ?? null;
      eventItem.wikidataImageHeight = imageInfo?.height ?? null;
      eventItem.wikidataImageLookupCompleted = true;
      return fileName && url ? { fileName, url } : null;
    } finally {
      pendingEventImageLookupBySourceId.delete(cacheKey);
    }
  })();
  pendingEventImageLookupBySourceId.set(cacheKey, lookupPromise);
  return lookupPromise;
}

function getEventImageDisplayUrl(eventItem, variant = "full") {
  if (eventItem?.imageDisplayEnabled !== true) return null;
  if (eventItem?.manualImageUrl) return eventItem.manualImageUrl;
  if (variant === "thumb") {
    return eventItem?.wikidataImageThumbUrl || eventItem?.wikidataImagePreviewUrl || eventItem?.wikidataImageUrl || null;
  }
  if (variant === "preview") {
    return eventItem?.wikidataImagePreviewUrl || eventItem?.wikidataImageUrl || null;
  }
  return eventItem?.wikidataImageUrl || eventItem?.wikidataImagePreviewUrl || eventItem?.wikidataImageThumbUrl || null;
}

function getEventPanelImageUrl(eventItem, variant = "preview") {
  if (!eventItem) return null;
  if (isFlagMarkerEvent(eventItem)) {
    return String(eventItem.flagImageUrl || "").trim() || null;
  }
  if ((variant === "preview" || variant === "full") && eventItem.imageSidePanelEnabled === false) {
    return null;
  }
  if (eventItem.manualImageUrl) {
    return eventItem.manualImageUrl;
  }
  if (variant === "thumb") {
    return eventItem?.wikidataImageThumbUrl || eventItem?.wikidataImagePreviewUrl || eventItem?.wikidataImageUrl || null;
  }
  if (variant === "preview") {
    return eventItem?.wikidataImagePreviewUrl || eventItem?.wikidataImageUrl || eventItem?.wikidataImageThumbUrl || null;
  }
  return eventItem?.wikidataImageUrl || eventItem?.wikidataImagePreviewUrl || eventItem?.wikidataImageThumbUrl || null;
}

function getEventImageSourceText(eventItem) {
  if (!eventItem) return "";
  if (isFlagMarkerEvent(eventItem)) {
    const selectedCandidate = getEventSelectedFlagCandidate(eventItem) ?? getStoredFlagCandidate(eventItem);
    return String(selectedCandidate?.sourceLabel || "").trim();
  }
  if (eventItem.manualImageUrl) {
    return String(eventItem.manualImageSource || eventItem.manualImageUrl || "").trim();
  }
  if (eventItem.wikidataImageUrl || eventItem.wikidataImagePreviewUrl || eventItem.wikidataImageThumbUrl) {
    if (eventItem.source === "tmdb") {
      return "TMDb";
    }
    return "Wikidata";
  }
  return "";
}

function parseWorkInformationLines(workInformation) {
  return String(workInformation || "")
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean)
    .map((line) => {
      const separatorIndex = line.indexOf(":");
      return separatorIndex >= 0 ? line.slice(separatorIndex + 1).trim() : line;
    })
    .filter(Boolean);
}

function applyCroppedImageToElement(imageElement, eventItem, frameWidth, frameHeight, options = {}) {
  if (!imageElement || !eventItem) return;
  const placement = getEventImagePlacement(eventItem, 0, 0, frameWidth, frameHeight, options);
  imageElement.style.left = `${placement.x}px`;
  imageElement.style.top = `${placement.y}px`;
  imageElement.style.width = `${placement.width}px`;
  imageElement.style.height = `${placement.height}px`;
}

function buildCroppedEventImagePreview(eventItem, sourceUrl, className = "event-image-display-preview") {
  const preview = document.createElement("div");
  preview.className = className;
  if (isCoverImageEvent(eventItem)) preview.classList.add("is-cover");
  if (!sourceUrl) return preview;
  const image = document.createElement("img");
  image.src = sourceUrl;
  image.alt = eventItem.title || "Wikidata image";
  const applyCrop = () => {
    const frameWidth = preview.clientWidth || 1;
    const frameHeight = preview.clientHeight || (frameWidth / getEventImageFrameAspectRatio(eventItem)) || 1;
    if (image.naturalWidth > 0 && image.naturalHeight > 0) {
      eventItem.wikidataImageWidth = image.naturalWidth;
      eventItem.wikidataImageHeight = image.naturalHeight;
    }
    applyCroppedImageToElement(image, eventItem, frameWidth, frameHeight, { variant: "preview" });
  };
  image.addEventListener("load", applyCrop);
  preview.appendChild(image);
  requestAnimationFrame(applyCrop);
  return preview;
}

function closeThumbCropModal() {
  if (ui.thumbCropViewport && thumbCropModalState.pointerId != null) {
    try {
      ui.thumbCropViewport.releasePointerCapture?.(thumbCropModalState.pointerId);
    } catch {}
  }
  thumbCropModalState.dragging = false;
  thumbCropModalState.pointerId = null;
  thumbCropModalState.eventId = null;
  thumbCropModalState.frameAspectRatio = 1;
  thumbCropModalState.onSave = null;
  ui.thumbCropViewport?.classList.remove("is-cover");
  if (ui.thumbCropModal) ui.thumbCropModal.hidden = true;
}

