if (ui.customFlagConfirmButton) {
  ui.customFlagConfirmButton.addEventListener("click", async () => {
    const ownerEvent = getEventById(customFlagModalState.ownerEventId);
    const flagEvent = getEventById(customFlagModalState.flagEventId);
    if (!ownerEvent || !flagEvent || !ui.customFlagUrlInput || !ui.customFlagSourceInput || !ui.customFlagFileInput) {
      closeCustomFlagModal();
      return;
    }
    const nextUrl = String(ui.customFlagUrlInput.value || "").trim();
    const nextSource = String(ui.customFlagSourceInput.value || "").trim();
    const nextFile = ui.customFlagFileInput.files?.[0] ?? null;
    if (!nextUrl && !nextFile) {
      ui.customFlagUrlInput.focus();
      ui.customFlagUrlInput.select?.();
      return;
    }
    let resolvedUrl = nextUrl;
    let resolvedAssetPath = "";
    let resolvedMediaSourceType = "url";
    let resolvedLabel = deriveFlagCandidateLabelFromUrl(nextUrl);
    let resolvedSourceLabel = nextSource;
    if (nextFile) {
      const nextAssetPath = await writeProjectAssetFile("flags", nextFile);
      if (!nextAssetPath) return;
      const nextAssetUrl = await resolveProjectAssetUrl(nextAssetPath);
      if (!nextAssetUrl) return;
      resolvedUrl = nextAssetUrl;
      resolvedAssetPath = nextAssetPath;
      resolvedMediaSourceType = "local-file";
      resolvedLabel = deriveFlagCandidateLabelFromUrl(nextFile.name);
      resolvedSourceLabel = nextSource || t("flag_custom_local_source");
    }
    const candidateKey = `manual:${createUniqueId("flag-option")}`;
    const nextCandidate = {
      key: candidateKey,
      fileName: candidateKey,
      url: resolvedUrl,
      label: resolvedLabel,
      sourceType: "manual",
      sourceLabel: resolvedSourceLabel,
      mediaSourceType: resolvedMediaSourceType,
      assetPath: resolvedAssetPath,
    };
    setSharedFlagImageCandidates(ownerEvent, [...getSharedFlagImageCandidates(ownerEvent), nextCandidate]);
    flagEvent.flagImageFileName = nextCandidate.key;
    flagEvent.flagImageUrl = nextCandidate.url;
    const rerenderCallback = customFlagModalState.onSave;
    closeCustomFlagModal();
    scheduleLocalAutosave();
    if (typeof rerenderCallback === "function") {
      rerenderCallback({ updateSelection: true });
    } else {
      rerenderEditor({ updateSelection: true });
    }
  });
}

