function primeEventImageMemoryCache(url) {
  if (!url) return;
  const existing = eventImageMemoryCache.get(url);
  if (existing) {
    existing.lastUsed = Date.now();
    return;
  }
  if (typeof Image === "undefined") return;
  const img = new Image();
  img.decoding = "async";
  img.loading = "eager";
  img.src = url;
  eventImageMemoryCache.set(url, {
    image: img,
    lastUsed: Date.now(),
  });
  if (eventImageMemoryCache.size <= EVENT_IMAGE_MEMORY_CACHE_LIMIT) return;
  const entries = [...eventImageMemoryCache.entries()].sort((left, right) => left[1].lastUsed - right[1].lastUsed);
  while (entries.length && eventImageMemoryCache.size > EVENT_IMAGE_MEMORY_CACHE_LIMIT) {
    const [staleUrl] = entries.shift();
    eventImageMemoryCache.delete(staleUrl);
  }
}

function getFlagImageAspectRatio(url) {
  const fallbackRatio = 3 / 2;
  if (!url) return fallbackRatio;
  const cachedAspect = flagImageAspectCache.get(url);
  if (Number.isFinite(cachedAspect?.ratio) && cachedAspect.ratio > 0) {
    return cachedAspect.ratio;
  }
  if (typeof Image === "undefined") return fallbackRatio;
  let cacheEntry = eventImageMemoryCache.get(url);
  if (!cacheEntry) {
    primeEventImageMemoryCache(url);
    cacheEntry = eventImageMemoryCache.get(url);
  }
  const image = cacheEntry?.image;
  if (!image) return fallbackRatio;
  cacheEntry.lastUsed = Date.now();
  if (image.naturalWidth > 0 && image.naturalHeight > 0) {
    const ratio = image.naturalWidth / image.naturalHeight;
    flagImageAspectCache.set(url, { ratio });
    return ratio;
  }
  if (!cachedAspect?.pending) {
    const resolveAspect = () => {
      const ratio = image.naturalWidth > 0 && image.naturalHeight > 0
        ? (image.naturalWidth / image.naturalHeight)
        : fallbackRatio;
      flagImageAspectCache.set(url, { ratio });
      requestAnimationFrame(() => {
        drawTimeline();
      });
    };
    flagImageAspectCache.set(url, { ratio: fallbackRatio, pending: true });
    image.addEventListener("load", resolveAspect, { once: true });
    image.addEventListener("error", resolveAspect, { once: true });
  }
  return fallbackRatio;
}

function warmVisibleEventImageCache(eventItems) {
  if (!Array.isArray(eventItems) || eventItems.length === 0) return;
  eventItems.forEach((eventItem) => {
    if (eventItem?.imageDisplayEnabled !== true) return;
    primeEventImageMemoryCache(getEventImageDisplayUrl(eventItem, "thumb"));
  });
  eventItems.forEach((eventItem) => {
    if (!isFlagMarkerEvent(eventItem) || eventItem?.flagDisplayEnabled !== true) return;
    primeEventImageMemoryCache(String(eventItem.flagImageUrl || "").trim());
  });
  const highlightedImageEventId = state.tooltipExpandedEventId || state.tooltipEventId || null;
  if (!highlightedImageEventId) return;
  const highlightedEvent = eventItems.find((eventItem) => eventItem?.id === highlightedImageEventId);
  if (!highlightedEvent) return;
  if (isFlagMarkerEvent(highlightedEvent) && highlightedEvent.flagDisplayEnabled === true) {
    primeEventImageMemoryCache(String(highlightedEvent.flagImageUrl || "").trim());
    return;
  }
  if (highlightedEvent.imageDisplayEnabled !== true) return;
  primeEventImageMemoryCache(getEventImageDisplayUrl(highlightedEvent, "preview"));
  primeEventImageMemoryCache(getEventImageDisplayUrl(highlightedEvent, "full"));
}

function drawEventImageCard(eventItem, centerX, centerY, width, height, defs) {
  const href = getEventImageDisplayUrl(eventItem, "thumb");
  if (!href || !Number.isFinite(centerX) || !Number.isFinite(centerY)) return null;
  const x = centerX - width / 2;
  const y = centerY - height / 2;
  const imagePlacement = getEventImagePlacement(eventItem, x, y, width, height, { variant: "thumb" });
  const clipId = `event-image-clip-${String(eventItem.id).replace(/[^a-zA-Z0-9_-]/g, "-")}`;
  const clipPath = createSvgElement("clipPath", { id: clipId });
  clipPath.appendChild(createSvgElement("rect", {
    x,
    y,
    width,
    height,
    rx: 8,
  }));
  defs.appendChild(clipPath);

  const group = createSvgElement("g", {
    class: "timeline-event-image-card",
    tabindex: 0,
    role: "button",
    "aria-label": `${eventItem.title}, ${getEventDateLabel(eventItem)}`,
  });
  const shadow = createSvgElement("rect", {
    x,
    y,
    width,
    height,
    rx: 8,
    fill: "rgba(14, 18, 21, 0.78)",
    stroke: "rgba(215, 237, 242, 0.2)",
    "stroke-width": 1,
  });
  const image = createSvgElement("image", {
    href,
    x: imagePlacement.x,
    y: imagePlacement.y,
    width: imagePlacement.width,
    height: imagePlacement.height,
    preserveAspectRatio: "none",
    "clip-path": `url(#${clipId})`,
  });
  group.appendChild(shadow);
  group.appendChild(image);
  return { group, rect: { x, y, width, height } };
}

function drawTimelineFlagMarker(eventItem, centerX, markerY) {
  if (!eventItem || eventItem.flagDisplayEnabled !== true) return null;
  const href = String(eventItem.flagImageUrl || "").trim();
  if (!href || !Number.isFinite(centerX) || !Number.isFinite(markerY)) return null;
  const mastX = centerX;
  const mastHeight = scaleTimelineElementSize(28);
  const mastTopY = markerY - mastHeight;
  const strokeWidth = scaleTimelineElementSize(1.6);
  const imageAspectRatio = getFlagImageAspectRatio(href);
  const presentationMode = normalizeFlagPresentationMode(eventItem.flagPresentationMode);
  const fixedPoleFlagHeight = scaleTimelineElementSize(12);
  const fixedBannerFlagWidth = fixedPoleFlagHeight;
  const armLength = fixedBannerFlagWidth + scaleTimelineElementSize(2);
  const flagHeight = presentationMode === "banner"
    ? (fixedBannerFlagWidth / imageAspectRatio)
    : fixedPoleFlagHeight;
  const flagWidth = presentationMode === "banner"
    ? fixedBannerFlagWidth
    : (fixedPoleFlagHeight * imageAspectRatio);
  const flagX = mastX + scaleTimelineElementSize(2);
  const flagY = presentationMode === "banner"
    ? mastTopY + strokeWidth * 0.5
    : mastTopY + scaleTimelineElementSize(2);
  const group = createSvgElement("g", {
    class: "timeline-flag-marker",
    tabindex: 0,
    role: "button",
    "aria-label": `${eventItem.title}, ${getEventDateLabel(eventItem)}`,
  });
  group.appendChild(createSvgElement("line", {
    x1: mastX,
    y1: mastTopY,
    x2: mastX,
    y2: markerY,
    stroke: "rgba(210, 219, 225, 0.9)",
    "stroke-width": strokeWidth,
    "stroke-linecap": "round",
  }));
  if (presentationMode === "banner") {
    group.appendChild(createSvgElement("line", {
      x1: mastX,
      y1: mastTopY,
      x2: mastX + armLength,
      y2: mastTopY,
      stroke: "rgba(210, 219, 225, 0.9)",
      "stroke-width": strokeWidth,
      "stroke-linecap": "round",
    }));
  }
  group.appendChild(createSvgElement("circle", {
    cx: mastX,
    cy: mastTopY,
    r: scaleTimelineElementSize(1.8),
    fill: "#d7edf2",
  }));
  group.appendChild(createSvgElement("image", {
    href,
    x: flagX,
    y: flagY,
    width: flagWidth,
    height: flagHeight,
    preserveAspectRatio: "xMidYMid meet",
  }));
  group.appendChild(createSvgElement("rect", {
    x: flagX,
    y: flagY,
    width: flagWidth,
    height: flagHeight,
    rx: scaleTimelineElementSize(1.4),
    fill: "none",
    stroke: "rgba(215, 237, 242, 0.55)",
    "stroke-width": 0.8,
  }));
  return {
    group,
    rect: {
      x: mastX - scaleTimelineElementSize(2),
      y: mastTopY - scaleTimelineElementSize(2),
      width: Math.max(flagWidth + scaleTimelineElementSize(6), armLength + scaleTimelineElementSize(4)),
      height: Math.max(mastHeight + scaleTimelineElementSize(2), (flagY - mastTopY) + flagHeight + scaleTimelineElementSize(2)),
    },
  };
}

function applyWikidataLocalizationToEvent(eventItem, entity, fallback = {}) {
  if (!eventItem || !entity) return;
  const preferredLanguage = getWikidataLanguageCode();
  const currentLanguage = getContentLanguageCode();
  const fallbackLanguage = preferredLanguage === "de" ? "en" : "de";
  const label = entity.labels?.[preferredLanguage]?.value || entity.labels?.[fallbackLanguage]?.value || fallback.label;
  const description = entity.descriptions?.[preferredLanguage]?.value || entity.descriptions?.[fallbackLanguage]?.value || fallback.description;
  const previousLocalizedTitle = String(eventItem.wikidataTitle || "");
  const previousLocalizedDescription = String(eventItem.wikidataDescription || "");
  const manualTitle = String(eventItem.customTitle || "").trim();
  const manualTitleLanguage = String(eventItem.customTitleLanguage || "").trim();

  if (label) {
    if (manualTitle && manualTitleLanguage === currentLanguage) {
      eventItem.title = manualTitle;
    } else if (!eventItem.title || eventItem.title === previousLocalizedTitle || eventItem.title === manualTitle) {
      eventItem.title = label;
    }
  }
  if (description && (!eventItem.description || eventItem.description === previousLocalizedDescription)) {
    eventItem.description = description;
  }
  if (label) {
    eventItem.wikidataTitle = label;
  }
  if (description) {
    eventItem.wikidataDescription = description;
    eventItem.wikidataDescriptionMap[getContentLanguageCode()] = description;
  }
  applyResolvedDescription(eventItem);

  const flagImageUrl = getFlagImageUrl(entity);
  if (flagImageUrl) {
    eventItem.flagImageUrl = flagImageUrl;
  }
}

function applyWikidataEntityToGroup(groupItem, entity) {
  if (!groupItem || !entity) return;
  ensureLocalizedDescriptionState(groupItem);
  const preferredLanguage = getWikidataLanguageCode();
  const fallbackLanguage = preferredLanguage === "de" ? "en" : "de";
  const label = entity.labels?.[preferredLanguage]?.value || entity.labels?.[fallbackLanguage]?.value;
  const description = entity.descriptions?.[preferredLanguage]?.value || entity.descriptions?.[fallbackLanguage]?.value;
  if (label) {
    groupItem.title = label;
  }
  const currentLanguage = getContentLanguageCode();
  const previousLocalizedDescription = String(groupItem.wikidataDescriptionMap[currentLanguage] ?? "");
  if (description && (!groupItem.description || groupItem.description === previousLocalizedDescription)) {
    groupItem.description = description;
  }
  if (description) {
    groupItem.wikidataDescriptionMap[currentLanguage] = description;
  }
  applyResolvedDescription(groupItem);
}

async function refreshLocalizedWikidataContent() {
  const wikidataEvents = timelineEvents.filter((eventItem) => eventItem?.sourceId && ["wikidata", "imdb"].includes(eventItem.source));
  const wikidataGroups = eventGroups.filter((groupItem) => groupItem?.sourceId && groupItem.source === "wikidata-preset");
  const allIds = [
    ...wikidataEvents.map((eventItem) => eventItem.sourceId),
    ...wikidataGroups.map((groupItem) => groupItem.sourceId),
  ];

  if (allIds.length === 0) return;

  try {
    const entities = await fetchWikidataEntities(allIds);
    for (const eventItem of wikidataEvents) {
      const entity = entities[eventItem.sourceId];
      if (!entity) continue;
      applyWikidataLocalizationToEvent(eventItem, entity);
      await ensureEventWikidataInstanceOfInfo(eventItem, { force: true, entity }).catch(() => {});
    }
    wikidataGroups.forEach((groupItem) => {
      const entity = entities[groupItem.sourceId];
      if (!entity) return;
      applyWikidataEntityToGroup(groupItem, entity);
    });
  } catch {
    // Keep current visible texts if a language refresh from Wikidata fails.
  }
}

async function hydrateEventsFromWikidata(eventItems) {
  const pendingEvents = eventItems.filter((eventItem) => eventItem?.sourceId);
  if (pendingEvents.length === 0) return;

  const ids = pendingEvents.map((eventItem) => eventItem.sourceId);
  const entities = await fetchWikidataEntities(ids);
  pendingEvents.forEach((eventItem) => {
    const entity = entities[eventItem.sourceId];
    if (!entity) return;
    applyWikidataEntityToEvent(eventItem, entity);
  });
  await Promise.all(pendingEvents.map((eventItem) => {
    const entity = entities[eventItem.sourceId];
    if (!entity) return Promise.resolve();
    return ensureEventWikidataInstanceOfInfo(eventItem, { force: true, entity }).catch(() => {});
  }));
}

async function ensureEventFlag(eventItem) {
  if (!eventItem || eventItem.source !== "wikidata" || !eventItem.sourceId || eventItem.flagImageUrl) {
    return;
  }
  try {
    const entity = await fetchWikidataEntity(eventItem.sourceId);
    if (!entity) return;
    const flagCandidates = getFlagImageCandidates(entity);
    const mergedCandidates = mergeSharedFlagImageCandidates(getSharedFlagImageCandidates(eventItem), flagCandidates);
    setSharedFlagImageCandidates(eventItem, mergedCandidates);
    const selectedFlagCandidate = mergedCandidates.find((candidate) => candidate.key === String(eventItem.flagImageFileName || "").trim())
      ?? mergedCandidates[0]
      ?? null;
    eventItem.flagImageFileName = selectedFlagCandidate?.key ?? "";
    eventItem.flagImageUrl = selectedFlagCandidate?.url ?? null;
  } catch {
    // Ignore flag lookup failures and keep the text-only fallback.
  }
}

async function ensureEventFlagCandidates(eventItem) {
  const lookupEntityId = getFlagLookupEntityId(eventItem);
  if (!eventItem || !lookupEntityId) return [];
  const ownerEvent = getFlagLibraryOwnerEvent(eventItem);
  const currentCandidates = getSharedFlagImageCandidates(eventItem);
  if (currentCandidates.length > 0) {
    if (ownerEvent) {
      ownerEvent.wikidataFlagCandidates = currentCandidates;
      ownerEvent.wikidataFlagCandidatesLookupCompleted = true;
      syncFlagCandidateSelectionsForFamily(ownerEvent);
    }
    return currentCandidates;
  }
  if (ownerEvent?.wikidataFlagCandidatesLookupCompleted === true || eventItem.wikidataFlagCandidatesLookupCompleted === true) return [];
  try {
    const entity = await fetchWikidataEntity(lookupEntityId);
    if (!entity) return [];
    const candidates = getFlagImageCandidates(entity);
    const mergedCandidates = mergeSharedFlagImageCandidates(getSharedFlagImageCandidates(eventItem), candidates);
    setSharedFlagImageCandidates(eventItem, mergedCandidates);
    const selectedFlagCandidate = mergedCandidates.find((candidate) => candidate.key === String(eventItem.flagImageFileName || "").trim())
      ?? mergedCandidates[0]
      ?? null;
    if (selectedFlagCandidate) {
      eventItem.flagImageFileName = selectedFlagCandidate.key;
      eventItem.flagImageUrl = selectedFlagCandidate.url;
    }
    return mergedCandidates;
  } catch {
    if (ownerEvent) ownerEvent.wikidataFlagCandidatesLookupCompleted = true;
    eventItem.wikidataFlagCandidatesLookupCompleted = true;
    return [];
  }
}

async function addWikidataResult(result, onProgress = null) {
  const existing = getEventsWithSameSourceIdInScope(result.id, UNGROUPED_EVENT_SCOPE_KEY)[0] ?? null;

  try {
    const entity = await fetchWikidataEntity(result.id);
    if (!entity) return null;
    const importedEvent = buildEventFromWikidata(result.id, entity, result);
    if (typeof onProgress === "function") {
      onProgress({
        text: tf("loading_processing_result", { title: importedEvent.title || result.label }),
        progress: 62,
      });
    }

      if (existing) {
        applyWikidataEntityToEvent(existing, entity, result);
        await ensureEventWikidataInstanceOfInfo(existing, { force: true, entity });
        await ensurePaintingInfo(existing, { force: true, entity });
        existing.enabled = true;

      // Refresh empty/default metadata from the current Wikidata payload without
      // overwriting user edits indiscriminately.
      if (!existing.title || existing.title === result.label) {
        existing.title = importedEvent.title;
      }
      if (!existing.description || existing.description === result.description) {
        existing.description = importedEvent.description;
      }
      if (!existing.category || existing.category === "Wikidata") {
        existing.category = importedEvent.category;
      }
      if (existing.visibleStepMin === undefined) existing.visibleStepMin = null;
      if (existing.visibleStepMax === undefined) existing.visibleStepMax = null;
      if (existing.lane === undefined) existing.lane = null;
      if (!existing.displayMode) existing.displayMode = importedEvent.displayMode;
      normalizeEventDisplaySettings(existing);
      if (typeof onProgress === "function") {
        onProgress({
          text: t("loading_update_view"),
          progress: 84,
        });
      }
      return existing;
    }

      const targetGroup = getDefaultGroupForNewItem("events");
      if (targetGroup) {
        importedEvent.groupId = targetGroup.id;
        expandGroupAncestors(targetGroup.id);
      }
      timelineEvents.push(importedEvent);
      await ensureEventWikidataInstanceOfInfo(importedEvent, { force: true, entity });
      await ensurePaintingInfo(importedEvent, { force: true, entity });
      if (typeof onProgress === "function") {
      onProgress({
        text: t("loading_update_view"),
        progress: 84,
      });
    }
    return importedEvent;
  } catch {
    if (existing) {
      existing.enabled = true;
      return existing;
    }
    return null;
  }
}

async function addSearchResult(result, onProgress = null) {
  return addWikidataResult(result, onProgress);
}

async function handleSearchSubmit(event) {
  event.preventDefault();
  const query = ui.searchInput.value.trim();
  if (!query) {
    state.searchResultsVisibleCount = SEARCH_RESULTS_PAGE_SIZE;
    ui.searchStatus.textContent = t("search_enter_query");
    return;
  }

  ui.searchStatus.textContent = tf("search_loading", { query });
  try {
    state.searchResults = await searchWikidata(query);
    await enrichSearchResultsWithInstanceOf(state.searchResults);
    state.searchResults = state.searchResults.filter((result) => !isExcludedWikidataEventSearchResult(result));
    state.searchResultsVisibleCount = SEARCH_RESULTS_PAGE_SIZE;
    syncSearchResultFilterOptions();
    updateSearchStatusForResults();
  } catch {
    state.searchResults = [];
    state.searchResultsVisibleCount = SEARCH_RESULTS_PAGE_SIZE;
    state.searchResultFilterValue = "";
    state.searchResultFilterOptions = [];
    ui.searchStatus.textContent = t("search_failed");
  }
  renderSearchFilterUi();
  renderSearchResults();
}

function createNewEventInGroup(targetGroupId = null) {
  const newEvent = createEmptyEvent();
  const targetGroup = targetGroupId ? getGroupById(targetGroupId) : getDefaultGroupForNewItem("events");
  if (targetGroup) {
    newEvent.groupId = targetGroup.id;
    expandGroupAncestors(targetGroup.id);
  }
  timelineEvents.push(newEvent);
  state.openGroupEditorId = null;
  state.openChartEditorId = null;
  state.openSourceCollectionEditorId = null;
  state.openBookmarkEditorId = null;
  state.openEditorId = newEvent.id;
  selectEvent(newEvent.id, true);
  renderEventList();
  scrollToDetails("auto");
  focusEditorNameField("event", { reveal: true, behavior: "auto" });
  scheduleLocalAutosave();
  return newEvent;
}

function createNewEventFromBrowser() {
  return createNewEventInGroup();
}

function createNewChartFromBrowser() {
  const newChart = createEmptyChart();
  const targetGroup = getDefaultGroupForNewItem("charts");
  if (targetGroup) {
    newChart.groupId = targetGroup.id;
    expandGroupAncestors(targetGroup.id);
  }
  newChart.setupMode = "csv-template";
  newChart.csvPasteDraft = buildDefaultChartCsvTemplate(newChart.title);
  newChart.setupError = "";
  ensureChartEditableTable(newChart);
  chartItems.push(newChart);
  state.openEditorId = null;
  state.openGroupEditorId = null;
  state.openSourceEditorId = null;
  state.openSourceCollectionEditorId = null;
  state.openBookmarkEditorId = null;
  state.openChartCommentEditorId = null;
  state.chartFolderExpanded = !targetGroup;
  state.openChartEditorId = newChart.id;
  state.chartValueDraftEditorId = null;
  state.chartCodeDraftEditorId = null;
  activateChartAxisSelection(newChart);
  renderEventList();
  renderChartResults();
  drawTimeline();
  scrollToDetails("auto");
}

function createNewSourceFromSourcesPanel(event) {
  event?.preventDefault?.();
  const title = String(ui.sourcesCreateTitleInput?.value || "").trim();
  if (!title) {
    if (ui.sourcesCreateStatus) ui.sourcesCreateStatus.textContent = t("source_create_missing_title");
    ui.sourcesCreateTitleInput?.focus();
    return;
  }
  const sourceType = normalizeSourceType(ui.sourcesCreateTypeSelect?.value || "image");
  const yearText = String(ui.sourcesCreateYearInput?.value || "").trim();
  const url = String(ui.sourcesCreateUrlInput?.value || "").trim();
  const imageUrl = String(ui.sourcesCreateImageUrlInput?.value || "").trim();
  const imageSource = String(ui.sourcesCreateImageSourceInput?.value || "").trim();
  const temporalValue = parseEditorTemporalValue(yearText);
  const targetGroup = getDefaultGroupForNewSource(sourceType);
  const sourceDraft = {
    id: createUniqueId(`source-${sourceType}`),
    kind: "source",
    sourceType,
    source: "manual",
    sourceId: "",
    externalId: "",
    title,
    description: "",
    url,
    imageUrl,
    yearLabel: yearText,
    imageDisplayEnabled: Boolean(imageUrl),
    imageSidePanelEnabled: true,
    manualImageUrl: imageUrl,
    manualImageSource: imageSource,
    manualImageSourceType: imageUrl ? "url" : "none",
    wikidataImageLookupCompleted: true,
    groupId: targetGroup?.id ?? null,
    enabled: true,
  };
  if (temporalValue) {
    sourceDraft.startYear = temporalValue.value;
    sourceDraft.endYear = temporalValue.value;
    sourceDraft.startDateValue = temporalValue.value;
    sourceDraft.endDateValue = temporalValue.value;
    sourceDraft.startPrecision = temporalValue.precision;
    sourceDraft.endPrecision = temporalValue.precision;
    sourceDraft.isRange = false;
  }
  const sourceItem = normalizeSourceItem(sourceDraft);
  if (!sourceItem) return;
  sourceItems.push(sourceItem);
  const movedSource = moveSourceToSubtype(sourceItem, sourceType) || sourceItem;
  const sourceRoot = movedSource.groupId ? getGroupById(getRootGroupId(movedSource.groupId)) : null;
  if (sourceRoot) sourceRoot.expanded = true;
  if (movedSource.groupId) expandGroupAncestors(movedSource.groupId);
  if (ui.sourcesCreateStatus) ui.sourcesCreateStatus.textContent = tf("source_created", { title: movedSource.title });
  if (ui.sourcesCreateForm) ui.sourcesCreateForm.reset();
  if (ui.sourcesCreateTypeSelect) ui.sourcesCreateTypeSelect.value = sourceType;
  openSourceInLibrary(movedSource);
  drawTimeline();
  scheduleLocalAutosave();
}

function createNewSourceCollectionInGroup(targetGroupId = null, { openCsv = false } = {}) {
  const targetGroup = targetGroupId ? getGroupById(targetGroupId) : getDefaultGroupForNewSourceCollection();
  const collection = normalizeSourceCollection({
    ...createEmptySourceCollection(),
    groupId: targetGroup?.id ?? null,
    activeTab: openCsv ? "csv" : "general",
  });
  if (!collection) return null;
  sourceCollections.push(collection);
  const sourceRoot = collection.groupId ? getGroupById(getRootGroupId(collection.groupId)) : null;
  if (sourceRoot) sourceRoot.expanded = true;
  if (targetGroup) expandGroupAncestors(targetGroup.id);
  openSourceCollectionInLibrary(collection);
  scheduleLocalAutosave();
  return collection;
}

function createNewSourceCollectionFromSourcesPanel({ openCsv = false } = {}) {
  return createNewSourceCollectionInGroup(null, { openCsv });
}

function createNewChartToCsvCodeTab() {
  createNewChartFromBrowser();
  const openChart = getOpenEditorChart();
  if (!openChart) return;
  openChart.setupMode = "csv-empty";
  openChart.csvPasteDraft = "";
  state.chartValueDraftEditorId = null;
  state.chartCodeDraftEditorId = openChart.id;
  renderEventList();
  drawTimeline();
  scrollToDetails("auto");
}

